def _exam_type_badge_html_od(exam_type: str, is_online: bool = False) -> str:
    """Sinav turu icin renkli pill HTML badge."""
    label, color, bg = EXAM_TYPE_DISPLAY.get(exam_type, (exam_type or "Sınav", "#64748b", "#1A2035"))
    online_tag = ""
    if is_online:
        online_tag = (' <span style="background:#7c3aed;color:white;'
                      'padding:1px 6px;border-radius:8px;font-size:0.6rem;'
                      'font-weight:700;margin-left:4px">ONLINE</span>')
    return (f'<span style="display:inline-block;background:{bg};color:{color};'
            f'padding:2px 10px;border-radius:10px;font-size:0.72rem;font-weight:700;'
            f'border:1px solid {color}20;margin-left:8px;">{label}{online_tag}</span>')


def _normalize_month_tag(month_name: str) -> str:
    """Ay adını tag formatına çevir: Kasım -> ay_kasim"""
    return "ay_" + month_name.lower().replace('ı', 'i').replace('ş', 's').replace('ü', 'u').replace('ö', 'o').replace('ç', 'c')

