def _grade_label(g):
    """Sınıf etiketi: 1 → '1. Sınıf', 'Hazırlık' → 'Hazırlık', None → 'Tümü'."""
    if g is None:
        return "Tümü"
    if isinstance(g, str):
        return g
    return f"{g}. Sınıf"

def _grade_sort_key(g):
    """Sıralama anahtarı: int değer, 'Hazırlık' → 8.5."""
    if isinstance(g, int):
        return g
    if g == "Hazırlık":
        return 8.5
    return 99


