def _get_kademe(grade) -> str:
    if grade == "Hazırlık":
        return "LISE"
    if isinstance(grade, int):
        if 1 <= grade <= 4: return "ILKOKUL"
        elif 5 <= grade <= 8: return "ORTAOKUL"
        elif 9 <= grade <= 12: return "LISE"
    return "ORTAOKUL"

