def _get_students_path() -> str:
    """Öğrenci veri dosyası yolunu döndürür (merkezi kaynak: data/akademik)."""
    return os.path.join(os.path.dirname(os.path.dirname(__file__)), "data", "akademik", "students.json")


def _load_students() -> list:
    """Tüm öğrencileri yükler (merkezi kaynak: Akademik Takip)."""
    from utils.shared_data import load_shared_students
    return load_shared_students()


def _save_students(students: list):
    """Öğrenci listesini kaydeder (merkezi kaynak: data/akademik)."""
    path = _get_students_path()
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, 'w', encoding='utf-8') as f:
        json.dump(students, f, ensure_ascii=False, indent=2)


def _get_classes() -> list:
    """Mevcut sınıf/şube listesini döndürür."""
    students = _load_students()
    classes = set()
    for s in students:
        classes.add(f"{s['sinif']}{s['sube']}")
    return sorted(list(classes))


def _get_students_by_class(sinif: int, sube: str) -> list:
    """Belirli sınıf ve şubedeki öğrencileri döndürür."""
    students = _load_students()
    return [s for s in students if s['sinif'] == sinif and s['sube'] == sube]


def _generate_booklet_number(exam_id: str, student_id: str) -> str:
    """Benzersiz kitapçık numarası oluşturur."""
    import hashlib
    combined = f"{exam_id}_{student_id}"
    hash_obj = hashlib.md5(combined.encode())
    return hash_obj.hexdigest()[:8].upper()


# ============================================================
# AI KAZANIM EŞLEŞTİRME
# ============================================================

def ai_match_outcome(question_text: str, outcomes: list, grade: int = None, subject: str = None) -> dict:
    """
    AI destekli kazanım eşleştirme.
    Soru metnini analiz eder ve en uygun kazanımı bulur.

    Returns:
        dict: {"outcome": Outcome, "confidence": float, "reasoning": str} veya {"error": str}
    """
    try:
        from openai import OpenAI

        api_key = os.environ.get("OPENAI_API_KEY")
        if not api_key:
            return {"error": "OPENAI_API_KEY tanımlı değil. Lütfen .env dosyasını kontrol edin."}

        client = OpenAI(api_key=api_key)

        # Kazanımları filtrele (sınıf ve ders bazlı)
        filtered_outcomes = outcomes
        if grade:
            filtered_outcomes = [o for o in filtered_outcomes if o.grade == grade]
        if subject:
            filtered_outcomes = [o for o in filtered_outcomes if o.subject == subject]

        if not filtered_outcomes:
            # Filtre sonucu boşsa tüm kazanımları kullan
            filtered_outcomes = outcomes

        if not filtered_outcomes:
            return {"error": "Sistemde kayıtlı kazanım bulunamadı."}

        # Kazanım listesini hazırla
        outcome_list = []
        for i, o in enumerate(filtered_outcomes[:50]):  # Max 50 kazanım
            outcome_list.append(f"{i+1}. [{o.outcome_code}] {o.outcome_text}")

        outcomes_text = "\n".join(outcome_list)

        # AI'ya sor
        prompt = f"""Aşağıdaki soru için en uygun kazanımı belirle.

SORU:
{question_text}

KAZANIMLAR:
{outcomes_text}

Yanıtını şu formatta ver (sadece JSON):
{{
    "selected_index": <1-{len(filtered_outcomes)} arası numara>,
    "confidence": <0.0-1.0 arası güven skoru>,
    "reasoning": "<kısa açıklama>"
}}

Eğer hiçbir kazanım uygun değilse:
{{
    "selected_index": 0,
    "confidence": 0.0,
    "reasoning": "<neden uygun kazanım bulunamadı>"
}}"""

        response = client.chat.completions.create(
            model="gpt-4o-mini",
            messages=[
                {"role": "system", "content": "Sen bir eğitim uzmanısın. Soruları kazanımlarla eşleştiriyorsun. Yanıtını sadece JSON formatında ver."},
                {"role": "user", "content": prompt}
            ],
            max_tokens=300,
            temperature=0.3
        )

        result_text = response.choices[0].message.content.strip()

        # JSON parse
        # Markdown code block varsa temizle
        if result_text.startswith("```"):
            result_text = result_text.split("```")[1]
            if result_text.startswith("json"):
                result_text = result_text[4:]
            result_text = result_text.strip()

        result = json.loads(result_text)

        selected_index = result.get("selected_index", 0)
        confidence = result.get("confidence", 0.0)
        reasoning = result.get("reasoning", "")

        if selected_index > 0 and selected_index <= len(filtered_outcomes):
            return {
                "outcome": filtered_outcomes[selected_index - 1],
                "confidence": confidence,
                "reasoning": reasoning
            }
        else:
            return {
                "outcome": None,
                "confidence": 0.0,
                "reasoning": reasoning or "Uygun kazanım bulunamadı"
            }

    except json.JSONDecodeError as e:
        return {"error": f"AI yanıtı parse edilemedi: {str(e)}"}
    except Exception as e:
        return {"error": f"AI eşleştirme hatası: {str(e)}"}


def ai_match_outcomes_bulk(questions: list, outcomes: list, grade: int = None, subject: str = None) -> list:
    """
    Toplu AI kazanım eşleştirme.
    Birden fazla soru için tek seferde eşleştirme yapar (daha verimli).

    Returns:
        list: Her soru için {"outcome": Outcome, "confidence": float} listesi
    """
    try:
        from openai import OpenAI

        api_key = os.environ.get("OPENAI_API_KEY")
        if not api_key:
            return [{"error": "OPENAI_API_KEY tanımlı değil"}] * len(questions)

        client = OpenAI(api_key=api_key)

        # Kazanımları filtrele
        filtered_outcomes = outcomes
        if grade:
            filtered_outcomes = [o for o in filtered_outcomes if o.grade == grade]
        if subject:
            filtered_outcomes = [o for o in filtered_outcomes if o.subject == subject]

        if not filtered_outcomes:
            filtered_outcomes = outcomes

        if not filtered_outcomes:
            return [{"error": "Kazanım bulunamadı"}] * len(questions)

        # Kazanım listesini hazırla
        outcome_list = []
        for i, o in enumerate(filtered_outcomes[:50]):
            outcome_list.append(f"{i+1}. [{o.outcome_code}] {o.outcome_text}")

        outcomes_text = "\n".join(outcome_list)

        # Soru listesini hazırla
        questions_text = ""
        for i, q in enumerate(questions):
            q_text = q.get('stem', q.get('question_text', f'Görsel Soru #{i+1}'))
            questions_text += f"SORU {i+1}: {q_text}\n\n"

        prompt = f"""Aşağıdaki soruların her biri için en uygun kazanımı belirle.

SORULAR:
{questions_text}

KAZANIMLAR:
{outcomes_text}

Her soru için yanıtını şu formatta ver (JSON dizisi):
[
    {{"question_index": 1, "outcome_index": <1-{len(filtered_outcomes)}>, "confidence": <0.0-1.0>}},
    ...
]

Uygun kazanım yoksa outcome_index: 0 yaz."""

        response = client.chat.completions.create(
            model="gpt-4o-mini",
            messages=[
                {"role": "system", "content": "Sen bir eğitim uzmanısın. Soruları kazanımlarla eşleştiriyorsun. Yanıtını sadece JSON formatında ver."},
                {"role": "user", "content": prompt}
            ],
            max_tokens=1000,
            temperature=0.3
        )

        result_text = response.choices[0].message.content.strip()

        # JSON parse
        if result_text.startswith("```"):
            result_text = result_text.split("```")[1]
            if result_text.startswith("json"):
                result_text = result_text[4:]
            result_text = result_text.strip()

        results = json.loads(result_text)

        # Sonuçları işle
        matched = []
        for i, q in enumerate(questions):
            match = next((r for r in results if r.get("question_index") == i + 1), None)
            if match and match.get("outcome_index", 0) > 0:
                idx = match["outcome_index"] - 1
                if idx < len(filtered_outcomes):
                    matched.append({
                        "outcome": filtered_outcomes[idx],
                        "confidence": match.get("confidence", 0.5)
                    })
                else:
                    matched.append({"outcome": None, "confidence": 0.0})
            else:
                matched.append({"outcome": None, "confidence": 0.0})

        return matched

    except Exception as e:
        return [{"error": str(e)}] * len(questions)


