@st.fragment
def _render_od_dashboard():
    """Olcme Degerlendirme Dashboard - genel bakis paneli."""

    # --- Veri yukle (cache'li) ---
    outcomes = _cached_get_all_outcomes()
    questions = _cached_get_questions_light()
    blueprints = _cached_get_blueprints()
    exams = _cached_get_exams()
    sessions = _cached_get_sessions()
    results = _cached_get_all_results()

    # --- KPI Stat Cards ---
    styled_stat_row([
        ("Toplam Kazanim", len(outcomes), "#2563eb", "\U0001F3AF"),
        ("Toplam Soru", len(questions), "#10b981", "\U0001F4DD"),
        ("Sablon", len(blueprints), "#8b5cf6", "\U0001F4CB"),
        ("Sınav", len(exams), "#f59e0b", "\U0001F4C4"),
        ("Oturum", len(sessions), "#00695c", "\U0001F465"),
        ("Sonuc", len(results), "#ef4444", "\U0001F4CA"),
    ], compact=True)

    st.markdown("<div style='height:18px'></div>", unsafe_allow_html=True)

    # --- Aktif sinav badge ---
    active_exams = [e for e in exams if getattr(e, "status", "") == "active"]
    if active_exams:
        styled_info_banner(
            f"Su anda <b>{len(active_exams)}</b> aktif sinav bulunuyor.",
            banner_type="success"
        )

    # --- Hızlı Aksiyonlar ---
    styled_section("Hizli Aksiyonlar", "#1e3a5f")
    qa1, qa2, qa3, qa4 = st.columns(4)
    _qa_cards = [
        ("🤖", "Soru Uret", "linear-gradient(135deg,#1e3a5f,#3b6fa0)"),
        ("📋", "Sinav Olustur", "linear-gradient(135deg,#10b981,#34d399)"),
        ("📝", "Degerlendir", "linear-gradient(135deg,#C8952E,#E8C975)"),
        ("📈", "Rapor Al", "linear-gradient(135deg,#8b5cf6,#a78bfa)"),
    ]
    for col, (ic, lbl, grad) in zip([qa1, qa2, qa3, qa4], _qa_cards):
        with col:
            st.markdown(f"""<div style="background:{grad};
            padding:14px 16px;border-radius:14px;text-align:center;color:white;font-size:0.85rem;
            font-weight:700;cursor:pointer;box-shadow:0 6px 20px rgba(0,0,0,0.12);
            transition:all 0.3s ease;position:relative;overflow:hidden">
            <div style="position:absolute;top:0;left:0;right:0;height:2px;
            background:linear-gradient(90deg,transparent,rgba(255,255,255,0.5),transparent)"></div>
            <span style="font-size:1.3rem;display:block;margin-bottom:4px">{ic}</span>{lbl}</div>""", unsafe_allow_html=True)

    st.markdown("<div style='height:12px'></div>", unsafe_allow_html=True)

    # --- Son Oluşturulan Sınavlar ---
    styled_section("Son Oluşturulan Sınavlar", "#2563eb")

    if exams:
        sorted_exams = sorted(exams, key=lambda e: getattr(e, "created_at", ""), reverse=True)[:8]
        exam_cols = st.columns(min(len(sorted_exams), 4))
        for idx, ex in enumerate(sorted_exams):
            with exam_cols[idx % 4]:
                status = getattr(ex, "status", "draft")
                status_color = "#10b981" if status == "active" else "#64748b"
                status_label = "Aktif" if status == "active" else "Taslak" if status == "draft" else status.capitalize()
                q_count = len(getattr(ex, "question_ids", []))
                title = getattr(ex, "title", "Isimsiz Sınav")
                subject = getattr(ex, "subject", "")
                created = getattr(ex, "created_at", "")[:10]
                st.markdown(f"""
                <div style="background:linear-gradient(135deg,#0a1628 0%,#122240 100%);border:1px solid rgba(200,149,46,0.25);border-radius:16px;
                padding:18px;margin:6px 0;box-shadow:0 4px 16px rgba(0,0,0,0.3);
                border-top:3px solid {status_color};transition:all 0.3s ease">
                  <div style="font-size:0.85rem;font-weight:700;color:#e2e8f0;
                  margin-bottom:6px;line-height:1.3;min-height:36px;
                  overflow:hidden;text-overflow:ellipsis;display:-webkit-box;
                  -webkit-line-clamp:2;-webkit-box-orient:vertical;">{title}</div>
                  <div style="font-size:0.75rem;color:#C8952E;margin-bottom:4px;font-weight:600">
                    {subject}</div>
                  <div style="display:flex;justify-content:space-between;align-items:center;margin-top:8px;">
                    <span style="font-size:0.75rem;color:#94a3b8;font-weight:500">{q_count} soru</span>
                    <span style="background:{status_color}25;color:{status_color};
                    padding:3px 12px;border-radius:12px;font-size:0.68rem;
                    font-weight:700;border:1px solid {status_color}40">{status_label}</span>
                  </div>
                  <div style="font-size:0.68rem;color:#64748b;margin-top:6px;
                  text-align:right;font-weight:500">{created}</div>
                </div>
                """, unsafe_allow_html=True)
    else:
        st.info("Henuz sinav olusturulmadi.")

    # --- Kullanim Kilavuzu PDF ---
    st.markdown("<div style='height:18px'></div>", unsafe_allow_html=True)
    styled_section("Dokumantasyon", "#6b21a8")

    col_doc1, col_doc2 = st.columns([3, 1])
    with col_doc1:
        st.markdown("""
        <div style="background:linear-gradient(135deg,#6b21a822,#a855f722);border:1px solid #a855f733;
        border-radius:14px;padding:18px 22px">
            <div style="font-size:1rem;font-weight:700;color:#6b21a8;margin-bottom:6px">
                Kullanma Kilavuzu & Ozellik Rehberi</div>
            <div style="font-size:0.78rem;color:#64748b;line-height:1.5">
                Tum ozelliklerin detayli aciklamasi, adim adim kullanim talimatlari,
                soru tipleri, IRT/CAT analiz rehberi, LTI entegrasyon, proctoring ve daha fazlasi.
                Profesyonel PDF formatinda indirin.</div>
        </div>
        """, unsafe_allow_html=True)
    with col_doc2:
        if st.button("PDF Kilavuz Olustur", type="primary", key="gen_kilavuz_pdf", use_container_width=True):
            with st.spinner("PDF kilavuz hazirlaniyor..."):
                pdf_bytes = _generate_kilavuz_pdf()
            if pdf_bytes:
                st.session_state['_kilavuz_pdf'] = pdf_bytes

    if st.session_state.get('_kilavuz_pdf'):
        st.download_button(
            "Kilavuzu Indir (PDF)",
            st.session_state['_kilavuz_pdf'],
            file_name="SmartCampus_Olcme_Degerlendirme_Kilavuz.pdf",
            mime="application/pdf",
            use_container_width=True,
            key="dl_kilavuz"
        )


def _generate_kilavuz_pdf() -> bytes:
    """Olcme Degerlendirme modulu icin profesyonel kullanma kilavuzu PDF'i uret."""
    try:
        from reportlab.lib import colors
        from reportlab.lib.pagesizes import A4
        from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
        from reportlab.lib.units import cm
        from reportlab.platypus import (
            SimpleDocTemplate, Paragraph, Spacer, Table, TableStyle,
            PageBreak, KeepTogether
        )
        from reportlab.lib.enums import TA_CENTER, TA_LEFT, TA_JUSTIFY
    except ImportError:
        return None

    from utils.shared_data import ensure_turkish_pdf_fonts
    font_name, font_bold = ensure_turkish_pdf_fonts()

    buffer = io.BytesIO()
    doc = SimpleDocTemplate(
        buffer, pagesize=A4,
        topMargin=2*cm, bottomMargin=2*cm,
        leftMargin=2.2*cm, rightMargin=2.2*cm
    )

    styles = getSampleStyleSheet()

    # --- Ozel Stiller ---
    NAVY = colors.HexColor('#0f2744')
    GOLD = colors.HexColor('#C8952E')
    BLUE = colors.HexColor('#1e3a5f')
    DARK = colors.HexColor('#94A3B8')
    GRAY = colors.HexColor('#64748b')
    GREEN = colors.HexColor('#059669')
    WHITE = colors.white

    styles.add(ParagraphStyle('KapakBaslik', fontSize=28, leading=34, alignment=TA_CENTER,
                               fontName=font_bold, textColor=NAVY, spaceAfter=8))
    styles.add(ParagraphStyle('KapakAlt', fontSize=14, leading=18, alignment=TA_CENTER,
                               fontName=font_name, textColor=GOLD, spaceAfter=6))
    styles.add(ParagraphStyle('KapakInfo', fontSize=10, leading=14, alignment=TA_CENTER,
                               fontName=font_name, textColor=GRAY, spaceAfter=4))
    styles.add(ParagraphStyle('Bolum', fontSize=18, leading=22, fontName=font_bold,
                               textColor=NAVY, spaceBefore=24, spaceAfter=14,
                               borderWidth=0, borderColor=GOLD, borderPadding=6))
    styles.add(ParagraphStyle('AltBolum', fontSize=13, leading=17, fontName=font_bold,
                               textColor=BLUE, spaceBefore=14, spaceAfter=8))
    styles.add(ParagraphStyle('Metin', fontSize=9.5, leading=14, fontName=font_name,
                               textColor=DARK, spaceAfter=6, alignment=TA_JUSTIFY))
    styles.add(ParagraphStyle('MetinBold', fontSize=9.5, leading=14, fontName=font_bold,
                               textColor=DARK, spaceAfter=4))
    styles.add(ParagraphStyle('Madde', fontSize=9, leading=13, fontName=font_name,
                               textColor=DARK, spaceAfter=3, leftIndent=14,
                               bulletIndent=0, bulletFontSize=9))
    styles.add(ParagraphStyle('TabloBaslik', fontSize=8.5, leading=11, fontName=font_bold,
                               textColor=WHITE, alignment=TA_CENTER))
    styles.add(ParagraphStyle('TabloHucre', fontSize=8.5, leading=11, fontName=font_name,
                               textColor=DARK))
    styles.add(ParagraphStyle('Dipnot', fontSize=7.5, leading=10, fontName=font_name,
                               textColor=GRAY, spaceAfter=2))
    styles.add(ParagraphStyle('SayfaNo', fontSize=8, leading=10, fontName=font_name,
                               textColor=GRAY, alignment=TA_CENTER))

    elements = []

    def gold_line():
        """Altin ayirici cizgi."""
        t = Table([['']],colWidths=[doc.width])
        t.setStyle(TableStyle([
            ('LINEBELOW', (0,0), (-1,-1), 2, GOLD),
            ('TOPPADDING', (0,0), (-1,-1), 0),
            ('BOTTOMPADDING', (0,0), (-1,-1), 6),
        ]))
        return t

    def section_header(text):
        """Bolum basligi — altin cizgili."""
        return KeepTogether([
            Paragraph(text, styles['Bolum']),
            gold_line(),
        ])

    def sub_header(text):
        return Paragraph(text, styles['AltBolum'])

    def para(text):
        return Paragraph(text, styles['Metin'])

    def bold_para(text):
        return Paragraph(text, styles['MetinBold'])

    def bullet(text):
        return Paragraph(f"• {text}", styles['Madde'])

    def spacer(h=0.3):
        return Spacer(1, h*cm)

    def feature_table(rows, col_widths=None):
        """Ozellik tablosu olustur."""
        if not col_widths:
            col_widths = [4*cm, doc.width - 4*cm]
        t = Table(rows, colWidths=col_widths, repeatRows=1)
        style_cmds = [
            ('BACKGROUND', (0, 0), (-1, 0), NAVY),
            ('TEXTCOLOR', (0, 0), (-1, 0), WHITE),
            ('FONTNAME', (0, 0), (-1, 0), font_bold),
            ('FONTSIZE', (0, 0), (-1, 0), 9),
            ('FONTNAME', (0, 1), (-1, -1), font_name),
            ('FONTSIZE', (0, 1), (-1, -1), 8.5),
            ('ALIGN', (0, 0), (-1, 0), 'CENTER'),
            ('VALIGN', (0, 0), (-1, -1), 'TOP'),
            ('GRID', (0, 0), (-1, -1), 0.5, colors.HexColor('#e2e8f0')),
            ('ROWBACKGROUNDS', (0, 1), (-1, -1), [WHITE, colors.HexColor('#111827')]),
            ('TOPPADDING', (0, 0), (-1, -1), 5),
            ('BOTTOMPADDING', (0, 0), (-1, -1), 5),
            ('LEFTPADDING', (0, 0), (-1, -1), 6),
            ('RIGHTPADDING', (0, 0), (-1, -1), 6),
        ]
        t.setStyle(TableStyle(style_cmds))
        return t

    # ================================================================
    # KAPAK SAYFASI
    # ================================================================
    elements.append(Spacer(1, 4*cm))

    # Ust dekoratif cizgi
    t = Table([['']],colWidths=[doc.width])
    t.setStyle(TableStyle([('LINEBELOW',(0,0),(-1,-1),3,GOLD)]))
    elements.append(t)
    elements.append(spacer(1))

    elements.append(Paragraph("OLCME VE DEGERLENDIRME", styles['KapakBaslik']))
    elements.append(Paragraph("KULLANMA KILAVUZU", styles['KapakBaslik']))
    elements.append(spacer(0.5))
    elements.append(Paragraph("Tum Ozellikler & Adim Adim Rehber", styles['KapakAlt']))
    elements.append(spacer(0.8))

    t = Table([['']],colWidths=[doc.width])
    t.setStyle(TableStyle([('LINEBELOW',(0,0),(-1,-1),1.5,GOLD)]))
    elements.append(t)
    elements.append(spacer(1.5))

    elements.append(Paragraph("SmartCampus AI Egitim Platformu", styles['KapakInfo']))
    elements.append(Paragraph("Versiyon 4.0 — Sektor Standardi Uzeri", styles['KapakInfo']))
    elements.append(Paragraph("Mart 2026", styles['KapakInfo']))

    elements.append(Spacer(1, 3*cm))

    # Alt dekoratif cizgi
    t = Table([['']],colWidths=[doc.width])
    t.setStyle(TableStyle([('LINEBELOW',(0,0),(-1,-1),3,GOLD)]))
    elements.append(t)

    elements.append(PageBreak())

    # ================================================================
    # ICINDEKILER
    # ================================================================
    elements.append(section_header("ICINDEKILER"))
    elements.append(spacer(0.3))

    toc_items = [
        ("1.", "Genel Bakis ve Modul Yapisi"),
        ("2.", "Soru Merkezi"),
        ("  2.1", "AI ile Soru Uretimi"),
        ("  2.2", "Soru Bankasi"),
        ("  2.3", "Ice Aktarma (PDF / Excel)"),
        ("  2.4", "Rubrik Yonetimi"),
        ("  2.5", "Versiyon Yonetimi"),
        ("3.", "Soru Tipleri"),
        ("4.", "Sinav Olusturma"),
        ("  4.1", "Hizli Sinav Olusturma"),
        ("  4.2", "Gelismis Ayarlar"),
        ("  4.3", "PDF Sinav Export"),
        ("5.", "Online Sinav Sistemi"),
        ("  5.1", "Ogrenci Giris ve Sinav Cozme"),
        ("  5.2", "Canli Sinav Izleme"),
        ("  5.3", "Proctoring (Gozetim)"),
        ("6.", "Degerlendirme ve Puanlama"),
        ("  6.1", "Otomatik Puanlama"),
        ("  6.2", "Negatif Puanlama"),
        ("  6.3", "Not Aktarimi"),
        ("7.", "Raporlar ve Analiz"),
        ("  7.1", "Performans Dashboard"),
        ("  7.2", "Psikometrik Analiz"),
        ("  7.3", "Celdirici Analizi"),
        ("  7.4", "IRT Madde Tepki Kurami"),
        ("  7.5", "CAT — Bilgisayar Uyarlamali Test"),
        ("  7.6", "Ogrenme Analitikleri"),
        ("  7.7", "Benchmark Karsilastirma"),
        ("  7.8", "Guvenlik Raporu"),
        ("8.", "Entegrasyonlar"),
        ("  8.1", "QTI 2.1 Import/Export"),
        ("  8.2", "LTI 1.3 (Moodle/Canvas)"),
        ("9.", "Bloom Taksonomisi"),
        ("10.", "Telafi Sistemi"),
        ("11.", "Stok Kontrol"),
        ("12.", "Teknik Bilgiler"),
    ]
    toc_rows = [[
        Paragraph("No", styles['TabloBaslik']),
        Paragraph("Konu", styles['TabloBaslik'])
    ]]
    for no, konu in toc_items:
        indent = "    " if no.startswith("  ") else ""
        toc_rows.append([no.strip(), f"{indent}{konu}"])
    elements.append(feature_table(toc_rows, [1.5*cm, doc.width - 1.5*cm]))
    elements.append(PageBreak())

    # ================================================================
    # 1. GENEL BAKIS
    # ================================================================
    elements.append(section_header("1. GENEL BAKIS VE MODUL YAPISI"))

    elements.append(para(
        "Olcme ve Degerlendirme modulu, SmartCampus AI platformunun en kapsamli moduludur. "
        "Soru uretiminden sinav olusturmaya, online sinav uygulamasindan psikometrik analize kadar "
        "egitim olcme-degerlendirme surecinin tamamini kapsar."
    ))
    elements.append(spacer(0.3))

    elements.append(sub_header("Ana Sekmeler"))
    tabs_data = [
        [Paragraph("Sekme", styles['TabloBaslik']),
         Paragraph("Icerik", styles['TabloBaslik']),
         Paragraph("Alt Sekmeler", styles['TabloBaslik'])],
        ["Dashboard", "Genel bakis, KPI kartlari, hizli aksiyonlar", "—"],
        ["Soru Merkezi", "Soru uretimi, soru bankasi, ice aktar, rubrik, versiyon", "5 tab"],
        ["Sinav Olustur", "Hizli sinav, disaridan yukleme, arsiv", "3 tab"],
        ["Online Sinav", "Ogrenci giris, sinav cozme, izleme", "3+ tab"],
        ["Degerlendir", "Puanlama, sonuc, canli izleme, not aktarim", "6 tab"],
        ["Raporlar", "Performans, psikometrik, IRT, CAT, LTI, proctoring", "3 grup, 16 tab"],
    ]
    elements.append(feature_table(tabs_data, [2.5*cm, 5.5*cm, doc.width - 8*cm]))
    elements.append(spacer(0.5))

    elements.append(sub_header("Temel Yetenekler"))
    for item in [
        "AI destekli soru uretimi (OpenAI GPT-4o-mini)",
        "MEB yillik plan entegrasyonu (6800+ kazanim)",
        "7 farkli soru tipi destegi",
        "Online sinav sistemi (QR kod ile giris)",
        "Otomatik puanlama ve telafi sistemi",
        "IRT (1-PL, 2-PL, 3-PL) madde analizi",
        "CAT (Computerized Adaptive Testing)",
        "LTI 1.3 ile LMS entegrasyonu",
        "Proctoring (sinav gozetim) sistemi",
        "QTI 2.1 standardi ile interoperability",
        "Profesyonel PDF sinav ve optik form uretimi",
    ]:
        elements.append(bullet(item))

    elements.append(PageBreak())

    # ================================================================
    # 2. SORU MERKEZI
    # ================================================================
    elements.append(section_header("2. SORU MERKEZI"))

    elements.append(sub_header("2.1 AI ile Soru Uretimi"))
    elements.append(para(
        "Soru Merkezi > Soru Uret sekmesinden AI destekli soru uretimi yapilir. "
        "Sistem MEB yillik plani uzerinden kazanim secer ve her kazanima uygun sorular uretir."
    ))
    elements.append(spacer(0.2))
    elements.append(bold_para("Adim Adim:"))
    for step in [
        "Sinif ve ders secin",
        "Kazanim secimi yapin (otomatik veya manuel)",
        "Soru sayisi ve zorluk seviyesini belirleyin",
        "Bloom taksonomisi seviyesini secin (opsiyonel)",
        "'Soru Uret' butonuna basin — AI soruları uretiricektir",
        "Uretilen sorular onay bekliyor (draft) olarak soru bankasina eklenir",
    ]:
        elements.append(bullet(step))
    elements.append(spacer(0.3))

    elements.append(sub_header("2.2 Soru Bankasi"))
    elements.append(para(
        "Tum sorular iki kategoride yonetilir: Kazanim Bankasi (AI uretimi) ve Disardan Yuklenen "
        "(PDF import, manuel). Filtreler: Durum, Sinif, Ders, Ay, Arama."
    ))
    elements.append(spacer(0.2))
    elements.append(bold_para("Soru Durumu Akisi:"))
    elements.append(para("draft → in_review → approved (veya rejected)"))
    elements.append(spacer(0.3))

