def _sinav_sonuclari_filters(key_prefix: str = "ss"):
    """Sınav sonuçları filtre bileşeni. Returns tuple of filter values."""
    from utils.shared_data import get_sinif_sube_listesi
    from datetime import timedelta

    sinif_sube_data = get_sinif_sube_listesi()
    siniflar = sinif_sube_data.get("siniflar", [])
    subeler = sinif_sube_data.get("subeler", [])

    fc1, fc2, fc3, fc4 = st.columns(4)
    with fc1:
        grade_options = [None] + GRADES
        grade_filter = st.selectbox(
            "Sınıf", grade_options,
            format_func=lambda g: "Tümü" if g is None else _grade_label(g),
            key=f"{key_prefix}_grade"
        )
    with fc2:
        section_options = ["Tümü"] + subeler
        section_filter = st.selectbox("Şube", section_options, key=f"{key_prefix}_section")
        if section_filter == "Tümü":
            section_filter = None
    with fc3:
        subject_filter = st.multiselect("Ders", SUBJECTS, key=f"{key_prefix}_subject")
    with fc4:
        exam_type_filter = st.multiselect("Sınav Türü", EXAM_TYPES, key=f"{key_prefix}_type")

    fc5, fc6, fc7, _ = st.columns(4)
    with fc5:
        today = datetime.now().date()
        start_date = st.date_input(
            "Başlangıç", value=today - timedelta(days=180),
            key=f"{key_prefix}_start"
        )
    with fc6:
        end_date = st.date_input("Bitiş", value=today, key=f"{key_prefix}_end")
    with fc7:
        student_search = st.text_input(
            "Öğrenci Ara", placeholder="Ad veya numara...",
            key=f"{key_prefix}_student"
        )

    return (
        grade_filter, section_filter,
        subject_filter or None, exam_type_filter or None,
        start_date, end_date, student_search.strip() if student_search else None,
    )


def _collect_sinav_sonuclari(store, grade=None, section=None, subjects=None,
                              exam_types=None, start_date=None, end_date=None,
                              student_search=None):
    """Filtrelenmiş sınav sonuçlarını toplar (batch loading ile hızlı).

    Returns:
        (filtered_exams, all_results, exam_map)
    """
    all_exams = _cached_get_exams()
    filtered_exams = []

    for e in all_exams:
        # Tarih filtresi
        if start_date or end_date:
            try:
                exam_date = datetime.fromisoformat(e.created_at).date()
                if start_date and exam_date < start_date:
                    continue
                if end_date and exam_date > end_date:
                    continue
            except Exception:
                pass
        # Sınıf filtresi
        if grade is not None:
            try:
                if isinstance(grade, int) and int(e.grade) != grade:
                    continue
                elif isinstance(grade, str) and str(e.grade) != grade:
                    continue
            except (ValueError, TypeError):
                if str(e.grade) != str(grade):
                    continue
        # Ders filtresi
        if subjects and e.subject not in subjects:
            continue
        # Sınav türü filtresi
        if exam_types and e.exam_type not in exam_types:
            continue
        filtered_exams.append(e)

    # Toplu veri yükleme: TÜM sonuçları bir kerede yükle (N+1 query yerine)
    all_db_results = _cached_get_all_results()
    filtered_exam_ids = {exam.id for exam in filtered_exams}

    # Sonuçları filtrele
    all_results = []
    exam_map = {}
    for r in all_db_results:
        if r.exam_id not in filtered_exam_ids:
            continue
        # Şube filtresi
        if section and r.section != section:
            continue
        # Öğrenci arama
        if student_search:
            search_lower = student_search.lower()
            if (search_lower not in (r.student_name or "").lower()
                    and search_lower not in (r.student_number or "")):
                continue
        all_results.append(r)
        if r.exam_id not in exam_map:
            for exam in filtered_exams:
                if exam.id == r.exam_id:
                    exam_map[exam.id] = exam
                    break

    return filtered_exams, all_results, exam_map


def _render_ss_tum_sonuclar(store):
    """Alt Sekme 1: Tüm sınav sonuçları - filtrelenebilir master görünüm."""
    st.markdown("#### 📋 Tüm Sınav Sonuçları")
    st.caption("Tüm sınavların sonuçlarını filtreleyin ve görüntüleyin.")

    # Filtreler
    (grade, section, subjects, exam_types,
     start_date, end_date, student_search) = _sinav_sonuclari_filters("ss_tum")

    # Veri topla
    filtered_exams, all_results, exam_map = _collect_sinav_sonuclari(
        store, grade, section, subjects, exam_types, start_date, end_date, student_search)

    if not all_results:
        styled_info_banner("Filtrelere uygun sonuç bulunamadı.", "warning")
        return

    # KPI istatistikler
    scores = [r.score for r in all_results]
    avg = sum(scores) / len(scores) if scores else 0
    basari = (sum(1 for s in scores if s >= 50) / len(scores) * 100) if scores else 0
    styled_stat_row([
        ("Sınav Sayısı", str(len(exam_map)), "#2563eb", "📝"),
        ("Toplam Sonuç", str(len(all_results)), "#8b5cf6", "📊"),
        ("Genel Ort.", f"{avg:.1f}", "#10b981" if avg >= 60 else "#f59e0b", "📈"),
        ("Başarı %", f"%{basari:.0f}", "#059669" if basari >= 60 else "#ef4444", "🎯"),
    ])

    st.markdown("---")

    # Sınava göre gruplandır (en yeniden eskiye)
    exams_sorted = sorted(exam_map.values(), key=lambda e: e.created_at or "", reverse=True)

    for exam in exams_sorted:
        exam_results = [r for r in all_results if r.exam_id == exam.id]
        exam_scores = [r.score for r in exam_results]
        exam_avg = sum(exam_scores) / len(exam_scores) if exam_scores else 0
        tarih = exam.created_at[:10] if exam.created_at else ""
        try:
            tarih_fmt = f"{tarih[8:10]}.{tarih[5:7]}.{tarih[:4]}" if len(tarih) >= 10 else tarih
        except Exception:
            tarih_fmt = tarih
        type_badge = _exam_type_badge_html_od(exam.exam_type, is_online=getattr(exam, 'online_sinav', False))
        avg_color = "#16a34a" if exam_avg >= 70 else ("#d97706" if exam_avg >= 50 else "#dc2626")

        header_html = f"""<div style="display:flex;justify-content:space-between;align-items:center;
            flex-wrap:wrap;padding:8px 0;">
            <div>
                <span style="font-weight:700;font-size:0.95rem;color:#94A3B8;">{exam.name}</span>
                {type_badge}
                <div style="font-size:0.78rem;color:#64748b;margin-top:4px;">
                    {_grade_label(exam.grade)} | {exam.subject} | {tarih_fmt} | {len(exam_results)} öğrenci
                </div>
            </div>
            <div style="text-align:right;">
                <span style="font-size:1.3rem;font-weight:800;color:{avg_color};">{exam_avg:.1f}</span>
                <div style="font-size:0.72rem;color:#64748b;">Ortalama</div>
            </div>
        </div>"""

        with st.expander(f"{exam.name} — {_grade_label(exam.grade)} {exam.subject} ({len(exam_results)} sonuç)", expanded=False):
            st.markdown(header_html, unsafe_allow_html=True)
            result_data = []
            for idx, r in enumerate(sorted(exam_results, key=lambda x: x.score, reverse=True)):
                result_data.append({
                    "Sıra": idx + 1,
                    "Öğrenci": r.student_name,
                    "Numara": r.student_number,
                    "Şube": r.section,
                    "Doğru": r.correct_count,
                    "Yanlış": r.wrong_count,
                    "Boş": r.empty_count,
                    "Net": f"{r.net_score:.2f}",
                    "Puan": f"{r.score:.1f}",
                })
            df = pd.DataFrame(result_data)
            st.dataframe(df, use_container_width=True, hide_index=True)

    # Excel export (tüm sonuçlar)
    st.markdown("---")
    all_export = []
    for r in all_results:
        exam = exam_map.get(r.exam_id)
        all_export.append({
            "Sınav": exam.name if exam else "",
            "Tür": exam.exam_type if exam else "",
            "Sınıf": _grade_label(exam.grade) if exam else "",
            "Ders": exam.subject if exam else "",
            "Tarih": (exam.created_at[:10] if exam and exam.created_at else ""),
            "Öğrenci": r.student_name,
            "Numara": r.student_number,
            "Şube": r.section,
            "Doğru": r.correct_count,
            "Yanlış": r.wrong_count,
            "Boş": r.empty_count,
            "Net": r.net_score,
            "Puan": r.score,
        })
    if all_export:
        df_all = pd.DataFrame(all_export)
        _rapor_excel_export(df_all, f"tum_sinav_sonuclari_{start_date}_{end_date}")


# ─────────────────────── Karşılaştırma Utility Fonksiyonları ───────────────────────

def _find_previous_exams(store, exam, limit=3):
    """Aynı tür + sınıf + ders'teki önceki sınavları bulur (en yeniden eskiye)."""
    all_exams = [e for e in _cached_get_exams()
                 if str(e.grade) == str(exam.grade) and e.subject == exam.subject]
    same_type = [e for e in all_exams
                 if e.exam_type == exam.exam_type and e.id != exam.id
                 and (e.created_at or "") < (exam.created_at or "")]
    same_type.sort(key=lambda x: x.created_at or "", reverse=True)
    return same_type[:limit]


def _build_comparison_data(store, current_exam, prev_exams):
    """Mevcut sınav ile öncekiler arasında karşılaştırma verisi oluşturur."""
    def _exam_stats(exam):
        results = _cached_get_results_for_exam(exam.id)
        if not results:
            return {"avg": 0, "max_score": 0, "min_score": 0, "success_pct": 0, "count": 0}
        scores = [r.score for r in results if r.score is not None]
        if not scores:
            return {"avg": 0, "max_score": 0, "min_score": 0, "success_pct": 0, "count": 0}
        avg = sum(scores) / len(scores)
        success = sum(1 for s in scores if s >= 50) / len(scores) * 100
        return {
            "avg": round(avg, 1),
            "max_score": round(max(scores), 1),
            "min_score": round(min(scores), 1),
            "success_pct": round(success, 1),
            "count": len(scores),
        }

    cur = _exam_stats(current_exam)
    cur["exam_name"] = current_exam.name
    cur["date"] = (current_exam.created_at or "")[:10]
    cur["is_current"] = True
    cur["delta_avg"] = 0
    cur["delta_success"] = 0

    rows = [cur]
    for pe in prev_exams:
        ps = _exam_stats(pe)
        ps["exam_name"] = pe.name
        ps["date"] = (pe.created_at or "")[:10]
        ps["is_current"] = False
        ps["delta_avg"] = round(cur["avg"] - ps["avg"], 1)
        ps["delta_success"] = round(cur["success_pct"] - ps["success_pct"], 1)
        rows.append(ps)
    return rows


def _render_comparison_html(comparison_data):
    """Karşılaştırma verilerini premium HTML kartları olarak gösterir."""
    if not comparison_data or len(comparison_data) < 2:
        return

    def _delta_badge(val, unit=""):
        if val > 0:
            return f'<span style="color:#16a34a;font-weight:700;font-size:0.85rem;">↑ +{val}{unit}</span>'
        elif val < 0:
            return f'<span style="color:#dc2626;font-weight:700;font-size:0.85rem;">↓ {val}{unit}</span>'
        return f'<span style="color:#64748b;font-weight:600;font-size:0.85rem;">→ {val}{unit}</span>'

    # Header row
    html = """<div style="overflow-x:auto;margin:12px 0;">
    <table style="width:100%;border-collapse:collapse;font-size:0.88rem;">
    <thead><tr style="background:linear-gradient(135deg,#94A3B8,#334155);color:#fff;">
        <th style="padding:10px 14px;text-align:left;border-radius:8px 0 0 0;">Sınav</th>
        <th style="padding:10px 14px;text-align:center;">Tarih</th>
        <th style="padding:10px 14px;text-align:center;">Katılım</th>
        <th style="padding:10px 14px;text-align:center;">Ortalama</th>
        <th style="padding:10px 14px;text-align:center;">En Yüksek</th>
        <th style="padding:10px 14px;text-align:center;">Başarı %</th>
        <th style="padding:10px 14px;text-align:center;">Δ Ort</th>
        <th style="padding:10px 14px;text-align:center;border-radius:0 8px 0 0;">Δ Başarı</th>
    </tr></thead><tbody>"""

    for i, row in enumerate(comparison_data):
        bg = "background:linear-gradient(135deg,#0f1d32,#162a4a);" if row.get("is_current") else ""
        bold = "font-weight:700;" if row.get("is_current") else ""
        label = " (Mevcut)" if row.get("is_current") else ""
        try:
            date_fmt = f"{row['date'][8:10]}.{row['date'][5:7]}.{row['date'][:4]}" if len(row.get("date", "")) >= 10 else row.get("date", "")
        except Exception:
            date_fmt = row.get("date", "")

        # Avg color
        avg_v = row["avg"]
        avg_c = "#16a34a" if avg_v >= 70 else "#d97706" if avg_v >= 50 else "#dc2626"

        html += f"""<tr style="{bg}border-bottom:1px solid #e2e8f0;">
            <td style="padding:10px 14px;{bold}">{row['exam_name']}{label}</td>
            <td style="padding:10px 14px;text-align:center;color:#64748b;">{date_fmt}</td>
            <td style="padding:10px 14px;text-align:center;">{row['count']}</td>
            <td style="padding:10px 14px;text-align:center;{bold}color:{avg_c};">{avg_v}</td>
            <td style="padding:10px 14px;text-align:center;">{row['max_score']}</td>
            <td style="padding:10px 14px;text-align:center;">%{row['success_pct']}</td>
            <td style="padding:10px 14px;text-align:center;">{_delta_badge(row['delta_avg']) if not row.get('is_current') else '—'}</td>
            <td style="padding:10px 14px;text-align:center;">{_delta_badge(row['delta_success'], '%') if not row.get('is_current') else '—'}</td>
        </tr>"""

    html += "</tbody></table></div>"
    st.markdown(html, unsafe_allow_html=True)


# ─────────────────────── Sınav Detayı ───────────────────────

def _render_ss_sinav_detayi(store):
    """Alt Sekme 2: Sınav Detayı - tek sınav seçip detaylı görüntüleme."""
    st.markdown("#### 📊 Sınav Detayı")
    st.caption("Bir sınav seçerek öğrenci sonuçlarını detaylı görüntüleyin.")

    all_exams = _cached_get_exams()
    if not all_exams:
        styled_info_banner("Henüz sınav bulunmuyor.", "info")
        return

    # Filtreler (sınıf, ders, tür)
    fc1, fc2, fc3 = st.columns(3)
    with fc1:
        grade_options = [None] + GRADES
        det_grade = st.selectbox(
            "Sınıf Filtresi", grade_options,
            format_func=lambda g: "Tümü" if g is None else _grade_label(g),
            key="ss_det_grade"
        )
    with fc2:
        det_subject = st.selectbox("Ders Filtresi", ["Tümü"] + SUBJECTS, key="ss_det_subject")
    with fc3:
        det_type = st.selectbox("Tür Filtresi", ["Tümü"] + EXAM_TYPES, key="ss_det_type")

    # Sınav listesini filtrele
    filtered = all_exams
    if det_grade is not None:
        filtered = [e for e in filtered if str(e.grade) == str(det_grade)]
    if det_subject != "Tümü":
        filtered = [e for e in filtered if e.subject == det_subject]
    if det_type != "Tümü":
        filtered = [e for e in filtered if e.exam_type == det_type]

    if not filtered:
        styled_info_banner("Filtrelere uygun sınav bulunamadı.", "warning")
        return

    # Sınav seçimi
    exam_options = {f"{e.name} ({_grade_label(e.grade)} - {e.subject} - {e.exam_type})": e
                    for e in sorted(filtered, key=lambda x: x.created_at or "", reverse=True)}
    selected_name = st.selectbox("Sınav Seç", ["Seçiniz..."] + list(exam_options.keys()),
                                  key="ss_det_sinav_sec")
    if selected_name == "Seçiniz...":
        return

    selected_exam = exam_options[selected_name]

    # İstatistikler (cache'li)
    stats = store.get_exam_statistics(selected_exam.id)
    sessions = store.get_sessions(exam_id=selected_exam.id)
    results = _cached_get_results_for_exam(selected_exam.id)

    st.markdown("---")

    # KPI
    col1, col2, col3, col4 = st.columns(4)
    col1.metric("👥 Toplam Katılımcı", len(sessions) if sessions else len(results))
    col2.metric("✅ Değerlendirilen", len(results))
    col3.metric("📊 Ortalama Puan", f"{stats.get('average_score', 0):.1f}" if stats else "-")
    col4.metric("📈 En Yüksek", f"{stats.get('max_score', 0):.1f}" if stats else "-")

    if not results:
        styled_info_banner("Bu sınava ait sonuç bulunmuyor.", "info")
        return

    # Şube filtresi
    subeler = sorted(set(r.section for r in results if r.section))
    if subeler:
        sube_filtre = st.selectbox("Şube", ["Tümü"] + subeler, key="ss_det_sube")
        if sube_filtre != "Tümü":
            results = [r for r in results if r.section == sube_filtre]

    # Sonuç tablosu
    st.markdown("### 📋 Sonuç Listesi")
    result_data = []
    for r in sorted(results, key=lambda x: x.score, reverse=True):
        result_data.append({
            "Sıra": len(result_data) + 1,
            "Öğrenci": r.student_name,
            "Numara": r.student_number,
            "Şube": r.section,
            "Doğru": r.correct_count,
            "Yanlış": r.wrong_count,
            "Boş": r.empty_count,
            "Net": f"{r.net_score:.2f}",
            "Puan": f"{r.score:.1f}",
        })

    df = pd.DataFrame(result_data)
    st.dataframe(df, use_container_width=True, hide_index=True)

    # Puan dağılımı grafiği
    if len(results) >= 3:
        import plotly.graph_objects as go
        scores = [r.score for r in results]
        bins = {"0-25": 0, "25-50": 0, "50-75": 0, "75-100": 0}
        for s in scores:
            if s < 25:
                bins["0-25"] += 1
            elif s < 50:
                bins["25-50"] += 1
            elif s < 75:
                bins["50-75"] += 1
            else:
                bins["75-100"] += 1
        fig = go.Figure(go.Bar(
            x=list(bins.keys()), y=list(bins.values()),
            marker_color=SC_COLORS[:4],
            text=list(bins.values()), textposition="outside",
        ))
        fig.update_layout(title="Puan Dağılımı", xaxis_title="Puan Aralığı", yaxis_title="Öğrenci Sayısı")
        sc_bar(fig, height=320)
        st.plotly_chart(fig, use_container_width=True, config=SC_CHART_CFG)

    # ─── Önceki Sınavlarla Karşılaştırma ───
    prev_exams = _find_previous_exams(store, selected_exam)
    if prev_exams:
        st.markdown("---")
        styled_section("Önceki Sınavlarla Karşılaştırma", "#7c3aed")
        comparison = _build_comparison_data(store, selected_exam, prev_exams)
        _render_comparison_html(comparison)

        # Grouped bar chart
        import plotly.graph_objects as go
        cur_row = comparison[0]
        fig_cmp = go.Figure()
        fig_cmp.add_trace(go.Bar(
            name=f"{cur_row['exam_name']} (Mevcut)",
            x=["Ortalama", "En Yüksek", "Başarı %"],
            y=[cur_row["avg"], cur_row["max_score"], cur_row["success_pct"]],
            marker_color=SC_COLORS[0],
            text=[f"{cur_row['avg']}", f"{cur_row['max_score']}", f"%{cur_row['success_pct']}"],
            textposition="outside",
        ))
        for i, prev_row in enumerate(comparison[1:]):
            fig_cmp.add_trace(go.Bar(
                name=prev_row["exam_name"],
                x=["Ortalama", "En Yüksek", "Başarı %"],
                y=[prev_row["avg"], prev_row["max_score"], prev_row["success_pct"]],
                marker_color=SC_COLORS[(i + 1) % len(SC_COLORS)],
                text=[f"{prev_row['avg']}", f"{prev_row['max_score']}", f"%{prev_row['success_pct']}"],
                textposition="outside",
            ))
        fig_cmp.update_layout(
            barmode="group", title="Sınav Karşılaştırma",
            legend=dict(orientation="h", yanchor="bottom", y=1.02),
        )
        sc_bar(fig_cmp, height=340)
        st.plotly_chart(fig_cmp, use_container_width=True, config=SC_CHART_CFG)

    # Excel export
    col_e1, col_e2 = st.columns(2)
    with col_e1:
        _rapor_excel_export(df, f"sinav_detay_{selected_exam.name}")


def _render_ss_ogrenci_karnesi(store):
    """Alt Sekme 3: Öğrenci Karnesi - tek öğrenci seçip tüm sınavlarını görme."""
    st.markdown("#### 👤 Öğrenci Karnesi")
    st.caption("Bir öğrenci seçerek tüm sınav sonuçlarını görüntüleyin.")

    from utils.shared_data import get_sinif_sube_listesi, get_sinif_ogrenci_listesi

    sinif_sube_data = get_sinif_sube_listesi()
    siniflar = sinif_sube_data.get("siniflar", [])
    subeler = sinif_sube_data.get("subeler", [])

    fc1, fc2 = st.columns(2)
    with fc1:
        sinif_sec = st.selectbox("Sınıf", siniflar, key="ss_karne_sinif") if siniflar else None
    with fc2:
        sube_sec = st.selectbox("Şube", subeler, key="ss_karne_sube") if subeler else None

    if not sinif_sec or not sube_sec:
        styled_info_banner("Sınıf ve şube seçiniz.", "info")
        return

    ogrenciler = get_sinif_ogrenci_listesi(sinif_sec, sube_sec)
    if not ogrenciler:
        styled_info_banner("Bu sınıf/şubede öğrenci bulunamadı.", "warning")
        return

    ogr_options = {f"{o.get('ad', '')} {o.get('soyad', '')} ({o.get('numara', '')})": o for o in ogrenciler}
    ogr_sec = st.selectbox("Öğrenci", ["Seçiniz..."] + list(ogr_options.keys()), key="ss_karne_ogr")

    if ogr_sec == "Seçiniz...":
        return

    selected_student = ogr_options[ogr_sec]
    student_id = selected_student.get("id", "")

    # Sonuçları çek (toplu yükleme + filtre)
    all_results = _cached_get_all_results()
    results = [r for r in all_results if r.student_id == student_id]
    if not results:
        styled_info_banner(f"{ogr_sec} için sınav sonucu bulunamadı.", "info")
        return

    # Exam cache (toplu yükleme)
    all_exams = _cached_get_exams()
    all_exam_map = {e.id: e for e in all_exams}
    exam_cache = {r.exam_id: all_exam_map.get(r.exam_id) for r in results if r.exam_id}

    # Ders ve tür filtreleri
    ders_secenekleri = sorted(set(
        exam_cache[r.exam_id].subject for r in results
        if r.exam_id in exam_cache and exam_cache[r.exam_id] and exam_cache[r.exam_id].subject
    ))
    tur_secenekleri = sorted(set(
        exam_cache[r.exam_id].exam_type for r in results
        if r.exam_id in exam_cache and exam_cache[r.exam_id] and exam_cache[r.exam_id].exam_type
    ))

    fc3, fc4 = st.columns(2)
    with fc3:
        filtre_ders = st.multiselect("Ders Filtresi", ders_secenekleri, key="ss_karne_ders")
    with fc4:
        filtre_tur = st.multiselect("Sınav Türü Filtresi", tur_secenekleri, key="ss_karne_tur")

    # Filtre uygula
    filtered = results
    if filtre_ders:
        filtered = [r for r in filtered
                    if r.exam_id in exam_cache and exam_cache[r.exam_id]
                    and exam_cache[r.exam_id].subject in filtre_ders]
    if filtre_tur:
        filtered = [r for r in filtered
                    if r.exam_id in exam_cache and exam_cache[r.exam_id]
                    and exam_cache[r.exam_id].exam_type in filtre_tur]

    if not filtered:
        styled_info_banner("Filtrelere uygun sonuç bulunamadı.", "warning")
        return

    # ─── Görünüm Modu ───
    gorunum = st.radio("Görünüm", [
        "📋 Kronolojik",
        "📚 Türe Göre Grupla",
        "📊 Toplu Ekran",
        "🤖 AI Analiz",
    ], horizontal=True, key="ss_karne_gorunum")

    student_info = {
        "ad": selected_student.get("ad", ""),
        "soyad": selected_student.get("soyad", ""),
        "numara": selected_student.get("numara", ""),
        "sinif": sinif_sec,
        "sube": sube_sec,
        "id": student_id,
    }

    if gorunum == "📋 Kronolojik":
        _render_karne_kronolojik(filtered, exam_cache, ogr_sec)
    elif gorunum == "📚 Türe Göre Grupla":
        _render_karne_tur_gruplama(filtered, exam_cache)
    elif gorunum == "📊 Toplu Ekran":
        _render_karne_toplu_ekran(filtered, exam_cache, student_info, store)
    else:
        _render_karne_ai_analiz(filtered, exam_cache, student_info, store)


def _get_student_rankings(store, result, exam_cache):
    """Öğrencinin şube ve genel sıralamasını hesaplar (cache'li). Return: (sube_sira, sube_toplam, genel_sira, genel_toplam)"""
    try:
        exam = exam_cache.get(result.exam_id) if exam_cache else None
        if not exam:
            return None, None, None, None
        all_results = _cached_get_results_for_exam(result.exam_id)
        if not all_results:
            return None, None, None, None
        # Genel sıralama
        all_sorted = sorted(all_results, key=lambda x: x.score or 0, reverse=True)
        genel_sira = next((i + 1 for i, r in enumerate(all_sorted) if r.student_id == result.student_id), None)
        genel_toplam = len(all_sorted)
        # Şube sıralaması
        if result.section:
            sube_results = [r for r in all_results if r.section == result.section]
            sube_sorted = sorted(sube_results, key=lambda x: x.score or 0, reverse=True)
            sube_sira = next((i + 1 for i, r in enumerate(sube_sorted) if r.student_id == result.student_id), None)
            sube_toplam = len(sube_sorted)
        else:
            sube_sira, sube_toplam = genel_sira, genel_toplam
        return sube_sira, sube_toplam, genel_sira, genel_toplam
    except Exception:
        return None, None, None, None


def _render_ders_kazanim_pasta(filtered, exam_cache, store):
    """Ders bazlı + kazanım bazlı pasta grafikleri gösterir."""
    import plotly.graph_objects as go

    # Ders bazlı dağılım
    ders_scores: dict[str, list] = {}
    for r in filtered:
        exam = exam_cache.get(r.exam_id)
        if exam and r.score is not None:
            ders_scores.setdefault(exam.subject or "Diğer", []).append(r.score)

    # Kazanım bazlı toplam
    kazanim_data: dict[str, dict] = {}  # {outcome_id: {total, correct, name}}
    for r in filtered:
        ob = getattr(r, "outcome_breakdown", None) or {}
        for oid, vals in ob.items():
            if oid not in kazanim_data:
                kazanim_data[oid] = {"total": 0, "correct": 0}
            kazanim_data[oid]["total"] += vals.get("total", 0)
            kazanim_data[oid]["correct"] += vals.get("correct", 0)

    pc1, pc2, pc3 = st.columns(3)

    # 1. D/Y/B Pasta
    with pc1:
        total_d = sum(r.correct_count for r in filtered)
        total_y = sum(r.wrong_count for r in filtered)
        total_b = sum(r.empty_count for r in filtered)
        if total_d + total_y + total_b > 0:
            fig_dyb = go.Figure(go.Pie(
                labels=["Doğru", "Yanlış", "Boş"],
                values=[total_d, total_y, total_b],
                marker=dict(colors=SC_COLORS[:3], line=dict(color="#fff", width=2)),
                hole=0.55, textinfo="label+percent", textfont_size=11,
                pull=[0.04, 0.04, 0.04],
            ))
            sc_pie(fig_dyb, height=280)
            st.plotly_chart(fig_dyb, use_container_width=True, config=SC_CHART_CFG)

    # 2. Ders bazlı pasta
    with pc2:
        if ders_scores:
            ders_labels = list(ders_scores.keys())
            ders_counts = [len(v) for v in ders_scores.values()]
            fig_ders = go.Figure(go.Pie(
                labels=ders_labels, values=ders_counts,
                marker=dict(colors=SC_COLORS[:len(ders_labels)], line=dict(color="#fff", width=2)),
                hole=0.55, textinfo="label+percent", textfont_size=11,
                pull=[0.03] * len(ders_labels),
            ))
            sc_pie(fig_ders, height=280)
            st.plotly_chart(fig_ders, use_container_width=True, config=SC_CHART_CFG)

    # 3. Ders bazlı ortalama bar
    with pc3:
        if ders_scores:
            ders_avgs = {d: round(sum(s) / len(s), 1) for d, s in ders_scores.items() if s}
            sorted_ders = sorted(ders_avgs.items(), key=lambda x: x[1])
            d_labels = [d for d, _ in sorted_ders]
            d_vals = [v for _, v in sorted_ders]
            d_colors = [SC_COLORS[1] if v >= 70 else SC_COLORS[0] if v >= 50 else SC_COLORS[4] for v in d_vals]
            fig_dbar = go.Figure(go.Bar(
                x=d_vals, y=d_labels, orientation="h",
                marker_color=d_colors, text=[f"{v}" for v in d_vals], textposition="outside",
            ))
            fig_dbar.update_layout(title="Ders Ortalamaları")
            sc_bar(fig_dbar, height=280, horizontal=True)
            st.plotly_chart(fig_dbar, use_container_width=True, config=SC_CHART_CFG)

    # 4. Kazanım performans tablosu
    if kazanim_data:
        st.markdown("### 🎯 Kazanım Bazlı Performans")
        # Kazanım isimlerini çöz
        try:
            outcomes = store.get_outcomes() if hasattr(store, "get_outcomes") else []
            outcome_map = {o.id: o.description for o in outcomes} if outcomes else {}
        except Exception:
            outcome_map = {}

        kaz_rows = []
        for oid, vals in sorted(kazanim_data.items(), key=lambda x: (x[1]["correct"] / x[1]["total"] * 100) if x[1]["total"] > 0 else 0):
            total = vals["total"]
            correct = vals["correct"]
            pct = round(correct / total * 100, 1) if total > 0 else 0
            name = outcome_map.get(oid, oid[:30] if len(oid) > 30 else oid)
            if pct >= 70:
                renk, band = "#16a34a", "Başarılı"
            elif pct >= 50:
                renk, band = "#d97706", "Geliştirilmeli"
            else:
                renk, band = "#dc2626", "Zayıf"
            kaz_rows.append((name, total, correct, pct, renk, band))

        if kaz_rows:
            kaz_html = """<div style="overflow-x:auto;"><table style="width:100%;border-collapse:collapse;font-size:0.85rem;">
            <thead><tr style="background:linear-gradient(135deg,#94A3B8,#334155);color:#fff;">
                <th style="padding:8px 12px;text-align:left;border-radius:8px 0 0 0;">Kazanım</th>
                <th style="padding:8px;text-align:center;">Soru</th>
                <th style="padding:8px;text-align:center;">Doğru</th>
                <th style="padding:8px;text-align:center;">Başarı</th>
                <th style="padding:8px;text-align:center;">Seviye</th>
                <th style="padding:8px;text-align:center;border-radius:0 8px 0 0;">Grafik</th>
            </tr></thead><tbody>"""
            for name, total, correct, pct, renk, band in kaz_rows:
                kaz_html += f"""<tr style="border-bottom:1px solid #1A2035;">
                    <td style="padding:8px 12px;max-width:250px;overflow:hidden;text-overflow:ellipsis;">{name}</td>
                    <td style="padding:8px;text-align:center;">{total}</td>
                    <td style="padding:8px;text-align:center;color:#16a34a;font-weight:600;">{correct}</td>
                    <td style="padding:8px;text-align:center;font-weight:700;color:{renk};">%{pct}</td>
                    <td style="padding:8px;text-align:center;"><span style="background:{renk}22;color:{renk};
                        padding:2px 8px;border-radius:6px;font-size:0.78rem;font-weight:600;">{band}</span></td>
                    <td style="padding:8px;text-align:center;min-width:100px;">
                        <div style="background:#1A2035;border-radius:4px;height:10px;overflow:hidden;">
                            <div style="width:{pct}%;background:{renk};height:100%;border-radius:4px;"></div>
                        </div>
                    </td></tr>"""
            kaz_html += "</tbody></table></div>"
            st.markdown(kaz_html, unsafe_allow_html=True)


def _render_karne_kronolojik(filtered, exam_cache, ogr_sec):
    """Kronolojik görünüm — KPI + chart + pasta + sıralama + kartlar."""
    store = get_store()
    puanlar = [r.score for r in filtered if r.score is not None]
    if puanlar:
        ort = round(sum(puanlar) / len(puanlar), 1)
        en_yuksek = max(puanlar)
        toplam_dogru = sum(r.correct_count for r in filtered)
        toplam_yanlis = sum(r.wrong_count for r in filtered)
        styled_stat_row([
            ("Sınav Sayısı", str(len(filtered)), "#4472C4", "📝"),
            ("Ortalama", f"{ort}", "#C8952E", "📊"),
            ("En Yüksek", f"{en_yuksek:.0f}", "#16a34a", "🏆"),
            ("Toplam D/Y", f"{toplam_dogru}/{toplam_yanlis}", "#7c3aed", "🎯"),
        ])

    if puanlar and len(puanlar) >= 2:
        import plotly.graph_objects as go
        sinav_labels = []
        for i, r in enumerate(filtered):
            exam = exam_cache.get(r.exam_id)
            name = exam.name[:18] if exam and exam.name else f"Sınav {i + 1}"
            sinav_labels.append(name)
        c1, c2 = st.columns(2)
        with c1:
            fig_line = go.Figure()
            fig_line.add_trace(go.Scatter(
                x=sinav_labels, y=puanlar,
                mode="lines+markers+text",
                text=[f"{p:.0f}" for p in puanlar],
                textposition="top center",
                line=dict(color=SC_COLORS[0], width=3),
                marker=dict(size=10, color=SC_COLORS[0], line=dict(color=SC_COLORS[2], width=2)),
                fill="tozeroy", fillcolor="rgba(59,130,246,0.1)",
            ))
            ort_val = sum(puanlar) / len(puanlar)
            fig_line.add_hline(y=ort_val, line_dash="dash", line_color=SC_COLORS[3], line_width=2,
                               annotation_text=f"Ort: {ort_val:.1f}",
                               annotation_font_color=SC_COLORS[3])
            fig_line.update_layout(
                title="Sınav Puan Trendi", height=340,
                margin=dict(l=40, r=20, t=50, b=40),
            )
            st.plotly_chart(fig_line, use_container_width=True, config=SC_CHART_CFG)
        with c2:
            ort_gauge = round(sum(puanlar) / len(puanlar), 1)
            fig_gauge = go.Figure(go.Indicator(
                mode="gauge+number+delta",
                value=ort_gauge,
                title={"text": "Sınav Ortalaması"},
                delta={"reference": 70, "increasing": {"color": SC_COLORS[0]}},
                gauge={
                    "axis": {"range": [0, 100]},
                    "bar": {"color": SC_COLORS[0]},
                    "steps": [
                        {"range": [0, 50], "color": "#F7CBAC"},
                        {"range": [50, 70], "color": "#FFE699"},
                        {"range": [70, 85], "color": "#8FAADC"},
                        {"range": [85, 100], "color": SC_COLORS[0]},
                    ],
                },
            ))
            fig_gauge.update_layout(
                height=340, margin=dict(l=40, r=20, t=50, b=40),
            )
            st.plotly_chart(fig_gauge, use_container_width=True, config=SC_CHART_CFG)

    # ─── Pasta Grafikleri + Ders/Kazanım Analizi ───
    _render_ders_kazanim_pasta(filtered, exam_cache, store)

    # Detaylı sonuç kartları (en yeniden eskiye) + sıralama
    st.markdown("### 📋 Sınav Sonuçları")
    for r in reversed(filtered):
        exam = exam_cache.get(r.exam_id)
        exam_name = exam.name if exam and exam.name else "Sınav"
        exam_type = exam.exam_type if exam else ""
        exam_subject = exam.subject if exam and exam.subject else ""
        tarih = r.graded_at[:10] if r.graded_at else ""
        try:
            tarih_fmt = f"{tarih[8:10]}.{tarih[5:7]}.{tarih[:4]}" if len(tarih) >= 10 else tarih
        except Exception:
            tarih_fmt = tarih
        puan = r.score if r.score is not None else 0
        if puan >= 85:
            puan_renk = "#2563eb"
        elif puan >= 70:
            puan_renk = "#16a34a"
        elif puan >= 50:
            puan_renk = "#d97706"
        else:
            puan_renk = "#dc2626"
        basari_pct = round((r.correct_count / r.total_questions) * 100) if r.total_questions > 0 else 0
        type_badge = _exam_type_badge_html_od(exam_type, is_online=getattr(exam, 'online_sinav', False) if exam else False)

        # Sıralama
        s_sira, s_top, g_sira, g_top = _get_student_rankings(store, r, exam_cache)
        sira_html = ""
        if s_sira is not None:
            sira_html = f"""<div style="display:flex;gap:10px;margin-top:4px;">
                <span style="font-size:0.72rem;color:#4472C4;font-weight:600;">Şube: {s_sira}/{s_top}</span>
                <span style="font-size:0.72rem;color:#7c3aed;font-weight:600;">Genel: {g_sira}/{g_top}</span>
            </div>"""

        card_html = f"""<div style="border:1px solid rgba(200,149,46,0.2);border-radius:12px;margin-bottom:12px;
                    overflow:hidden;background:linear-gradient(135deg,#0a1628,#122240);box-shadow:0 2px 8px rgba(0,0,0,0.3);">
            <div style="padding:14px 18px;border-bottom:1px solid rgba(200,149,46,0.15);
                        display:flex;justify-content:space-between;align-items:flex-start;flex-wrap:wrap;gap:8px;
                        background:linear-gradient(135deg,#0f1d32,#162a4a);">
                <div>
                    <div style="display:flex;align-items:center;flex-wrap:wrap;gap:4px;">
                        <span style="font-weight:700;font-size:0.95rem;color:#e2e8f0;">{exam_name}</span>
                        {type_badge}
                    </div>
                    <div style="font-size:0.78rem;color:#64748b;margin-top:4px;">
                        {f'{exam_subject} | ' if exam_subject else ''}{tarih_fmt} | {r.total_questions} Soru
                    </div>
                    {sira_html}
                </div>
                <div style="text-align:right;">
                    <span style="font-size:1.5rem;font-weight:800;color:{puan_renk};">{puan:.0f}</span>
                    <div style="font-size:0.72rem;color:#64748b;">Net: {r.net_score:.1f}</div>
                </div>
            </div>
            <div style="padding:10px 18px;display:flex;align-items:center;gap:16px;flex-wrap:wrap;">
                <span style="color:#16a34a;font-weight:600;font-size:0.85rem;">✅ {r.correct_count}</span>
                <span style="color:#dc2626;font-weight:600;font-size:0.85rem;">❌ {r.wrong_count}</span>
                <span style="color:#94a3b8;font-weight:600;font-size:0.85rem;">⬜ {r.empty_count}</span>
                <div style="flex:1;min-width:80px;background:#1A2035;border-radius:6px;height:8px;">
                    <div style="width:{basari_pct}%;background:linear-gradient(90deg,{puan_renk},
                        {puan_renk}cc);height:100%;border-radius:6px;transition:width 0.3s;"></div>
                </div>
                <span style="font-size:0.75rem;font-weight:700;color:{puan_renk};">%{basari_pct}</span>
            </div>
        </div>"""
        st.markdown(card_html, unsafe_allow_html=True)

    # Excel export
    export_data = []
    for r in filtered:
        exam = exam_cache.get(r.exam_id)
        s_s, s_t, g_s, g_t = _get_student_rankings(store, r, exam_cache)
        export_data.append({
            "Sınav": exam.name if exam else "",
            "Tür": exam.exam_type if exam else "",
            "Ders": exam.subject if exam else "",
            "Tarih": r.graded_at[:10] if r.graded_at else "",
            "Doğru": r.correct_count,
            "Yanlış": r.wrong_count,
            "Boş": r.empty_count,
            "Net": r.net_score,
            "Puan": r.score,
            "Şube Sıra": f"{s_s}/{s_t}" if s_s else "",
            "Genel Sıra": f"{g_s}/{g_t}" if g_s else "",
        })
    if export_data:
        df_exp = pd.DataFrame(export_data)
        _rapor_excel_export(df_exp, f"ogrenci_karnesi_{ogr_sec}")


# ─────────────────────── Karne: Türe Göre Grupla ───────────────────────

def _render_karne_tur_gruplama(filtered, exam_cache):
    """Sınav sonuçlarını türe göre gruplar, her grupta delta karşılaştırma gösterir."""
    # Türe göre grupla
    groups: dict[str, list] = {}
    for r in filtered:
        exam = exam_cache.get(r.exam_id)
        if not exam:
            continue
        etype = exam.exam_type or "Diğer"
        groups.setdefault(etype, []).append((r, exam))

    if not groups:
        styled_info_banner("Gruplandırılacak sonuç bulunamadı.", "info")
        return

    for etype, items in sorted(groups.items()):
        # Tarihe göre sırala (eskiden yeniye)
        items.sort(key=lambda x: x[1].created_at or "")
        badge = _exam_type_badge_html_od(etype)
        puanlar = [r.score for r, _ in items if r.score is not None]
        ort = round(sum(puanlar) / len(puanlar), 1) if puanlar else 0

        # Trend hesapla
        if len(puanlar) >= 2:
            trend_val = round(puanlar[-1] - puanlar[0], 1)
            if trend_val > 0:
                trend_html = f'<span style="color:#16a34a;font-weight:700;">↑ +{trend_val}</span>'
            elif trend_val < 0:
                trend_html = f'<span style="color:#dc2626;font-weight:700;">↓ {trend_val}</span>'
            else:
                trend_html = '<span style="color:#64748b;font-weight:600;">→ 0</span>'
        else:
            trend_html = '<span style="color:#64748b;">—</span>'

        # Grup başlığı
        header_html = f"""<div style="background:linear-gradient(135deg,#111827,#eef2ff);
            border:1px solid #e2e8f0;border-radius:12px;padding:14px 18px;margin:16px 0 8px 0;
            display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:8px;">
            <div style="display:flex;align-items:center;gap:8px;">
                {badge}
                <span style="font-weight:700;color:#94A3B8;">{len(items)} Sınav</span>
            </div>
            <div style="display:flex;gap:16px;align-items:center;">
                <span style="font-size:0.82rem;color:#64748b;">Ort: <b style="color:#4472C4;">{ort}</b></span>
                <span style="font-size:0.82rem;color:#64748b;">Trend: {trend_html}</span>
                <span style="font-size:0.82rem;color:#64748b;">En ↑: <b style="color:#16a34a;">{max(puanlar):.0f}</b></span>
                <span style="font-size:0.82rem;color:#64748b;">En ↓: <b style="color:#dc2626;">{min(puanlar):.0f}</b></span>
            </div>
        </div>"""
        st.markdown(header_html, unsafe_allow_html=True)

        # Karşılaştırmalı tablo
        tbl_html = """<table style="width:100%;border-collapse:collapse;font-size:0.85rem;margin-bottom:4px;">
        <thead><tr style="background:#1A2035;"><th style="padding:8px 10px;text-align:left;">Sınav</th>
        <th style="padding:8px;text-align:center;">Ders</th>
        <th style="padding:8px;text-align:center;">Tarih</th>
        <th style="padding:8px;text-align:center;">Puan</th>
        <th style="padding:8px;text-align:center;">Δ Önceki</th>
        <th style="padding:8px;text-align:center;">D/Y/B</th>
        <th style="padding:8px;text-align:center;">Net</th></tr></thead><tbody>"""

        prev_score = None
        for r, exam in items:
            puan = r.score if r.score is not None else 0
            p_color = "#16a34a" if puan >= 70 else "#d97706" if puan >= 50 else "#dc2626"
            tarih = r.graded_at[:10] if r.graded_at else ""
            try:
                t_fmt = f"{tarih[8:10]}.{tarih[5:7]}.{tarih[:4]}" if len(tarih) >= 10 else tarih
            except Exception:
                t_fmt = tarih

            if prev_score is not None:
                delta = round(puan - prev_score, 1)
                if delta > 0:
                    d_html = f'<span style="color:#16a34a;font-weight:700;">↑ +{delta}</span>'
                elif delta < 0:
                    d_html = f'<span style="color:#dc2626;font-weight:700;">↓ {delta}</span>'
                else:
                    d_html = '<span style="color:#64748b;">→ 0</span>'
            else:
                d_html = '<span style="color:#94a3b8;">—</span>'

            tbl_html += f"""<tr style="border-bottom:1px solid #1A2035;">
                <td style="padding:8px 10px;font-weight:600;">{exam.name}</td>
                <td style="padding:8px;text-align:center;color:#64748b;">{exam.subject or ''}</td>
                <td style="padding:8px;text-align:center;color:#64748b;">{t_fmt}</td>
                <td style="padding:8px;text-align:center;font-weight:700;color:{p_color};">{puan:.0f}</td>
                <td style="padding:8px;text-align:center;">{d_html}</td>
                <td style="padding:8px;text-align:center;">{r.correct_count}/{r.wrong_count}/{r.empty_count}</td>
                <td style="padding:8px;text-align:center;">{r.net_score:.1f}</td></tr>"""
            prev_score = puan

        tbl_html += "</tbody></table>"
        st.markdown(tbl_html, unsafe_allow_html=True)

        # Mini line chart
        if len(puanlar) >= 2:
            import plotly.graph_objects as go
            labels = [items[i][1].name[:15] for i in range(len(items))]
            fig_mini = go.Figure()
            fig_mini.add_trace(go.Scatter(
                x=labels, y=puanlar, mode="lines+markers+text",
                text=[f"{p:.0f}" for p in puanlar], textposition="top center",
                line=dict(color=SC_COLORS[0], width=2), marker=dict(size=8, color=SC_COLORS[0]),
            ))
            fig_mini.update_layout(
                height=220, margin=dict(l=30, r=20, t=30, b=30),
                showlegend=False,
            )
            st.plotly_chart(fig_mini, use_container_width=True, config=SC_CHART_CFG)


# ─────────────────────── Karne: Toplu Ekran ───────────────────────

def _render_karne_toplu_ekran(filtered, exam_cache, student_info, store):
    """Tek sayfada tüm sınavlar: KPI + trend + tablo + tür özeti + PDF."""
    full_name = f"{student_info['ad']} {student_info['soyad']}"

    # Öğrenci bilgi kartı
    info_html = f"""<div style="background:linear-gradient(135deg,#94A3B8,#334155);
        border-radius:12px;padding:18px 24px;margin-bottom:16px;color:#fff;
        display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:12px;">
        <div>
            <div style="font-size:1.2rem;font-weight:800;">{full_name}</div>
            <div style="font-size:0.85rem;color:#94a3b8;margin-top:4px;">
                {student_info['sinif']}. Sınıf / {student_info['sube']} Şubesi | No: {student_info['numara']}
            </div>
        </div>
        <div style="text-align:right;">
            <div style="font-size:0.78rem;color:#94a3b8;">Toplam Sınav</div>
            <div style="font-size:1.6rem;font-weight:800;color:#C8952E;">{len(filtered)}</div>
        </div>
    </div>"""
    st.markdown(info_html, unsafe_allow_html=True)

    # KPI
    puanlar = [r.score for r in filtered if r.score is not None]
    if not puanlar:
        styled_info_banner("Puanlı sonuç bulunamadı.", "info")
        return

    ort = round(sum(puanlar) / len(puanlar), 1)
    en_yuksek = max(puanlar)
    basari_pct = round(sum(1 for p in puanlar if p >= 50) / len(puanlar) * 100, 1)
    toplam_d = sum(r.correct_count for r in filtered)
    toplam_y = sum(r.wrong_count for r in filtered)

    # Trend
    if len(puanlar) >= 2:
        trend_val = round(puanlar[-1] - puanlar[0], 1)
        trend_str = f"+{trend_val}" if trend_val > 0 else str(trend_val)
        trend_color = "#16a34a" if trend_val > 0 else "#dc2626" if trend_val < 0 else "#64748b"
    else:
        trend_str, trend_color = "—", "#64748b"

    styled_stat_row([
        ("Ortalama", f"{ort}", "#C8952E", "📊"),
        ("En Yüksek", f"{en_yuksek:.0f}", "#16a34a", "🏆"),
        ("Başarı %", f"%{basari_pct}", "#4472C4", "📈"),
        ("Trend", trend_str, trend_color, "📉"),
    ])

    # Grafik satırı
    import plotly.graph_objects as go
    c1, c2 = st.columns(2)

    with c1:
        # Puan trendi
        labels = []
        for i, r in enumerate(filtered):
            exam = exam_cache.get(r.exam_id)
            labels.append(exam.name[:15] if exam and exam.name else f"S{i+1}")
        fig_trend = go.Figure()
        fig_trend.add_trace(go.Scatter(
            x=labels, y=puanlar, mode="lines+markers+text",
            text=[f"{p:.0f}" for p in puanlar], textposition="top center",
            line=dict(color=SC_COLORS[0], width=3), marker=dict(size=10, color=SC_COLORS[0]),
            fill="tozeroy", fillcolor="rgba(59,130,246,0.1)",
        ))
        fig_trend.add_hline(y=ort, line_dash="dash", line_color=SC_COLORS[3], line_width=2,
                            annotation_text=f"Ort: {ort}", annotation_font_color=SC_COLORS[3])
        fig_trend.update_layout(title="Puan Trendi", height=320,
                                margin=dict(l=40, r=20, t=50, b=40))
        st.plotly_chart(fig_trend, use_container_width=True, config=SC_CHART_CFG)

    with c2:
        # Tür bazlı ortalamalar
        type_scores: dict[str, list] = {}
        for r in filtered:
            exam = exam_cache.get(r.exam_id)
            if exam and r.score is not None:
                type_scores.setdefault(exam.exam_type or "Diğer", []).append(r.score)
        type_avgs = {t: round(sum(s)/len(s), 1) for t, s in type_scores.items() if s}
        if type_avgs:
            sorted_types = sorted(type_avgs.items(), key=lambda x: x[1], reverse=True)
            t_labels = [EXAM_TYPE_DISPLAY.get(t, (t, "#64748b", "#1A2035"))[0] for t, _ in sorted_types]
            t_vals = [v for _, v in sorted_types]
            t_colors = [SC_COLORS[1] if v >= 70 else SC_COLORS[0] if v >= 50 else SC_COLORS[4] for v in t_vals]
            fig_type = go.Figure(go.Bar(
                x=t_vals, y=t_labels, orientation="h",
                marker_color=t_colors, text=[f"{v}" for v in t_vals], textposition="outside",
            ))
            fig_type.update_layout(title="Tür Bazlı Ortalamalar")
            sc_bar(fig_type, height=320, horizontal=True)
            st.plotly_chart(fig_type, use_container_width=True, config=SC_CHART_CFG)

    # ─── Pasta Grafikleri + Ders/Kazanım Analizi ───
    _render_ders_kazanim_pasta(filtered, exam_cache, store)

    # Tüm sınavlar tablosu (sıralama dahil)
    st.markdown("### 📋 Tüm Sınav Tablosu")
    tbl_data = []
    prev_score_map: dict[str, float] = {}
    for r in filtered:
        exam = exam_cache.get(r.exam_id)
        if not exam:
            continue
        puan = r.score if r.score is not None else 0
        etype = exam.exam_type or "Diğer"

        prev_p = prev_score_map.get(etype)
        if prev_p is not None:
            delta = round(puan - prev_p, 1)
            delta_str = f"+{delta}" if delta > 0 else str(delta)
        else:
            delta_str = "—"
        prev_score_map[etype] = puan

        tarih = r.graded_at[:10] if r.graded_at else ""
        try:
            t_fmt = f"{tarih[8:10]}.{tarih[5:7]}.{tarih[:4]}" if len(tarih) >= 10 else tarih
        except Exception:
            t_fmt = tarih

        s_s, s_t, g_s, g_t = _get_student_rankings(store, r, exam_cache)
        tbl_data.append({
            "Sınav": exam.name,
            "Tür": EXAM_TYPE_DISPLAY.get(etype, (etype,))[0],
            "Ders": exam.subject or "",
            "Tarih": t_fmt,
            "Puan": round(puan, 1),
            "Δ": delta_str,
            "D/Y/B": f"{r.correct_count}/{r.wrong_count}/{r.empty_count}",
            "Net": round(r.net_score, 1),
            "Şube": f"{s_s}/{s_t}" if s_s else "—",
            "Genel": f"{g_s}/{g_t}" if g_s else "—",
        })

    if tbl_data:
        df_all = pd.DataFrame(tbl_data)
        st.dataframe(df_all, use_container_width=True, hide_index=True)

    # Tür bazlı özet tablosu
    st.markdown("### 📚 Tür Bazlı Özet")
    ozet_data = []
    for etype, scores in sorted(type_scores.items()):
        if not scores:
            continue
        t_ort = round(sum(scores)/len(scores), 1)
        t_trend = round(scores[-1] - scores[0], 1) if len(scores) >= 2 else 0
        t_trend_str = f"+{t_trend}" if t_trend > 0 else str(t_trend) if t_trend != 0 else "—"
        ozet_data.append({
            "Tür": EXAM_TYPE_DISPLAY.get(etype, (etype,))[0],
            "Sınav": len(scores),
            "Ortalama": t_ort,
            "Trend": t_trend_str,
            "En Yüksek": max(scores),
            "En Düşük": min(scores),
        })
    if ozet_data:
        df_ozet = pd.DataFrame(ozet_data)
        st.dataframe(df_ozet, use_container_width=True, hide_index=True)

    # PDF + Excel
    st.markdown("---")
    bc1, bc2 = st.columns(2)
    with bc1:
        if st.button("📥 Toplu Karne PDF İndir", key="karne_toplu_pdf_btn", use_container_width=True):
            pdf_bytes = _generate_ogrenci_toplu_karne_pdf(student_info, filtered, exam_cache)
            if pdf_bytes:
                st.download_button("📄 PDF İndir", data=pdf_bytes,
                                   file_name=f"karne_{full_name.replace(' ', '_')}.pdf",
                                   mime="application/pdf", key="karne_toplu_pdf_dl")
            else:
                st.error("PDF oluşturulamadı.")
    with bc2:
        if tbl_data:
            _rapor_excel_export(pd.DataFrame(tbl_data), f"karne_toplu_{full_name}")


