def _build_ai_results_summary(filtered, exam_cache):
    """AI analiz için sonuç özetini dict olarak oluşturur."""
    summary = {"exams": [], "subjects": {}, "types": {}}
    for r in filtered:
        exam = exam_cache.get(r.exam_id)
        if not exam:
            continue
        puan = r.score if r.score is not None else 0
        entry = {
            "name": exam.name, "type": exam.exam_type or "Diğer",
            "subject": exam.subject or "", "score": puan,
            "correct": r.correct_count, "wrong": r.wrong_count,
            "empty": r.empty_count, "net": round(r.net_score, 1),
            "date": (r.graded_at or "")[:10],
        }
        summary["exams"].append(entry)
        summary["subjects"].setdefault(exam.subject or "Diğer", []).append(puan)
        summary["types"].setdefault(exam.exam_type or "Diğer", []).append(puan)

    # Ders bazlı ortalamalar
    for k, v in summary["subjects"].items():
        summary["subjects"][k] = {"avg": round(sum(v)/len(v), 1), "count": len(v),
                                   "max": max(v), "min": min(v)}
    for k, v in summary["types"].items():
        if isinstance(v, list):
            summary["types"][k] = {"avg": round(sum(v)/len(v), 1), "count": len(v),
                                    "trend": round(v[-1] - v[0], 1) if len(v) >= 2 else 0}
    return summary


def _render_ss_analiz(store):
    """Alt Sekme 4: Analiz - Performans, Ders, Sınıf/Şube analizleri."""
    analiz_turu = st.radio(
        "Analiz Türü",
        ["📊 Genel Performans", "👨‍🎓 Öğrenci Performansı", "📚 Ders Performansı", "🏫 Sınıf & Şube Analizi"],
        horizontal=True,
        key="ss_analiz_turu"
    )
    if analiz_turu == "📊 Genel Performans":
        _render_performans_dashboard()
    elif analiz_turu == "👨‍🎓 Öğrenci Performansı":
        _render_ogrenci_performans()
    elif analiz_turu == "📚 Ders Performansı":
        _render_ders_performans()
    else:
        _render_sinif_sube_analizi()

    # Dönemsel karşılaştırma + AI önerileri + PDF export
    try:
        from utils.report_utils import (
            ai_recommendations_html, period_comparison_row_html,
            generate_module_pdf, render_pdf_download_button,
            render_report_kunye_html, ReportStyler as _RS,
        )
        from datetime import timedelta

        st.markdown("---")
        st.markdown(_RS.section_divider_html("Dönemsel Performans Karşılaştırma", "#0d9488"), unsafe_allow_html=True)

        now = datetime.now()
        cur_m_start = now.replace(day=1).strftime("%Y-%m-%d")
        cur_m_end = now.strftime("%Y-%m-%d")
        prev_m_end_dt = now.replace(day=1) - timedelta(days=1)
        prev_m_start = prev_m_end_dt.replace(day=1).strftime("%Y-%m-%d")
        prev_m_end = prev_m_end_dt.strftime("%Y-%m-%d")

        all_exams = _cached_get_exams()
        all_results = _cached_get_all_results()

        # exam_id bazlı index oluştur
        _results_by_exam = {}
        for r in all_results:
            _results_by_exam.setdefault(r.exam_id, []).append(r)

        cur_exams = [e for e in all_exams
                     if hasattr(e, "created_at") and e.created_at and cur_m_start <= e.created_at[:10] <= cur_m_end]
        prev_exams = [e for e in all_exams
                      if hasattr(e, "created_at") and e.created_at and prev_m_start <= e.created_at[:10] <= prev_m_end]

        cur_results = []
        for e in cur_exams:
            cur_results.extend(_results_by_exam.get(e.id, []))
        prev_results = []
        for e in prev_exams:
            prev_results.extend(_results_by_exam.get(e.id, []))

        cur_avg = (sum(r.score for r in cur_results) / len(cur_results)) if cur_results else 0
        prev_avg = (sum(r.score for r in prev_results) / len(prev_results)) if prev_results else 0
        cur_basari = (sum(1 for r in cur_results if r.score >= 50) / len(cur_results) * 100) if cur_results else 0
        prev_basari = (sum(1 for r in prev_results if r.score >= 50) / len(prev_results) * 100) if prev_results else 0

        comparisons = [
            {"label": "Sınav Sayısı", "current": len(cur_exams), "previous": len(prev_exams)},
            {"label": "Ort. Puan", "current": cur_avg, "previous": prev_avg},
            {"label": "Başarı Oranı (%)", "current": cur_basari, "previous": prev_basari, "unit": "%"},
            {"label": "Sonuç Sayısı", "current": len(cur_results), "previous": len(prev_results)},
        ]
        st.markdown(period_comparison_row_html(comparisons), unsafe_allow_html=True)

        # AI Önerileri
        insights = []
        all_questions = store.get_questions()
        approved_q = [q for q in all_questions if q.status == "approved"]
        draft_q = [q for q in all_questions if q.status == "draft"]

        if len(draft_q) > len(approved_q) * 0.5 and draft_q:
            insights.append({
                "icon": "📝", "title": "Soru Onay Kuyruğu",
                "text": f"<b>{len(draft_q)}</b> soru onay bekliyor. Soru bankası kalitesini artırmak için inceleme kuyruğunu hızlandırınız.",
                "color": "#f59e0b",
            })
        if all_results:
            total_scores = [r.score for r in all_results]
            genel_ort = sum(total_scores) / len(total_scores)
            if genel_ort < 40:
                insights.append({
                    "icon": "⚠️", "title": "Düşük Genel Ortalama",
                    "text": f"Genel ortalama <b>{genel_ort:.1f}</b> puan. Blueprint'lerde kolay/orta soru oranlarını artırmayı deneyin.",
                    "color": "#ef4444",
                })
            cok_dusuk = [r for r in all_results if r.score < 30]
            if cok_dusuk:
                unique_students = set(r.student_number for r in cok_dusuk)
                insights.append({
                    "icon": "🎯", "title": "Kritik Performans Uyarısı",
                    "text": f"<b>{len(unique_students)}</b> farklı öğrenci 30 puan altında sonuç aldı. Telafi programı planlanmalı.",
                    "color": "#ef4444",
                })

        if insights:
            st.markdown(ai_recommendations_html(insights), unsafe_allow_html=True)

        st.markdown(render_report_kunye_html(), unsafe_allow_html=True)

        # PDF Export
        st.markdown(_RS.section_divider_html("PDF Genel Rapor", "#1e40af"), unsafe_allow_html=True)
        if st.button("📥 Ölçme Değerlendirme Raporu (PDF)", key="ss_analiz_pdf_btn", use_container_width=True):
            try:
                genel_ort_all = (sum(r.score for r in all_results) / len(all_results)) if all_results else 0
                basari_all = (sum(1 for r in all_results if r.score >= 50) / len(all_results) * 100) if all_results else 0
                exam_map = {e.id: e for e in all_exams}
                sections = [
                    {
                        "title": "Genel Özet",
                        "metrics": [
                            ("Sınav", str(len(all_exams)), "#2563eb"),
                            ("Sonuç", str(len(all_results)), "#8b5cf6"),
                            ("Ortalama", f"{genel_ort_all:.1f}", "#10b981"),
                            ("Başarı %", f"{basari_all:.0f}%", "#f59e0b"),
                        ],
                        "text": f"Toplam Soru: {len(all_questions)} | Onaylı: {len(approved_q)}",
                    },
                ]
                ders_scores_pdf: dict[str, list] = {}
                for r in all_results:
                    exam = exam_map.get(r.exam_id)
                    if exam:
                        ders_scores_pdf.setdefault(exam.subject, []).append(r.score)
                if ders_scores_pdf:
                    ders_ort_pdf = {d: round(sum(s) / len(s), 1) for d, s in ders_scores_pdf.items() if s}
                    if ders_ort_pdf:
                        sections.append({
                            "title": "Ders Bazlı Ortalama",
                            "bar_data": ders_ort_pdf,
                            "bar_title": "Ders Ortalamaları",
                            "bar_color": "#2563eb",
                        })
                if insights:
                    import re as _re
                    oneri_text = "\n".join([f"- {i['title']}: {_re.sub(r'<[^>]+>', '', i['text'])}" for i in insights])
                    sections.append({"title": "AI Önerileri", "text": oneri_text})
                pdf_bytes = generate_module_pdf("Ölçme Değerlendirme Raporu", sections)
                render_pdf_download_button(pdf_bytes, "od_raporu.pdf", "Ölçme Değerlendirme Raporu", "ss_analiz_dl")
            except Exception as e:
                st.error(f"PDF oluşturma hatası: {e}")
    except Exception:
        pass


