def _render_sinif_ogrenci_sonuclari(store: DataStore):
    """Sinif veya ogrenci bazli kategorik sinav sonuclari — en yeniden eskiye, PDF'li."""

    st.markdown("""
    <div style="background:linear-gradient(135deg,#0f172a,#1e293b);border-radius:14px;
    padding:14px 18px;margin-bottom:12px;border:1px solid rgba(124,58,237,0.2);">
    <div style="font-size:.9rem;font-weight:700;color:#c4b5fd;">📋 Sınıf & Öğrenci Bazlı Sonuçlar</div>
    <div style="font-size:.75rem;color:#64748b;margin-top:2px;">
    Sınıf seçin → tüm sınıfın sonuçlarını veya tek öğrencinin sonuçlarını kategorik görün</div>
    </div>""", unsafe_allow_html=True)

    results = _cached_get_all_results()
    exams = _cached_get_exams()

    if not results:
        styled_info_banner("Henüz sınav sonucu bulunmuyor.", "info")
        return

    # Exam cache
    exam_cache = {}
    for e in exams:
        exam_cache[e.id] = e

    # Filtreler — sinif + gosterim modu
    from utils.shared_data import load_shared_students
    students = load_shared_students()

    fc1, fc2, fc3 = st.columns([1, 1, 1])
    with fc1:
        sinif_set = sorted(set(str(s.get("sinif", "")) for s in students if s.get("durum", "aktif") == "aktif"))
        sinif_sec = st.selectbox("Sınıf", ["Tümü"] + sinif_set, key="ss_sinif_filtre")
    with fc2:
        gosterim = st.radio("Gösterim", ["📋 Tüm Sınıf", "👤 Tek Öğrenci"], key="ss_gosterim", horizontal=True)
    with fc3:
        kapsam = st.radio("Kapsam", ["Son Sınav", "Tümü"], key="ss_kapsam", horizontal=True)

    # Ogrenci secimi
    secili_ogrenci_id = None
    if "Tek Öğrenci" in gosterim:
        filtered_stu = students
        if sinif_sec != "Tümü":
            filtered_stu = [s for s in students if str(s.get("sinif", "")) == sinif_sec]
        stu_opts = {f"{s.get('ad', '')} {s.get('soyad', '')} ({s.get('sinif', '')}/{s.get('sube', '')})": s.get("id", "")
                     for s in filtered_stu if s.get("durum", "aktif") == "aktif"}
        sel = st.selectbox("Öğrenci Seçin", [""] + list(stu_opts.keys()), key="ss_ogrenci_sec")
        if sel and sel in stu_opts:
            secili_ogrenci_id = stu_opts[sel]

    # Sonuclari filtrele
    filtered = results
    if secili_ogrenci_id:
        filtered = [r for r in results if r.student_id == secili_ogrenci_id]
    elif sinif_sec != "Tümü":
        # Siniftaki ogrenci ID'leri
        sinif_ids = set(s.get("id", "") for s in students if str(s.get("sinif", "")) == sinif_sec)
        filtered = [r for r in results if r.student_id in sinif_ids]

    if not filtered:
        st.info("Seçilen filtreler için sonuç bulunamadı.")
        return

    # En yeniden eskiye sirala
    filtered.sort(key=lambda x: x.graded_at or "", reverse=True)

    # Son sinav modu
    if kapsam == "Son Sınav":
        seen = set()
        son = []
        for r in filtered:
            key = f"{r.student_id}_{r.exam_id}"
            if key not in seen:
                seen.add(key)
                son.append(r)
        filtered = son

    # KATEGORİK GRUPLAMA
    tur_gruplari: dict[str, list] = {}
    for r in filtered:
        exam = exam_cache.get(r.exam_id)
        tur = (exam.exam_type if exam and hasattr(exam, "exam_type") and exam.exam_type else "Diger")
        if "Yazili" in tur or "Donem" in tur:
            kategori = "🏫 Okul Yazılıları"
        elif tur in ("LGS", "TYT", "AYT Sayısal", "AYT Esit Agirlik", "AYT Sozel"):
            kategori = "📊 LGS / TYT / AYT"
        elif tur == "Deneme":
            kategori = "📝 Deneme Sınavları"
        elif tur == "Quiz":
            kategori = "⚡ Quiz"
        elif "Kazanim" in tur:
            kategori = "🎯 Kazanım Ölçme"
        else:
            kategori = "📋 Diğer Sınavlar"
        tur_gruplari.setdefault(kategori, []).append(r)

    # Ozet KPI
    puanlar = [r.score for r in filtered if r.score is not None]
    if puanlar:
        ort = round(sum(puanlar) / len(puanlar), 1)
        styled_stat_row([
            ("Sonuç", str(len(filtered)), "#7c3aed", "📋"),
            ("Ortalama", f"{ort}", "#2563eb", "📊"),
            ("En Yüksek", f"{max(puanlar):.0f}", "#22c55e", "🏆"),
            ("En Düşük", f"{min(puanlar):.0f}", "#ef4444", "📉"),
        ])

    # Her kategori
    kategori_sira = ["🏫 Okul Yazılıları", "📊 LGS / TYT / AYT", "📝 Deneme Sınavları",
                      "🎯 Kazanım Ölçme", "⚡ Quiz", "📋 Diğer Sınavlar"]

    for kategori in kategori_sira:
        items = tur_gruplari.get(kategori, [])
        if not items:
            continue

        items.sort(key=lambda x: x.graded_at or "", reverse=True)
        kat_puanlar = [r.score for r in items if r.score is not None]
        kat_ort = round(sum(kat_puanlar) / len(kat_puanlar), 1) if kat_puanlar else 0
        ort_clr = "#22c55e" if kat_ort >= 70 else ("#f59e0b" if kat_ort >= 50 else "#ef4444")

        with st.expander(f"{kategori} — {len(items)} sonuç | Ort: {kat_ort}", expanded=True):
            import pandas as pd
            rows = []
            for r in items:
                exam = exam_cache.get(r.exam_id)
                exam_name = exam.name if exam else "?"
                exam_subject = exam.subject if exam else ""
                exam_type = exam.exam_type if exam and hasattr(exam, "exam_type") else ""
                tarih = r.graded_at[:10] if r.graded_at else ""
                puan = r.score if r.score is not None else 0
                _notes = r.notes or ""
                kaynak = "Dış Sınav" if "Dis sinav" in _notes else "Sistem"
                rows.append({
                    "Öğrenci": r.student_name or "?",
                    "Sınav": exam_name[:30],
                    "Ders": exam_subject,
                    "Puan": f"{puan:.0f}",
                    "Net": f"{r.net_score:.1f}" if r.net_score else "-",
                    "D": r.correct_count, "Y": r.wrong_count, "B": r.empty_count,
                    "Tarih": tarih,
                    "Kaynak": kaynak,
                })
            df = pd.DataFrame(rows)
            st.dataframe(df, use_container_width=True, height=min(400, len(rows) * 40 + 50))

            # Dis sinav PDF arsivinden goruntuleme
            _arsiv_path = os.path.join(os.path.dirname(os.path.dirname(os.path.abspath(__file__))),
                                       "data", "olcme", "dis_sinav_pdf")
            if os.path.exists(_arsiv_path):
                pdfs = [f for f in os.listdir(_arsiv_path) if f.endswith(".pdf")]
                if pdfs:
                    with st.expander(f"📎 Dış Sınav PDF Arşivi ({len(pdfs)} dosya)", expanded=False):
                        for pdf_name in sorted(pdfs, reverse=True)[:10]:
                            _fp = os.path.join(_arsiv_path, pdf_name)
                            with open(_fp, "rb") as _pf:
                                _pb = _pf.read()
                            st.download_button(f"📄 {pdf_name}", data=_pb,
                                               file_name=pdf_name, mime="application/pdf",
                                               key=f"arsiv_{pdf_name[:20]}_{kategori[:5]}",
                                               use_container_width=True)

            # Toplu PDF
            if st.button(f"📄 {kategori} Toplu PDF", key=f"ss_kat_pdf_{kategori[:8]}", use_container_width=True):
                st.info("Toplu PDF oluşturma — Belgeler & Raporlar sekmesinden alınabilir.")


