def render_soru_bankasi():
    """Soru bankasi ekrani - Grafikler ve detayli istatistikler."""
    styled_section("Soru Bankasi", "#00695c")

    store = get_store()

    # Tum sorulari al (istatistikler icin) - HAFIF + CACHE
    all_questions = _cached_get_questions_light(status="approved")
    all_questions_all_status = _cached_get_questions_light()

    # ============================================
    # GENEL BAKIŞ - GRAFIKLER VE ISTATISTIKLER
    # ============================================
    # Kategori sayılarını hesapla
    ai_count = len([q for q in all_questions if q.source in ("ai_blueprint", "ai_bulk_gen")])
    ext_count = len([q for q in all_questions if q.source in ("pdf_visual_import", "manual", "template", "imported")])

    tab_overview, tab_ai, tab_ext = st.tabs([
        "📊 Genel Bakış",
        f"🤖 Kazanım Bankası ({ai_count})",
        f"📥 Dışardan Yüklenen ({ext_count})"
    ])

    with tab_overview:
        # ── Kompakt metrik satırı ──────────────────────────────────────
        gorsel_sorular = [q for q in all_questions if q.image_data]
        metin_sorular  = [q for q in all_questions if not q.image_data]
        draft_count    = len([q for q in all_questions_all_status if q.status == "draft"])
        review_count   = len([q for q in all_questions_all_status if q.status == "in_review"])

        styled_stat_row([
            ("Onaylı Soru",  str(len(all_questions)), "#10b981", "✅"),
            ("Görsel",       str(len(gorsel_sorular)),"#e65100", "🖼️"),
            ("Metin",        str(len(metin_sorular)), "#2563eb", "📝"),
            ("Taslak",       str(draft_count),        "#8b5cf6", "📄"),
            ("İncelemede",   str(review_count),       "#f59e0b", "🔍"),
        ])

        if not all_questions:
            styled_info_banner("Henüz onaylı soru bulunmuyor.", "info")
            return

        st.markdown("<div style='height:8px'></div>", unsafe_allow_html=True)

        # ── İki kolon: Kategori dağılımı + Zorluk dağılımı ──────────────
        col_chart1, col_chart2 = st.columns(2)

        def _html_bar_chart(items, title, color, max_bars=10):
            """Styled HTML yatay bar chart."""
            if not items:
                return
            styled_section(title, color)
            max_val = max(v for _, v in items) or 1
            rows_html = ""
            for label, val in items[:max_bars]:
                pct = int(val / max_val * 100)
                rows_html += (
                    f"<div style='display:flex;align-items:center;gap:8px;margin-bottom:5px'>"
                    f"<div style='min-width:110px;font-size:0.78rem;color:#334155;font-weight:500;"
                    f"white-space:nowrap;overflow:hidden;text-overflow:ellipsis' title='{label}'>{label}</div>"
                    f"<div style='flex:1;background:#1A2035;border-radius:4px;height:18px;position:relative'>"
                    f"<div style='width:{pct}%;background:{color};border-radius:4px;height:100%;min-width:2px'></div>"
                    f"</div>"
                    f"<div style='min-width:28px;text-align:right;font-size:0.78rem;font-weight:700;color:{color}'>{val}</div>"
                    f"</div>"
                )
            st.markdown(f"<div style='padding:4px 0'>{rows_html}</div>", unsafe_allow_html=True)

        # 1. Kategori dağılımı
        with col_chart1:
            kategori_sayilari = {}
            for q in all_questions:
                kat = q.subject if q.subject else "Belirtilmemiş"
                kategori_sayilari[kat] = kategori_sayilari.get(kat, 0) + 1
            sorted_kat = sorted(kategori_sayilari.items(), key=lambda x: x[1], reverse=True)
            _html_bar_chart(sorted_kat, "Kategori Dağılımı", "#2563eb", max_bars=10)

            # Sınav türleri özet satırı
            st.markdown("<div style='height:6px'></div>", unsafe_allow_html=True)
            styled_section("Sınav Türleri", "#6366f1")
            sinav_items = [(et, kategori_sayilari.get(et, 0)) for et in EXAM_TYPES if kategori_sayilari.get(et, 0) > 0]
            if sinav_items:
                _html_bar_chart(sinav_items, "", "#6366f1", max_bars=6)
            else:
                st.caption("Henüz sınav türü sorusu yok.")

        # 2. Zorluk + Sınıf dağılımı
        with col_chart2:
            zorluk_renk = {"Kolay": "#10b981", "Orta": "#f59e0b", "Zor": "#ef4444", "Karışık": "#8b5cf6"}
            zorluk_sayilari = {"Kolay": 0, "Orta": 0, "Zor": 0, "Karışık": 0}
            for q in all_questions:
                diff = q.difficulty if q.difficulty in zorluk_sayilari else "Orta"
                zorluk_sayilari[diff] += 1

            styled_section("Zorluk Dağılımı", "#8b5cf6")
            total_z = sum(zorluk_sayilari.values()) or 1
            rows_z = ""
            for z, cnt in zorluk_sayilari.items():
                pct = int(cnt / total_z * 100)
                clr = zorluk_renk[z]
                rows_z += (
                    f"<div style='display:flex;align-items:center;gap:8px;margin-bottom:6px'>"
                    f"<div style='min-width:58px;font-size:0.78rem;font-weight:600;color:{clr}'>{z}</div>"
                    f"<div style='flex:1;background:#1A2035;border-radius:4px;height:18px;position:relative'>"
                    f"<div style='width:{pct}%;background:{clr};border-radius:4px;height:100%;min-width:2px'></div>"
                    f"</div>"
                    f"<div style='min-width:50px;text-align:right;font-size:0.78rem;color:#64748b'>{cnt} (%{pct})</div>"
                    f"</div>"
                )
            st.markdown(f"<div style='padding:4px 0'>{rows_z}</div>", unsafe_allow_html=True)

            st.markdown("<div style='height:6px'></div>", unsafe_allow_html=True)

            # Sınıf dağılımı
            sinif_sayilari = {}
            for q in all_questions:
                if q.grade:
                    sinif_sayilari[q.grade] = sinif_sayilari.get(q.grade, 0) + 1
            if sinif_sayilari:
                sorted_sinif = sorted(sinif_sayilari.items(), key=lambda x: _grade_sort_key(x[0]))
                sinif_items = [(_grade_label(s), c) for s, c in sorted_sinif]
                _html_bar_chart(sinif_items, "Sınıf Dağılımı", "#0891b2", max_bars=12)

        st.markdown("<div style='height:12px'></div>", unsafe_allow_html=True)

        # ── Detaylı Tablo ──────────────────────────────────────────────
        styled_section("Detaylı Kategori Tablosu", "#0B0F19")

        tablo_data = []
        for kat in ALL_CATEGORIES:
            kat_sorular = [q for q in all_questions if q.subject == kat]
            if kat_sorular:
                gorsel = len([q for q in kat_sorular if q.image_data])
                metin = len(kat_sorular) - gorsel
                kolay = len([q for q in kat_sorular if q.difficulty == "Kolay"])
                orta = len([q for q in kat_sorular if q.difficulty == "Orta"])
                zor = len([q for q in kat_sorular if q.difficulty == "Zor"])
                # Sınıf dağılımını bul
                siniflar = {}
                for q in kat_sorular:
                    if q.grade:
                        siniflar[q.grade] = siniflar.get(q.grade, 0) + 1
                sinif_str = ", ".join(f"{_grade_label(s)}({c})" for s, c in sorted(siniflar.items(), key=lambda x: _grade_sort_key(x[0]))) if siniflar else "-"
                tablo_data.append({
                    "Kategori": kat,
                    "Toplam": len(kat_sorular),
                    "Sınıflar": sinif_str,
                    "Görsel": gorsel,
                    "Metin": metin,
                    "Kolay": kolay,
                    "Orta": orta,
                    "Zor": zor
                })

        if tablo_data:
            df = pd.DataFrame(tablo_data)
            st.dataframe(df, use_container_width=True, hide_index=True)
        else:
            st.info("Henüz soru bulunmuyor.")

        # Hazır Sınavlar Bölümü
        st.markdown("---")
        st.markdown("### 📁 Hazır Sınavlar")
        _render_hazir_sinavlar_listesi(store)

    # ── Ortak soru listesi render fonksiyonu ──
    def _render_bank_browse(source_cat: str, tab_key: str):
        """Soru bankası kategori tab'ı: filtreler + liste.
        source_cat: 'ai' veya 'external'
        """
        tum_sorular = store.get_questions_light(status="approved", source_category=source_cat)

        # Filtre için gerekli veri
        sinif_sayilari = {}
        for q in tum_sorular:
            if q.grade:
                sinif_sayilari[q.grade] = sinif_sayilari.get(q.grade, 0) + 1

        styled_section("Filtrele & Ara", "#00695c")

        col1, col2, col3 = st.columns(3)

        with col1:
            tum_sorular_all = store.get_questions_light(source_category=source_cat)
            status_counts = {}
            for q in tum_sorular_all:
                status_counts[q.status] = status_counts.get(q.status, 0) + 1

            status_options = ["approved", "draft", "in_review", "retired"]
            status_labels = {
                "approved": f"Onayli ({status_counts.get('approved', 0)})",
                "draft": f"Taslak ({status_counts.get('draft', 0)})",
                "in_review": f"Incelemede ({status_counts.get('in_review', 0)})",
                "retired": f"Emekli ({status_counts.get('retired', 0)})"
            }
            status_filter = st.selectbox("Durum", status_options,
                                          format_func=lambda x: status_labels.get(x, x),
                                          key=f"{tab_key}_status")

        with col2:
            grade_options = [None] + sorted(sinif_sayilari.keys(), key=_grade_sort_key)
            def _gf(x):
                if x is None:
                    return f"Tumu ({len(tum_sorular)})"
                return f"{_grade_label(x)} ({sinif_sayilari.get(x, 0)})"
            grade_filter = st.selectbox("Sinif", grade_options, format_func=_gf, key=f"{tab_key}_grade")

        with col3:
            kategori_sayilari = {}
            for q in tum_sorular:
                if q.subject:
                    kategori_sayilari[q.subject] = kategori_sayilari.get(q.subject, 0) + 1
            kategori_options = []
            for et in EXAM_TYPES:
                if kategori_sayilari.get(et, 0) > 0:
                    kategori_options.append(et)
            for ders in SUBJECTS:
                if kategori_sayilari.get(ders, 0) > 0:
                    kategori_options.append(ders)
            subject_filter = st.multiselect("Ders", kategori_options,
                                          format_func=lambda x: f"{x} ({kategori_sayilari.get(x, 0)})",
                                          key=f"{tab_key}_subject")

        # Ay filtresi + Arama + Kullanım filtresi satırı
        col_ay, col_search, col_usage = st.columns(3)
        with col_ay:
            ay_modu = st.radio("Ay Kapsamı", ["Tüm Yıl", "Belirli Ay(lar)"],
                              horizontal=True, key=f"{tab_key}_ay_modu")
            if ay_modu == "Belirli Ay(lar)":
                month_filter = st.multiselect("Ay Seçin", AY_SECENEKLERI, key=f"{tab_key}_months")
            else:
                month_filter = None
        with col_search:
            search_query = st.text_input("Arama", key=f"{tab_key}_search", placeholder="Soru metninde ara...")
        with col_usage:
            usage_filter = st.selectbox("Kullanim", ["Tumu", "Hic Kullanilmamis", "1-3 Kullanim", "3+ Kullanim"],
                                        key=f"{tab_key}_usage")

        # Sorguyu çalıştır
        questions = store.get_questions_light(
            status=status_filter, grade=grade_filter, subject=subject_filter,
            query=search_query, month=month_filter, source_category=source_cat
        )

        # Kullanım filtresi uygula
        if usage_filter == "Hic Kullanilmamis":
            questions = [q for q in questions if getattr(q, 'usage_count', 0) == 0]
        elif usage_filter == "1-3 Kullanim":
            questions = [q for q in questions if 1 <= getattr(q, 'usage_count', 0) <= 3]
        elif usage_filter == "3+ Kullanim":
            questions = [q for q in questions if getattr(q, 'usage_count', 0) > 3]

        if not questions:
            styled_info_banner("Bu filtrelere uygun soru bulunamadi.", "info")
            return

        _total_q = len(questions)
        _gorsel_q = sum(1 for q in questions if q.image_data)
        _ort_kal = sum(q.quality_score for q in questions) // max(_total_q, 1)
        st.markdown(
            f"<div style='background:#f0fdf4;border:1px solid #bbf7d0;border-radius:8px;"
            f"padding:8px 14px;margin:8px 0;font-size:0.85rem;color:#166534'>"
            f"<b>{_total_q}</b> soru bulundu · "
            f"<b>{_gorsel_q}</b> gorsel · "
            f"<b>{_total_q - _gorsel_q}</b> metin · "
            f"Ort. kalite: <b>{_ort_kal}</b>/100"
            f"</div>",
            unsafe_allow_html=True,
        )

        # Sayfalama
        items_per_page = 20
        total_pages = (len(questions) - 1) // items_per_page + 1 if questions else 1
        page_key = f"{tab_key}_page"
        if page_key not in st.session_state:
            st.session_state[page_key] = 1

        col_nav1, col_nav2, col_nav3 = st.columns([1, 2, 1])
        with col_nav1:
            if st.button("Onceki", disabled=st.session_state[page_key] <= 1, key=f"{tab_key}_prev"):
                st.session_state[page_key] -= 1
                st.rerun()
        with col_nav2:
            st.markdown(f"<center>Sayfa {st.session_state[page_key]} / {total_pages}</center>", unsafe_allow_html=True)
        with col_nav3:
            if st.button("Sonraki", disabled=st.session_state[page_key] >= total_pages, key=f"{tab_key}_next"):
                st.session_state[page_key] += 1
                st.rerun()

        start_idx = (st.session_state[page_key] - 1) * items_per_page
        page_questions = questions[start_idx:start_idx + items_per_page]

        for q in page_questions:
            badge_subject = f"{q.subject}" if q.subject else "?"
            badge_diff = {"Kolay": "K", "Orta": "O", "Zor": "Z", "Karışık": "KR"}.get(q.difficulty, "?")
            badge_type = "[G]" if q.image_data else "[M]"
            # Ay bilgisi
            ay_str = ", ".join(q.month_period) if q.month_period else ""
            # Bloom ve kullanım bilgisi
            bloom_badge = f" | B:{getattr(q, 'bloom_level', '')[:3]}" if getattr(q, 'bloom_level', '') else ""
            usage_badge = f" | K:{getattr(q, 'usage_count', 0)}" if getattr(q, 'usage_count', 0) > 0 else ""

            with st.expander(f"{badge_type} {q.id[-6:]} | {badge_subject} | {badge_diff} | {_grade_label(q.grade)}{bloom_badge}{usage_badge}" + (f" | {ay_str}" if ay_str else "")):
                if q.image_data:
                    try:
                        st.image(q.image_data, width=400)
                    except Exception:
                        pass

                st.markdown(f"**{q.stem}**")
                for letter, text in q.choices.items():
                    if letter == q.correct_choice:
                        st.markdown(f"**{letter})** {text} (dogru)")
                    else:
                        st.markdown(f"{letter}) {text}")

                col_i1, col_i2 = st.columns(2)
                with col_i1:
                    st.caption(f"{q.created_at[:10]} | {_grade_label(q.grade)} | {q.source}")
                    bloom_val = getattr(q, 'bloom_level', '')
                    if bloom_val:
                        st.caption(f"Bloom: {bloom_val}")
                with col_i2:
                    if q.month_period:
                        st.caption(f"Aylar: {', '.join(q.month_period)}")
                    usage_val = getattr(q, 'usage_count', 0)
                    if usage_val > 0:
                        st.caption(f"Kullanim: {usage_val} sinav | Son: {getattr(q, 'last_used_date', '')[:10]}")
                    if q.tags:
                        st.caption(f"Etiketler: {', '.join(q.tags[:5])}")

                if q.status == "approved":
                    if st.button("Emekli Et", key=f"retire_{tab_key}_{q.id}"):
                        store.update_question_status(q.id, "retired")
                        st.rerun()

    with tab_ai:
        styled_section("Kazanim Bankasi (AI Uretilmis)", "#1565c0")
        st.caption("AI ile kazanimlardan uretilen sorular. Esit kazanim dagilimi ve ay etiketleme uygulanmistir.")
        _render_bank_browse("ai", "bank_ai")

    with tab_ext:
        styled_section("Disardan Yuklenen Sorular", "#e65100")
        st.caption("PDF yuklemesi, kirpma veya dis kaynaktan aktarilan sorular.")
        _render_bank_browse("external", "bank_ext")


def _render_hazir_sinavlar_listesi(store: DataStore):
    """Hazır sınavları listele."""
    import os
    import json

    hazir_sinav_dir = os.path.join(store.base_path, "hazir_sinavlar")

    if not os.path.exists(hazir_sinav_dir):
        st.info("📁 Henüz hazır sınav yüklenmemiş. PDF İçe Aktar sekmesinden 'Hazır Sınav Olarak Yükle' seçeneğini kullanabilirsiniz.")
        return

    # Hazır sınav dosyalarını listele
    hazir_files = [f for f in os.listdir(hazir_sinav_dir) if f.endswith('.json')]

    if not hazir_files:
        st.info("📁 Henüz hazır sınav yüklenmemiş.")
        return

    st.success(f"📚 {len(hazir_files)} hazır sınav mevcut")

    for hf in hazir_files:
        filepath = os.path.join(hazir_sinav_dir, hf)
        try:
            with open(filepath, 'r', encoding='utf-8') as f:
                sinav_data = json.load(f)

            sinav_adi = sinav_data.get('name', hf.replace('.json', ''))
            sinav_turu = sinav_data.get('exam_type', 'Belirtilmemiş')
            soru_sayisi = sinav_data.get('question_count', 0)
            yuklenme = sinav_data.get('created_at', '')[:10]

            col1, col2, col3, col4 = st.columns([3, 1, 1, 1])
            with col1:
                st.write(f"📋 **{sinav_adi}**")
            with col2:
                st.caption(sinav_turu)
            with col3:
                st.caption(f"{soru_sayisi} soru")
            with col4:
                if st.button("🗑️", key=f"del_hazir_{hf}"):
                    os.remove(filepath)
                    # PDF'i de sil
                    pdf_path = filepath.replace('.json', '.pdf')
                    if os.path.exists(pdf_path):
                        os.remove(pdf_path)
                    st.rerun()

        except Exception as e:
            st.error(f"Dosya okunamadı: {hf}")


def _render_hazir_sinav_yukle(store: DataStore):
    """Hazır sınav olarak PDF yükleme - kesmeden, aynen kaydet."""
    import os
    import json
    import shutil
    from datetime import datetime

    st.markdown("### 📋 Hazır Sınav Yükle")

    st.info("""
    📋 **Hazır Sınav Nedir?**
    - PDF'i kesmeden, aynen kaydedersiniz
    - Örnek: "11.TYT Deneme 1" - 100 soruluk tam bir sınav
    - Sınav oluştururken "Hazır Sınav" seçeneğinden bu sınavları seçebilirsiniz
    - Sınav PDF olarak aynen sunulur

    💡 **Kullanım Alanları:** TYT, AYT, LGS denemeleri, genel değerlendirme sınavları
    """)

    # Hazır sınav dizini
    hazir_sinav_dir = os.path.join(store.base_path, "hazir_sinavlar")
    os.makedirs(hazir_sinav_dir, exist_ok=True)

    st.markdown("---")

    # 1. PDF Yükle
    st.markdown("#### 📁 1. PDF Dosyası Seç")
    uploaded_pdf = st.file_uploader(
        "PDF Seç (Tam sınav dosyası)",
        type=['pdf'],
        key="hazir_sinav_pdf"
    )

    if uploaded_pdf:
        from utils.security import validate_upload
        _ok, _msg = validate_upload(uploaded_pdf, allowed_types=["pdf"], max_mb=50)
        if not _ok:
            st.error(f"⚠️ {_msg}")
            uploaded_pdf = None

    if not uploaded_pdf:
        return

    st.success(f"✅ Dosya seçildi: {uploaded_pdf.name}")

    st.markdown("---")

    # 2. Sınav Bilgileri
    st.markdown("#### 📝 2. Sınav Bilgileri")

    col1, col2 = st.columns(2)

    with col1:
        sinav_adi = st.text_input(
            "Sınav Adı *",
            value=uploaded_pdf.name.replace('.pdf', ''),
            placeholder="Örn: 11.TYT Deneme 1",
            key="hazir_sinav_adi"
        )

        sinav_turu = st.selectbox(
            "Sınav Turu *",
            EXAM_TYPES,
            key="hazir_sinav_turu"
        )

    with col2:
        soru_sayisi = st.number_input(
            "Soru Sayısı *",
            min_value=1,
            max_value=500,
            value=40,
            key="hazir_sinav_soru_sayisi"
        )

        sinav_sinifi = st.selectbox(
            "Sınıf",
            GRADES,
            index=7,  # 8. sınıf default
            format_func=_grade_label,
            key="hazir_sinav_sinifi"
        )

    # Ders secimi (zorunlu)
    sinav_dersi = st.selectbox("Ders *", ALL_CATEGORIES, key="hazir_sinav_ders")

    # Ay secimi (zorunlu)
    st.markdown("##### Ay Secimi (Zorunlu)")
    hazir_tum_yil = st.checkbox("Tum Yil", key="hazir_tum_yil")
    if hazir_tum_yil:
        hazir_selected_months = AY_SECENEKLERI.copy()
    else:
        hazir_selected_months = st.multiselect("Hangi Ay(lar)a Ait?", AY_SECENEKLERI, key="hazir_months")

    # Ek bilgiler
    with st.expander("📌 Ek Bilgiler (Opsiyonel)"):
        sinav_suresi = st.number_input("Sınav Süresi (dk)", min_value=0, value=0, key="hazir_sinav_sure")
        sinav_aciklama = st.text_area("Açıklama", key="hazir_sinav_aciklama", height=80)

    st.markdown("---")

    # 3. Kaydet
    st.markdown("#### 💾 3. Kaydet")

    zorunlu_eksik = []
    if not sinav_adi.strip():
        zorunlu_eksik.append("Sınav Adı")
    if not hazir_selected_months:
        zorunlu_eksik.append("Ay Secimi")

    if zorunlu_eksik:
        st.warning(f"⚠️ Zorunlu alanlar eksik: {', '.join(zorunlu_eksik)}")
        return

    # Dosya adı oluştur (güvenli)
    safe_name = "".join(c if c.isalnum() or c in "._- " else "_" for c in sinav_adi).strip()
    safe_name = safe_name.replace(" ", "_")

    col_btn1, col_btn2 = st.columns([2, 1])

    with col_btn1:
        if st.button("💾 Hazır Sınav Olarak Kaydet", type="primary", use_container_width=True):

            try:
                # PDF'i kaydet
                pdf_path = os.path.join(hazir_sinav_dir, f"{safe_name}.pdf")
                with open(pdf_path, 'wb') as f:
                    f.write(uploaded_pdf.getvalue())

                # Meta bilgileri kaydet
                meta_data = {
                    "id": f"hazir_{safe_name}_{datetime.now().strftime('%Y%m%d%H%M%S')}",
                    "name": sinav_adi,
                    "exam_type": sinav_turu,
                    "question_count": soru_sayisi,
                    "grade": sinav_sinifi,
                    "subject": sinav_dersi,
                    "month_period": hazir_selected_months,
                    "duration_minutes": sinav_suresi,
                    "description": sinav_aciklama,
                    "pdf_filename": f"{safe_name}.pdf",
                    "original_filename": uploaded_pdf.name,
                    "created_at": datetime.now().isoformat()
                }

                json_path = os.path.join(hazir_sinav_dir, f"{safe_name}.json")
                with open(json_path, 'w', encoding='utf-8') as f:
                    json.dump(meta_data, f, ensure_ascii=False, indent=2)

                st.success(f"✅ Hazır sınav kaydedildi: **{sinav_adi}**")
                st.balloons()

                st.info("""
                📋 **Sonraki Adımlar:**
                - Soru Bankası > Hazır Sınavlar bölümünden görebilirsiniz
                - Sınav Oluştur > Hazır Sınav Yükle seçeneğinden kullanabilirsiniz
                """)

            except Exception as e:
                st.error(f"❌ Kayıt hatası: {str(e)}")

    # Mevcut hazır sınavları göster
    st.markdown("---")
    st.markdown("#### 📚 Mevcut Hazır Sınavlar")
    _render_hazir_sinavlar_listesi(store)


def _render_disaridan_sinav_yukle(store: DataStore):
    """Dışarıdan sınav yükle: cevap anahtarı gir, optik form oluştur."""
    import os
    import json
    from datetime import datetime

    st.markdown("### 📋 Dışarıdan Sınav Yükle")

    st.info("""
    📋 **Dışarıdan Sınav Yükle Nedir?**
    - Kendi hazırladığınız veya dışarıdan aldığınız sınavı sisteme yüklersiniz
    - Cevap anahtarını manuel girersiniz (ABCD veya Doğru/Yanlış)
    - Sistem otomatik olarak kişisel optik formları oluşturur
    - QR kod ile okutarak otomatik değerlendirme yapılır

    💡 **Kullanım:** Kağıt sınavlar, dışarıdan alınan denemeler, hazırlık sınavları
    """)

    st.markdown("---")

    # ============================================
    # 1. SINAV BİLGİLERİ
    # ============================================
    st.markdown("#### 📝 1. Sınav Bilgileri")

    col1, col2 = st.columns(2)

    with col1:
        ds_sinav_adi = st.text_input(
            "Sınav Adı *",
            placeholder="Örn: Matematik 1. Yazılı",
            key="ds_sinav_adi"
        )

        ds_sinav_turu = st.selectbox(
            "Sınav Türü *",
            EXAM_TYPES,
            key="ds_sinav_turu"
        )

        ds_ders = st.selectbox(
            "Ders *",
            ALL_CATEGORIES,
            key="ds_ders"
        )

    with col2:
        ds_sinif = st.selectbox(
            "Sınıf *",
            GRADES,
            index=7,
            format_func=_grade_label,
            key="ds_sinif"
        )

        # Şube listesi
        from utils.shared_data import get_sinif_sube_listesi, get_sinif_ogrenci_listesi
        sinif_sube_data = get_sinif_sube_listesi()
        sube_listesi = sinif_sube_data.get("subeler", ["A", "B", "C", "D", "E"])
        if not sube_listesi:
            sube_listesi = ["A", "B", "C", "D", "E"]
        ds_sube = st.selectbox("Şube *", sube_listesi, key="ds_sube")

        ds_soru_sayisi = st.number_input(
            "Soru Sayısı *",
            min_value=1,
            max_value=200,
            value=20,
            key="ds_soru_sayisi"
        )

    # Öğretmen seçimi
    col3, col4 = st.columns(2)
    with col3:
        from utils.shared_data import get_ik_employee_options
        ogretmen_opts = get_ik_employee_options(role_scope="TEACHER")
        if len(ogretmen_opts) <= 1:
            ogretmen_opts = get_ik_employee_options()
        if len(ogretmen_opts) > 1:
            ds_ogretmen_sel = st.selectbox("Sınavı Yapan Öğretmen", list(ogretmen_opts.keys()), key="ds_ogretmen")
            ds_ogretmen = ds_ogretmen_sel if ds_ogretmen_sel != "-- Secim yapin --" else ""
        else:
            ds_ogretmen = st.text_input("Sınavı Yapan Öğretmen", placeholder="Adı Soyadı")


    with col4:
        ds_sure = st.number_input(
            "Sınav Süresi (dk)",
            min_value=5,
            max_value=300,
            value=40,
            key="ds_sure"
        )

    # PDF yükleme (opsiyonel)
    with st.expander("📁 PDF Dosya Yükle (Opsiyonel)", expanded=False):
        ds_pdf = st.file_uploader(
            "Sınav PDF dosyası",
            type=['pdf'],
            key="ds_pdf_upload"
        )
        if ds_pdf:
            from utils.security import validate_upload
            _ok, _msg = validate_upload(ds_pdf, allowed_types=["pdf"], max_mb=50)
            if not _ok:
                st.error(f"⚠️ {_msg}")
                ds_pdf = None
        if ds_pdf:
            st.success(f"✅ PDF yüklendi: {ds_pdf.name}")

    st.markdown("---")

    # ============================================
    # 2. SORU TÜRLERİ
    # ============================================
    st.markdown("#### 📝 2. Soru Türleri")

    ds_tur_modu = st.radio(
        "Soru Türü Modu",
        ["📋 Tüm Sorular Aynı Tür", "🔀 Karışık (Soru Bazlı)"],
        horizontal=True,
        key="ds_tur_modu"
    )

    # Her soru için tür bilgisini tutan liste
    soru_turleri = []  # "mcq4", "mcq5", "dy"

    if "Tüm Sorular" in ds_tur_modu:
        ds_toplu_tur = st.radio(
            "Soru Türü",
            ["Çoktan Seçmeli (A/B/C/D)", "Çoktan Seçmeli (A/B/C/D/E)", "Doğru-Yanlış (D/Y)"],
            horizontal=True,
            key="ds_toplu_tur"
        )
        if "D/E)" in ds_toplu_tur:
            soru_turleri = ["mcq5"] * ds_soru_sayisi
        elif "D/Y)" in ds_toplu_tur:
            soru_turleri = ["dy"] * ds_soru_sayisi
        else:
            soru_turleri = ["mcq4"] * ds_soru_sayisi
    else:
        st.caption("Her soru için ayrı tür seçin:")
        cols_per_row = 5
        for row_start in range(0, ds_soru_sayisi, cols_per_row):
            cols = st.columns(cols_per_row)
            for i, col in enumerate(cols):
                soru_idx = row_start + i
                if soru_idx < ds_soru_sayisi:
                    with col:
                        tur = st.selectbox(
                            f"S{soru_idx + 1}",
                            ["ABCD", "ABCDE", "D/Y"],
                            key=f"ds_soru_tur_{soru_idx}"
                        )
                        if tur == "ABCDE":
                            soru_turleri.append("mcq5")
                        elif tur == "D/Y":
                            soru_turleri.append("dy")
                        else:
                            soru_turleri.append("mcq4")

    # Eksik tür varsa tamamla
    while len(soru_turleri) < ds_soru_sayisi:
        soru_turleri.append("mcq4")

    st.markdown("---")

    # ============================================
    # 3. CEVAP ANAHTARI
    # ============================================
    st.markdown("#### 🔑 3. Cevap Anahtarı")

    # Session state for cevap anahtari
    cevap_key = "ds_cevaplar"
    if cevap_key not in st.session_state:
        st.session_state[cevap_key] = {}

    dolu_count = 0
    cols_per_row = 5
    for row_start in range(0, ds_soru_sayisi, cols_per_row):
        cols = st.columns(cols_per_row)
        for i, col in enumerate(cols):
            soru_idx = row_start + i
            if soru_idx < ds_soru_sayisi:
                with col:
                    tur = soru_turleri[soru_idx]
                    if tur == "dy":
                        secenekler = ["", "D", "Y"]
                        label = f"S{soru_idx + 1} (D/Y)"
                    elif tur == "mcq5":
                        secenekler = ["", "A", "B", "C", "D", "E"]
                        label = f"S{soru_idx + 1}"
                    else:
                        secenekler = ["", "A", "B", "C", "D"]
                        label = f"S{soru_idx + 1}"

                    cevap = st.selectbox(
                        label,
                        secenekler,
                        key=f"ds_cevap_{soru_idx}"
                    )
                    if cevap:
                        st.session_state[cevap_key][soru_idx] = cevap
                        dolu_count += 1
                    else:
                        st.session_state[cevap_key].pop(soru_idx, None)

    # Özet
    if dolu_count == ds_soru_sayisi:
        st.success(f"✅ Tüm cevaplar girildi: {dolu_count}/{ds_soru_sayisi}")
    elif dolu_count > 0:
        st.warning(f"⚠️ {dolu_count}/{ds_soru_sayisi} cevap girildi. Eksik: {ds_soru_sayisi - dolu_count}")
    else:
        st.info("📝 Cevap anahtarını doldurun.")

    st.markdown("---")

    # ============================================
    # 4. ÖĞRENCİ LİSTESİ ÖNİZLEME
    # ============================================
    st.markdown("#### 👥 4. Öğrenci Listesi")

    ogrenci_listesi = get_sinif_ogrenci_listesi(ds_sinif, ds_sube)

    if ogrenci_listesi:
        st.success(f"✅ {_grade_label(ds_sinif)} {ds_sube} şubesinde **{len(ogrenci_listesi)}** öğrenci bulundu.")
        with st.expander(f"📋 Öğrenci Listesi ({len(ogrenci_listesi)} kişi)", expanded=False):
            for idx, s in enumerate(ogrenci_listesi, 1):
                st.write(f"{idx}. {s.get('ad', '')} {s.get('soyad', '')} - No: {s.get('numara', '')}")
    else:
        st.warning(f"⚠️ {_grade_label(ds_sinif)} {ds_sube} şubesinde kayıtlı öğrenci bulunamadı. "
                   "Öğrenci listesini **Kurumsal İletişim > Sınıf Listeleri**'nden yükleyin.")

    st.markdown("---")

    # ============================================
    # 5. KAYDET & OPTİK FORM OLUŞTUR
    # ============================================
    st.markdown("#### 💾 5. Kaydet & Optik Form Oluştur")

    # Zorunlu alan kontrolü
    zorunlu_eksik = []
    if not ds_sinav_adi.strip():
        zorunlu_eksik.append("Sınav Adı")
    if dolu_count < ds_soru_sayisi:
        zorunlu_eksik.append(f"Cevap Anahtarı ({ds_soru_sayisi - dolu_count} eksik)")
    if not ogrenci_listesi:
        zorunlu_eksik.append("Öğrenci Listesi (sınıfta öğrenci yok)")

    if zorunlu_eksik:
        st.warning(f"⚠️ Eksik alanlar: {', '.join(zorunlu_eksik)}")

    if st.button("💾 Sınavı Kaydet & Optik Formları Oluştur", type="primary",
                 use_container_width=True, disabled=bool(zorunlu_eksik)):
        try:
            with st.spinner("Sınav oluşturuluyor ve optik formlar hazırlanıyor..."):
                # 1. Question nesneleri oluştur
                created_questions = []
                for idx in range(ds_soru_sayisi):
                    tur = soru_turleri[idx]
                    cevap = st.session_state[cevap_key].get(idx, "")

                    if tur == "dy":
                        q_type = "true_false"
                        q_choices = {"D": "Doğru", "Y": "Yanlış"}
                        q_choices_count = 2
                    elif tur == "mcq5":
                        q_type = "mcq"
                        q_choices = {"A": "-", "B": "-", "C": "-", "D": "-", "E": "-"}
                        q_choices_count = 5
                    else:
                        q_type = "mcq"
                        q_choices = {"A": "-", "B": "-", "C": "-", "D": "-"}
                        q_choices_count = 4

                    q = Question(
                        grade=ds_sinif,
                        subject=ds_ders,
                        question_type=q_type,
                        choices_count=q_choices_count,
                        correct_choice=cevap,
                        stem=f"Soru {idx + 1} (Dışarıdan yüklenmiş sınav)",
                        choices=q_choices,
                        status="approved",
                        source="external_upload"
                    )
                    store.save_question(q)
                    created_questions.append(q)

                # 2. Exam nesnesi oluştur
                exam = Exam(
                    name=ds_sinav_adi.strip(),
                    grade=ds_sinif,
                    subject=ds_ders,
                    section=ds_sube,
                    exam_type=ds_sinav_turu,
                    question_ids=[q.id for q in created_questions],
                    status="active",
                    duration_minutes=ds_sure
                )
                store.save_exam(exam)

                # 3. PDF kaydet (opsiyonel)
                if ds_pdf:
                    hazir_dir = os.path.join(store.base_path, "hazir_sinavlar")
                    os.makedirs(hazir_dir, exist_ok=True)
                    safe_name = "".join(c if c.isalnum() or c in "._- " else "_" for c in ds_sinav_adi).strip().replace(" ", "_")
                    pdf_path = os.path.join(hazir_dir, f"{safe_name}.pdf")
                    with open(pdf_path, 'wb') as f:
                        f.write(ds_pdf.getvalue())

                # 4. Kişisel optik formlar oluştur
                # Soru türlerinden question_types listesi oluştur
                question_types_list = []
                for tur in soru_turleri:
                    if tur == "dy":
                        question_types_list.append("true_false")
                    else:
                        question_types_list.append("mcq")

                # En yaygın şık sayısını belirle (D/Y hariç)
                mcq_turleri = [t for t in soru_turleri if t != "dy"]
                if mcq_turleri:
                    mcq5_count = mcq_turleri.count("mcq5")
                    ana_sik = 5 if mcq5_count > len(mcq_turleri) / 2 else 4
                else:
                    ana_sik = 4

                # Öğrenci listesini optik form formatına dönüştür
                students_for_form = []
                for s in ogrenci_listesi:
                    students_for_form.append({
                        'id': s.get('id', f"{s.get('numara', '')}_{ds_sube}"),
                        'tc_no': s.get('tc_no', ''),
                        'ad': s.get('ad', ''),
                        'soyad': s.get('soyad', ''),
                        'sinif': ds_sinif,
                        'sube': ds_sube,
                        'numara': s.get('numara', '')
                    })

                pdf_bytes = _generate_personalized_optik_forms_pdf(
                    exam=exam,
                    store=store,
                    students=students_for_form,
                    sik_sayisi=ana_sik,
                    question_types=question_types_list
                )

            st.success(f"✅ Sınav oluşturuldu: **{ds_sinav_adi}** | {ds_soru_sayisi} soru | {len(ogrenci_listesi)} öğrenci")
            st.balloons()

            # Sınav bilgi kartı
            col_i1, col_i2, col_i3, col_i4 = st.columns(4)
            col_i1.metric("Sınav ID", exam.id[:12])
            col_i2.metric("Soru Sayısı", ds_soru_sayisi)
            col_i3.metric("Öğrenci", len(ogrenci_listesi))
            col_i4.metric("Durum", "Aktif")

            # Optik form indirme
            if pdf_bytes and pdf_bytes != b"PDF olusturulamadi - reportlab yuklu degil":
                st.download_button(
                    label=f"📥 Kişisel Optik Formları İndir (PDF - {len(ogrenci_listesi)} sayfa)",
                    data=pdf_bytes,
                    file_name=f"optik_formlar_{exam.id[:8]}_{_grade_label(ds_sinif)}_{ds_sube}.pdf",
                    mime="application/pdf",
                    use_container_width=True,
                    key="ds_optik_pdf_indir"
                )
                st.info("💡 Her öğrencinin formu ayrı sayfada, kendi bilgileriyle ve QR koduyla basılmıştır. "
                        "QR kod ile **Uygula & Değerlendir > Cevap Toplama > AI ile Okutma** sekmesinden okutabilirsiniz.")
            else:
                st.warning("⚠️ Optik form PDF oluşturulamadı. ReportLab kütüphanesi kontrol edin.")

            if ds_ogretmen:
                st.caption(f"📌 Sınavı yapan öğretmen: {ds_ogretmen}")

        except Exception as e:
            st.error(f"❌ Hata: {str(e)}")
            import traceback
            st.code(traceback.format_exc())


def _parse_sonuc_belgesi_with_ai(file_bytes: bytes, file_type: str, mode: str = "toplu", soru_sayisi: int = 0) -> dict:
    """AI ile sonuç belgesini parse eder. mode: 'toplu' veya 'bireysel'.

    Returns:
        dict: {"ogrenciler": [...]} (toplu) veya {"ad_soyad": ..., "puan": ...} (bireysel)
              veya {"error": "..."} hata durumunda
    """
    import json
    import base64

    try:
        import openai
        api_key = os.environ.get("OPENAI_API_KEY")
        if not api_key:
            return {"error": "OPENAI_API_KEY bulunamadi. Ayarlar > API Key bolumunden ekleyin."}

        client = openai.OpenAI(api_key=api_key)
        extracted_text = ""
        image_b64 = None

        # 1. Dosya tipine gore icerik cikar
        if file_type == "pdf":
            try:
                import fitz
                doc = fitz.open(stream=file_bytes, filetype="pdf")
                for page in doc:
                    extracted_text += page.get_text() + "\n"
                doc.close()
            except Exception:
                pass

            # Text az veya bos ise → sayfayi image olarak render et
            if len(extracted_text.strip()) < 50:
                try:
                    import fitz
                    doc = fitz.open(stream=file_bytes, filetype="pdf")
                    page = doc.load_page(0)
                    pix = page.get_pixmap(matrix=fitz.Matrix(2, 2))
                    img_bytes = pix.tobytes("png")
                    image_b64 = base64.b64encode(img_bytes).decode('utf-8')
                    doc.close()
                except Exception:
                    return {"error": "PDF dosyasi okunamadi"}

        elif file_type in ("docx", "doc"):
            try:
                from docx import Document as DocxDocument
                from io import BytesIO
                doc = DocxDocument(BytesIO(file_bytes))
                for para in doc.paragraphs:
                    extracted_text += para.text + "\n"
                for table in doc.tables:
                    for row in table.rows:
                        row_text = " | ".join(cell.text.strip() for cell in row.cells)
                        extracted_text += row_text + "\n"
            except Exception:
                return {"error": "Word dosyasi okunamadi. python-docx yuklu mu?"}

        elif file_type in ("jpg", "jpeg", "png"):
            image_b64 = base64.b64encode(file_bytes).decode('utf-8')

        else:
            return {"error": f"Desteklenmeyen dosya tipi: {file_type}"}

        # 2. AI prompt olustur
        soru_bilgi = f"\nSoru sayisi: {soru_sayisi}" if soru_sayisi > 0 else ""

        if mode == "toplu":
            parse_prompt = f"""Bu belge bir sinav sonuc belgesidir. Belgedeki TUM ogrencilerin sonuclarini cikar.{soru_bilgi}

Her ogrenci icin su bilgileri bul:
- ad_soyad: Ogrenci adi soyadi
- numara: Ogrenci numarasi (varsa, yoksa "")
- puan: Sinav puani (sayi olarak)
- dogru: Dogru cevap sayisi (varsa, yoksa 0)
- yanlis: Yanlis cevap sayisi (varsa, yoksa 0)
- bos: Bos cevap sayisi (varsa, yoksa 0)
- net: Net puani (varsa, yoksa 0)

SADECE asagidaki JSON formatinda cevap ver, baska hicbir sey yazma:
{{"ogrenciler": [{{"ad_soyad": "Ali Yilmaz", "numara": "101", "puan": 85, "dogru": 17, "yanlis": 2, "bos": 1, "net": 16.5}}]}}"""
        else:
            parse_prompt = f"""Bu belge bir ogrencinin sinav sonuc belgesidir. Sonuc bilgilerini cikar.{soru_bilgi}

SADECE asagidaki JSON formatinda cevap ver:
{{"ad_soyad": "Ali Yilmaz", "numara": "101", "puan": 85, "dogru": 17, "yanlis": 2, "bos": 1, "net": 16.5, "soru_sayisi": 20}}"""

        # 3. AI'a gonder
        if image_b64:
            # Vision API kullan
            messages = [
                {"role": "system", "content": "Sen sinav sonuc belgesi okuma uzmanisin. Belgedeki tum ogrenci sonuclarini dogru okuyor ve JSON olarak donduruyorsun."},
                {"role": "user", "content": [
                    {"type": "text", "text": parse_prompt},
                    {"type": "image_url", "image_url": {"url": f"data:image/png;base64,{image_b64}", "detail": "high"}}
                ]}
            ]
        else:
            # Text tabanli
            messages = [
                {"role": "system", "content": "Sen sinav sonuc belgesi okuma uzmanisin. Belgedeki tum ogrenci sonuclarini dogru okuyor ve JSON olarak donduruyorsun."},
                {"role": "user", "content": f"{parse_prompt}\n\n--- BELGE ICERIGI ---\n{extracted_text[:6000]}"}
            ]

        response = client.chat.completions.create(
            model="gpt-4o-mini",
            messages=messages,
            max_tokens=4000,
            temperature=0.1
        )

        content = response.choices[0].message.content.strip()
        if "```json" in content:
            content = content.split("```json")[1].split("```")[0]
        elif "```" in content:
            content = content.split("```")[1].split("```")[0]

        result = json.loads(content.strip())
        return result

    except json.JSONDecodeError:
        return {"error": "AI yaniti JSON formatinda degil. Belge icerigini kontrol edin."}
    except Exception as e:
        return {"error": f"Islem hatasi: {str(e)[:200]}"}


def _match_students(ai_results: list, system_students: list) -> list:
    """AI sonuçlarını sistemdeki öğrencilerle eşleştirir.

    Returns:
        list: [{"ai_data": {...}, "matched_student": {...} veya None, "match_type": "exact"/"fuzzy"/"none"}, ...]
    """
    import unicodedata

    def normalize_name(name: str) -> str:
        """Turkce karakter normalize + lowercase."""
        if not name:
            return ""
        name = name.strip().lower()
        replacements = {'ı': 'i', 'ğ': 'g', 'ü': 'u', 'ş': 's', 'ö': 'o', 'ç': 'c',
                        'İ': 'i', 'Ğ': 'g', 'Ü': 'u', 'Ş': 's', 'Ö': 'o', 'Ç': 'c'}
        for old, new in replacements.items():
            name = name.replace(old, new)
        return name

    results = []
    for ai_item in ai_results:
        ai_name = ai_item.get("ad_soyad", "").strip()
        ai_numara = str(ai_item.get("numara", "")).strip()
        matched = None
        match_type = "none"

        # 1. Numara eşleşmesi (en güvenilir)
        if ai_numara:
            for stu in system_students:
                stu_numara = str(stu.get("numara", "")).strip()
                if stu_numara and stu_numara == ai_numara:
                    matched = stu
                    match_type = "exact"
                    break

        # 2. Tam isim eşleşmesi
        if not matched and ai_name:
            norm_ai = normalize_name(ai_name)
            for stu in system_students:
                stu_fullname = f"{stu.get('ad', '')} {stu.get('soyad', '')}".strip()
                if normalize_name(stu_fullname) == norm_ai:
                    matched = stu
                    match_type = "exact"
                    break

        # 3. Fuzzy eşleşme (soyad eşleşmesi + isim benzerliği)
        if not matched and ai_name:
            norm_ai = normalize_name(ai_name)
            best_match = None
            best_score = 0
            for stu in system_students:
                stu_fullname = f"{stu.get('ad', '')} {stu.get('soyad', '')}".strip()
                norm_stu = normalize_name(stu_fullname)
                # Soyad eşleşmesi
                ai_parts = norm_ai.split()
                stu_parts = norm_stu.split()
                if ai_parts and stu_parts:
                    # Son kelime (soyad) eşleşmesi
                    if ai_parts[-1] == stu_parts[-1]:
                        score = 80
                        # İlk isim de eşleşiyorsa
                        if ai_parts[0] == stu_parts[0]:
                            score = 95
                        if score > best_score:
                            best_score = score
                            best_match = stu
            if best_match and best_score >= 70:
                matched = best_match
                match_type = "fuzzy"

        results.append({
            "ai_data": ai_item,
            "matched_student": matched,
            "match_type": match_type
        })

    return results


def _render_sonuc_belgesi_yukle(store: DataStore):
    """Dışarıdan sınav sonuç belgesi yükleme ekranı."""
    from datetime import datetime

    st.markdown("#### 📤 Dışarıdan Sınav Sonuç Belgesi Yükle")
    st.info("""
    📤 **Sonuç Belgesi Yükleme**
    - Dışarıda yapılmış bir sınavın sonuç belgesini yükleyin
    - AI belgeyi okuyarak öğrenci sonuçlarını otomatik çıkarır
    - Sonuçlar öğrenci/veli panellerine otomatik yansır

    💡 **Desteklenen Formatlar:** PDF, Word (DOCX), JPEG, PNG
    """)

    st.markdown("---")

    # ============================================
    # 1. ZORUNLU ALANLAR
    # ============================================
    st.markdown("##### 📋 1. Sınav Bilgileri (Zorunlu)")

    col1, col2 = st.columns(2)

    with col1:
        sb_sinav_adi = st.text_input(
            "Sınav Adı *",
            placeholder="Örn: Matematik 1. Yazılı",
            key="sb_sinav_adi"
        )

        sb_sinav_turu = st.selectbox(
            "Sınav Türü *",
            EXAM_TYPES,
            key="sb_sinav_turu"
        )

        sb_ders = st.selectbox(
            "Ders *",
            ALL_CATEGORIES,
            key="sb_ders"
        )

    with col2:
        sb_sinif = st.selectbox(
            "Sınıf *",
            GRADES,
            index=7,
            format_func=_grade_label,
            key="sb_sinif"
        )

        from utils.shared_data import get_sinif_sube_listesi, get_sinif_ogrenci_listesi
        sinif_sube_data = get_sinif_sube_listesi()
        sube_listesi = sinif_sube_data.get("subeler", ["A", "B", "C", "D", "E"])
        if not sube_listesi:
            sube_listesi = ["A", "B", "C", "D", "E"]
        sb_sube = st.selectbox("Şube *", sube_listesi, key="sb_sube")

        sb_soru_sayisi = st.number_input(
            "Soru Sayısı (opsiyonel)",
            min_value=0,
            max_value=200,
            value=0,
            key="sb_soru_sayisi",
            help="0 = AI belgeden otomatik çıkarır"
        )

    # Zorunlu alan kontrolü
    zorunlu_tamam = bool(sb_sinav_adi.strip()) and bool(sb_ders) and bool(sb_sube)

    if not zorunlu_tamam:
        st.warning("⚠️ Sınav Adı, Ders, Sınıf ve Şube alanlarını doldurmadan belge yükleyemezsiniz.")
        return

    # Öğrenci listesini yükle
    ogrenci_listesi = get_sinif_ogrenci_listesi(sb_sinif, sb_sube)
    if ogrenci_listesi:
        st.success(f"✅ {_grade_label(sb_sinif)} {sb_sube} şubesinde **{len(ogrenci_listesi)}** öğrenci kayıtlı.")
    else:
        st.warning(f"⚠️ {_grade_label(sb_sinif)} {sb_sube} şubesinde kayıtlı öğrenci yok. Kurumsal İletişim > Sınıf Listeleri'nden yükleyin.")

    st.markdown("---")

    # ============================================
    # 2. YÜKLEME MODU
    # ============================================
    st.markdown("##### 📤 2. Yükleme Modu")

    sb_mod = st.radio(
        "Yükleme Modu",
        ["📚 Toplu Yükleme (Tüm sınıf sonuçları)", "👤 Bireysel Yükleme (Tek öğrenci)"],
        horizontal=True,
        key="sb_mod"
    )

    st.markdown("---")

    # ============================================
    # TOPLU YÜKLEME
    # ============================================
    if "Toplu" in sb_mod:
        st.markdown("##### 📁 3. Sonuç Belgesi Yükle (Toplu)")
        st.caption("Tüm sınıfın sonuçlarını içeren belgeyi yükleyin. AI otomatik olarak öğrenci bilgilerini çıkaracak.")

        sb_dosya = st.file_uploader(
            "Sonuç belgesi seç (PDF, Word, JPEG, PNG)",
            type=['pdf', 'docx', 'doc', 'jpg', 'jpeg', 'png'],
            key="sb_toplu_dosya"
        )

        if sb_dosya:
            from utils.security import validate_upload
            _ok, _msg = validate_upload(sb_dosya, allowed_types=["pdf", "docx", "doc", "jpg", "jpeg", "png"], max_mb=50)
            if not _ok:
                st.error(f"⚠️ {_msg}")
                sb_dosya = None

        if not sb_dosya:
            return

        st.success(f"✅ Dosya yüklendi: {sb_dosya.name} ({len(sb_dosya.getvalue()) // 1024} KB)")

        # AI ile parse et
        if st.button("🤖 AI ile Belgeyi Oku", type="primary", use_container_width=True, key="sb_toplu_parse"):
            file_bytes = sb_dosya.getvalue()
            file_ext = sb_dosya.name.rsplit('.', 1)[-1].lower()

            with st.spinner("AI sonuç belgesini okuyor... (10-30 saniye)"):
                ai_result = _parse_sonuc_belgesi_with_ai(file_bytes, file_ext, mode="toplu", soru_sayisi=sb_soru_sayisi)

            if "error" in ai_result:
                st.error(f"❌ AI Okuma Hatası: {ai_result['error']}")
                return

            ogrenciler_data = ai_result.get("ogrenciler", [])
            if not ogrenciler_data:
                st.warning("⚠️ Belgede öğrenci sonuç verisi bulunamadı.")
                return

            st.success(f"✅ AI {len(ogrenciler_data)} öğrenci sonucu okudu!")

            # Eşleştirme
            eslesmeler = _match_students(ogrenciler_data, ogrenci_listesi)

            # Session state'e kaydet
            st.session_state['sb_eslesmeler'] = eslesmeler
            st.session_state['sb_parse_done'] = True

        # Parse sonuçlarını göster
        if st.session_state.get('sb_parse_done'):
            eslesmeler = st.session_state.get('sb_eslesmeler', [])

            st.markdown("---")
            st.markdown("##### 📊 4. Eşleştirme ve Düzeltme")

            eslesen_count = sum(1 for e in eslesmeler if e['matched_student'])
            eslesmyen_count = len(eslesmeler) - eslesen_count

            col_s1, col_s2, col_s3 = st.columns(3)
            col_s1.metric("📋 Toplam", len(eslesmeler))
            col_s2.metric("✅ Eşleşen", eslesen_count)
            col_s3.metric("❌ Eşleşmeyen", eslesmyen_count)

            # Eşleştirme tablosu - düzenlenebilir
            ogrenci_sec_options = {"-- Eşleşme Yok --": None}
            for s in ogrenci_listesi:
                key = f"{s.get('ad', '')} {s.get('soyad', '')} - No: {s.get('numara', '')}"
                ogrenci_sec_options[key] = s

            for idx, eslesme in enumerate(eslesmeler):
                ai_data = eslesme['ai_data']
                matched = eslesme['matched_student']
                m_type = eslesme['match_type']

                # Renk
                if m_type == "exact":
                    renk = "🟢"
                elif m_type == "fuzzy":
                    renk = "🟡"
                else:
                    renk = "🔴"

                col_a, col_b, col_c, col_d, col_e = st.columns([3, 3, 1.5, 1.5, 1])

                with col_a:
                    st.write(f"{renk} **{ai_data.get('ad_soyad', '?')}** (No: {ai_data.get('numara', '-')})")

                with col_b:
                    # Eşleşen öğrenci seçimi (düzenlenebilir)
                    if matched:
                        default_key = f"{matched.get('ad', '')} {matched.get('soyad', '')} - No: {matched.get('numara', '')}"
                    else:
                        default_key = "-- Eşleşme Yok --"
                    default_idx = list(ogrenci_sec_options.keys()).index(default_key) if default_key in ogrenci_sec_options else 0

                    secim = st.selectbox(
                        f"Öğrenci #{idx+1}",
                        list(ogrenci_sec_options.keys()),
                        index=default_idx,
                        key=f"sb_eslestir_{idx}",
                        label_visibility="collapsed"
                    )
                    eslesmeler[idx]['matched_student'] = ogrenci_sec_options[secim]

                with col_c:
                    st.write(f"**{ai_data.get('puan', '-')}** puan")

                with col_d:
                    st.write(f"D:{ai_data.get('dogru', '-')} Y:{ai_data.get('yanlis', '-')}")

                with col_e:
                    st.write(f"B:{ai_data.get('bos', '-')}")

            # Kaydet butonu
            st.markdown("---")
            kayit_yapilabilir = [e for e in eslesmeler if e['matched_student'] is not None]

            if not kayit_yapilabilir:
                st.warning("⚠️ Kayıt yapılabilecek eşleşme bulunamadı.")
                return

            st.info(f"📊 **{len(kayit_yapilabilir)}/{len(eslesmeler)}** öğrenci eşleştirildi ve kaydedilecek.")

            if st.button(f"💾 {len(kayit_yapilabilir)} Sonucu Kaydet", type="primary", use_container_width=True, key="sb_toplu_kaydet"):
                try:
                    with st.spinner("Sonuçlar kaydediliyor..."):
                        # Exam nesnesi oluştur (tek sefer)
                        exam = Exam(
                            name=sb_sinav_adi.strip(),
                            grade=sb_sinif,
                            subject=sb_ders,
                            section=sb_sube,
                            exam_type=sb_sinav_turu,
                            question_ids=[],
                            status="completed",
                            duration_minutes=0
                        )
                        store.save_exam(exam)

                        kayit_sayisi = 0
                        for eslesme in eslesmeler:
                            matched = eslesme['matched_student']
                            if matched is None:
                                continue

                            ai_data = eslesme['ai_data']
                            student_id = f"{matched.get('numara', '')}_{sb_sube}"
                            student_name = f"{matched.get('ad', '')} {matched.get('soyad', '')}".strip()

                            puan = float(ai_data.get('puan', 0) or 0)
                            dogru = int(ai_data.get('dogru', 0) or 0)
                            yanlis = int(ai_data.get('yanlis', 0) or 0)
                            bos = int(ai_data.get('bos', 0) or 0)
                            net = float(ai_data.get('net', 0) or 0)
                            soru_s = int(ai_data.get('soru_sayisi', sb_soru_sayisi) or sb_soru_sayisi)

                            result = ExamResult(
                                exam_id=exam.id,
                                student_id=student_id,
                                student_name=student_name,
                                student_number=str(matched.get('numara', '')),
                                section=sb_sube,
                                total_questions=soru_s if soru_s > 0 else (dogru + yanlis + bos),
                                correct_count=dogru,
                                wrong_count=yanlis,
                                empty_count=bos,
                                score=round(puan, 2),
                                net_score=round(net, 2),
                                graded_by="external_upload",
                                notes=f"Disaridan yuklenmis sonuc belgesi: {sb_dosya.name}"
                            )
                            store.save_result(result)
                            kayit_sayisi += 1

                    st.success(f"✅ **{kayit_sayisi}** öğrencinin sonucu başarıyla kaydedildi!")
                    st.balloons()

                    col_i1, col_i2, col_i3 = st.columns(3)
                    col_i1.metric("Sınav", sb_sinav_adi[:20])
                    col_i2.metric("Kayıt Sayısı", kayit_sayisi)
                    col_i3.metric("Sınav ID", exam.id[:12])

                    st.info("💡 Sonuçlar öğrenci ve veli panellerindeki **Sınav Sonuçları** sekmesinde görünecektir.")

                    # Temizle
                    st.session_state.pop('sb_eslesmeler', None)
                    st.session_state.pop('sb_parse_done', None)

                except Exception as e:
                    st.error(f"❌ Kayıt hatası: {str(e)}")
                    import traceback
                    st.code(traceback.format_exc())

    # ============================================
    # BİREYSEL YÜKLEME
    # ============================================
    else:
        st.markdown("##### 👤 3. Öğrenci Seç & Belge Yükle (Bireysel)")

        if not ogrenci_listesi:
            st.warning("⚠️ Öğrenci listesi boş. Önce sınıf/şube bilgilerini kontrol edin.")
            return

        # Öğrenci seçimi
        ogrenci_options = {"-- Öğrenci Seçin --": None}
        for s in ogrenci_listesi:
            key = f"{s.get('ad', '')} {s.get('soyad', '')} - No: {s.get('numara', '')}"
            ogrenci_options[key] = s

        sb_ogrenci_sec = st.selectbox("Öğrenci *", list(ogrenci_options.keys()), key="sb_bireysel_ogrenci")
        selected_student = ogrenci_options[sb_ogrenci_sec]

        if not selected_student:
            st.info("👆 Sonuç yüklemek için bir öğrenci seçin.")
            return

        st.success(f"✅ Seçilen: **{selected_student.get('ad', '')} {selected_student.get('soyad', '')}** (No: {selected_student.get('numara', '')})")

        st.markdown("---")

        # Dosya yükleme veya manuel giriş
        sb_bireysel_mod = st.radio(
            "Giriş Yöntemi",
            ["📁 Belge Yükle (AI ile oku)", "✏️ Manuel Giriş"],
            horizontal=True,
            key="sb_bireysel_mod"
        )

        if "Belge Yükle" in sb_bireysel_mod:
            sb_dosya_bireysel = st.file_uploader(
                "Sonuç belgesi (PDF, Word, JPEG, PNG)",
                type=['pdf', 'docx', 'doc', 'jpg', 'jpeg', 'png'],
                key="sb_bireysel_dosya"
            )

            if sb_dosya_bireysel:
                from utils.security import validate_upload
                _ok, _msg = validate_upload(sb_dosya_bireysel, allowed_types=["pdf", "docx", "doc", "jpg", "jpeg", "png"], max_mb=50)
                if not _ok:
                    st.error(f"⚠️ {_msg}")
                    sb_dosya_bireysel = None
            if sb_dosya_bireysel:
                st.success(f"✅ Dosya: {sb_dosya_bireysel.name}")

                if st.button("🤖 AI ile Oku", type="primary", key="sb_bireysel_parse"):
                    file_bytes = sb_dosya_bireysel.getvalue()
                    file_ext = sb_dosya_bireysel.name.rsplit('.', 1)[-1].lower()

                    with st.spinner("AI sonuç belgesini okuyor..."):
                        ai_result = _parse_sonuc_belgesi_with_ai(file_bytes, file_ext, mode="bireysel", soru_sayisi=sb_soru_sayisi)

                    if "error" in ai_result:
                        st.error(f"❌ {ai_result['error']}")
                    else:
                        st.session_state['sb_bireysel_data'] = ai_result
                        st.session_state['sb_bireysel_parsed'] = True

            # Parse sonuçları varsa göster
            if st.session_state.get('sb_bireysel_parsed'):
                ai_data = st.session_state.get('sb_bireysel_data', {})
                st.markdown("---")
                st.markdown("##### 📊 Okunan Sonuç (düzenleyebilirsiniz)")

                col_p1, col_p2, col_p3 = st.columns(3)
                with col_p1:
                    sb_puan = st.number_input("Puan", value=float(ai_data.get('puan', 0) or 0), min_value=0.0, max_value=500.0, key="sb_b_puan")
                    sb_dogru = st.number_input("Doğru", value=int(ai_data.get('dogru', 0) or 0), min_value=0, key="sb_b_dogru")
                with col_p2:
                    sb_yanlis = st.number_input("Yanlış", value=int(ai_data.get('yanlis', 0) or 0), min_value=0, key="sb_b_yanlis")
                    sb_bos = st.number_input("Boş", value=int(ai_data.get('bos', 0) or 0), min_value=0, key="sb_b_bos")
                with col_p3:
                    sb_net = st.number_input("Net", value=float(ai_data.get('net', 0) or 0), key="sb_b_net")
                    sb_soru_s = st.number_input("Soru Sayısı", value=int(ai_data.get('soru_sayisi', sb_soru_sayisi) or sb_soru_sayisi), min_value=0, key="sb_b_soru")

                if st.button("💾 Sonucu Kaydet", type="primary", use_container_width=True, key="sb_bireysel_kaydet"):
                    _save_bireysel_sonuc(store, sb_sinav_adi, sb_sinif, sb_ders, sb_sube, sb_sinav_turu,
                                         selected_student, sb_puan, sb_dogru, sb_yanlis, sb_bos, sb_net, sb_soru_s,
                                         "AI ile okunan belge")

        else:
            # Manuel giriş
            st.markdown("##### ✏️ Manuel Sonuç Girişi")

            col_m1, col_m2, col_m3 = st.columns(3)
            with col_m1:
                sb_m_puan = st.number_input("Puan *", value=0.0, min_value=0.0, max_value=500.0, key="sb_m_puan")
                sb_m_dogru = st.number_input("Doğru", value=0, min_value=0, key="sb_m_dogru")
            with col_m2:
                sb_m_yanlis = st.number_input("Yanlış", value=0, min_value=0, key="sb_m_yanlis")
                sb_m_bos = st.number_input("Boş", value=0, min_value=0, key="sb_m_bos")
            with col_m3:
                sb_m_net = st.number_input("Net", value=0.0, key="sb_m_net")
                sb_m_soru = st.number_input("Soru Sayısı", value=sb_soru_sayisi, min_value=0, key="sb_m_soru")

            if st.button("💾 Sonucu Kaydet", type="primary", use_container_width=True, key="sb_manuel_kaydet"):
                _save_bireysel_sonuc(store, sb_sinav_adi, sb_sinif, sb_ders, sb_sube, sb_sinav_turu,
                                     selected_student, sb_m_puan, sb_m_dogru, sb_m_yanlis, sb_m_bos, sb_m_net, sb_m_soru,
                                     "Manuel giris")


def _save_bireysel_sonuc(store, sinav_adi, sinif, ders, sube, sinav_turu,
                          student, puan, dogru, yanlis, bos, net, soru_sayisi, kaynak):
    """Bireysel sonuç kaydetme helper."""
    from datetime import datetime
    try:
        # Mevcut exam var mı kontrol et (aynı ada sahip)
        existing_exams = store.get_exams()
        exam = None
        for e in existing_exams:
            if e.name == sinav_adi.strip() and e.grade == sinif and e.subject == ders:
                exam = e
                break

        if not exam:
            exam = Exam(
                name=sinav_adi.strip(),
                grade=sinif,
                subject=ders,
                section=sube,
                exam_type=sinav_turu,
                question_ids=[],
                status="completed",
                duration_minutes=0
            )
            store.save_exam(exam)

        student_id = f"{student.get('numara', '')}_{sube}"
        student_name = f"{student.get('ad', '')} {student.get('soyad', '')}".strip()

        result = ExamResult(
            exam_id=exam.id,
            student_id=student_id,
            student_name=student_name,
            student_number=str(student.get('numara', '')),
            section=sube,
            total_questions=soru_sayisi if soru_sayisi > 0 else (dogru + yanlis + bos),
            correct_count=dogru,
            wrong_count=yanlis,
            empty_count=bos,
            score=round(puan, 2),
            net_score=round(net, 2),
            graded_by="external_upload",
            notes=f"Disaridan yuklenmis: {kaynak}"
        )
        store.save_result(result)

        st.success(f"✅ **{student_name}** - Puan: {puan} | Sonuç kaydedildi!")
        st.balloons()
        st.info("💡 Sonuç öğrenci ve veli panellerindeki **Sınav Sonuçları** sekmesinde görünecektir.")

        # Temizle
        st.session_state.pop('sb_bireysel_data', None)
        st.session_state.pop('sb_bireysel_parsed', None)

    except Exception as e:
        st.error(f"❌ Kayıt hatası: {str(e)}")
        import traceback
        st.code(traceback.format_exc())


def _render_hazir_sinav_sec(store: DataStore):
    """Hazır sınavı seç ve kullan."""
    import os
    import json
    from datetime import datetime

    st.markdown("### 📁 Hazır Sınav Kullan")

    st.info("""
    📋 **Hazır Sınav Nedir?**
    - Önceden yüklenmiş tam sınav PDF'leri
    - TYT, AYT, LGS denemeleri gibi hazır sınavlar
    - Seçtiğiniz sınav aynen PDF olarak sunulur

    💡 Hazır sınav eklemek için: **PDF İçe Aktar** > **Hazır Sınav Olarak Yükle**
    """)

    # Hazır sınav dizini
    hazir_sinav_dir = os.path.join(store.base_path, "hazir_sinavlar")

    if not os.path.exists(hazir_sinav_dir):
        os.makedirs(hazir_sinav_dir, exist_ok=True)

    # Hazır sınav dosyalarını listele
    hazir_files = [f for f in os.listdir(hazir_sinav_dir) if f.endswith('.json')]

    if not hazir_files:
        st.warning("📁 Henüz hazır sınav yüklenmemiş!")
        st.markdown("""
        **Hazır sınav yüklemek için:**
        1. **PDF İçe Aktar** sekmesine gidin
        2. **Hazır Sınav Olarak Yükle** modunu seçin
        3. PDF'i yükleyin ve bilgileri girin
        """)
        return

    st.markdown("---")

    # Hazır sınavları yükle
    hazir_sinavlar = []
    for hf in hazir_files:
        filepath = os.path.join(hazir_sinav_dir, hf)
        try:
            with open(filepath, 'r', encoding='utf-8') as f:
                sinav_data = json.load(f)
                sinav_data['_filepath'] = filepath
                hazir_sinavlar.append(sinav_data)
        except Exception:
            pass

    if not hazir_sinavlar:
        st.warning("Hazır sınav dosyaları okunamadı.")
        return

    # Sınav seçimi
    st.markdown("#### 📋 Sınav Seç")

    # Kategorilere göre grupla
    kategoriler = {}
    for sinav in hazir_sinavlar:
        kat = sinav.get('exam_type', 'Diğer')
        if kat not in kategoriler:
            kategoriler[kat] = []
        kategoriler[kat].append(sinav)

    # Kategori filtresi
    secili_kategori = st.selectbox(
        "Kategori Filtrele",
        ["Tümü"] + list(kategoriler.keys()),
        key="hazir_sinav_kategori"
    )

    # Filtrelenmiş sınavlar
    if secili_kategori == "Tümü":
        gosterilecek = hazir_sinavlar
    else:
        gosterilecek = kategoriler.get(secili_kategori, [])

    if not gosterilecek:
        st.info("Bu kategoride sınav bulunamadı.")
        return

    # Sınav seçimi
    sinav_options = {f"{s.get('name', 'İsimsiz')} ({s.get('question_count', '?')} soru)": s for s in gosterilecek}

    secili_sinav_key = st.selectbox(
        "Sınav Seç",
        list(sinav_options.keys()),
        key="hazir_sinav_sec"
    )

    secili_sinav = sinav_options[secili_sinav_key]

    # Sınav detayları
    st.markdown("---")
    st.markdown("#### 📊 Sınav Detayları")

    col1, col2, col3, col4 = st.columns(4)
    col1.metric("📋 Sınav Adı", secili_sinav.get('name', '-'))
    col2.metric("📝 Soru Sayısı", secili_sinav.get('question_count', '-'))
    col3.metric("🎯 Tür", secili_sinav.get('exam_type', '-'))
    col4.metric("🎓 Sınıf", f"{_grade_label(secili_sinav.get('grade', '-'))}")

    # Ek bilgiler
    if secili_sinav.get('duration_minutes'):
        st.caption(f"⏱️ Süre: {secili_sinav.get('duration_minutes')} dakika")
    if secili_sinav.get('description'):
        st.caption(f"📝 Açıklama: {secili_sinav.get('description')}")

    st.markdown("---")

    # PDF İndir / Sınavı Kullan
    st.markdown("#### 🚀 Sınavı Kullan")

    col_btn1, col_btn2 = st.columns(2)

    with col_btn1:
        # PDF İndir
        pdf_filename = secili_sinav.get('pdf_filename', '')
        pdf_path = os.path.join(hazir_sinav_dir, pdf_filename)

        if os.path.exists(pdf_path):
            with open(pdf_path, 'rb') as f:
                pdf_data = f.read()

            st.download_button(
                "📥 PDF İndir",
                pdf_data,
                file_name=f"{secili_sinav.get('name', 'sinav')}.pdf",
                mime="application/pdf",
                use_container_width=True
            )
        else:
            st.error("PDF dosyası bulunamadı!")

    with col_btn2:
        # Aktif sınav olarak ekle
        if st.button("🎓 Online Sınav Olarak Etkinleştir", type="primary", use_container_width=True):

            # Exam objesi oluştur
            exam = Exam(
                name=secili_sinav.get('name', 'Hazır Sınav'),
                grade=secili_sinav.get('grade', 8),
                subject=secili_sinav.get('subject') or secili_sinav.get('exam_type', 'Genel'),
                exam_type=secili_sinav.get('exam_type', ''),
                question_ids=[],  # Hazır sınavlarda soru ID yok
                status="active",
                duration_minutes=secili_sinav.get('duration_minutes', 60),
                start_date=datetime.now().isoformat(),
            )
            # Hazır sınav bilgisini ekle
            exam_dict = exam.to_dict()
            exam_dict['is_hazir_sinav'] = True
            exam_dict['hazir_sinav_path'] = pdf_path
            exam_dict['question_count'] = secili_sinav.get('question_count', 0)

            # Manuel kaydet
            exams_data = []
            exams_file = os.path.join(store.base_path, "exams.json")
            if os.path.exists(exams_file):
                with open(exams_file, 'r', encoding='utf-8') as f:
                    exams_data = json.load(f)

            exams_data.append(exam_dict)

            with open(exams_file, 'w', encoding='utf-8') as f:
                json.dump(exams_data, f, ensure_ascii=False, indent=2)

            st.success(f"✅ '{secili_sinav.get('name')}' aktif sınav olarak eklendi!")
            st.info("📋 Online Sınav sekmesinden öğrenciler bu sınava erişebilir.")


