def _render_blueprint_sablonlar():
    """Blueprint şablonları yönetimi - bağımsız fonksiyon."""
    store = get_store()
    blueprints = store.get_blueprints()

    if st.button("➕ Yeni Şablon"):

        st.session_state.show_new_blueprint = True

    if st.session_state.get('show_new_blueprint'):
        with st.form("new_blueprint_form"):
            col1, col2 = st.columns(2)
            with col1:
                bp_name = st.text_input("Şablon Adı")

                bp_grade = st.selectbox("Sınıf", GRADES, format_func=_grade_label)

                bp_subject = st.selectbox("Ders / Sınav Türü", ALL_CATEGORIES)

            with col2:
                bp_term = st.selectbox("Dönem", ["1. Dönem", "2. Dönem", "Yaz"])

                bp_type = st.selectbox("Sınav Turu", EXAM_TYPES)


            total_questions = st.number_input("Toplam Soru Sayısı", min_value=5, max_value=50, value=20)

            easy_pct = st.slider("Kolay %", 0, 100, 30)

            medium_pct = st.slider("Orta %", 0, 100, 50)

            hard_pct = 100 - easy_pct - medium_pct
            st.write(f"Zor: %{hard_pct}")

            if st.form_submit_button("Kaydet", type="primary"):
                blueprint = Blueprint(
                    name=bp_name, grade=bp_grade, subject=bp_subject,
                    term=bp_term, exam_type=bp_type,
                    total_questions=total_questions,
                    rules=[
                        {"difficulty": "Kolay", "count": int(total_questions * easy_pct / 100)},
                        {"difficulty": "Orta", "count": int(total_questions * medium_pct / 100)},
                        {"difficulty": "Zor", "count": int(total_questions * hard_pct / 100)},
                    ]
                )
                store.save_blueprint(blueprint)
                st.success("Şablon kaydedildi!")
                st.session_state.show_new_blueprint = False
                st.rerun()

    if blueprints:
        for bp in blueprints:
            with st.expander(f"{bp.name} - {_grade_label(bp.grade)} {bp.subject}"):
                st.write(f"**Dönem:** {bp.term} | **Tür:** {bp.exam_type} | **Soru:** {bp.total_questions}")
                for rule in bp.rules:
                    st.write(f"- {rule.get('difficulty', 'Genel')}: {rule.get('count', 0)} soru")
                if st.button("✓ Doğrula", key=f"validate_{bp.id}"):
                    validation = store.validate_blueprint(bp.id)
                    if validation.get('valid'):
                        st.success("✅ Yeterli soru mevcut!")
                    else:
                        st.error("❌ Eksik soru var:")
                        for m in validation.get('missing', []):
                            st.write(f"- Kazanım {m['outcome_id']}: {m['missing']} soru eksik")
    else:
        st.info("Henüz şablon bulunmuyor.")


def _render_gelismis_sinav():
    """Gelişmiş sınav oluştur - Blueprint'ten sınav üretimi."""
    store = get_store()
    blueprints = store.get_blueprints()

    if not blueprints:
        st.warning("Önce bir şablon oluşturun.")
        return

    bp_options = {f"{bp.name} ({_grade_label(bp.grade)} {bp.subject})": bp for bp in blueprints}
    selected_bp = st.selectbox("Şablon Seç", list(bp_options.keys()))

    blueprint = bp_options[selected_bp]

    col1, col2 = st.columns(2)
    with col1:
        section = st.selectbox("Şube", ["A", "B", "C", "D", "E"])

        seed = st.number_input("Random Seed (opsiyonel)", min_value=0, value=0)
    with col2:
        booklet_count = st.selectbox("Kitapçık Sayısı", [1, 2, 3, 4])

    if st.button("🚀 Sınav Oluştur", type="primary", use_container_width=True, key="gelismis_sinav_olustur"):
        with st.spinner("Sınav oluşturuluyor..."):
            generator = ExamGenerator(store)
            exams = generator.generate(
                blueprint_id=blueprint.id,
                seed=seed if seed > 0 else None,
                booklet_count=booklet_count
            )
            if exams:
                st.success(f"✅ {len(exams)} kitapçık oluşturuldu!")
                for exam in exams:
                    st.markdown(f"**{exam.name}** (ID: {exam.id})")
                    st.write(f"Soru sayısı: {len(exam.question_ids)}")
                    pdf_data = _generate_exam_pdf(exam, store)
                    st.download_button(f"📕 PDF İndir - {exam.booklet_type}", pdf_data,
                        file_name=f"{exam.id}.pdf", mime="application/pdf")
            else:
                st.error("Sınav oluşturulamadı. Yeterli onaylı soru olmayabilir.")



