def _render_hizli_sinav(store: DataStore):
    """Sınav Oluşturma — Sade 3 adımlı akış."""
    import random

    all_outcomes = _cached_get_all_outcomes(status="active")
    if not all_outcomes:
        styled_info_banner("Önce kazanım yükleyin! (Soru Havuzu sekmesinden)", "warning")
        return

    all_questions = _cached_get_questions_light(status="approved")
    grades_available = sorted(set(o.grade for o in all_outcomes), key=_grade_sort_key)

    # ═══════════════════════════════════════════════════════════════
    # TEK SATIR: SINIF + DERS + TÜR + OLUŞTUR
    # ═══════════════════════════════════════════════════════════════
    st.markdown("""
    <div style="background:linear-gradient(135deg,#0f172a,#1e293b);border-radius:14px;
    padding:14px 18px;margin-bottom:12px;border:1px solid rgba(99,102,241,0.2);">
    <div style="font-size:.9rem;font-weight:700;color:#c7d2fe;">⚡ Hızlı Sınav Oluştur</div>
    <div style="font-size:.75rem;color:#64748b;margin-top:2px;">
    Sınıf ve ders seçin — sistem onaylı sorulardan otomatik sınav oluşturur</div>
    </div>""", unsafe_allow_html=True)

    col_a1, col_a2, col_a3 = st.columns(3)
    with col_a1:
        selected_grade = st.selectbox("Sınıf", grades_available,
                                      format_func=_grade_label, key="hs_grade_normal")
    with col_a2:
        sinav_kategorisi = st.selectbox(
            "Sınav Türü",
            ["🏫 Okul Yazılısı", "🎯 Kazanım Ölçme", "📝 Deneme", "📊 LGS-TYT-AYT", "⚡ Quiz"],
            key="hs_sinav_kategorisi",
        )
    with col_a3:
        selected_term = st.selectbox("Dönem", ["1. Dönem", "2. Dönem", "Tüm Yıl"], key="hs_term_normal")

    # Sınav türü belirleme — sadece gerektiğinde ekstra seçenek göster
    sinav_turu = "Kazanim Değerlendirme"
    if "Okul Yazılısı" in sinav_kategorisi:
        sinav_turu = st.selectbox("Yazılı Türü",
            ["1. Donem 1. Yazili", "1. Donem 2. Yazili", "2. Donem 1. Yazili", "2. Donem 2. Yazili"],
            key="hs_okul_sinav_alt")
    elif "Kazanım" in sinav_kategorisi:
        sinav_turu = "Kazanim Değerlendirme"
    elif "Deneme" in sinav_kategorisi:
        sinav_turu = "Deneme"
    elif "LGS-TYT-AYT" in sinav_kategorisi:
        sinav_turu = st.radio("Sınav", ["LGS", "TYT", "AYT Sayısal", "AYT Esit Agirlik", "AYT Sozel"],
            key="hs_lgs_tyt_ayt_alt", horizontal=True)
        if sinav_turu == "LGS":
            selected_grade = 8
        elif sinav_turu in ["AYT Esit Agirlik", "AYT Sayısal", "AYT Sozel"]:
            selected_grade = 12
        selected_term = "Tüm Yıl"
        if sinav_turu in SINAV_BOLUM_YAPISI:
            _bolum_yapi = SINAV_BOLUM_YAPISI[sinav_turu]
            st.caption(f"{sinav_turu} · {_bolum_yapi['toplam_soru']} soru · {_bolum_yapi['toplam_sure']} dk · Net: {_bolum_yapi['net_formul']}")
    elif "Quiz" in sinav_kategorisi:
        sinav_turu = "Quiz"

    # Ders + Soru sayısı — tek satır
    grade_subjects = sorted(set(o.subject for o in all_outcomes if o.grade == selected_grade))
    if not grade_subjects:
        st.warning(f"{_grade_label(selected_grade)} için ders bulunamadı!")
        return

    SABIT_SINAV_DAGILIMI = {
        "LGS": {"toplam": 90, "dersler": {"Matematik": 20, "Türkçe": 20, "Fen Bilimleri": 20, "Sosyal Bilgiler": 10, "Din Kültürü ve Ahlak Bilgisi": 10, "Din Kültürü": 10, "İngilizce": 10}},
        "TYT": {"toplam": 120, "dersler": {"Türkçe": 40, "Sosyal Bilgiler": 20, "Matematik": 40, "Fen Bilimleri": 20}},
        "AYT Esit Agirlik": {"toplam": 80, "dersler": {"Edebiyat": 24, "Tarih": 10, "Coğrafya": 6, "Matematik": 40}},
        "AYT Sayısal": {"toplam": 80, "dersler": {"Matematik": 40, "Fizik": 14, "Kimya": 13, "Biyoloji": 13}},
        "AYT Sozel": {"toplam": 80, "dersler": {"Edebiyat": 24, "Tarih": 10, "Coğrafya": 6, "Tarih-2": 11, "Coğrafya-2": 11, "Felsefe": 12, "Din Kültürü": 6}},
    }

    is_sabit = sinav_turu in SABIT_SINAV_DAGILIMI

    if is_sabit:
        # LGS/TYT/AYT — dersler otomatik, multiselect ile göster
        sabit = SABIT_SINAV_DAGILIMI[sinav_turu]
        default_ders = [s for s in grade_subjects if s in sabit["dersler"]]
        selected_subjects = st.multiselect("Dersler", grade_subjects, default=default_ders,
                                            placeholder="Ders seçiniz...", key="hs_subjects_new")
        ders_soru_sayilari = {s: sabit["dersler"].get(s, 0) for s in selected_subjects if sabit["dersler"].get(s, 0) > 0}
        total_questions = sum(ders_soru_sayilari.values())
    else:
        dc1, dc2 = st.columns([3, 1])
        with dc1:
            selected_subjects = st.multiselect("Dersler", grade_subjects, default=grade_subjects[:1],
                                                placeholder="Ders seçiniz...", key="hs_subjects_new")
        with dc2:
            total_questions = st.selectbox("Soru", [5, 10, 15, 20, 25, 30, 40], index=3, key="hs_total_q")
        ders_soru_sayilari = {}
        if selected_subjects:
            soru_per_ders = total_questions // len(selected_subjects)
            kalan = total_questions % len(selected_subjects)
            for i, subject in enumerate(selected_subjects):
                ders_soru_sayilari[subject] = soru_per_ders + (1 if i < kalan else 0)

    if not selected_subjects:
        st.warning("En az bir ders seçin.")
        return

    if ders_soru_sayilari:
        st.caption(" · ".join([f"**{k}**: {v}" for k, v in ders_soru_sayilari.items()]) + f" = **{total_questions} soru**")

    # ═══════════════════════════════════════════════════════════════
    # SINAV ADI (otomatik) + OLUŞTUR BUTONU — tek satır
    # ═══════════════════════════════════════════════════════════════
    kurum_ayarlari = _load_kurum_ayarlari()
    varsayilan_sinav_adi = f"{_grade_label(selected_grade)} {selected_subjects[0] if selected_subjects else ''} {sinav_turu}"

    col_k1, col_k2 = st.columns([3, 1])
    with col_k1:
        sinav_adi = st.text_input("Sınav Adı", value=varsayilan_sinav_adi, key="kapak_sinav_adi",
                                   label_visibility="collapsed", placeholder="Sınav adı...")
    with col_k2:
        sinav_tarihi = st.date_input("Tarih", value=datetime.now(), key="kapak_tarih",
                                      label_visibility="collapsed")

    secilen_kaynak = "AI Akıllı Seçim"  # Varsayılan — bankadan seç

    # Gelişmiş ayarlar (expander)
    soru_turu = "Çoktan Secmeli ABCD"
    kitapcik_turu = "Yok"
    kolay_pct, orta_pct, zor_pct = 30, 40, 30
    shuffle_questions = False
    shuffle_choices = False
    negatif_puanlama = False
    negatif_oran = 0.0
    tab_switch_detection = False
    max_tab_switches = 3
    auto_submit_exceed = False
    show_feedback = False
    show_correct = False
    ai_aktif = secilen_kaynak in ["AI Otomatik Üret", "AI Karışık"]
    gorsel_ekle = False
    bloom_dagilim = None
    sinav_secili_aylar = None
    sinav_suresi = 40

    with st.expander("⚙️ Gelişmiş Ayarlar", expanded=False):
        gc1, gc2, gc3, gc4 = st.columns(4)
        with gc1:
            soru_turu = st.selectbox("Soru Türü", ["Çoktan Secmeli ABCD", "Çoktan Secmeli ABCDE", "Dogru Yanlis"], key="hs_soru_turu")
        with gc2:
            zorluk_preset = st.selectbox("Zorluk", ["Dengeli", "Kolay Ağırlıklı", "Zor Ağırlıklı"], key="hs_zorluk_p")
            if zorluk_preset == "Kolay Ağırlıklı": kolay_pct, orta_pct, zor_pct = 50, 35, 15
            elif zorluk_preset == "Zor Ağırlıklı": kolay_pct, orta_pct, zor_pct = 15, 35, 50
        with gc3:
            sinav_suresi = st.selectbox("Süre (dk)", [20, 30, 40, 45, 60, 90, 120], index=2, key="hs_sure")
        with gc4:
            kitapcik_turu = st.selectbox("Kitapçık", ["Yok", "A", "B"], key="hs_kitapcik")
        col_e1, col_e2 = st.columns(2)
        with col_e1:
            shuffle_questions = st.checkbox("Soru sırasını karıştır", key="hs_shuffle_q")
            negatif_puanlama = st.checkbox("Negatif puanlama", key="hs_negative_scoring")
            if negatif_puanlama:
                negatif_oran = st.selectbox("Yanlış katsayısı", [0.25, 0.33, 0.5], key="hs_neg_ratio")
        with col_e2:
            ai_aktif = st.checkbox("AI ile soru üret", value=ai_aktif, key="hs_ai_new")
            sinav_ay_modu = st.radio("Ay Kapsamı", ["Tüm Yıl", "Belirli Ay(lar)"], key="hs_ay_modu", horizontal=True)
            if sinav_ay_modu == "Belirli Ay(lar)":
                sinav_secili_aylar = st.multiselect("Ay Seçin", AY_SECENEKLERI, key="hs_sinav_aylar")

    # Kazanım seçimi (Kazanım Ölçme için)
    secilen_kazanimlar_data = None
    _next_step = 2

    # ═══════════════════════════════════════════════════════════════
    # OLUŞTUR
    # ═══════════════════════════════════════════════════════════════
    st.markdown("---")
    kurum_adi = kurum_ayarlari.get("kurum_adi", "")
    uygulayici_adi = ""
    sinav_kurallari = f"1. Sınav süresi {sinav_suresi} dakikadır.\n2. Her sorunun tek doğru cevabı vardır.\n3. Sınav süresince konuşmak yasaktır."
    bloom_preset = "Dengeli"
    gorsel_ekle = False

    if st.button("🚀 Sınavı Oluştur", type="primary", use_container_width=True, key="hizli_sinav_olustur_sade"):
        if total_questions < 3:
            st.error("En az 3 soru gerekli!")
        else:
            with st.spinner("Sınav oluşturuluyor..."):
                kapak_bilgileri = {
                    "kurum_adi": kurum_adi,
                    "kurum_logo": kurum_ayarlari.get("logo_base64", ""),
                    "sinav_adi": sinav_adi.strip(),
                    "uygulayici_adi": uygulayici_adi,
                    "sinav_tarihi": sinav_tarihi.strftime("%d.%m.%Y"),
                    "sinav_suresi": sinav_suresi,
                    "sinav_kurallari": sinav_kurallari,
                }

                sinav = _generate_hizli_sinav(
                    store=store,
                    grade=selected_grade,
                    subjects=selected_subjects,
                    ders_soru_sayilari=ders_soru_sayilari,
                    term=selected_term,
                    sinav_turu=sinav_turu,
                    soru_turu=soru_turu,
                    kitapcik_turu=kitapcik_turu,
                    zorluk_dagilimi={"Kolay": kolay_pct, "Orta": orta_pct, "Zor": zor_pct},
                    ai_aktif=ai_aktif,
                    gorsel_ekle=gorsel_ekle,
                    soru_kaynagi=secilen_kaynak,
                    kapak_bilgileri=kapak_bilgileri,
                    ay_filtresi=sinav_secili_aylar,
                    bloom_dagilimi=bloom_dagilim,
                    shuffle_questions=shuffle_questions,
                    shuffle_choices=False,
                    negative_scoring=negatif_puanlama,
                    negative_ratio=negatif_oran,
                )

                if sinav:
                    sinav['created_at'] = datetime.now().isoformat()
                    sinav['access_code'] = _generate_access_code()

                    from models.olcme_degerlendirme import balance_answer_keys, validate_answer_pattern
                    sinav['sorular'] = balance_answer_keys(sinav.get('sorular', []), max_consecutive=2)

                    cevap_harfleri = [["A","B","C","D","E"][s.get('dogru',0)] for s in sinav.get('sorular',[]) if isinstance(s.get('dogru'),int) and s.get('dogru',0)<5]
                    sinav['desen_analizi'] = validate_answer_pattern(cevap_harfleri, 4)

                    _save_exam_to_archive(sinav)
                    st.session_state.hizli_sinav_sonuc = sinav
                    st.rerun()

    if st.session_state.get('hizli_sinav_sonuc'):
        _render_hizli_sinav_ozet(st.session_state.hizli_sinav_sonuc)
        # Detailed result view
        _render_hizli_sinav_sonuc(st.session_state.hizli_sinav_sonuc, store)


def _generate_hizli_sinav(store: DataStore, grade: int, subjects: list, ders_soru_sayilari: dict,
                          term: str, sinav_turu: str, zorluk_dagilimi: dict,
                          kitapcik_turu: str = "A", soru_turu: str = "Çoktan Secmeli ABCD",
                          ai_aktif: bool = True, gorsel_ekle: bool = False,
                          soru_kaynagi: str = "Tümü", kapak_bilgileri: dict = None,
                          ay_filtresi: list = None,
                          bloom_dagilimi: dict = None,
                          shuffle_questions: bool = False,
                          shuffle_choices: bool = False,
                          negative_scoring: bool = False,
                          negative_ratio: float = 0.0,
                          tab_switch_detection: bool = False,
                          max_tab_switches: int = 3,
                          auto_submit_on_exceed: bool = False,
                          show_feedback: bool = False,
                          show_correct_answers: bool = False) -> dict:
    """Kazanimlara dayali sinav olustur - AI ve gorsel destekli.

    soru_kaynagi parametresi:
    - "Tümü": Tüm kaynaklardan
    - "Sadece Soru Bankası": Sadece metin soruları
    - "Sadece Görsel Sorular (PDF'den Kesilen)": Sadece görsel sorular
    - "Sadece TYT/AYT/LGS/Deneme": İlgili sınav türünden

    kapak_bilgileri parametresi:
    - kurum_adi, kurum_logo, sinav_adi, uygulayici_adi, sinav_tarihi, sinav_suresi, sinav_kurallari

    kitapcik_turu parametresi:
    - A, B, C, D: Kitapçık türü (soru sıralaması değişir)
    """
    import random
    from datetime import datetime
    import streamlit as st
    from models.olcme_degerlendirme import balance_answer_keys

    sorular = []
    soru_no = 1
    toplam_soru = sum(ders_soru_sayilari.values())

    # Soru kaynagina gore filtreleme - HER ZAMAN sınıf filtresi uygula + ay filtresi
    tum_sorular = store.get_questions(status="approved", grade=grade, month=ay_filtresi)

    # Görsel + Kategori filtresi (örn: "Görsel+Kategori:LGS")
    gorsel_kategori = None
    if soru_kaynagi.startswith("Görsel+Kategori:"):
        gorsel_kategori = soru_kaynagi.replace("Görsel+Kategori:", "")
        tum_sorular = [q for q in tum_sorular if q.image_data and q.subject == gorsel_kategori]
    elif soru_kaynagi == "Sadece Soru Bankası":
        tum_sorular = [q for q in tum_sorular if not q.image_data]
    elif soru_kaynagi == "Sadece Görsel Sorular (PDF'den Kesilen)":
        tum_sorular = [q for q in tum_sorular if q.image_data]
    elif soru_kaynagi.startswith("Sadece "):
        # Sinav turu (TYT, AYT, LGS, Deneme)
        sinav_tur = soru_kaynagi.replace("Sadece ", "")
        tum_sorular = [q for q in tum_sorular if q.subject == sinav_tur]
    elif soru_kaynagi == "AI Otomatik Üret":
        # AI ile tüm soruları üret - soru bankasından kullanma
        tum_sorular = []
    elif soru_kaynagi == "AI Akıllı Seçim":
        # Soru bankasından seç - grade zaten yukarıda filtreli
        pass
    elif soru_kaynagi == "AI Karışık":
        # AI karışık - grade filtreli sorular + eksik AI ile tamamlanacak
        pass
    elif soru_kaynagi == "AI Kazanım Eşleştir":
        # Kazanımlara eşleştir - grade filtreli sorular kullanılır
        pass
    elif soru_kaynagi == "Görsel Sorular":
        # Sadece görsel soruları filtrele (image_data IS NOT NULL)
        tum_sorular = [q for q in tum_sorular if q.image_data]

    # Filtrelenmis soru sayisini kontrol et
    if soru_kaynagi not in ["AI Otomatik Üret", "AI Akıllı Seçim", "AI Karışık", "AI Kazanım Eşleştir", "Görsel Sorular"]:
        if len(tum_sorular) < toplam_soru and not ai_aktif:
            st.warning(f"⚠️ Seçilen kaynakta sadece {len(tum_sorular)} soru var. AI ile tamamlanacak.")

    # Bloom seviyesi dağılımı oluştur
    bloom_levels_for_questions = []
    if bloom_dagilimi:
        from models.olcme_degerlendirme import BLOOM_LEVELS
        for level in BLOOM_LEVELS:
            pct = bloom_dagilimi.get(level, 0)
            count = round(toplam_soru * pct / 100)
            bloom_levels_for_questions.extend([level] * count)
        # Eksik/fazla düzelt
        while len(bloom_levels_for_questions) < toplam_soru:
            bloom_levels_for_questions.append("Uygulama")
        bloom_levels_for_questions = bloom_levels_for_questions[:toplam_soru]
        import random as _rnd
        _rnd.shuffle(bloom_levels_for_questions)

    def _get_bloom_for_question(idx: int) -> str:
        """Soru indeksine göre bloom seviyesi döndür."""
        if bloom_levels_for_questions and idx < len(bloom_levels_for_questions):
            return bloom_levels_for_questions[idx]
        return ""

    # ── Soru Türü: Paragraf & Tablo/Grafik Kontrolü ──
    _st_parts = [t.strip() for t in soru_turu.split("+")]
    _has_passage = any("Paragraf" in t for t in _st_parts)
    _has_data = any("Tablo" in t or "Grafik" in t for t in _st_parts)
    _n_types = max(len(_st_parts), 1)

    def _generate_special_questions_for_subject(subject, soru_sayisi, progress_bar, status_text, soru_no_ref):
        """Paragraf ve Tablo/Grafik soruları üret. Returns (sorular_list, new_soru_no)."""
        import random as _rnd2
        _special = []
        _sno = soru_no_ref

        _passage_n = max(1, soru_sayisi // _n_types) if _has_passage else 0
        _data_n = max(1, soru_sayisi // _n_types) if _has_data else 0

        outcomes = store.get_outcomes(grade=grade, subject=subject, status="active")
        if not outcomes:
            return _special, _sno

        # ── Paragraf Tabanlı Sorular ──
        if _passage_n > 0:
            outcome = _rnd2.choice(outcomes)
            status_text.text(f"📝 {subject} - Paragraf tabanli {_passage_n} soru uretiliyor...")
            _pg_data = _generate_passage_questions(
                ders=subject, konu=outcome.topic or "",
                kazanim=outcome.outcome_text,
                soru_sayisi=_passage_n, grade=grade,
                bloom_level=_get_bloom_for_question(_sno - 1)
            )
            if _pg_data and _pg_data.get('sorular'):
                _pg_id = f"PG_{datetime.now().strftime('%Y%m%d%H%M%S')}_{subject[:3]}"
                for _ps in _pg_data['sorular'][:_passage_n]:
                    _special.append({
                        'numara': _sno, 'metin': _ps.get('metin', ''),
                        'secenekler': _ps.get('secenekler', []),
                        'dogru': _ps.get('dogru', 0), 'zorluk': 'Orta',
                        'ders': subject, 'kaynak': 'ai_passage',
                        'passage': _pg_data['paragraf'],
                        'passage_group_id': _pg_id,
                        'bloom_level': _ps.get('bloom_level', ''),
                    })
                    _sno += 1
                    progress_bar.progress(min(_sno / toplam_soru, 1.0))

        # ── Tablo/Grafik Yorumlama Soruları ──
        if _data_n > 0:
            for _ in range(_data_n):
                outcome = _rnd2.choice(outcomes)
                _ct = _rnd2.choice(["table", "bar", "line", "pie"])
                status_text.text(f"📊 {subject} - {_ct} sorusu uretiliyor...")
                _dr = _generate_data_question(
                    ders=subject, konu=outcome.topic or "",
                    kazanim=outcome.outcome_text,
                    chart_type=_ct, grade=grade,
                    bloom_level=_get_bloom_for_question(_sno - 1)
                )
                if _dr:
                    _special.append({
                        'numara': _sno, 'metin': _dr.get('metin', ''),
                        'secenekler': _dr.get('secenekler', []),
                        'dogru': _dr.get('dogru', 0), 'zorluk': 'Orta',
                        'ders': subject, 'kaynak': 'ai_data',
                        'data_table': _dr.get('veri', {}),
                        'chart_type': _dr.get('grafik_turu', _ct),
                        'bloom_level': _dr.get('bloom_level', 'Analiz'),
                    })
                    _sno += 1
                    progress_bar.progress(min(_sno / toplam_soru, 1.0))

        return _special, _sno

    # Tier 1 ortak ayarlar — her return edilen sinav dict'ine eklenir
    _tier1_config = {
        'shuffle_questions': shuffle_questions,
        'shuffle_choices': shuffle_choices,
        'negative_scoring': negative_scoring,
        'negative_ratio': negative_ratio,
        'tab_switch_detection': tab_switch_detection,
        'max_tab_switches': max_tab_switches,
        'auto_submit_on_exceed': auto_submit_on_exceed,
        'show_feedback': show_feedback,
        'show_correct_answers': show_correct_answers,
    }

    # Progress bar
    progress_bar = st.progress(0)
    status_text = st.empty()

    # Kullanilan soru ID'lerini takip et
    kullanilan_ids = set()

    # ============================================
    # ÖZEL MOD: Sadece Görsel Sorular (PDF'den Kesilen)'    # ============================================
    if soru_kaynagi == "Sadece Görsel Sorular (PDF'den Kesilen)" or soru_kaynagi.startswith("Görsel+Kategori:"):
        # Görsel sorulardan random seçim yap
        kategori_info = f" ({gorsel_kategori})" if gorsel_kategori else ""
        st.info(f"🖼️ PDF'den kesilen{kategori_info} {len(tum_sorular)} görsel sorudan {toplam_soru} tanesi seçilecek...")

        # Soruları karıştır
        random.shuffle(tum_sorular)

        for i, q in enumerate(tum_sorular[:toplam_soru]):
            status_text.text(f"🖼️ Görsel soru {i+1}/{toplam_soru} ekleniyor...")
            progress_bar.progress((i + 1) / toplam_soru)

            soru = {
                'numara': i + 1,
                'metin': q.stem,
                'secenekler': list(q.choices.values()) if q.choices else ["A", "B", "C", "D"],
                'dogru': list(q.choices.keys()).index(q.correct_choice) if q.correct_choice and q.choices else 0,
                'zorluk': q.difficulty or "Karışık",
                'ders': q.subject or "Genel",
                'kaynak': 'gorsel_pdf',
                'soru_id': q.id,
                'gorsel': q.image_data
            }
            sorular.append(soru)

        # Progress temizle
        progress_bar.empty()
        status_text.empty()

        st.success(f"✅ {len(sorular)} görsel soru eklendi!")

        # Kaynak istatistikleri
        kaynak_stats = {
            'soru_bankasi': 0,
            'ai_generated': 0,
            'template': 0,
            'gorsel': len(sorular)
        }

        # Sinav objesi olustur
        sinav = {
            'ad': kapak_bilgileri.get('sinav_adi', f"{sinav_turu} - {_grade_label(grade)}") if kapak_bilgileri else f"{sinav_turu} - {_grade_label(grade)}",
            'sinif': grade,
            'donem': term,
            'tarih': kapak_bilgileri.get('sinav_tarihi', datetime.now().strftime('%d.%m.%Y')) if kapak_bilgileri else datetime.now().strftime('%d.%m.%Y'),
            'kod': f"SINAV_{datetime.now().strftime('%Y%m%d%H%M%S')}",
            'kitapcik_turu': kitapcik_turu,
            'toplam_soru': len(sorular),
            'ders_dagilimi': {s.subject or "Genel": 1 for s in tum_sorular[:toplam_soru]},
            'zorluk_dagilimi': zorluk_dagilimi,
            'sorular': sorular,
            'kaynak_stats': kaynak_stats,
            'soru_kaynagi': soru_kaynagi,
            'sinav_turu': sinav_turu,
            'soru_turu': soru_turu,
            'kapak_bilgileri': kapak_bilgileri  # Kapak sayfası bilgileri
        }
        sinav['sorular'] = balance_answer_keys(sinav.get('sorular', []), max_consecutive=2)
        sinav.update(_tier1_config)
        return sinav

    # ============================================
    # ÖZEL MOD: Görsel Sorular (Şablon + AI)
    # ============================================
    if soru_kaynagi == "Görsel Sorular":
        gorsel_banka = [q for q in tum_sorular if q.image_data]
        st.info(f"📸 Görsel soru bankasından {len(gorsel_banka)} mevcut görsel soru bulundu. Hedef: {toplam_soru}")

        random.shuffle(gorsel_banka)
        bankadan_alinan = gorsel_banka[:toplam_soru]

        for i, q in enumerate(bankadan_alinan):
            status_text.text(f"📸 Görsel soru {i+1}/{toplam_soru} ekleniyor...")
            progress_bar.progress((i + 1) / toplam_soru)

            soru = {
                'numara': i + 1,
                'metin': q.stem,
                'secenekler': list(q.choices.values()) if q.choices else ["A", "B", "C", "D"],
                'dogru': list(q.choices.keys()).index(q.correct_choice) if q.correct_choice and q.choices else 0,
                'zorluk': q.difficulty or "Karışık",
                'ders': q.subject or "Genel",
                'kaynak': 'gorsel_banka',
                'soru_id': q.id,
                'gorsel': q.image_data
            }
            sorular.append(soru)
            kullanilan_ids.add(q.id)

        # Yetersizse şablonlardan üret
        eksik = toplam_soru - len(sorular)
        if eksik > 0:
            st.info(f"📸 {eksik} eksik soru şablonlardan üretiliyor...")
            try:
                from views.question_builder._visual_questions import generate_visual_question, get_available_visual_subjects
                available = get_available_visual_subjects()
                # Sınav derslerini şablon dersleriyle eşleştir
                for subj in subjects:
                    if eksik <= 0:
                        break
                    matching = [a for a in available if a.lower() in subj.lower() or subj.lower() in a.lower()]
                    sablon_ders = matching[0] if matching else (available[0] if available else None)
                    if sablon_ders:
                        for _ in range(min(eksik, ders_soru_sayilari.get(subj, eksik))):
                            result = generate_visual_question(sablon_ders)
                            if result:
                                import base64
                                img_data = result.get('image_data') or result.get('gorsel')
                                gorsel_b64 = None
                                if img_data:
                                    gorsel_b64 = base64.b64encode(img_data).decode('utf-8') if isinstance(img_data, bytes) else img_data

                                soru = {
                                    'numara': len(sorular) + 1,
                                    'metin': result.get('question', result.get('soru', '')),
                                    'secenekler': result.get('options', result.get('secenekler', [])),
                                    'dogru': result.get('correct_answer', result.get('dogru', 0)),
                                    'zorluk': 'orta',
                                    'ders': subj,
                                    'kaynak': 'gorsel_sablon',
                                    'gorsel': gorsel_b64
                                }
                                sorular.append(soru)
                                eksik -= 1
                                progress_bar.progress(len(sorular) / toplam_soru)
            except ImportError:
                st.warning("Şablon modülü yüklenemedi.")

        progress_bar.empty()
        status_text.empty()
        st.success(f"✅ {len(sorular)} görsel soru hazırlandı! (Banka: {len(bankadan_alinan)}, Şablon: {len(sorular) - len(bankadan_alinan)})")

        kaynak_stats = {'soru_bankasi': len(bankadan_alinan), 'ai_generated': 0, 'template': len(sorular) - len(bankadan_alinan), 'gorsel': len(sorular)}
        sinav = {
            'ad': kapak_bilgileri.get('sinav_adi', f"{sinav_turu} - {_grade_label(grade)}") if kapak_bilgileri else f"{sinav_turu} - {_grade_label(grade)}",
            'sinif': grade, 'donem': term,
            'tarih': kapak_bilgileri.get('sinav_tarihi', datetime.now().strftime('%d.%m.%Y')) if kapak_bilgileri else datetime.now().strftime('%d.%m.%Y'),
            'kod': f"SINAV_{datetime.now().strftime('%Y%m%d%H%M%S')}",
            'kitapcik_turu': kitapcik_turu, 'toplam_soru': len(sorular),
            'ders_dagilimi': {}, 'zorluk_dagilimi': zorluk_dagilimi,
            'sorular': sorular, 'kaynak_stats': kaynak_stats,
            'soru_kaynagi': soru_kaynagi, 'sinav_turu': sinav_turu,
            'soru_turu': soru_turu, 'kapak_bilgileri': kapak_bilgileri
        }
        sinav['sorular'] = balance_answer_keys(sinav.get('sorular', []), max_consecutive=2)
        sinav.update(_tier1_config)
        return sinav

    # ============================================
    # ÖZEL MOD: AI Otomatik Üret
    # ============================================
    if soru_kaynagi == "AI Otomatik Üret":
        st.info("🤖 AI Destekli Otomatik Soru Üretimi başlatılıyor...")

        # Kazanımları al
        all_outcomes = store.get_outcomes(grade=grade, status="active")

        for subject in subjects:
            soru_sayisi = ders_soru_sayilari.get(subject, 0)
            if soru_sayisi == 0:
                continue

            # Dersin kazanımlarını al
            subject_outcomes = [o for o in all_outcomes if o.subject == subject]

            # ── Paragraf & Tablo/Grafik özel soruları üret ──
            _special_qs, soru_no = _generate_special_questions_for_subject(
                subject, soru_sayisi, progress_bar, status_text, soru_no
            )
            if _special_qs:
                sorular.extend(_special_qs)

            _remaining_count = soru_sayisi - len(_special_qs)
            for i in range(_remaining_count):
                status_text.text(f"🤖 {subject} - Soru {soru_no}/{toplam_soru} AI ile üretiliyor...")
                progress_bar.progress(soru_no / toplam_soru)

                # Zorluk belirle
                rand = random.randint(1, 100)
                if rand <= zorluk_dagilimi["Kolay"]:
                    zorluk = "Kolay"
                elif rand <= zorluk_dagilimi["Kolay"] + zorluk_dagilimi["Orta"]:
                    zorluk = "Orta"
                else:
                    zorluk = "Zor"

                # Rastgele kazanım seç
                if subject_outcomes:
                    outcome = random.choice(subject_outcomes)
                    soru = _generate_question_from_outcome(outcome, zorluk, soru_no, ai_aktif=True, gorsel_ekle=gorsel_ekle, bloom_level=_get_bloom_for_question(soru_no - 1))
                    soru['ders'] = subject
                    soru['kaynak'] = 'ai_generated'
                    sorular.append(soru)
                else:
                    # Kazanım yoksa template kullan
                    soru = {
                        'numara': soru_no,
                        'metin': f"{subject} dersi {zorluk.lower()} seviye soru",
                        'secenekler': ["Seçenek A", "Seçenek B", "Seçenek C", "Seçenek D"],
                        'dogru': 0,
                        'zorluk': zorluk,
                        'ders': subject,
                        'kaynak': 'template'
                    }
                    sorular.append(soru)

                soru_no += 1

        progress_bar.empty()
        status_text.empty()
        st.success(f"✅ {len(sorular)} soru AI ile üretildi!")

        kaynak_stats = {
            'soru_bankasi': 0,
            'ai_generated': len(sorular),
            'template': 0,
            'gorsel': len([s for s in sorular if s.get('gorsel')])
        }

        sinav = {
            'ad': kapak_bilgileri.get('sinav_adi', f"{_grade_label(grade)} {sinav_turu} - {term}") if kapak_bilgileri else f"{_grade_label(grade)} {sinav_turu} - {term}",
            'kod': f"AI-{datetime.now().strftime('%Y%m%d%H%M')}",
            'sinif': grade,
            'sube': 'A',
            'kitapcik_turu': kitapcik_turu,
            'tarih': kapak_bilgileri.get('sinav_tarihi', datetime.now().strftime('%d.%m.%Y')) if kapak_bilgileri else datetime.now().strftime('%d.%m.%Y'),
            'toplam_soru': len(sorular),
            'ders_dagilimi': ders_soru_sayilari,
            'soru_kaynagi': soru_kaynagi,
            'sinav_turu': sinav_turu,
            'soru_turu': soru_turu,
            'kaynak_stats': kaynak_stats,
            'sorular': sorular,
            'kapak_bilgileri': kapak_bilgileri
        }
        sinav['sorular'] = balance_answer_keys(sinav.get('sorular', []), max_consecutive=2)
        sinav.update(_tier1_config)
        return sinav

    # ============================================
    # ÖZEL MOD: AI Akıllı Seçim
    # ============================================
    if soru_kaynagi == "AI Akıllı Seçim":
        st.info(f"📚 Soru bankasından seçim: {_grade_label(grade)} - {len(tum_sorular)} soru mevcut")

        for subject in subjects:
            soru_sayisi = ders_soru_sayilari.get(subject, 0)
            if soru_sayisi == 0:
                continue

            # Ders ve sınıfa göre soruları filtrele
            subject_sorular = [q for q in tum_sorular if q.subject == subject and q.id not in kullanilan_ids]

            # Zorluk dağılımına göre sırala ve seç
            kolay = [q for q in subject_sorular if q.difficulty == "Kolay"]
            orta = [q for q in subject_sorular if q.difficulty == "Orta"]
            zor = [q for q in subject_sorular if q.difficulty == "Zor"]
            karisik = [q for q in subject_sorular if q.difficulty == "Karışık"]

            # Kullanım bazlı sıralama fonksiyonu (az kullanılanı öncelikle seç)
            def _usage_sort(questions_list):
                """Soruları kullanım sayısına göre sırala (az kullanılan önce), sonra karıştır."""
                random.shuffle(questions_list)
                return sorted(questions_list, key=lambda q: getattr(q, 'usage_count', 0))

            # Akıllı seçim: Önce zorluk dengesini kur
            kolay_hedef = int(soru_sayisi * zorluk_dagilimi["Kolay"] / 100)
            orta_hedef = int(soru_sayisi * zorluk_dagilimi["Orta"] / 100)
            zor_hedef = soru_sayisi - kolay_hedef - orta_hedef

            secilen_sorular = []

            # Kolay sorular (kullanım bazlı sıralı)
            for q in _usage_sort(kolay)[:kolay_hedef]:
                if q.id not in kullanilan_ids:
                    secilen_sorular.append((q, "Kolay"))
                    kullanilan_ids.add(q.id)

            # Orta sorular (kullanım bazlı sıralı)
            for q in _usage_sort(orta)[:orta_hedef]:
                if q.id not in kullanilan_ids:
                    secilen_sorular.append((q, "Orta"))
                    kullanilan_ids.add(q.id)

            # Zor sorular (kullanım bazlı sıralı)
            for q in _usage_sort(zor)[:zor_hedef]:
                if q.id not in kullanilan_ids:
                    secilen_sorular.append((q, "Zor"))
                    kullanilan_ids.add(q.id)

            # Eksik varsa karışık'tan tamamla
            eksik = soru_sayisi - len(secilen_sorular)
            if eksik > 0:
                for q in _usage_sort(karisik)[:eksik]:
                    if q.id not in kullanilan_ids:
                        secilen_sorular.append((q, "Karışık"))
                        kullanilan_ids.add(q.id)

            # Hala eksik varsa diğer zorluklardan al
            if len(secilen_sorular) < soru_sayisi:
                kalan = [q for q in subject_sorular if q.id not in kullanilan_ids]
                for q in _usage_sort(kalan)[:soru_sayisi - len(secilen_sorular)]:
                    secilen_sorular.append((q, q.difficulty or "Orta"))
                    kullanilan_ids.add(q.id)

            # Soruları ekle
            for q, zorluk in secilen_sorular:
                status_text.text(f"🧠 {subject} - Soru {soru_no}/{toplam_soru} akıllı seçildi...")
                progress_bar.progress(soru_no / toplam_soru)

                soru = {
                    'numara': soru_no,
                    'metin': q.stem,
                    'secenekler': list(q.choices.values()) if q.choices else ["A", "B", "C", "D"],
                    'dogru': list(q.choices.keys()).index(q.correct_choice) if q.correct_choice and q.choices else 0,
                    'zorluk': zorluk,
                    'ders': subject,
                    'kaynak': 'ai_akilli_secim',
                    'soru_id': q.id
                }

                if q.image_data:
                    soru['gorsel'] = q.image_data

                sorular.append(soru)
                soru_no += 1

        progress_bar.empty()
        status_text.empty()
        st.success(f"✅ {len(sorular)} soru bankasından seçildi!")

        kaynak_stats = {
            'soru_bankasi': len(sorular),
            'ai_generated': 0,
            'template': 0,
            'gorsel': len([s for s in sorular if s.get('gorsel')]),
            'ai_secim': True
        }

        sinav = {
            'ad': kapak_bilgileri.get('sinav_adi', f"{_grade_label(grade)} {sinav_turu} - {term}") if kapak_bilgileri else f"{_grade_label(grade)} {sinav_turu} - {term}",
            'kod': f"AIS-{datetime.now().strftime('%Y%m%d%H%M')}",
            'sinif': grade,
            'sube': 'A',
            'kitapcik_turu': kitapcik_turu,
            'tarih': kapak_bilgileri.get('sinav_tarihi', datetime.now().strftime('%d.%m.%Y')) if kapak_bilgileri else datetime.now().strftime('%d.%m.%Y'),
            'toplam_soru': len(sorular),
            'ders_dagilimi': ders_soru_sayilari,
            'soru_kaynagi': soru_kaynagi,
            'sinav_turu': sinav_turu,
            'soru_turu': soru_turu,
            'kaynak_stats': kaynak_stats,
            'sorular': sorular,
            'kapak_bilgileri': kapak_bilgileri
        }
        sinav['sorular'] = balance_answer_keys(sinav.get('sorular', []), max_consecutive=2)
        sinav.update(_tier1_config)
        return sinav

    # ============================================
    # ÖZEL MOD: AI Karışık (Tüm Kaynaklardan)
    # ============================================
    if soru_kaynagi == "AI Karışık":
        st.info("🔀 AI Karışık Seçim başlatılıyor - Soru bankası + Görsel + AI üretimi...")

        # Kazanımları al
        all_outcomes = store.get_outcomes(grade=grade, status="active")

        # Görsel ve metin soruları ayır
        gorsel_sorular_list = [q for q in tum_sorular if q.image_data]
        metin_sorular_list = [q for q in tum_sorular if not q.image_data]

        for subject in subjects:
            soru_sayisi = ders_soru_sayilari.get(subject, 0)
            if soru_sayisi == 0:
                continue

            # Dersin kazanımlarını al
            subject_outcomes = [o for o in all_outcomes if o.subject == subject]

            # Derse göre mevcut soruları filtrele
            subject_gorsel = [q for q in gorsel_sorular_list if q.subject == subject and q.id not in kullanilan_ids]
            subject_metin = [q for q in metin_sorular_list if q.subject == subject and q.id not in kullanilan_ids]

            # Kaynak dağılımı: %40 görsel, %40 metin, %20 AI üretimi (varsa)
            gorsel_hedef = min(int(soru_sayisi * 0.4), len(subject_gorsel))
            metin_hedef = min(int(soru_sayisi * 0.4), len(subject_metin))
            ai_hedef = soru_sayisi - gorsel_hedef - metin_hedef

            # Eğer görsel/metin yetersizse AI'dan daha fazla al
            if gorsel_hedef + metin_hedef < soru_sayisi * 0.5:
                ai_hedef = soru_sayisi - gorsel_hedef - metin_hedef

            eklenen = 0

            # 1. Görsel sorulardan seç
            random.shuffle(subject_gorsel)
            for q in subject_gorsel[:gorsel_hedef]:
                if q.id not in kullanilan_ids:
                    status_text.text(f"🔀 {subject} - Soru {soru_no}/{toplam_soru} (görsel)...")
                    progress_bar.progress(soru_no / toplam_soru)

                    soru = {
                        'numara': soru_no,
                        'metin': q.stem,
                        'secenekler': list(q.choices.values()) if q.choices else ["A", "B", "C", "D"],
                        'dogru': list(q.choices.keys()).index(q.correct_choice) if q.correct_choice and q.choices else 0,
                        'zorluk': q.difficulty or "Karışık",
                        'ders': subject,
                        'kaynak': 'karisik_gorsel',
                        'soru_id': q.id,
                        'gorsel': q.image_data
                    }
                    sorular.append(soru)
                    kullanilan_ids.add(q.id)
                    soru_no += 1
                    eklenen += 1

            # 2. Metin sorulardan seç
            random.shuffle(subject_metin)
            for q in subject_metin[:metin_hedef]:
                if q.id not in kullanilan_ids:
                    status_text.text(f"🔀 {subject} - Soru {soru_no}/{toplam_soru} (metin)...")
                    progress_bar.progress(soru_no / toplam_soru)

                    soru = {
                        'numara': soru_no,
                        'metin': q.stem,
                        'secenekler': list(q.choices.values()) if q.choices else ["A", "B", "C", "D"],
                        'dogru': list(q.choices.keys()).index(q.correct_choice) if q.correct_choice and q.choices else 0,
                        'zorluk': q.difficulty or "Karışık",
                        'ders': subject,
                        'kaynak': 'karisik_metin',
                        'soru_id': q.id
                    }
                    sorular.append(soru)
                    kullanilan_ids.add(q.id)
                    soru_no += 1
                    eklenen += 1

            # 3. Eksik kalanı AI ile üret
            eksik = soru_sayisi - eklenen
            if eksik > 0 and subject_outcomes:
                for i in range(eksik):
                    status_text.text(f"🔀 {subject} - Soru {soru_no}/{toplam_soru} (AI üretimi)...")
                    progress_bar.progress(soru_no / toplam_soru)

                    # Zorluk belirle
                    rand = random.randint(1, 100)
                    if rand <= zorluk_dagilimi["Kolay"]:
                        zorluk = "Kolay"
                    elif rand <= zorluk_dagilimi["Kolay"] + zorluk_dagilimi["Orta"]:
                        zorluk = "Orta"
                    else:
                        zorluk = "Zor"

                    outcome = random.choice(subject_outcomes)
                    soru = _generate_question_from_outcome(outcome, zorluk, soru_no, ai_aktif=True, gorsel_ekle=gorsel_ekle, bloom_level=_get_bloom_for_question(soru_no - 1))
                    soru['ders'] = subject
                    soru['kaynak'] = 'karisik_ai'
                    sorular.append(soru)
                    soru_no += 1

        progress_bar.empty()
        status_text.empty()

        gorsel_count = len([s for s in sorular if s.get('gorsel')])
        metin_count = len([s for s in sorular if s.get('kaynak') == 'karisik_metin'])
        ai_count = len([s for s in sorular if s.get('kaynak') == 'karisik_ai'])

        st.success(f"✅ {len(sorular)} soru karışık seçildi! (🖼️ {gorsel_count} görsel, 📝 {metin_count} metin, 🤖 {ai_count} AI)")

        kaynak_stats = {
            'soru_bankasi': metin_count,
            'ai_generated': ai_count,
            'template': 0,
            'gorsel': gorsel_count,
            'karisik': True
        }

        sinav = {
            'ad': kapak_bilgileri.get('sinav_adi', f"{_grade_label(grade)} {sinav_turu} - {term}") if kapak_bilgileri else f"{_grade_label(grade)} {sinav_turu} - {term}",
            'kod': f"MIX-{datetime.now().strftime('%Y%m%d%H%M')}",
            'sinif': grade,
            'sube': 'A',
            'kitapcik_turu': kitapcik_turu,
            'tarih': kapak_bilgileri.get('sinav_tarihi', datetime.now().strftime('%d.%m.%Y')) if kapak_bilgileri else datetime.now().strftime('%d.%m.%Y'),
            'toplam_soru': len(sorular),
            'ders_dagilimi': ders_soru_sayilari,
            'soru_kaynagi': soru_kaynagi,
            'sinav_turu': sinav_turu,
            'soru_turu': soru_turu,
            'kaynak_stats': kaynak_stats,
            'sorular': sorular,
            'kapak_bilgileri': kapak_bilgileri
        }
        sinav['sorular'] = balance_answer_keys(sinav.get('sorular', []), max_consecutive=2)
        sinav.update(_tier1_config)
        return sinav

    # ============================================
    # ÖZEL MOD: AI Kazanımlara Eşleştir
    # ============================================
    if soru_kaynagi == "AI Kazanım Eşleştir":
        st.info("🎯 Kazanımlara Eşleştirme başlatılıyor - Sorular kazanımlarla eşleştiriliyor...")

        # Tüm kazanımları al
        all_outcomes = store.get_outcomes(grade=grade, status="active")

        if not all_outcomes:
            st.error("❌ Bu sınıf için aktif kazanım bulunamadı!")
            return None

        for subject in subjects:
            soru_sayisi = ders_soru_sayilari.get(subject, 0)
            if soru_sayisi == 0:
                continue

            # Dersin kazanımlarını al
            subject_outcomes = [o for o in all_outcomes if o.subject == subject]

            if not subject_outcomes:
                st.warning(f"⚠️ {subject} dersi için kazanım bulunamadı!")
                continue

            # Derse göre mevcut soruları filtrele
            subject_sorular = [q for q in tum_sorular if q.subject == subject and q.id not in kullanilan_ids]

            # Her kazanım için en az 1 soru seçmeye çalış
            kazanim_soru_map = {o.id: [] for o in subject_outcomes}

            # Soruları kazanımlarla eşleştir
            for q in subject_sorular:
                # Soru zaten bir kazanımla eşleşmiş mi?
                if q.outcome_id and q.outcome_id in kazanim_soru_map:
                    kazanim_soru_map[q.outcome_id].append(q)
                else:
                    # AI ile en uygun kazanımı bul
                    if ai_aktif and subject_outcomes:
                        try:
                            # Soru metni ile kazanımları karşılaştır
                            best_match = None
                            best_score = 0

                            for outcome in subject_outcomes:
                                # Basit kelime eşleştirme (AI yerine hızlı çözüm)
                                soru_kelimeler = set(q.stem.lower().split())
                                kazanim_kelimeler = set(outcome.description.lower().split())
                                ortak = soru_kelimeler & kazanim_kelimeler
                                score = len(ortak)

                                if score > best_score:
                                    best_score = score
                                    best_match = outcome

                            if best_match:
                                kazanim_soru_map[best_match.id].append(q)
                        except Exception:
                            # Hata durumunda rastgele bir kazanıma ekle
                            random_outcome = random.choice(subject_outcomes)
                            kazanim_soru_map[random_outcome.id].append(q)
                    else:
                        # AI yoksa rastgele bir kazanıma ekle
                        random_outcome = random.choice(subject_outcomes)
                        kazanim_soru_map[random_outcome.id].append(q)

            # Her kazanımdan eşit sayıda soru seç
            soru_per_kazanim = max(1, soru_sayisi // len(subject_outcomes))
            kalan_soru = soru_sayisi
            eklenen = 0

            for outcome_id, outcome_sorular in kazanim_soru_map.items():
                if kalan_soru <= 0:
                    break

                secilecek = min(soru_per_kazanim, len(outcome_sorular), kalan_soru)
                random.shuffle(outcome_sorular)

                for q in outcome_sorular[:secilecek]:
                    if q.id not in kullanilan_ids:
                        status_text.text(f"🎯 {subject} - Soru {soru_no}/{toplam_soru} (kazanım eşleştirme)...")
                        progress_bar.progress(soru_no / toplam_soru)

                        soru = {
                            'numara': soru_no,
                            'metin': q.stem,
                            'secenekler': list(q.choices.values()) if q.choices else ["A", "B", "C", "D"],
                            'dogru': list(q.choices.keys()).index(q.correct_choice) if q.correct_choice and q.choices else 0,
                            'zorluk': q.difficulty or "Karışık",
                            'ders': subject,
                            'kaynak': 'kazanim_eslestir',
                            'soru_id': q.id,
                            'kazanim_id': outcome_id,
                            'gorsel': q.image_data if q.image_data else None
                        }
                        sorular.append(soru)
                        kullanilan_ids.add(q.id)
                        soru_no += 1
                        eklenen += 1
                        kalan_soru -= 1

            # Eksik kalanı AI ile üret (kazanımlara göre)
            if kalan_soru > 0 and ai_aktif:
                # Eksik kazanımları bul (soruda temsil edilmeyenler)
                kullanilan_kazanimlar = set(s.get('kazanim_id') for s in sorular if s.get('ders') == subject)
                eksik_kazanimlar = [o for o in subject_outcomes if o.id not in kullanilan_kazanimlar]

                if not eksik_kazanimlar:
                    eksik_kazanimlar = subject_outcomes

                for i in range(kalan_soru):
                    status_text.text(f"🎯 {subject} - Soru {soru_no}/{toplam_soru} (AI üretimi - kazanım)...")
                    progress_bar.progress(soru_no / toplam_soru)

                    # Zorluk belirle
                    rand = random.randint(1, 100)
                    if rand <= zorluk_dagilimi["Kolay"]:
                        zorluk = "Kolay"
                    elif rand <= zorluk_dagilimi["Kolay"] + zorluk_dagilimi["Orta"]:
                        zorluk = "Orta"
                    else:
                        zorluk = "Zor"

                    outcome = random.choice(eksik_kazanimlar)
                    soru = _generate_question_from_outcome(outcome, zorluk, soru_no, ai_aktif=True, gorsel_ekle=gorsel_ekle, bloom_level=_get_bloom_for_question(soru_no - 1))
                    soru['ders'] = subject
                    soru['kaynak'] = 'kazanim_ai'
                    soru['kazanim_id'] = outcome.id
                    sorular.append(soru)
                    soru_no += 1

        progress_bar.empty()
        status_text.empty()

        bankadan_count = len([s for s in sorular if s.get('kaynak') == 'kazanim_eslestir'])
        ai_count = len([s for s in sorular if s.get('kaynak') == 'kazanim_ai'])
        gorsel_count = len([s for s in sorular if s.get('gorsel')])
        unique_kazanim = len(set(s.get('kazanim_id') for s in sorular if s.get('kazanim_id')))

        st.success(f"✅ {len(sorular)} soru kazanımlara eşleştirildi! (📚 {bankadan_count} bankadan, 🤖 {ai_count} AI, 🎯 {unique_kazanim} farklı kazanım)")

        kaynak_stats = {
            'soru_bankasi': bankadan_count,
            'ai_generated': ai_count,
            'template': 0,
            'gorsel': gorsel_count,
            'kazanim_eslestir': True,
            'unique_kazanim': unique_kazanim
        }

        sinav = {
            'ad': kapak_bilgileri.get('sinav_adi', f"{_grade_label(grade)} {sinav_turu} - {term}") if kapak_bilgileri else f"{_grade_label(grade)} {sinav_turu} - {term}",
            'kod': f"KZN-{datetime.now().strftime('%Y%m%d%H%M')}",
            'sinif': grade,
            'sube': 'A',
            'kitapcik_turu': kitapcik_turu,
            'tarih': kapak_bilgileri.get('sinav_tarihi', datetime.now().strftime('%d.%m.%Y')) if kapak_bilgileri else datetime.now().strftime('%d.%m.%Y'),
            'toplam_soru': len(sorular),
            'ders_dagilimi': ders_soru_sayilari,
            'soru_kaynagi': soru_kaynagi,
            'sinav_turu': sinav_turu,
            'soru_turu': soru_turu,
            'kaynak_stats': kaynak_stats,
            'sorular': sorular,
            'kapak_bilgileri': kapak_bilgileri
        }
        sinav['sorular'] = balance_answer_keys(sinav.get('sorular', []), max_consecutive=2)
        sinav.update(_tier1_config)
        return sinav

    # ============================================
    # NORMAL MOD: Ders bazlı soru seçimi
    # ============================================
    for subject in subjects:
        soru_sayisi = ders_soru_sayilari.get(subject, 0)
        if soru_sayisi == 0:
            continue

        # ── Paragraf & Tablo/Grafik özel soruları üret ──
        _special_qs, soru_no = _generate_special_questions_for_subject(
            subject, soru_sayisi, progress_bar, status_text, soru_no
        )
        if _special_qs:
            sorular.extend(_special_qs)

        _normal_remaining = soru_sayisi - len(_special_qs)

        # Oncelikle soru bankasindan mevcut sorulari kullan
        # Filtrelenmis kaynak + ders filtresi
        if soru_kaynagi.startswith("Sadece ") and soru_kaynagi.replace("Sadece ", "") in EXAM_TYPES:
            # Sinav turunden seciliyorsa (TYT, AYT, LGS, Deneme)
            mevcut_sorular = [q for q in tum_sorular if q.id not in kullanilan_ids]
        else:
            # Diger durumlarda ders bazli filtrele
            mevcut_sorular = [q for q in tum_sorular if q.subject == subject and q.id not in kullanilan_ids]

        # Zorluga gore filtrele
        kolay_sorular = [q for q in mevcut_sorular if q.difficulty == "Kolay"]
        orta_sorular = [q for q in mevcut_sorular if q.difficulty == "Orta"]
        zor_sorular = [q for q in mevcut_sorular if q.difficulty == "Zor"]
        karisik_sorular = [q for q in mevcut_sorular if q.difficulty == "Karışık"]

        # Mevcut sorulardan secim yap
        bankadan_eklenen = 0

        for _ in range(_normal_remaining):
            # Zorluk belirle
            rand = random.randint(1, 100)
            if rand <= zorluk_dagilimi["Kolay"]:
                zorluk = "Kolay"
                uygun_sorular = kolay_sorular + karisik_sorular
            elif rand <= zorluk_dagilimi["Kolay"] + zorluk_dagilimi["Orta"]:
                zorluk = "Orta"
                uygun_sorular = orta_sorular + karisik_sorular
            else:
                zorluk = "Zor"
                uygun_sorular = zor_sorular + karisik_sorular

            # Kullanilmamis sorulardan sec
            uygun_sorular = [q for q in uygun_sorular if q.id not in kullanilan_ids]

            # Progress guncelle
            status_text.text(f"📚 {subject} - Soru {soru_no}/{toplam_soru}...")
            progress_bar.progress(soru_no / toplam_soru)

            if uygun_sorular:
                # Soru bankasindan sec
                secilen_q = random.choice(uygun_sorular)
                kullanilan_ids.add(secilen_q.id)
                bankadan_eklenen += 1

                # Soru formatina cevir
                soru = {
                    'numara': soru_no,
                    'metin': secilen_q.stem,
                    'secenekler': list(secilen_q.choices.values()) if secilen_q.choices else ["A", "B", "C", "D"],
                    'dogru': list(secilen_q.choices.keys()).index(secilen_q.correct_choice) if secilen_q.correct_choice and secilen_q.choices else 0,
                    'zorluk': zorluk,
                    'ders': subject,
                    'kaynak': 'soru_bankasi',
                    'soru_id': secilen_q.id
                }

                # Gorsel varsa ekle
                if secilen_q.image_data:
                    soru['gorsel'] = secilen_q.image_data

                sorular.append(soru)
                soru_no += 1

            elif ai_aktif:
                # Mevcut soru yoksa AI ile olustur
                if gorsel_ekle:
                    status_text.text(f"🤖🎨 {subject} - Soru {soru_no}/{toplam_soru} + görsel oluşturuluyor...")
                else:
                    status_text.text(f"🤖 {subject} - Soru {soru_no}/{toplam_soru} AI ile oluşturuluyor...")

                # Bu dersin kazanimlarini al
                outcomes = store.get_outcomes(grade=grade, subject=subject, status="active")
                if outcomes:
                    outcome = random.choice(outcomes)
                    soru = _generate_question_from_outcome(outcome, zorluk, soru_no, ai_aktif, gorsel_ekle, bloom_level=_get_bloom_for_question(soru_no - 1))
                    soru['ders'] = subject
                    soru['kaynak'] = 'ai_generated'
                    sorular.append(soru)
                    soru_no += 1
            else:
                # AI kapaliysa template kullan
                outcomes = store.get_outcomes(grade=grade, subject=subject, status="active")
                if outcomes:
                    outcome = random.choice(outcomes)
                    soru = _generate_template_question(outcome, zorluk, soru_no)
                    soru['ders'] = subject
                    soru['kaynak'] = 'template'
                    sorular.append(soru)
                    soru_no += 1

        if bankadan_eklenen > 0:
            st.toast(f"✅ {subject}: {bankadan_eklenen} soru bankasından eklendi")

    # Progress temizle
    progress_bar.empty()
    status_text.empty()

    # Sorular ders bazli gruplanmis halde kaliyor (karistirilmiyor)
    # Numaralari guncelle
    for i, soru in enumerate(sorular, 1):
        soru['numara'] = i

    # Kaynak istatistikleri
    kaynak_stats = {
        'soru_bankasi': len([s for s in sorular if s.get('kaynak') == 'soru_bankasi']),
        'ai_generated': len([s for s in sorular if s.get('kaynak') == 'ai_generated']),
        'template': len([s for s in sorular if s.get('kaynak') == 'template']),
        'gorsel': len([s for s in sorular if s.get('gorsel')])
    }

    # Sinav objesi
    sinav = {
        'ad': kapak_bilgileri.get('sinav_adi', f"{_grade_label(grade)} {sinav_turu} - {term}") if kapak_bilgileri else f"{_grade_label(grade)} {sinav_turu} - {term}",
        'kod': f"SNV-{datetime.now().strftime('%Y%m%d%H%M')}",
        'sinif': grade,
        'sube': 'A',
        'kitapcik_turu': kitapcik_turu,
        'tarih': kapak_bilgileri.get('sinav_tarihi', datetime.now().strftime('%d.%m.%Y')) if kapak_bilgileri else datetime.now().strftime('%d.%m.%Y'),
        'toplam_soru': len(sorular),
        'ders_dagilimi': ders_soru_sayilari,
        'soru_kaynagi': soru_kaynagi,
        'sinav_turu': sinav_turu,
        'soru_turu': soru_turu,
        'kaynak_stats': kaynak_stats,
        'sorular': sorular,
        'kapak_bilgileri': kapak_bilgileri  # Kapak sayfası bilgileri
    }
    sinav['sorular'] = balance_answer_keys(sinav.get('sorular', []), max_consecutive=2)
    sinav.update(_tier1_config)
    return sinav


def _generate_question_from_outcome(outcome, zorluk: str, soru_no: int,
                                     ai_aktif: bool = True, gorsel_ekle: bool = False,
                                     bloom_level: str = "") -> dict:
    """Kazanimdan AI destekli soru olustur."""
    import random
    import os

    # Ders ve konu bilgisi
    ders = outcome.subject
    konu = outcome.topic if outcome.topic else ""
    kazanim = outcome.outcome_text
    sinif = outcome.grade if hasattr(outcome, 'grade') else None

    # AI ile soru uret
    soru_data = None
    if ai_aktif:
        soru_data = _generate_ai_question(ders, konu, kazanim, zorluk, gorsel_ekle, grade=sinif, bloom_level=bloom_level)

    if soru_data:
        soru_data['numara'] = soru_no
        soru_data['kazanim_id'] = outcome.id
        soru_data['kazanim_kodu'] = outcome.outcome_code
        soru_data['kazanim_metni'] = kazanim
        soru_data['zorluk'] = zorluk
        if bloom_level:
            soru_data['bloom_level'] = bloom_level
        return soru_data

    # AI basarisiz olursa template kullan
    return _generate_template_question(outcome, zorluk, soru_no)


def _generate_ai_question(ders: str, konu: str, kazanim: str, zorluk: str, gorsel_ekle: bool = False, grade: int = None, bloom_level: str = "") -> dict:
    """MEB/ÖSYM motoru ile kaliteli soru üret — fallback olarak legacy prompt."""
    import os

    api_key = os.environ.get('OPENAI_API_KEY', '')
    if not api_key:
        return None

    try:
        motor = _get_meb_motoru()
        engine = select_engine(ders)

        # Soru tipi: engine profile'dan en yaygın tipi otomatik seç
        from models.meb_sinav_motoru import get_blueprint_profile
        profile = get_blueprint_profile(engine, grade or 9, ders)
        tur_dag = profile.get("tur_dagilim", {})
        soru_tipi = max(tur_dag, key=tur_dag.get) if tur_dag else "kavram"

        result = motor.generate_soru_unified(
            kazanim=kazanim,
            engine=engine,
            soru_tipi=soru_tipi,
            zorluk=zorluk,
            grade=grade or 9,
            subject=ders,
            bloom_level=bloom_level,
        )
        if "error" in result or not result.get("kok"):
            raise ValueError("MEB motor basarisiz")

        # Hard validation
        from models.meb_sinav_motoru import validate_hard
        hard = validate_hard(result, engine, grade or 9)

        # MEB formatını mevcut dict formatına dönüştür
        secenekler_dict = result.get('secenekler', {})
        secenekler_list = list(secenekler_dict.values())
        cevap_harf = result.get('cevap', 'A')
        harfler = list(secenekler_dict.keys())
        dogru_idx = harfler.index(cevap_harf) if cevap_harf in harfler else 0

        data = {
            'metin': result.get('kok', ''),
            'secenekler': secenekler_list,
            'dogru': dogru_idx,
            'aciklama': result.get('gerekce', ''),
            'ders': ders,
            'konu': konu,
            'kaynak': 'meb_pipeline',
            'zorluk': result.get('zorluk', zorluk),
            'beceri_etiketi': result.get('beceri_etiketi', ''),
            'validator_score': result.get('validator_score', 0),
            'validator_status': result.get('validator_status', ''),
            'engine_type': result.get('engine_type', engine),
            'veri_tablosu': result.get('veri_tablosu'),
            'gorsel_aciklama': result.get('gorsel_aciklama', ''),
            'bloom_level': bloom_level or result.get('bloom_level', ''),
        }

        # Görsel üretimi isteniyorsa
        if gorsel_ekle and data.get('metin'):
            st.info(f"🎨 {ders} dersi için soruya uygun görsel üretiliyor...")
            soru_metni = data.get('metin', '')
            gorsel_aciklama = f"{ders} dersi, {konu} konusu için eğitici diyagram. Soru bağlamı: {soru_metni[:100]}"
            gorsel_data = _generate_question_image(
                gorsel_aciklama=gorsel_aciklama, ders=ders, konu=konu, soru_metni=soru_metni)
            if gorsel_data:
                import base64
                data['gorsel'] = base64.b64encode(gorsel_data).decode('utf-8')
                st.success("✅ Görsel başarıyla oluşturuldu!")

        return data

    except Exception:
        # Fallback: eski basit prompt (güvenlik ağı)
        return _generate_ai_question_legacy(ders, konu, kazanim, zorluk, gorsel_ekle, grade, bloom_level)


def _generate_ai_question_legacy(ders: str, konu: str, kazanim: str, zorluk: str, gorsel_ekle: bool = False, grade: int = None, bloom_level: str = "") -> dict:
    """Eski basit prompt ile soru üret — MEB motoru başarısız olduğunda fallback."""
    import os
    import json

    api_key = os.environ.get('OPENAI_API_KEY', '')
    if not api_key:
        return None

    sinif_bilgisi = f"{grade}. sınıf" if grade else ""

    zorluk_aciklama = {
        "Kolay": "Temel kavram bilgisi, doğrudan hatırlama, basit uygulama",
        "Orta": "Kavramları uygulama, basit analiz, ilişkilendirme",
        "Zor": "Sentez, değerlendirme, çok adımlı problem çözme, eleştirel düşünme"
    }

    # Bloom taksonomisi bölümü
    from models.olcme_degerlendirme import BLOOM_DESCRIPTIONS
    bloom_section = ""
    if bloom_level:
        bloom_aciklama = BLOOM_DESCRIPTIONS.get(bloom_level, "")
        bloom_section = f"""
## BLOOM TAKSONOMİSİ SEVİYESİ
{bloom_level}: {bloom_aciklama}
Soru bu bilişsel seviyeyi ölçmelidir."""

    prompt = f"""Sen deneyimli bir {ders} öğretmenisin. MEB müfredatına uygun soru hazırla.

## KAZANIM
{kazanim}

## SINIF: {sinif_bilgisi or "Belirtilmemiş"}
## KONU: {konu if konu else ders}
## ZORLUK: {zorluk}: {zorluk_aciklama.get(zorluk, "Orta düzey")}
{bloom_section}

## KURALLAR
1. Soru metni en az 2-3 cümle, gerçek hayattan senaryo
2. 4 seçenek (A,B,C,D) - hepsi mantıklı
3. Tek doğru cevap
4. Çeldiriciler yaygın öğrenci hatalarına dayalı

## ÇIKTI (SADECE JSON)
```json
{{"metin": "...", "secenekler": ["A","B","C","D"], "dogru": 0, "aciklama": "...", "bloom_level": "{bloom_level or 'Uygulama'}"}}
```"""

    try:
        import openai
        client = openai.OpenAI()
        response = client.chat.completions.create(
            model="gpt-4o-mini",
            messages=[
                {"role": "system", "content": f"Sen bir {sinif_bilgisi + ' ' if sinif_bilgisi else ''}{ders} öğretmenisin. MEB standardında sorular hazırlıyorsun. Sadece JSON formatında cevap ver."},
                {"role": "user", "content": prompt}
            ],
            temperature=0.7, max_tokens=1200
        )
        content = response.choices[0].message.content
        if "```json" in content:
            content = content.split("```json")[1].split("```")[0]
        elif "```" in content:
            content = content.split("```")[1].split("```")[0]

        data = json.loads(content.strip())
        if not data.get('metin') or not data.get('secenekler') or len(data.get('secenekler', [])) != 4:
            return None

        data['ders'] = ders
        data['konu'] = konu
        data['kaynak'] = 'ai_generated'

        if gorsel_ekle:
            soru_metni = data.get('metin', '')
            gorsel_aciklama = f"{ders} dersi, {konu} konusu için eğitici diyagram. Soru bağlamı: {soru_metni[:100]}"
            gorsel_data = _generate_question_image(gorsel_aciklama=gorsel_aciklama, ders=ders, konu=konu, soru_metni=soru_metni)
            if gorsel_data:
                import base64
                data['gorsel'] = base64.b64encode(gorsel_data).decode('utf-8')

        return data
    except Exception:
        return None


def _generate_question_image(gorsel_aciklama: str, ders: str, konu: str = "", soru_metni: str = "") -> bytes:
    """DALL-E ile derse ve soruya uygun görsel üret."""
    import os
    import requests
    import streamlit as st

    api_key = os.environ.get('OPENAI_API_KEY')
    if not api_key:
        st.warning("OPENAI_API_KEY bulunamadı - görsel üretilemedi")
        return None

    # Ders bazlı görsel türleri ve örnekler
    ders_gorsel_rehberi = {
        "matematik": {
            "turler": ["geometrik şekil", "grafik", "sayı doğrusu", "koordinat düzlemi", "tablo", "kesir gösterimi"],
            "stil": "mathematical diagram with clean lines, geometric precision",
            "ornek": "coordinate plane, geometric shapes, number line, fraction visualization"
        },
        "fen bilimleri": {
            "turler": ["deney düzeneği", "hücre yapısı", "atom modeli", "besin zinciri", "elektrik devresi", "kuvvet diyagramı"],
            "stil": "scientific illustration, labeled diagram style",
            "ornek": "cell structure, circuit diagram, food chain, force diagram"
        },
        "sosyal bilgiler": {
            "turler": ["harita", "zaman çizelgesi", "karşılaştırma tablosu", "nüfus grafiği"],
            "stil": "map illustration, historical diagram, infographic style",
            "ornek": "geographical map, timeline, population chart"
        },
        "türkçe": {
            "turler": ["kavram haritası", "metin yapısı şeması", "kelime ağı"],
            "stil": "concept map, text structure diagram",
            "ornek": "word web, paragraph structure, concept hierarchy"
        },
        "fizik": {
            "turler": ["kuvvet diyagramı", "hareket grafiği", "dalga şeması", "optik ışın diyagramı"],
            "stil": "physics diagram with vectors and labels",
            "ornek": "force diagram, motion graph, wave pattern, ray diagram"
        },
        "kimya": {
            "turler": ["molekül yapısı", "periyodik tablo bölümü", "kimyasal bağ şeması", "deney düzeneği"],
            "stil": "chemistry molecular diagram, structural formula",
            "ornek": "molecular structure, chemical bonds, lab equipment"
        },
        "biyoloji": {
            "turler": ["hücre yapısı", "organ sistemi", "DNA/RNA şeması", "ekoloji diyagramı"],
            "stil": "biological illustration, anatomical diagram",
            "ornek": "cell organelles, digestive system, DNA helix, ecosystem"
        }
    }

    # Ders için uygun rehberi bul
    ders_lower = ders.lower()
    rehber = None
    for key, value in ders_gorsel_rehberi.items():
        if key in ders_lower:
            rehber = value
            break

    if not rehber:
        rehber = {
            "turler": ["diyagram", "şema", "tablo"],
            "stil": "educational diagram, clean illustration",
            "ornek": "concept diagram, comparison chart"
        }

    # Soru metninden anahtar kelimeler çıkar
    soru_kisaltma = soru_metni[:150] if soru_metni else gorsel_aciklama[:150]

    # Derse özel, soruyla alakalı prompt oluştur
    prompt = f"""Create an educational diagram for a Turkish {ders} exam question.

SUBJECT: {ders}
TOPIC: {konu if konu else "General"}
QUESTION CONTEXT: {soru_kisaltma}

STYLE REQUIREMENTS:
- {rehber['stil']}
- Black and white line drawing (suitable for printing)
- Clean, professional textbook quality
- NO text, NO labels, NO numbers (teacher will add these)
- Simple and clear for students to understand
- Educational and age-appropriate

EXAMPLE VISUAL TYPES for {ders}: {rehber['ornek']}

SPECIFIC REQUEST: {gorsel_aciklama[:200] if gorsel_aciklama else f'A relevant diagram for {konu}'}

Create a single, focused educational diagram that directly relates to the question topic."""

    try:
        import openai
        client = openai.OpenAI()

        # DALL-E 3 ile görsel üret
        response = client.images.generate(
            model="dall-e-3",
            prompt=prompt,
            size="1024x1024",
            quality="standard",
            n=1
        )

        # URL'den görseli indir
        image_url = response.data[0].url
        img_response = requests.get(image_url, timeout=30)
        if img_response.status_code == 200:
            return img_response.content

        return None

    except Exception as e:
        st.warning(f"Görsel üretilemedi: {str(e)[:80]}")
        return None


def _generate_passage_questions(ders: str, konu: str, kazanim: str, soru_sayisi: int = 4, grade: int = None, bloom_level: str = "") -> dict:
    """Bir paragraftan birden fazla soru üret."""
    import os, json

    api_key = os.environ.get('OPENAI_API_KEY', '')
    if not api_key:
        return None

    sinif_bilgisi = f"{grade}. sınıf" if grade else ""
    bloom_section = ""
    if bloom_level:
        from models.olcme_degerlendirme import BLOOM_DESCRIPTIONS
        bloom_section = f"\nSorular {bloom_level} ({BLOOM_DESCRIPTIONS.get(bloom_level, '')}) seviyesinde olmalıdır."

    prompt = f"""Sen deneyimli bir {ders} öğretmenisin. MEB müfredatına uygun paragraf tabanlı sorular hazırla.

## GÖREV
{sinif_bilgisi} {ders} dersi için bir okuma parçası/paragraf yazıp,
bu parçadan {soru_sayisi} adet çoktan seçmeli soru hazırla.

## KAZANIM
{kazanim}

## KONU: {konu if konu else ders}
{bloom_section}

## PARAGRAF KURALLARI
- 150-300 kelime arası
- Konuya uygun, bilimsel/edebi metin
- Öğrenci seviyesine uygun dil ({sinif_bilgisi})

## ÇIKTI (SADECE JSON)
```json
{{
    "paragraf": "Paragraf metni...",
    "sorular": [
        {{"metin": "Soru metni...", "secenekler": ["A seçeneği", "B seçeneği", "C seçeneği", "D seçeneği"], "dogru": 0, "aciklama": "...", "bloom_level": "Anlama"}},
        {{"metin": "Soru 2 metni...", "secenekler": ["A", "B", "C", "D"], "dogru": 1, "aciklama": "...", "bloom_level": "Analiz"}}
    ]
}}
```"""

    try:
        import openai
        client = openai.OpenAI()
        response = client.chat.completions.create(
            model="gpt-4o-mini",
            messages=[
                {"role": "system", "content": f"Sen bir {sinif_bilgisi + ' ' if sinif_bilgisi else ''}{ders} öğretmenisin. Paragraf tabanlı MEB standardında sorular hazırlıyorsun. Sadece JSON formatında cevap ver."},
                {"role": "user", "content": prompt}
            ],
            temperature=0.7, max_tokens=2500
        )
        content = response.choices[0].message.content
        if "```json" in content:
            content = content.split("```json")[1].split("```")[0]
        elif "```" in content:
            content = content.split("```")[1].split("```")[0]

        data = json.loads(content.strip())
        if not data.get('paragraf') or not data.get('sorular'):
            return None
        return data
    except Exception:
        return None


