        story.append(Spacer(1, 0.1*cm))

        kt_header = [Paragraph("<b>Kitapçık</b>", styles['OFSmall'])]
        kt_row = [""]
        for kt in ['A', 'B', 'C', 'D']:
            kt_header.append(Paragraph(f"<b>{kt}</b>", styles['OFSmall']))
