    # ========================================
    # CEVAP BALONCUKLARI
    # ========================================
    # ÖSYM sınavlarında bölüm başlığı ekle
    _of_bolum_yapisi = SINAV_BOLUM_YAPISI.get(_of_sinav_turu, {})
    if _of_bolum_yapisi and len(_of_bolum_yapisi.get('bolumler', [])) > 1:
        _bolum_aciklama = " | ".join([f"{b['ad']} (1-{sum(t['soru_sayisi'] for t in b['testler'])})" if bi == 0 else f"{b['ad']} ({sum(t['soru_sayisi'] for t in _of_bolum_yapisi['bolumler'][bi-1]['testler'])+1}-{sum(t['soru_sayisi'] for t in _of_bolum_yapisi['bolumler'][bi-1]['testler'])+sum(t['soru_sayisi'] for t in b['testler'])})" for bi, b in enumerate(_of_bolum_yapisi['bolumler'])])
