def _render_ogrenci_telafi_giris(store: DataStore):
    """Öğrenci telafi görevleri giriş ve çözme arayüzü."""
    from models.olcme_degerlendirme import TelafiGorev, RemediationEngine

    st.markdown("### 📚 Telafi Görevlerim")

    # Aktif telafi quiz'i varsa göster
    if st.session_state.get("telafi_active_task"):
        _render_telafi_quiz(store, st.session_state.telafi_active_task)
        return

    # Giriş formu
    st.info("Telafi görevlerinizi görmek için bilgilerinizi girin.")

    col1, col2 = st.columns(2)
    with col1:
        from utils.shared_data import get_student_display_options as _tel_stu
        _tel_opts = _tel_stu(include_empty=True)
        if len(_tel_opts) > 1:
            _tel_sel = st.selectbox("Öğrenci Sec", list(_tel_opts.keys()), key="telafi_ogrenci_sec")
            _tel_s = _tel_opts.get(_tel_sel, {})
            t_number = _tel_s.get("numara", "") if _tel_s else ""
            st.caption(f"No: {t_number}" if t_number else "")
        else:
            t_number = st.text_input("Öğrenci Numarasi", key="telafi_number")
            _tel_s = {}
    with col2:
        _tel_sube_def = _tel_s.get("sube", "") if _tel_s else ""
        _tel_sube_opts = ["A", "B", "C", "D", "E"]
        _tel_sube_idx = _tel_sube_opts.index(_tel_sube_def) if _tel_sube_def in _tel_sube_opts else 0
        t_section = st.selectbox("Şube", _tel_sube_opts, index=_tel_sube_idx, key="telafi_section")

    if st.button("📚 Görevlerimi Göster", type="primary", key="telafi_show"):
        if not t_number:
            st.error("Öğrenci numarası gerekli!")
            return
        student_id = f"{t_number}_{t_section}"
        st.session_state.telafi_student_id = student_id
        st.rerun()

    # Görevleri göster
    student_id = st.session_state.get("telafi_student_id")
    if not student_id:
        return

    tasks = store.get_telafi_tasks(student_id=student_id)
    if not tasks:
        st.success("✅ Şu anda telafi göreviniz yok. Harika!")
        return

    # Özet
    summary = store.get_student_telafi_summary(student_id)
    mc1, mc2, mc3, mc4 = st.columns(4)
    mc1.metric("🔴 Acil", summary.get("RED", 0))
    mc2.metric("🟡 Pekiştirme", summary.get("YELLOW", 0))
    mc3.metric("🟢 Tekrar", summary.get("GREEN", 0))
    mc4.metric("🔵 İleri", summary.get("BLUE", 0))

    st.markdown(f"**Toplam:** {summary['total']} görev | "
                f"**Tamamlanan:** {summary['completed']} | "
                f"**Bekleyen:** {summary['pending']}")

    # Sekmeler
    tab_pending, tab_done = st.tabs([
        f"📋 Bekleyen ({summary['pending']})",
        f"✅ Tamamlanan ({summary['completed']})"
    ])

    COLOR_EMOJI = {"RED": "🔴", "YELLOW": "🟡", "GREEN": "🟢", "BLUE": "🔵"}
    TASK_LABELS = {
        "mini_summary": "📖 Konu Özeti",
        "mini_quiz_1": "📝 Mini Quiz-1",
        "mini_quiz_2": "📝 Mini Quiz-2",
        "reinforcement": "💪 Pekiştirme",
        "weekly_review": "🔄 Haftalık Tekrar",
        "challenge": "🏆 İleri Düzey",
        "speed_drill": "⚡ Hız Çalışması",
    }

    with tab_pending:
        pending = [t for t in tasks if t.status in ("assigned", "in_progress")]
        pending.sort(key=lambda t: t.due_date or "9999")

        for task in pending:
            emoji = COLOR_EMOJI.get(task.color_band, "⚪")
            label = TASK_LABELS.get(task.task_type, task.task_type)

            with st.expander(f"{emoji} {label} | {task.outcome_text[:55]}..."):
                st.markdown(f"**Kazanım:** {task.outcome_text}")
                st.markdown(f"**Performans:** %{task.performance_pct:.0f} ({task.color_band})")

                if task.question_count > 0:
                    st.markdown(f"**Soru Sayısı:** {task.question_count}")
                if task.due_date:
                    st.markdown(f"**Son Tarih:** {task.due_date[:10]}")

                if task.task_type == "mini_summary":
                    if task.summary_text:
                        st.markdown("---")
                        st.markdown(task.summary_text)
                        if st.button("✅ Okudum", key=f"read_{task.id}"):
                            task.status = "completed"
                            task.completed_at = datetime.now().isoformat()
                            task.score = 100.0
                            store.save_telafi_task(task)
                            st.rerun()
                    else:
                        # AI ile özet üret
                        if st.button("📖 Özeti Oluştur", key=f"gen_{task.id}"):
                            with st.spinner("AI konu özeti üretiliyor..."):
                                engine = RemediationEngine(store)
                                summary_text = engine.generate_mini_summary(
                                    task.outcome_text, task.grade, task.subject
                                )
                                task.summary_text = summary_text
                                store.save_telafi_task(task)
                                st.rerun()
                else:
                    # Quiz görevleri
                    if task.question_ids:
                        if st.button("▶️ Başla", key=f"start_{task.id}", type="primary"):
                            st.session_state.telafi_active_task = task.id
                            st.session_state.telafi_answers = {}
                            st.rerun()
                    else:
                        st.caption("⚠️ Bu görev için henüz soru atanamamış.")

    with tab_done:
        completed = [t for t in tasks if t.status == "completed"]
        for task in completed:
            emoji = COLOR_EMOJI.get(task.color_band, "⚪")
            label = TASK_LABELS.get(task.task_type, task.task_type)
            st.markdown(
                f"{emoji} **{label}** | %{task.performance_pct:.0f} → "
                f"Puan: **{task.score:.0f}** | {task.completed_at[:10] if task.completed_at else ''}"
            )


def _render_telafi_quiz(store: DataStore, task_id: str):
    """Telafi quiz çözme arayüzü."""
    task = store.get_telafi_task(task_id)
    if not task:
        st.error("Görev bulunamadı!")
        st.session_state.telafi_active_task = None
        return

    st.markdown(f"### 📝 {task.task_type.replace('_', ' ').title()}")
    st.caption(f"Kazanım: {task.outcome_text[:80]}")

    if "telafi_answers" not in st.session_state:
        st.session_state.telafi_answers = {}

    # Soruları yükle
    questions = []
    for qid in task.question_ids:
        q = store.get_question(qid)
        if q:
            questions.append(q)

    if not questions:
        st.warning("Bu görev için soru bulunamadı.")
        if st.button("← Geri Dön"):

            st.session_state.telafi_active_task = None
            st.rerun()
        return

    # İlerleme
    answered = len(st.session_state.telafi_answers)
    total = len(questions)
    st.progress(answered / total if total > 0 else 0)
    st.caption(f"Cevaplanan: {answered}/{total}")

    # Sorular
    for i, q in enumerate(questions, 1):
        st.markdown(f"---\n**Soru {i}/{total}** ({q.difficulty})")
        st.markdown(q.stem)

        if q.question_type in ("mcq", "true_false") and q.choices:
            current = st.session_state.telafi_answers.get(q.id, "")
            cols = st.columns(len(q.choices))
            for j, (key, val) in enumerate(q.choices.items()):
                with cols[j]:
                    btn_type = "primary" if current == key else "secondary"
                    if st.button(f"{key}) {val}", key=f"tq_{task_id}_{q.id}_{key}",
                                 type=btn_type, use_container_width=True):
                        if current == key:
                            st.session_state.telafi_answers.pop(q.id, None)
                        else:
                            st.session_state.telafi_answers[q.id] = key
                        st.rerun()

        elif q.question_type == "fill_blank":
            ans = st.text_input("Cevabınız:", key=f"tq_fb_{task_id}_{q.id}",
                                value=st.session_state.telafi_answers.get(q.id, ""))
            if ans:
                st.session_state.telafi_answers[q.id] = ans

    # Butonlar
    st.markdown("---")
    col1, col2 = st.columns(2)
    with col1:
        if st.button("← Geri Dön", key="telafi_quiz_back"):
            st.session_state.telafi_active_task = None
            st.session_state.telafi_answers = {}
            st.rerun()

    with col2:
        if st.button("✅ Gönder", type="primary", key="telafi_quiz_submit"):
            # Puanla
            correct = 0
            for q in questions:
                student_ans = st.session_state.telafi_answers.get(q.id, "")
                if q.question_type == "fill_blank":
                    if student_ans.strip().lower() == q.correct_choice.strip().lower():
                        correct += 1
                elif student_ans == q.correct_choice:
                    correct += 1

            score = (correct / total * 100) if total > 0 else 0
            task.status = "completed"
            task.completed_at = datetime.now().isoformat()
            task.score = round(score, 1)
            store.save_telafi_task(task)

            st.session_state.telafi_active_task = None
            st.session_state.telafi_answers = {}

            st.success(f"🎉 Tebrikler! Puanınız: **{score:.0f}/100** "
                       f"({correct}/{total} doğru)")
            st.balloons()


def _generate_access_code():
    """6 haneli benzersiz erisim kodu uretir."""
    import random
    import string
    chars = string.ascii_uppercase + string.digits
    return ''.join(random.choices(chars, k=6))


def _build_qr_data_with_url(data: dict, exam_access_code: str = "") -> dict:
    """QR kod verisine sistem URL'si ekler. URL ayarlanmadıysa sadece JSON döner.

    Args:
        data: Mevcut QR verisi (sinav_kodu, tip vb.)
        exam_access_code: Sınav erişim kodu (öğrenci girişi için)

    Returns:
        URL + JSON verisi içeren dict
    """
    kurum = _load_kurum_ayarlari()
    base_url = kurum.get("app_base_url", "").strip().rstrip("/")

    if base_url and exam_access_code:
        # URL parametreli bağlantı: QR okutunca doğrudan sınava yönlendir
        import urllib.parse
        params = urllib.parse.urlencode({
            "sinav_kod": exam_access_code,
            "modul": "olcme",
            "aksiyon": "sinav_giris"
        })
        data["url"] = f"{base_url}?{params}"
    elif base_url:
        # Erişim kodu yoksa sadece modül bağlantısı
        data["url"] = f"{base_url}?modul=olcme"

    return data


def _generate_sinav_davet_email(email: str, sinav_adi: str, access_code: str,
                                  sure_dk: int, soru_sayisi: int, kurum_adi: str = "") -> str:
    """Online sinav davet mailto linki olusturur."""
    import urllib.parse

    kurum_text = f"{kurum_adi} - " if kurum_adi else ""

    # QR link varsa mesaja ekle
    _kurum = _load_kurum_ayarlari()
    _base = _kurum.get("app_base_url", "").strip().rstrip("/")
    qr_link_text = ""
    if _base and access_code:
        _qr_url = f"{_base}?sinav_kod={urllib.parse.quote(access_code)}&modul=olcme&aksiyon=sinav_giris"
        qr_link_text = f"\nDogrudan Giris Linki: {_qr_url}\n"

    subject = f"{kurum_text}Online Sinav Daveti - {sinav_adi}"
    body = f"""Sayin Veli / Ogrenci,

{sinav_adi} sinavi baslamistir.

Sinav Erisim Kodu: {access_code}
{qr_link_text}
Sinav Bilgileri:
- Sure: {sure_dk} dakika
- Soru Sayisi: {soru_sayisi}

Sinava Giris:
1. SmartCampus uygulamasini acin
2. Online Sinav > Sinava Gir sekmesine gidin
3. Erisim kodunu girin: {access_code}
4. Bilgilerinizi doldurup sinava baslayin

Sinav suresi baslatildiktan sonra geri sayim baslar. Sure bitiminde sinav otomatik kapanir.

SmartCampus AI - Olcme ve Degerlendirme"""

    params = urllib.parse.urlencode({"subject": subject, "body": body})
    return f"mailto:{email}?{params}"


def _generate_sinav_davet_sms(phone: str, sinav_adi: str, access_code: str,
                                sure_dk: int, soru_sayisi: int, kurum_adi: str = "") -> str:
    """Online sinav davet SMS linki olusturur."""
    import urllib.parse

    phone = phone.strip().replace(" ", "").replace("-", "").replace("(", "").replace(")", "")
    if phone.startswith("0"):
        phone = "+90" + phone[1:]
    elif not phone.startswith("+90") and not phone.startswith("90"):
        phone = "+90" + phone
    if not phone.startswith("+"):
        phone = "+" + phone

    kurum_text = f"{kurum_adi} - " if kurum_adi else ""

    # QR link
    _kurum = _load_kurum_ayarlari()
    _base = _kurum.get("app_base_url", "").strip().rstrip("/")
    qr_text = ""
    if _base and access_code:
        qr_text = f"\nGiris: {_base}?sinav_kod={urllib.parse.quote(access_code)}&modul=olcme&aksiyon=sinav_giris"

    message = f"""{kurum_text}SINAV DAVETI
{sinav_adi}
Erisim Kodu: {access_code}
Sure: {sure_dk} dk | Soru: {soru_sayisi}{qr_text}"""

    encoded_msg = urllib.parse.quote(message)
    return f"sms:{phone}?body={encoded_msg}"


def _render_dis_sinav_yukle(store: DataStore):
    """Dis sinav sonucu yukleme — Excel, PDF, Manuel. Tum analizlere dahil olur."""

    st.markdown("""
    <div style="background:linear-gradient(135deg,#0f172a,#1e293b);border-radius:14px;
    padding:14px 18px;margin-bottom:12px;border:1px solid rgba(245,158,11,0.2);">
    <div style="font-size:.9rem;font-weight:700;color:#fcd34d;">📥 Dış Sınav Sonucu Yükle</div>
    <div style="font-size:.75rem;color:#64748b;margin-top:2px;">
    Yayınevi deneme sınavı, dışarıdan alınan sınav sonuçlarını sisteme yükleyin.
    Yüklenen sonuçlar tüm analizlere dahil olur.</div>
    </div>""", unsafe_allow_html=True)

    yukleme_modu = st.radio("Yükleme Yöntemi",
        ["📊 Excel / CSV", "📄 PDF Sonuç Yükle", "✏️ Manuel Giriş"],
        key="dis_sinav_mod", horizontal=True)

    # Ortak alanlar
    st.markdown("---")
    dc1, dc2, dc3, dc4 = st.columns(4)
    with dc1:
        dis_sinav_adi = st.text_input("Sınav Adı *", placeholder="Ör: MEB Deneme 1", key="dis_sinav_adi")
    with dc2:
        dis_sinav_turu = st.selectbox("Sınav Türü", ["Deneme", "LGS", "TYT", "AYT Sayısal",
            "AYT Esit Agirlik", "AYT Sozel", "Yayınevi Deneme", "Diger"], key="dis_sinav_turu")
    with dc3:
        from utils.shared_data import get_sinif_sube_listesi
        _ss = get_sinif_sube_listesi()
        siniflar = _ss.get("siniflar", [str(i) for i in range(1, 13)])
        dis_sinif = st.selectbox("Sınıf", siniflar, key="dis_sinif")
    with dc4:
        dis_ders = st.text_input("Ders", value="Genel", key="dis_ders")

    dis_tarih = st.date_input("Sınav Tarihi", value=datetime.now(), key="dis_tarih")

    # ═══ EXCEL / CSV YUKLE ═══
    if "Excel" in yukleme_modu:
        st.markdown("#### 📊 Excel / CSV ile Toplu Yükleme")
        st.caption("Dosyada şu sütunlar olmalı: **ad** (veya ad_soyad), **numara** (veya no), **puan** (veya skor), "
                    "**dogru** (opsiyonel), **yanlis** (opsiyonel), **bos** (opsiyonel)")

        uploaded = st.file_uploader("Excel veya CSV Yükle", type=["xlsx", "xls", "csv"], key="dis_excel_file")
        if uploaded:
            try:
                import pandas as pd
                if uploaded.name.endswith(".csv"):
                    df = pd.read_csv(uploaded, dtype=str)
                else:
                    df = pd.read_excel(uploaded, dtype=str)

                st.success(f"✅ {len(df)} satır okundu")
                st.dataframe(df.head(10), use_container_width=True)

                # Auto-detect column mapping
                _auto_mapped = _auto_map_columns(list(df.columns))
                if _auto_mapped:
                    st.caption(f"Otomatik eslestirme: {_auto_mapped}")
                # Sutun eslestirme
                cols = list(df.columns)
                ec1, ec2, ec3, ec4, ec5 = st.columns(5)
                with ec1:
                    col_ad = st.selectbox("Ad Sütunu", cols, index=0, key="dis_col_ad")
                with ec2:
                    col_no = st.selectbox("No Sütunu", cols, index=min(1, len(cols)-1), key="dis_col_no")
                with ec3:
                    col_puan = st.selectbox("Puan Sütunu", cols, index=min(2, len(cols)-1), key="dis_col_puan")
                with ec4:
                    col_dogru = st.selectbox("Doğru (opsiyonel)", ["—"] + cols, key="dis_col_d")
                with ec5:
                    col_yanlis = st.selectbox("Yanlış (opsiyonel)", ["—"] + cols, key="dis_col_y")

                if st.button("💾 Sonuçları Kaydet", type="primary", use_container_width=True, key="dis_excel_save"):
                    if not dis_sinav_adi:
                        st.error("Sınav adı zorunludur!")
                    else:
                        saved = 0
                        for _, row in df.iterrows():
                            try:
                                ad = str(row.get(col_ad, "")).strip()
                                no = str(row.get(col_no, "")).strip()
                                puan = float(str(row.get(col_puan, 0)).replace(",", "."))
                                dogru = int(row.get(col_dogru, 0)) if col_dogru != "—" else 0
                                yanlis = int(row.get(col_yanlis, 0)) if col_yanlis != "—" else 0
                                bos = max(0, 100 - dogru - yanlis) if dogru + yanlis > 0 else 0

                                result = ExamResult(
                                    exam_id=f"dis_{dis_sinav_adi[:20]}_{dis_tarih.isoformat()}",
                                    student_id=f"{no}_A",
                                    student_name=ad,
                                    student_number=no,
                                    section="A",
                                    total_questions=dogru + yanlis + bos if dogru + yanlis > 0 else 0,
                                    correct_count=dogru,
                                    wrong_count=yanlis,
                                    empty_count=bos,
                                    score=round(min(100, max(0, puan)), 2),
                                    net_score=round(dogru - yanlis / 4, 2) if dogru + yanlis > 0 else 0,
                                    notes=f"Dis sinav: {dis_sinav_adi} ({dis_sinav_turu})",
                                )
                                store.save_result(result)
                                saved += 1
                            except Exception:
                                pass
                        st.success(f"✅ {saved}/{len(df)} sonuç kaydedildi! Tüm analizlere dahil oldu.")
                        st.rerun()
            except Exception as e:
                st.error(f"Dosya okunamadı: {e}")

    # ═══ PDF YUKLE ═══
    elif "PDF" in yukleme_modu:
        st.markdown("#### 📄 PDF Sonuç Belgesi Yükle")
        st.caption("Yayınevinin verdiği toplu veya bireysel PDF sonuç belgesini yükleyin. "
                    "Sistem PDF'den verileri çıkarmaya çalışır. Çıkaramazsa dosyayı arşivler.")

        pdf_modu = st.radio("PDF Türü", ["📋 Toplu PDF (sınıf listesi)", "👤 Bireysel PDF (tek öğrenci)"],
                             key="dis_pdf_modu", horizontal=True)

        uploaded_pdf = st.file_uploader("PDF Yükle", type=["pdf"], key="dis_pdf_file")
        if uploaded_pdf:
            pdf_bytes = uploaded_pdf.read()
            st.success(f"✅ {uploaded_pdf.name} yüklendi ({len(pdf_bytes)//1024} KB)")

            # PyMuPDF ile metin cikarmaya calis
            extracted_text = ""
            try:
                import fitz
                doc = fitz.open(stream=pdf_bytes, filetype="pdf")
                for page in doc:
                    extracted_text += page.get_text()
                doc.close()
                if extracted_text.strip():
                    with st.expander("📖 PDF'den Çıkarılan Metin", expanded=False):
                        st.text(extracted_text[:3000])
            except Exception:
                pass

            # PDF arsivle
            _arsiv_path = os.path.join(os.path.dirname(os.path.dirname(os.path.abspath(__file__))),
                                       "data", "olcme", "dis_sinav_pdf")
            os.makedirs(_arsiv_path, exist_ok=True)
            _fname = f"{dis_sinav_adi or 'sinav'}_{dis_tarih.isoformat()}_{uploaded_pdf.name}"
            _fpath = os.path.join(_arsiv_path, _fname)
            with open(_fpath, "wb") as f:
                f.write(pdf_bytes)
            st.info(f"📁 PDF arşivlendi: {_fname}")

            # PDF onizleme
            st.download_button("📥 Orijinal PDF İndir", data=pdf_bytes,
                               file_name=uploaded_pdf.name, mime="application/pdf",
                               key="dis_pdf_download", use_container_width=True)

            # AI ile parse etmeye calis
            if extracted_text.strip() and len(extracted_text) > 50:
                if st.button("🤖 AI ile Sonuçları Çıkar", key="dis_pdf_ai_parse", type="primary",
                               use_container_width=True):
                    try:
                        from utils.smarti_helper import _get_client
                        client = _get_client()
                        if client:
                            with st.spinner("AI PDF analiz ediyor..."):
                                resp = client.chat.completions.create(
                                    model="gpt-4o-mini",
                                    messages=[
                                        {"role": "system", "content":
                                         "PDF'den ogrenci sinav sonuclarini cikar. "
                                         "JSON array formatinda dondur: [{\"ad\": \"...\", \"no\": \"...\", "
                                         "\"puan\": 85, \"dogru\": 17, \"yanlis\": 3, \"bos\": 0}] "
                                         "Sadece JSON dondur, baska bir sey yazma."},
                                        {"role": "user", "content": f"PDF metni:\n{extracted_text[:4000]}"},
                                    ],
                                    max_tokens=2000, temperature=0.1,
                                )
                                ai_text = resp.choices[0].message.content or ""
                                # JSON parse
                                import json
                                # AI bazen ```json ... ``` ile sarar
                                ai_clean = ai_text.strip()
                                if ai_clean.startswith("```"):
                                    ai_clean = ai_clean.split("\n", 1)[-1].rsplit("```", 1)[0]
                                parsed = json.loads(ai_clean)
                                if isinstance(parsed, list) and parsed:
                                    st.session_state["_dis_pdf_parsed"] = parsed
                                    st.success(f"✅ {len(parsed)} öğrenci sonucu çıkarıldı!")
                                    import pandas as pd
                                    st.dataframe(pd.DataFrame(parsed), use_container_width=True)
                                else:
                                    st.warning("PDF'den sonuç çıkarılamadı. Manuel giriş yapın.")
                    except Exception as e:
                        st.error(f"AI parse hatası: {e}")

                # Parse edilmis veriyi kaydet
                if st.session_state.get("_dis_pdf_parsed"):
                    if st.button("💾 Çıkarılan Sonuçları Kaydet", key="dis_pdf_save",
                                   use_container_width=True):
                        saved = 0
                        for item in st.session_state["_dis_pdf_parsed"]:
                            try:
                                result = ExamResult(
                                    exam_id=f"dis_{dis_sinav_adi[:20]}_{dis_tarih.isoformat()}",
                                    student_id=f"{item.get('no', '')}_{item.get('sube', 'A')}",
                                    student_name=item.get("ad", "?"),
                                    student_number=str(item.get("no", "")),
                                    section=item.get("sube", "A"),
                                    total_questions=int(item.get("dogru", 0)) + int(item.get("yanlis", 0)) + int(item.get("bos", 0)),
                                    correct_count=int(item.get("dogru", 0)),
                                    wrong_count=int(item.get("yanlis", 0)),
                                    empty_count=int(item.get("bos", 0)),
                                    score=round(float(item.get("puan", 0)), 2),
                                    net_score=round(int(item.get("dogru", 0)) - int(item.get("yanlis", 0)) / 4, 2),
                                    notes=f"Dis sinav (PDF): {dis_sinav_adi} ({dis_sinav_turu})",
                                )
                                store.save_result(result)
                                saved += 1
                            except Exception:
                                pass
                        st.success(f"✅ {saved} sonuç kaydedildi!")
                        st.session_state.pop("_dis_pdf_parsed", None)
                        st.rerun()
            else:
                st.info("PDF'den metin çıkarılamadı. PDF arşivlendi — sonuçları Manuel Giriş ile ekleyebilirsiniz.")

    # ═══ MANUEL GIRIS ═══
    else:
        st.markdown("#### ✏️ Manuel Sonuç Girişi")
        st.caption("Öğrencileri tek tek girin veya listeden seçin")

        from utils.shared_data import load_shared_students
        students = load_shared_students()
        try:
            sinif_stu = [s for s in students if str(s.get("sinif", "")) == str(dis_sinif)
                         and s.get("durum", "aktif") == "aktif"]
        except Exception:
            sinif_stu = []

        if sinif_stu:
            st.markdown(f"**{dis_sinif}. Sınıf — {len(sinif_stu)} öğrenci**")
            with st.form("dis_manuel_form"):
                import pandas as pd
                rows = []
                for s in sinif_stu:
                    ad = f"{s.get('ad', '')} {s.get('soyad', '')}".strip()
                    no = s.get("numara", "")
                    rows.append({"ad": ad, "no": no, "puan": 0, "dogru": 0, "yanlis": 0, "bos": 0})
                df_edit = pd.DataFrame(rows)
                edited = st.data_editor(df_edit, use_container_width=True, num_rows="fixed",
                                         key="dis_manuel_editor")

                if st.form_submit_button("💾 Kaydet", type="primary", use_container_width=True):
                    if not dis_sinav_adi:
                        st.error("Sınav adı zorunludur!")
                    else:
                        saved = 0
                        for _, row in edited.iterrows():
                            puan = float(row.get("puan", 0))
                            if puan <= 0:
                                continue
                            result = ExamResult(
                                exam_id=f"dis_{dis_sinav_adi[:20]}_{dis_tarih.isoformat()}",
                                student_id=f"{row['no']}_A",
                                student_name=row["ad"],
                                student_number=str(row["no"]),
                                section="A",
                                total_questions=int(row.get("dogru", 0)) + int(row.get("yanlis", 0)) + int(row.get("bos", 0)),
                                correct_count=int(row.get("dogru", 0)),
                                wrong_count=int(row.get("yanlis", 0)),
                                empty_count=int(row.get("bos", 0)),
                                score=round(min(100, max(0, puan)), 2),
                                net_score=round(int(row.get("dogru", 0)) - int(row.get("yanlis", 0)) / 4, 2),
                                notes=f"Dis sinav (manuel): {dis_sinav_adi} ({dis_sinav_turu})",
                            )
                            store.save_result(result)
                            saved += 1
                        st.success(f"✅ {saved} sonuç kaydedildi! Tüm analizlere dahil oldu.")
                        st.rerun()
        else:
            st.warning(f"{dis_sinif}. Sınıfta öğrenci bulunamadı. KOİ > Sınıf Listeleri'nden öğrenci ekleyin.")
            # Serbest giriş
            with st.form("dis_manuel_serbest"):
                mc1, mc2 = st.columns(2)
                with mc1:
                    m_ad = st.text_input("Ad Soyad *")
                    m_puan = st.number_input("Puan *", 0.0, 100.0, 0.0, key="dis_m_puan")
                with mc2:
                    m_no = st.text_input("Öğrenci No *")
                    m_dogru = st.number_input("Doğru", 0, 200, 0, key="dis_m_d")
                m_yanlis = st.number_input("Yanlış", 0, 200, 0, key="dis_m_y")
                if st.form_submit_button("💾 Kaydet"):
                    if m_ad and m_no and m_puan > 0:
                        result = ExamResult(
                            exam_id=f"dis_{dis_sinav_adi[:20]}_{dis_tarih.isoformat()}",
                            student_id=f"{m_no}_A",
                            student_name=m_ad,
                            student_number=m_no,
                            total_questions=m_dogru + m_yanlis,
                            correct_count=m_dogru,
                            wrong_count=m_yanlis,
                            score=round(m_puan, 2),
                            net_score=round(m_dogru - m_yanlis / 4, 2),
                            notes=f"Dis sinav (manuel): {dis_sinav_adi} ({dis_sinav_turu})",
                        )
                        store.save_result(result)
                        st.success("✅ Kaydedildi!")
                        st.rerun()


def _render_ogrenci_sinav_sade():
    """Ogrenci icin sade sinav ekrani — giris yapmis, aktif sinavlari gorup cozer."""
    store = get_store()

    # Aktif oturum varsa sinavi goster
    if st.session_state.get('exam_session') and st.session_state.get('exam_started'):
        _render_sinav_cozme(store)
        return

    # Sonuc gosterilecekse
    if st.session_state.get('exam_result'):
        _render_sinav_sonucu(store)
        return

    # Dogrulanmis sinav varsa ogrenci bilgi formuna git
    if st.session_state.get('verified_exam_id'):
        _render_ogrenci_sinav(store)
        return

    # Ogrenci bilgilerini al
    from utils.auth import AuthManager as _AM
    auth_user = _AM.get_current_user()
    ogrenci_adi = auth_user.get("name", "")
    ogrenci_sinif = auth_user.get("sinif", "")
    ogrenci_sube = auth_user.get("sube", "")

    st.markdown(f"""
    <div style="background:linear-gradient(135deg,#0f172a,#1e1b4b);border-radius:16px;
    padding:20px 24px;margin-bottom:16px;border:1.5px solid rgba(99,102,241,0.25);">
    <div style="font-size:1.2rem;font-weight:900;color:#c7d2fe;">📝 Sınavlarım</div>
    <div style="font-size:.85rem;color:#818cf8;margin-top:4px;">
    Merhaba {ogrenci_adi}! Aktif sınavlarını aşağıda görebilirsin.</div>
    </div>""", unsafe_allow_html=True)

    # Aktif sinavlari getir
    all_exams = store.get_exams()
    aktif_sinavlar = [e for e in all_exams if e.status == "active"]

    # Sinif filtresi — ogrencinin sinifina uygun sinavlar
    if ogrenci_sinif:
        try:
            sinif_int = int(ogrenci_sinif)
            sinif_uygun = [e for e in aktif_sinavlar if e.grade == sinif_int]
            if sinif_uygun:
                aktif_sinavlar = sinif_uygun
        except (ValueError, TypeError):
            pass

    if not aktif_sinavlar:
        st.info("Şu anda aktif sınavın bulunmuyor. Öğretmenin sınav başlattığında burada görünecek.")
        return

    # Her aktif sinav icin kart
    for exam in aktif_sinavlar:
        # Bu sinavi daha once cozmis mi?
        sessions = store.get_sessions(exam_id=exam.id)
        student_id = f"{auth_user.get('student_number', auth_user.get('username', ''))}_{ogrenci_sube or 'A'}"
        my_session = next((s for s in sessions if s.student_id == student_id), None)
        cozuldu = my_session and my_session.status == "submitted"

        if cozuldu:
            # Sonuc goster
            my_result = store.get_result_by_session(my_session.id) if my_session else None
            puan = my_result.score if my_result else 0
            p_clr = "#22c55e" if puan >= 70 else ("#f59e0b" if puan >= 50 else "#ef4444")
            st.markdown(f"""<div style="background:#0f172a;border-radius:12px;padding:14px 18px;
            margin:6px 0;border-left:4px solid {p_clr};">
            <div style="display:flex;justify-content:space-between;align-items:center;">
            <div>
            <div style="font-size:.92rem;font-weight:700;color:#e2e8f0;">✅ {exam.name}</div>
            <div style="font-size:.78rem;color:#94a3b8;">{exam.subject} · {len(exam.question_ids)} soru</div>
            </div>
            <div style="font-size:1.8rem;font-weight:900;color:{p_clr};">{puan:.0f}</div>
            </div></div>""", unsafe_allow_html=True)
        else:
            # Sinava basla butonu
            st.markdown(f"""<div style="background:linear-gradient(135deg,#052e16,#14532d);
            border-radius:12px;padding:14px 18px;margin:6px 0;border:1.5px solid rgba(34,197,94,0.3);">
            <div style="font-size:.92rem;font-weight:700;color:#86efac;">📝 {exam.name}</div>
            <div style="font-size:.78rem;color:#4ade80;margin-top:2px;">
            {exam.subject} · {len(exam.question_ids)} soru · {exam.duration_minutes} dk</div>
            </div>""", unsafe_allow_html=True)

            if st.button(f"🚀 Sınava Başla — {exam.name}", key=f"stu_start_{exam.id}",
                           type="primary", use_container_width=True):
                st.session_state['verified_exam_id'] = exam.id
                st.session_state['verified_exam_code'] = getattr(exam, 'access_code', '')
                st.rerun()


def _render_sinav_uygula_sade(store: DataStore):
    """Sade sinav uygulama — ogretmen 3 hamlede sinavi uygular ve degerlendirir."""

    st.markdown("""
    <div style="background:linear-gradient(135deg,#0f172a,#1e293b);border-radius:14px;
    padding:14px 18px;margin-bottom:12px;border:1px solid rgba(34,197,94,0.2);">
    <div style="font-size:.9rem;font-weight:700;color:#86efac;">📡 Sınav Uygula & Değerlendir</div>
    <div style="font-size:.75rem;color:#64748b;margin-top:2px;">
    1) Sınavı aktifleştir → 2) Öğrenciler şifre ile girer → 3) Süre bitince değerlendir</div>
    </div>""", unsafe_allow_html=True)

    all_exams = store.get_exams()
    if not all_exams:
        st.info("Henüz sınav oluşturulmamış. 'Sınav Oluştur' sekmesinden başlayın.")
        return

    # Aktif sinavlar ust kisimda
    aktif = [e for e in all_exams if e.status == "active"]
    bekleyen = [e for e in all_exams if e.status in ("created", "draft")]
    bitmis = [e for e in all_exams if e.status == "completed"]

    # ── AKTİF SINAVLAR ──
    if aktif:
        for exam in aktif:
            sessions = store.get_sessions(exam_id=exam.id)
            submitted = len([s for s in sessions if s.status == "submitted"])
            devam = len([s for s in sessions if s.status == "in_progress"])
            access_code = getattr(exam, "access_code", "") or ""

            st.markdown(f"""<div style="background:linear-gradient(135deg,#052e16,#14532d);
            border-radius:14px;padding:16px 20px;margin:8px 0;border:1.5px solid rgba(34,197,94,0.3);">
            <div style="display:flex;justify-content:space-between;align-items:center;">
            <div>
            <div style="font-size:1rem;font-weight:700;color:#86efac;">🟢 {exam.name}</div>
            <div style="font-size:.82rem;color:#4ade80;margin-top:2px;">
            {_grade_label(exam.grade)} · {exam.subject} · {len(exam.question_ids)} soru · {exam.duration_minutes} dk</div>
            </div>
            <div style="text-align:right;">
            <div style="font-size:1.5rem;font-weight:900;color:#22c55e;">{access_code}</div>
            <div style="font-size:.65rem;color:#64748b;">Erişim Kodu</div>
            </div></div>
            <div style="display:flex;gap:20px;margin-top:8px;font-size:.82rem;color:#94a3b8;">
            <span>👨‍🎓 Katılımcı: {len(sessions)}</span>
            <span>🔄 Devam Eden: {devam}</span>
            <span>✅ Tamamlayan: {submitted}</span>
            </div></div>""", unsafe_allow_html=True)

            bc1, bc2, bc3 = st.columns(3)
            with bc1:
                if submitted > 0:
                    if st.button(f"📊 DEĞERLENDİR ({submitted} öğrenci)", key=f"sade_grade_{exam.id}",
                                   type="primary", use_container_width=True):
                        with st.spinner("Puanlama yapılıyor..."):
                            grader = AutoGrader(store)
                            results = grader.grade_exam_all(exam.id)
                            st.success(f"✅ {len(results)} öğrenci puanlandı!")
                            st.rerun()
            with bc2:
                if st.button("🔴 Sınavı Bitir", key=f"sade_end_{exam.id}", use_container_width=True):
                    exam.status = "completed"
                    store.save_exam(exam)
                    st.success("Sınav tamamlandı!")
                    st.rerun()
            with bc3:
                if st.button("📋 QR & Paylaş", key=f"sade_share_{exam.id}", use_container_width=True):
                    st.session_state[f"_show_qr_{exam.id}"] = not st.session_state.get(f"_show_qr_{exam.id}", False)

            # QR ve paylaşım paneli
            if st.session_state.get(f"_show_qr_{exam.id}"):
                try:
                    import qrcode
                    from utils.shared_data import load_kurum_profili
                    _profil = load_kurum_profili()
                    _base_url = _profil.get("web", "") or "http://localhost:8501"
                    import urllib.parse as _up_qr
                    _qr_link = f"{_base_url}?{_up_qr.urlencode({'sinav_kod': access_code, 'modul': 'olcme', 'aksiyon': 'sinav_giris'})}"
                    _qr = qrcode.QRCode(version=1, error_correction=qrcode.constants.ERROR_CORRECT_M, box_size=6, border=2)
                    _qr.add_data(_qr_link)
                    _qr.make(fit=True)
                    _qr_img = _qr.make_image(fill_color="black", back_color="white")
                    _qr_buf = io.BytesIO()
                    _qr_img.save(_qr_buf, format='PNG')
                    _qr_buf.seek(0)
                    qc1, qc2 = st.columns([1, 2])
                    with qc1:
                        st.image(_qr_buf, width=150)
                    with qc2:
                        st.code(access_code, language=None)
                        st.caption("Öğrenciler bu kodu veya QR'ı kullanarak sınava girer")
                except Exception:
                    st.code(access_code, language=None)
                    st.caption("Erişim kodunu öğrencilere paylaşın")

            # Sonuçlar varsa göster
            exam_results = store.get_results(exam_id=exam.id)
            if exam_results:
                with st.expander(f"📊 Sonuçlar ({len(exam_results)} öğrenci)", expanded=False):
                    import pandas as pd
                    df_rows = []
                    for r in sorted(exam_results, key=lambda x: x.score or 0, reverse=True):
                        df_rows.append({
                            "Öğrenci": r.student_name or "?",
                            "No": r.student_number or "-",
                            "Puan": f"{r.score:.0f}" if r.score else "-",
                            "Net": f"{r.net_score:.1f}" if r.net_score else "-",
                            "D": r.correct_count, "Y": r.wrong_count, "B": r.empty_count,
                        })
                    st.dataframe(pd.DataFrame(df_rows), use_container_width=True)

    # ── BEKLEYEN SINAVLAR ──
    if bekleyen:
        st.markdown("---")
        st.markdown("**Başlatılmayı Bekleyen Sınavlar:**")
        for exam in bekleyen:
            bc1, bc2 = st.columns([3, 1])
            with bc1:
                st.markdown(f"⚪ **{exam.name}** — {_grade_label(exam.grade)} · {exam.subject} · {len(exam.question_ids)} soru")
            with bc2:
                if st.button("🟢 Başlat", key=f"sade_start_{exam.id}", type="primary", use_container_width=True):
                    if not getattr(exam, "access_code", "") or not exam.access_code:
                        exam.access_code = _generate_access_code()
                    exam.status = "active"
                    store.save_exam(exam)
                    st.success(f"✅ Sınav başlatıldı! Erişim kodu: **{exam.access_code}**")
                    st.rerun()

    # ── BİTMİŞ SINAVLAR ──
    if bitmis:
        with st.expander(f"🏁 Tamamlanan Sınavlar ({len(bitmis)})", expanded=False):
            for exam in bitmis:
                exam_results = store.get_results(exam_id=exam.id)
                result_cnt = len(exam_results)
                avg = round(sum(r.score for r in exam_results if r.score) / result_cnt, 1) if result_cnt else 0
                st.markdown(f"✅ **{exam.name}** — {result_cnt} öğrenci · Ort: {avg}")

    # ── Eski panel (gizli, geriye dönük uyumluluk) ──
    with st.expander("⚙️ Gelişmiş Sınav Yönetimi", expanded=False):
        _render_sinav_yonetimi(store)
        st.markdown("---")
        st.markdown("**Öğrenci Sınav Girişi (test):**")
        _render_ogrenci_sinav(store)


def _render_sinav_yonetimi(store: DataStore):
    """Ogretmen sinav yonetim paneli."""

    # Zamanlanmis sinavlari otomatik aktiflestir
    _now_iso = datetime.now().isoformat()
    for _ze in store.get_exams():
        if _ze.status == 'created' and getattr(_ze, 'scheduled_start', '') and _ze.scheduled_start <= _now_iso:
            _ze.status = 'active'
            store.save_exam(_ze)

    st.markdown("### 👨‍🏫 Sınav Yönetimi")

    # Sinav listesi
    all_exams = store.get_exams()

    if not all_exams:
        st.info("Henuz sinav olusturulmamis. 'Sınav Oluştur' sekmesinden sinav olusturun.")
        return

    st.markdown("**Mevcut Sınavlar:**")

    for exam in all_exams:
        sessions = store.get_sessions(exam_id=exam.id)
        submitted_count = len([s for s in sessions if s.status == 'submitted'])

        status_icon = "🟢" if exam.status == 'active' else "🔴" if exam.status == 'completed' else "⚪"
        with st.expander(f"{status_icon} {exam.name} ({_grade_label(exam.grade)} - {exam.subject}) - {exam.status.upper()}"):
            col1, col2, col3 = st.columns(3)

            with col1:
                st.write(f"**ID:** {exam.id}")
                st.write(f"**Soru Sayısı:** {len(exam.question_ids)}")
                st.write(f"**Sure:** {exam.duration_minutes} dk")

            with col2:
                st.write(f"**Durum:** {exam.status}")
                st.write(f"**Katilimci:** {len(sessions)}")
                st.write(f"**Tamamlayan:** {submitted_count}")

            with col3:
                # Durum degistirme butonlari
                if exam.status != 'active':
                    if st.button("🟢 Aktiflestir", key=f"activate_{exam.id}"):
                        # Erisim kodu yoksa olustur
                        if not getattr(exam, 'access_code', '') or not exam.access_code:
                            exam.access_code = _generate_access_code()
                        exam.status = 'active'
                        store.save_exam(exam)
                        st.success("Sınav aktiflestirildi!")
                        st.rerun()
                else:
                    if st.button("🔴 Pasiflestir", key=f"deactivate_{exam.id}"):
                        exam.status = 'completed'
                        store.save_exam(exam)
                        st.warning("Sınav pasiflestirildi!")
                        st.rerun()

                # Toplu puanlama
                if submitted_count > 0:
                    if st.button("📊 Toplu Puanla", key=f"grade_all_{exam.id}"):
                        grader = AutoGrader(store)
                        results = grader.grade_exam_all(exam.id)
                        st.success(f"{len(results)} ogrenci puanlandi!")

            # Aktif sinav için erisim kodu ve paylasim paneli
            if exam.status == 'active':
                access_code = getattr(exam, 'access_code', '') or ''
                if not access_code:
                    access_code = _generate_access_code()
                    exam.access_code = access_code
                    store.save_exam(exam)

                st.markdown("---")
                st.markdown("#### 🔗 Sınav Erisim Bilgileri")

                code_col1, code_col2 = st.columns([2, 1])
                with code_col1:
                    st.markdown(f"""
<div style="background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
            padding: 20px; border-radius: 12px; text-align: center; color: white;">
    <div style="font-size: 14px; opacity: 0.9;">SINAV ERISIM KODU</div>
    <div style="font-size: 36px; font-weight: bold; letter-spacing: 8px; margin: 10px 0;">
        {access_code}
    </div>
    <div style="font-size: 12px; opacity: 0.8;">{exam.name} | {exam.duration_minutes} dk | {len(exam.question_ids)} soru</div>
</div>""", unsafe_allow_html=True)

                with code_col2:
                    st.markdown("<br>", unsafe_allow_html=True)
                    # Yeni kod uret butonu
                    if st.button("🔄 Yeni Kod Uret", key=f"newcode_{exam.id}", use_container_width=True):
                        exam.access_code = _generate_access_code()
                        store.save_exam(exam)
                        st.rerun()

                # QR ile giriş URL'si göster
                _kurum_ayar = _load_kurum_ayarlari()
                _app_url = _kurum_ayar.get("app_base_url", "").strip().rstrip("/")
                if _app_url:
                    import urllib.parse as _up
                    _qr_full_url = f"{_app_url}?{_up.urlencode({'sinav_kod': access_code, 'modul': 'olcme', 'aksiyon': 'sinav_giris'})}"
                    st.markdown(f"""
<div style="background: linear-gradient(135deg, #C8952E 0%, #E8C975 100%);
            padding: 12px; border-radius: 10px; text-align: center; color: white; margin-top: 8px;">
    <div style="font-size: 11px; opacity: 0.9;">QR KOD BAGLANTI LINKI</div>
    <div style="font-size: 10px; word-break: break-all; margin-top: 4px; background: rgba(0,0,0,0.15); padding: 6px; border-radius: 6px;">
        {_qr_full_url}
    </div>
    <div style="font-size: 10px; margin-top: 4px; opacity: 0.8;">Sınav kitapçığı ve optik form QR kodları bu URL'ye yönlendirir</div>
</div>""", unsafe_allow_html=True)
                else:
                    st.caption("Ayarlar > Uygulama URL'si girerek QR kodlara otomatik bağlantı ekleyebilirsiniz.")

                # Mail + SMS paylasim
                st.markdown("**📤 Veliye / Öğrenciye Gonder:**")
                _davet_yontemi = st.radio(
                    "Gonderim Yontemi",
                    ["📧 E-Posta", "📱 SMS"],
                    horizontal=True,
                    key=f"davet_yontem_{exam.id}",
                    label_visibility="collapsed"
                )

                if _davet_yontemi == "📧 E-Posta":
                    dv_col1, dv_col2 = st.columns([3, 1])
                    with dv_col1:
                        davet_email = st.text_input(
                            "E-Posta Adresi",
                            placeholder="veli@ornek.com",
                            key=f"davet_email_{exam.id}",
                            label_visibility="collapsed"
                        )
                    with dv_col2:
                        if st.button("📧 Mail Gonder", key=f"mail_send_{exam.id}",
                                      type="primary", use_container_width=True):
                            if davet_email and "@" in davet_email:
                                _kurum_adi = _load_kurum_ayarlari().get("kurum_adi", "SmartCampus AI")
                                mail_link = _generate_sinav_davet_email(
                                    davet_email, exam.name, access_code,
                                    exam.duration_minutes, len(exam.question_ids), _kurum_adi
                                )
                                st.session_state[f"davet_link_{exam.id}"] = mail_link
                            else:
                                st.error("Gecerli bir e-posta adresi girin.")

                    _d_link = st.session_state.get(f"davet_link_{exam.id}")
                    if _d_link:
                        st.markdown(f'<a href="{_d_link}" style="display:inline-block;'
                                    f'background-color:#1e3a5f;color:white;padding:10px 24px;border-radius:8px;'
                                    f'text-decoration:none;font-weight:bold;font-size:14px;">'
                                    f'📧 Mail Uygulamasinda Ac</a>', unsafe_allow_html=True)

                else:  # SMS
                    sms_col1, sms_col2 = st.columns([3, 1])
                    with sms_col1:
                        davet_tel = st.text_input(
                            "Telefon Numarasi",
                            placeholder="05XX XXX XX XX",
                            key=f"davet_tel_{exam.id}",
                            label_visibility="collapsed"
                        )
                    with sms_col2:
                        if st.button("📱 SMS Gonder", key=f"sms_send_{exam.id}",
                                      type="primary", use_container_width=True):
                            if davet_tel and len(davet_tel.replace(" ", "").replace("-", "")) >= 10:
                                _kurum_adi = _load_kurum_ayarlari().get("kurum_adi", "SmartCampus AI")
                                sms_link = _generate_sinav_davet_sms(
                                    davet_tel, exam.name, access_code,
                                    exam.duration_minutes, len(exam.question_ids), _kurum_adi
                                )
                                st.session_state[f"davet_link_{exam.id}"] = sms_link
                            else:
                                st.error("Gecerli bir telefon numarasi girin.")

                    _d_link = st.session_state.get(f"davet_link_{exam.id}")
                    if _d_link and _d_link.startswith("sms:"):
                        st.markdown(f'<a href="{_d_link}" style="display:inline-block;'
                                    f'background-color:#C8952E;color:white;padding:10px 24px;border-radius:8px;'
                                    f'text-decoration:none;font-weight:bold;font-size:14px;">'
                                    f'📱 SMS Gonder</a>', unsafe_allow_html=True)


def _render_oturum_takibi(store: DataStore):
    """Sinav oturumlari takip ekrani."""
    st.markdown("### 📋 Oturum Takibi")

    # Sinav secimi
    all_exams = store.get_exams()

    if not all_exams:
        st.info("Henüz sınav bulunmuyor.")
        return

    exam_options = {f"{e.name} ({e.id[-6:]})": e for e in all_exams}
    selected_exam_name = st.selectbox("Sınav Seç", list(exam_options.keys()), key="session_exam")
    selected_exam = exam_options[selected_exam_name]

    # Oturumlari listele
    sessions = store.get_sessions(exam_id=selected_exam.id)

    if not sessions:
        st.info("Bu sınavda henüz oturum yok.")
        return

    st.markdown(f"**{len(sessions)} oturum bulundu:**")

    # Tablo formatinda goster
    session_data = []
    for s in sessions:
        result = store.get_result_by_session(s.id)
        session_data.append({
            "Öğrenci": s.student_name,
            "Numara": s.student_number,
            "Şube": s.section,
            "Durum": {"not_started": "⏳ Başlamadı", "in_progress": "🔄 Devam Ediyor",
                      "submitted": "✅ Tamamlandı", "expired": "⏰ Süre Doldu"}.get(s.status, s.status),
            "Başlangıç": s.started_at[:16] if s.started_at else "-",
            "Puan": f"{result.score:.1f}" if result else "-",
            "Net": f"{result.net_score:.2f}" if result else "-"
        })

    df = pd.DataFrame(session_data)
    st.dataframe(df, use_container_width=True)

    # Excel export
    if st.button("📥 Excel İndir"):

        excel_buffer = io.BytesIO()
        df.to_excel(excel_buffer, index=False)
        excel_buffer.seek(0)
        st.download_button(
            "📥 İndir",
            excel_buffer.getvalue(),
            file_name=f"{selected_exam.id}_oturumlar.xlsx",
            mime="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet"
        )


