        selected_classes = st.multiselect(
            "Optik form oluşturulacak sınıfları seçin",
            options=classes,
            default=[],
            key="optik_sinif_sec"
        )

        if not selected_classes:
            st.info("👆 Form oluşturmak için en az bir sınıf seçin.")
            return

