# MEB Excel sütun adı eşleştirme sözlüğü
_MEB_COLUMN_ALIASES = {
    "week": ["hafta", "haftalar", "week", "süre", "sure", "ay/hafta", "ay / hafta", "ay-hafta"],
    "unit": ["ünite", "unite", "ünite adı", "unite adi", "ünite / tema", "tema", "ünite/tema",
             "öğrenme alanı", "ogrenme alani", "öğrenme alanı / ünite"],
    "topic": ["konu", "konular", "topic", "konu / alt konu", "alt konu", "konu başlığı",
              "konu basligi", "etkinlik", "etkinlikler"],
    "learning_outcomes": ["kazanım", "kazanımlar", "kazanim", "kazanimlar", "öğrenme çıktısı",
                          "öğrenme çıktıları", "ogrenme ciktisi", "ogrenme ciktilari",
                          "öğrenme çıktısı / kazanım", "beceri", "beceriler", "yeterlik"],
    "hours": ["saat", "ders saati", "süre (saat)", "sure", "süre", "ders saati sayısı"],
    "methods": ["yöntem", "yöntemler", "yöntem ve teknik", "yöntem ve teknikler",
                "yontem", "öğretme-öğrenme yöntem ve teknikleri", "strateji"],
    "assessment": ["ölçme", "ölçme değerlendirme", "ölçme ve değerlendirme",
                   "değerlendirme", "olcme", "degerlendirme", "ölçme-değerlendirme"],
    "notes": ["açıklama", "açıklamalar", "not", "notlar", "aciklama", "diğer", "diger"],
}


def _auto_map_columns(df_columns: list) -> dict:
    """DataFrame sütun adlarını otomatik eşleştir."""
    mapping = {}
    df_cols_lower = {col: col.strip().lower() for col in df_columns}

    for field_name, aliases in _MEB_COLUMN_ALIASES.items():
        for col, col_lower in df_cols_lower.items():
            if col_lower in aliases or any(alias in col_lower for alias in aliases):
                mapping[field_name] = col
                break

    return mapping


