def _resolve_kazanim_month(grade: int, subject: str, kazanim_text: str) -> dict:
    """Kazanım metninden ay ve ünite bilgisini çöz.
    Return: {"month_period": [...], "unit_name": "...", "ay_tags": [...]}
    """
    from models.olcme_degerlendirme import get_store as _get_store
    store = _get_store()
    plans = store.get_annual_plans(grade=grade, subject=subject)

    # 1) Yıllık planda ara - kazanım metninin ilk 30 karakteriyle eşle
    kaz_lower = kazanim_text.strip().lower()[:50]
    for plan in plans:
        for lo in plan.learning_outcomes:
            if kaz_lower in lo.strip().lower() or lo.strip().lower()[:50] in kaz_lower:
                # Bu kazanım bu plan kaydında - hafta bilgisinden ayı çıkar
                week_str = plan.week.upper() if plan.week else ""
                months = []
                for m in _TR_MONTHS + _EN_MONTHS:
                    if m in week_str:
                        normalized = _MONTH_NORMALIZE.get(m, m)
                        if normalized not in months:
                            months.append(normalized)
                        break
                if months:
                    ay_tags = []
                    for m in months:
                        tag = "ay_" + m.lower().replace('ı', 'i').replace('ş', 's').replace('ü', 'u').replace('ö', 'o').replace('ç', 'c')
                        ay_tags.append(tag)
                    return {"month_period": months, "unit_name": plan.unit, "ay_tags": ay_tags}

    # 2) Manuel eşleme tablosuna bak (yıllık planda olmayan dersler için)
    manual = _MANUAL_SUBJECT_MONTHS.get((grade, subject))
    if manual:
        best_months = None
        best_score = 0
        for keywords, months in manual:
            score = sum(1 for kw in keywords if kw.lower() in kaz_lower)
            if score > best_score:
                best_score = score
                best_months = months
        if best_months:
            ay_tags = []
            for m in best_months:
                tag = "ay_" + m.lower().replace('ı', 'i').replace('ş', 's').replace('ü', 'u').replace('ö', 'o').replace('ç', 'c')
                ay_tags.append(tag)
            return {"month_period": best_months, "unit_name": "", "ay_tags": ay_tags}

    # 3) Ünite sırasına göre kronolojik dağıt (plans varsa)
    if plans:
        plans_sorted = sorted(plans, key=lambda p: p.week or "")
        units_seen = []
        for p in plans_sorted:
            if p.unit and p.unit not in units_seen:
                units_seen.append(p.unit)
        # Kronolojik sıra: 10 ay / ünite sayısı
        all_months = ['Eylül', 'Ekim', 'Kasım', 'Aralık', 'Ocak', 'Şubat', 'Mart', 'Nisan', 'Mayıs', 'Haziran']
        if units_seen:
            months_per_unit = max(1, len(all_months) // len(units_seen))
            # Kazanım metnini ünite adlarıyla eşle
            for i, unit in enumerate(units_seen):
                unit_words = [w for w in unit.lower().split() if len(w) > 3]
                if any(w in kaz_lower for w in unit_words):
                    start = i * months_per_unit
                    end = min(start + months_per_unit, len(all_months))
                    months = all_months[start:end]
                    ay_tags = ["ay_" + m.lower().replace('ı', 'i').replace('ş', 's').replace('ü', 'u').replace('ö', 'o').replace('ç', 'c') for m in months]
                    return {"month_period": months, "unit_name": unit, "ay_tags": ay_tags}

    return {"month_period": [], "unit_name": "", "ay_tags": []}


def _generate_ai_questions_batch(ders: str, grade: int, kazanimlar: list, blueprint: dict, overrides: dict = None) -> list:
    """MEB/ÖSYM pipeline ile toplu soru üretimi — fallback olarak legacy prompt.

    KURAL: Her kazanımdan EŞİT SAYIDA soru üretilir.
    """
    import os

    api_key = os.environ.get('OPENAI_API_KEY', '')
    if not api_key:
        st.error("OpenAI API anahtarı bulunamadı. .env dosyasında OPENAI_API_KEY ayarlayın.")
        return []

    # Override uygulamaları
    bp = blueprint.copy()
    if overrides:
        bp.update(overrides)

    soru_sayisi = bp.get("soru_sayisi", 12)
    zorluk_orani = bp.get("zorluk_orani", {"kolay": 30, "orta": 50, "zor": 20})

    # Zorluk oranını MEB formatına: {"Kolay": 30, "Orta": 50, "Zor": 20}
    zorluk_dist = {}
    for k, v in zorluk_orani.items():
        zorluk_dist[k.capitalize()] = v

    # Kazanım text'leri
    kaz_texts = []
    for kz in kazanimlar:
        if isinstance(kz, str):
            kaz_texts.append(kz)
        elif isinstance(kz, dict):
            kaz_texts.append(kz.get('text', kz.get('outcome_text', str(kz))))
        else:
            kaz_texts.append(str(kz))

    try:
        ai_model = bp.get("ai_model", "gpt-4o")
        motor = _get_meb_motoru(model=ai_model)
        result = motor.pipeline(
            kazanimlar=kaz_texts,
            grade=grade,
            subject=ders,
            count=soru_sayisi,
            zorluk_dist=zorluk_dist,
        )

        if "error" in result or not result.get("results"):
            raise ValueError("MEB pipeline basarisiz")

        # MEB formatını mevcut list[dict] formatına dönüştür
        valid = []
        for i, soru in enumerate(result.get("results", [])):
            if not soru.get("kok"):
                continue
            if soru.get("validator_status") == "BASARISIZ":
                continue

            sec_dict = soru.get('secenekler', {})
            sec_list = list(sec_dict.values())
            cevap = soru.get('cevap', 'A')
            harfler = list(sec_dict.keys())
            dogru_idx = harfler.index(cevap) if cevap in harfler else 0

            kaz_idx = i % len(kaz_texts) if kaz_texts else 0

            valid.append({
                'soru_tipi': 'mcq' if len(sec_list) == 4 else ('mcq5' if len(sec_list) == 5 else 'mcq'),
                'metin': soru.get('kok', ''),
                'secenekler': sec_list,
                'dogru': dogru_idx,
                'aciklama': soru.get('gerekce', ''),
                'zorluk': soru.get('zorluk', 'Orta'),
                'kazanim_index': kaz_idx,
                'beceri_etiketi': soru.get('beceri_etiketi', ''),
                'validator_score': soru.get('validator_score', 0),
                'validator_status': soru.get('validator_status', ''),
                'engine_type': soru.get('engine_type', ''),
                'veri_tablosu': soru.get('veri_tablosu'),
                'gorsel_aciklama': soru.get('gorsel_aciklama', ''),
            })
        return valid

    except Exception:
        # Fallback: eski basit prompt
        return _generate_ai_questions_batch_legacy(ders, grade, kazanimlar, blueprint, overrides)


def _generate_ai_questions_batch_legacy(ders: str, grade: int, kazanimlar: list, blueprint: dict, overrides: dict = None) -> list:
    """Eski basit prompt ile toplu soru üretimi — MEB pipeline başarısız olduğunda fallback."""
    import os, json, openai

    api_key = os.environ.get('OPENAI_API_KEY', '')
    if not api_key:
        return []

    bp = blueprint.copy()
    if overrides:
        bp.update(overrides)

    soru_sayisi = bp.get("soru_sayisi", 12)
    kaz_count = len(kazanimlar) if kazanimlar else 1
    per_kazanim = soru_sayisi // kaz_count
    extra = soru_sayisi % kaz_count
    kazanim_dagilim = {}
    for i in range(kaz_count):
        kazanim_dagilim[i] = per_kazanim + (1 if i < extra else 0)

    specs = _calculate_question_distribution(bp, soru_sayisi)

    kazanim_text = ""
    for i, k in enumerate(kazanimlar):
        kazanim_text += f"{i+1}. {k} [Bu kazanımdan {kazanim_dagilim.get(i, per_kazanim)} soru üret]\n"

    tip_dagilim = {}
    for s in specs:
        tip = s["soru_tipi"]
        tip_dagilim[tip] = tip_dagilim.get(tip, 0) + 1
    tip_text = ""
    for tip, sayi in tip_dagilim.items():
        tip_label = SORU_TIPI_LABELS.get(tip, tip)
        tip_text += f"- {tip_label}: {sayi} soru\n"

    zorluk_dagilim = {}
    for s in specs:
        z = s["zorluk"]
        zorluk_dagilim[z] = zorluk_dagilim.get(z, 0) + 1
    zorluk_text = ""
    for z, sayi in zorluk_dagilim.items():
        zorluk_text += f"- {z}: {sayi} soru\n"

    kademe_adi = {"ILKOKUL": "İlkokul", "ORTAOKUL": "Ortaokul", "LISE": "Lise"}.get(_get_kademe(grade), "Ortaokul")

    prompt = f"""Sen deneyimli bir {ders} öğretmenisin. MEB müfredatına hakim.

## GÖREV: toplam {soru_sayisi} soru hazırla
## SINIF: {_grade_label(grade)} ({kademe_adi})

## KAZANIMLAR
{kazanim_text}

## ZORLUK DAĞILIMI
{zorluk_text}

## SORU TİPİ DAĞILIMI
{tip_text}

## KURALLAR
1. Kazanımlara uygun 2. Senaryo içeren 3. mcq:4 şık, tek doğru 4. Çeldiriciler yaygın hatalara dayalı
5. {grade}. sınıf dil seviyesi 6. Her soruya açıklama ekle

## ÇIKTI (JSON)
{{"sorular": [{{"soru_tipi":"mcq","zorluk":"Kolay","kazanim_index":0,"metin":"...","secenekler":["A","B","C","D"],"dogru":0,"aciklama":"..."}}]}}"""

    def _call_api(p, expected_count):
        try:
            client = openai.OpenAI()
            max_tok = min(4096, expected_count * 350 + 200)
            response = client.chat.completions.create(
                model="gpt-4o-mini",
                messages=[
                    {"role": "system", "content": f"Sen bir {ders} öğretmenisin. Sadece JSON formatında cevap ver."},
                    {"role": "user", "content": p}
                ],
                temperature=0.7, max_tokens=max_tok
            )
            content = response.choices[0].message.content
            if "```json" in content:
                content = content.split("```json")[1].split("```")[0]
            elif "```" in content:
                content = content.split("```")[1].split("```")[0]
            data = json.loads(content.strip())
            return data.get("sorular", [])
        except Exception:
            return []

    if soru_sayisi <= 15:
        all_questions = _call_api(prompt, soru_sayisi)
    else:
        half = soru_sayisi // 2
        prompt1 = prompt.replace(f"toplam {soru_sayisi} soru", f"toplam {half} soru (1. parti)")
        prompt2 = prompt.replace(f"toplam {soru_sayisi} soru", f"toplam {soru_sayisi - half} soru (2. parti)")
        all_questions = _call_api(prompt1, half) + _call_api(prompt2, soru_sayisi - half)

    valid = []
    for q in all_questions:
        if not isinstance(q, dict) or not q.get("metin"):
            continue
        tip = q.get("soru_tipi", "mcq")
        if tip in ("mcq", "mcq5"):
            if not q.get("secenekler") or len(q.get("secenekler", [])) < 2:
                continue
        valid.append(q)
    return valid


def _generate_ai_sorular_pdf(questions: list, grade: int, subject: str, cevap_goster: bool = False) -> bytes:
    """Premium baskıya hazır sınav PDF'i — soru bölünmez, kurumsal tasarım."""
    try:
        from reportlab.lib import colors
        from reportlab.lib.pagesizes import A4
        from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
        from reportlab.lib.units import cm, mm
        from reportlab.platypus import (SimpleDocTemplate, Paragraph, Spacer, Table,
                                         TableStyle, KeepTogether, PageBreak, HRFlowable, Image)
        from reportlab.lib.enums import TA_CENTER, TA_LEFT, TA_RIGHT
    except ImportError:
        return b"PDF olusturulamadi - reportlab yuklu degil"

    from utils.shared_data import ensure_turkish_pdf_fonts
    font_name, font_bold = ensure_turkish_pdf_fonts()

    # ═══ RENK PALETİ (Diamond) ═══
    NAVY = colors.HexColor('#1a1a2e')
    GOLD = colors.HexColor('#c9a84c')
    DARK_BLUE = colors.HexColor('#16213e')
    MID_BLUE = colors.HexColor('#0f3460')
    LIGHT_BG = colors.HexColor('#f8f9fa')
    ACCENT = colors.HexColor('#e94560')
    TEXT_DARK = colors.HexColor('#1a1a2e')
    TEXT_MID = colors.HexColor('#495057')
    TEXT_LIGHT = colors.HexColor('#6c757d')
    GREEN = colors.HexColor('#198754')
    WHITE = colors.white

    buffer = io.BytesIO()
    page_w, page_h = A4

    # ═══ SAYFA ALT ÜST ÇİZGİ (header/footer) ═══
    sinif_str = _grade_label(grade)
    from datetime import datetime
    tarih = datetime.now().strftime("%d.%m.%Y")

    def _draw_page(canvas, doc):
        canvas.saveState()
        w, h = page_w, page_h
        # Üst gold çizgi
        canvas.setStrokeColor(GOLD)
        canvas.setLineWidth(2.5)
        canvas.line(1.5*cm, h - 1*cm, w - 1.5*cm, h - 1*cm)
        # Üst navy çizgi
        canvas.setStrokeColor(NAVY)
        canvas.setLineWidth(0.8)
        canvas.line(1.5*cm, h - 1.15*cm, w - 1.5*cm, h - 1.15*cm)
        # Alt gold çizgi
        canvas.setStrokeColor(GOLD)
        canvas.setLineWidth(2.5)
        canvas.line(1.5*cm, 1*cm, w - 1.5*cm, 1*cm)
        canvas.setStrokeColor(NAVY)
        canvas.setLineWidth(0.8)
        canvas.line(1.5*cm, 1.15*cm, w - 1.5*cm, 1.15*cm)
        # Sayfa no
        canvas.setFont(font_name, 8)
        canvas.setFillColor(TEXT_LIGHT)
        canvas.drawCentredString(w / 2, 0.6*cm, f"Sayfa {doc.page}")
        # Sol alt: ders + sınıf
        canvas.setFont(font_name, 7)
        canvas.drawString(1.5*cm, 0.6*cm, f"{subject} - {sinif_str}")
        # Sağ alt: tarih
        canvas.drawRightString(w - 1.5*cm, 0.6*cm, tarih)
        canvas.restoreState()

    doc = SimpleDocTemplate(buffer, pagesize=A4,
                            topMargin=1.8*cm, bottomMargin=1.8*cm,
                            leftMargin=2*cm, rightMargin=2*cm)

    styles = getSampleStyleSheet()
    # Premium stiller
    styles.add(ParagraphStyle(name='PDFTitle', fontSize=18, leading=24, alignment=TA_CENTER,
                              fontName=font_bold, textColor=NAVY, spaceAfter=2))
    styles.add(ParagraphStyle(name='PDFSubtitle', fontSize=10, leading=14, alignment=TA_CENTER,
                              fontName=font_name, textColor=GOLD, spaceAfter=8))
    styles.add(ParagraphStyle(name='PDFInfo', fontSize=9, leading=13, alignment=TA_CENTER,
                              fontName=font_name, textColor=TEXT_LIGHT, spaceAfter=16))
    styles.add(ParagraphStyle(name='PDFSoruNo', fontSize=11, leading=15, fontName=font_bold,
                              textColor=WHITE, spaceBefore=0, spaceAfter=0))
    styles.add(ParagraphStyle(name='PDFSoruMetin', fontSize=10.5, leading=15, fontName=font_name,
                              textColor=TEXT_DARK, spaceAfter=6, spaceBefore=6))
    styles.add(ParagraphStyle(name='PDFSecenek', fontSize=10, leading=14, leftIndent=12,
                              fontName=font_name, textColor=TEXT_DARK, spaceAfter=2))
    styles.add(ParagraphStyle(name='PDFCevap', fontSize=10, leading=14, leftIndent=12,
                              fontName=font_bold, textColor=GREEN, spaceAfter=2))
    styles.add(ParagraphStyle(name='PDFAciklama', fontSize=9, leading=12, leftIndent=12,
                              fontName=font_name, textColor=TEXT_MID, spaceAfter=4,
                              borderColor=colors.HexColor('#dee2e6'), borderWidth=0.5,
                              borderPadding=6, borderRadius=4))
    styles.add(ParagraphStyle(name='PDFCevapKey', fontSize=12, leading=16, alignment=TA_CENTER,
                              fontName=font_bold, textColor=NAVY, spaceAfter=8))

    elements = []

    # ═══════════════════════════════════════════════
    # KAPAK BÖLÜMÜ
    # ═══════════════════════════════════════════════
    elements.append(Spacer(1, 1.5*cm))

    # Diamond çerçeveli başlık kutusu
    kapak_data = [[Paragraph(f"<b>{subject}</b>", styles['PDFTitle'])],
                  [Paragraph(f"{sinif_str}", styles['PDFSubtitle'])],
                  [Paragraph(f"{'◆' * 12}", ParagraphStyle('diamond', fontSize=8, alignment=TA_CENTER,
                              textColor=GOLD, fontName=font_name))],
                  [Paragraph(f"{len(questions)} Soru  |  {tarih}", styles['PDFInfo'])]]
    kapak_table = Table(kapak_data, colWidths=[14*cm])
    kapak_table.setStyle(TableStyle([
        ('ALIGN', (0, 0), (-1, -1), 'CENTER'),
        ('TOPPADDING', (0, 0), (-1, -1), 8),
        ('BOTTOMPADDING', (0, 0), (-1, -1), 4),
        ('BOX', (0, 0), (-1, -1), 2, GOLD),
        ('LINEABOVE', (0, 0), (-1, 0), 1, NAVY),
        ('LINEBELOW', (0, -1), (-1, -1), 1, NAVY),
        ('BACKGROUND', (0, 0), (-1, -1), colors.HexColor('#fafbfc')),
    ]))
    elements.append(kapak_table)
    elements.append(Spacer(1, 0.8*cm))

    # Öğrenci bilgi alanı — premium çerçeve
    ogrenci_data = [
        [Paragraph(f"<b>Adı Soyadı:</b>", ParagraphStyle('lbl', fontSize=10, fontName=font_bold, textColor=NAVY)),
         ''],
        [Paragraph(f"<b>Numarası:</b>", ParagraphStyle('lbl2', fontSize=10, fontName=font_bold, textColor=NAVY)),
         ''],
        [Paragraph(f"<b>Sınıf / Şube:</b>", ParagraphStyle('lbl3', fontSize=10, fontName=font_bold, textColor=NAVY)),
         ''],
    ]
    ogrenci_table = Table(ogrenci_data, colWidths=[3.5*cm, 13*cm], rowHeights=[0.9*cm]*3)
    ogrenci_table.setStyle(TableStyle([
        ('BOX', (0, 0), (-1, -1), 1.5, NAVY),
        ('INNERGRID', (0, 0), (-1, -1), 0.5, colors.HexColor('#dee2e6')),
        ('VALIGN', (0, 0), (-1, -1), 'MIDDLE'),
        ('BACKGROUND', (0, 0), (0, -1), colors.HexColor('#f0f2f5')),
        ('LEFTPADDING', (0, 0), (-1, -1), 8),
    ]))
    elements.append(ogrenci_table)
    elements.append(Spacer(1, 0.6*cm))

    # İnce ayırıcı
    elements.append(HRFlowable(width="100%", thickness=0.5, color=GOLD, spaceAfter=0.4*cm))

    # ═══════════════════════════════════════════════
    # SORULAR — KeepTogether ile bölünme engeli
    # ═══════════════════════════════════════════════
    usable_w = page_w - 4*cm  # sol+sağ margin

    for i, q in enumerate(questions):
        soru_elements = []  # Bu sorunun tüm parçaları — KeepTogether ile sarılacak

        soru_tipi = q.get("soru_tipi", "mcq")
        zorluk = q.get("zorluk", "Orta")
        zorluk_renk = {"Kolay": "#198754", "Orta": "#fd7e14", "Zor": "#dc3545"}.get(zorluk, "#6c757d")

        # Soru numarası başlık bandı
        soru_no_data = [[
            Paragraph(f"<b>Soru {i+1}</b>", styles['PDFSoruNo']),
            Paragraph(f"<font color='{zorluk_renk}' size='8'>{zorluk}</font>",
                      ParagraphStyle('zor', fontSize=8, alignment=TA_RIGHT, fontName=font_name, textColor=WHITE))
        ]]
        soru_no_table = Table(soru_no_data, colWidths=[usable_w * 0.7, usable_w * 0.3])
        soru_no_table.setStyle(TableStyle([
            ('BACKGROUND', (0, 0), (-1, -1), NAVY),
            ('TEXTCOLOR', (0, 0), (-1, -1), WHITE),
            ('TOPPADDING', (0, 0), (-1, -1), 5),
            ('BOTTOMPADDING', (0, 0), (-1, -1), 5),
            ('LEFTPADDING', (0, 0), (0, -1), 10),
            ('RIGHTPADDING', (-1, 0), (-1, -1), 10),
            ('VALIGN', (0, 0), (-1, -1), 'MIDDLE'),
            ('LINEBELOW', (0, 0), (-1, -1), 2, GOLD),
        ]))
        soru_elements.append(soru_no_table)

        # Görsel varsa
        gorsel_b64 = q.get('gorsel') or q.get('image_data')
        if gorsel_b64 and isinstance(gorsel_b64, str) and len(gorsel_b64) > 100:
            try:
                import base64
                img_bytes = base64.b64decode(gorsel_b64)
                img_buf = io.BytesIO(img_bytes)
                img = Image(img_buf, width=10*cm, height=6.5*cm)
                img.hAlign = 'CENTER'
                soru_elements.append(Spacer(1, 4))
                soru_elements.append(img)
                soru_elements.append(Spacer(1, 4))
            except Exception:
                pass

        # Soru metni
        metin = q.get("metin", "").replace("\n", "<br/>")
        soru_elements.append(Paragraph(metin, styles['PDFSoruMetin']))

        # Şıklar
        secenekler = q.get("secenekler", [])
        dogru = q.get("dogru", 0)

        if secenekler and soru_tipi in ("mcq", "mcq5", "dogru_yanlis"):
            sik_rows = []
            for j, sec in enumerate(secenekler):
                harf = chr(65 + j)
                if cevap_goster and isinstance(dogru, int) and j == dogru:
                    sik_rows.append([Paragraph(
                        f"<b><font color='#198754'>{harf})</font></b>",
                        ParagraphStyle('sh', fontSize=10, fontName=font_bold, textColor=GREEN)),
                        Paragraph(f"<b>{sec}</b>  <font color='#198754'>✓</font>",
                        ParagraphStyle('sv', fontSize=10, fontName=font_bold, textColor=GREEN))])
                else:
                    sik_rows.append([Paragraph(
                        f"<b>{harf})</b>",
                        ParagraphStyle(f'sh{j}', fontSize=10, fontName=font_bold, textColor=NAVY)),
                        Paragraph(str(sec),
                        ParagraphStyle(f'sv{j}', fontSize=10, fontName=font_name, textColor=TEXT_DARK))])

            sik_table = Table(sik_rows, colWidths=[1*cm, usable_w - 1.5*cm])
            sik_table.setStyle(TableStyle([
                ('VALIGN', (0, 0), (-1, -1), 'TOP'),
                ('TOPPADDING', (0, 0), (-1, -1), 3),
                ('BOTTOMPADDING', (0, 0), (-1, -1), 3),
                ('LEFTPADDING', (0, 0), (0, -1), 12),
            ]))
            soru_elements.append(sik_table)
        elif isinstance(dogru, str) and cevap_goster:
            soru_elements.append(Paragraph(f"<b>Cevap:</b> {dogru}", styles['PDFCevap']))

        # Açıklama
        if cevap_goster and q.get("aciklama"):
            aciklama = q['aciklama'].replace("\n", "<br/>")
            soru_elements.append(Spacer(1, 4))
            soru_elements.append(Paragraph(f"<i>Açıklama:</i> {aciklama}", styles['PDFAciklama']))

        # Alt ayırıcı çizgi
        soru_elements.append(Spacer(1, 6))
        soru_elements.append(HRFlowable(width="100%", thickness=0.3, color=colors.HexColor('#dee2e6'),
                                         spaceAfter=8))

        # KeepTogether — sorunun bölünmesini engeller
        elements.append(KeepTogether(soru_elements))

    # ═══════════════════════════════════════════════
    # CEVAP ANAHTARI — ayrı sayfa, premium tablo
    # ═══════════════════════════════════════════════
    if not cevap_goster:
        elements.append(PageBreak())
        elements.append(Spacer(1, 0.5*cm))
        elements.append(Paragraph("CEVAP ANAHTARI", styles['PDFCevapKey']))
        elements.append(HRFlowable(width="60%", thickness=1.5, color=GOLD, spaceAfter=0.5*cm))

        # Cevapları satırlara böl — 5'li gruplar halinde yatay
        cevaplar = []
        for i_q, q in enumerate(questions):
            soru_tipi = q.get("soru_tipi", "mcq")
            dogru = q.get("dogru", 0)
            if isinstance(dogru, int) and soru_tipi in ("mcq", "mcq5", "dogru_yanlis"):
                cevaplar.append((str(i_q + 1), chr(65 + dogru)))
            elif isinstance(dogru, str):
                cevaplar.append((str(i_q + 1), dogru[:20]))
            else:
                cevaplar.append((str(i_q + 1), "-"))

        # 5 sütunlu tablo
        cols_per_row = 5
        header_row = []
        for _ in range(cols_per_row):
            header_row.extend(["Soru", "Cevap"])
        rows = [header_row]

        for chunk_start in range(0, len(cevaplar), cols_per_row):
            chunk = cevaplar[chunk_start:chunk_start + cols_per_row]
            row = []
            for sno, cvp in chunk:
                row.extend([sno, cvp])
            # Kalan hücreleri doldur
            while len(row) < cols_per_row * 2:
                row.extend(["", ""])
            rows.append(row)

        col_w = usable_w / (cols_per_row * 2)
        cevap_table = Table(rows, colWidths=[col_w] * (cols_per_row * 2))
        cevap_table.setStyle(TableStyle([
            ('BACKGROUND', (0, 0), (-1, 0), NAVY),
            ('TEXTCOLOR', (0, 0), (-1, 0), WHITE),
            ('FONTNAME', (0, 0), (-1, 0), font_bold),
            ('FONTNAME', (0, 1), (-1, -1), font_name),
            ('FONTSIZE', (0, 0), (-1, -1), 10),
            ('ALIGN', (0, 0), (-1, -1), 'CENTER'),
            ('VALIGN', (0, 0), (-1, -1), 'MIDDLE'),
            ('GRID', (0, 0), (-1, -1), 0.5, colors.HexColor('#dee2e6')),
            ('BOX', (0, 0), (-1, -1), 1.5, NAVY),
            ('TOPPADDING', (0, 0), (-1, -1), 6),
            ('BOTTOMPADDING', (0, 0), (-1, -1), 6),
            ('ROWBACKGROUNDS', (0, 1), (-1, -1), [WHITE, colors.HexColor('#f8f9fa')]),
            # Her çift sütun (cevap) bold
            *[('FONTNAME', (c, 1), (c, -1), font_bold) for c in range(1, cols_per_row * 2, 2)],
            *[('TEXTCOLOR', (c, 1), (c, -1), NAVY) for c in range(1, cols_per_row * 2, 2)],
            # Sütun ayırıcılar
            *[('LINEBEFORE', (c*2, 0), (c*2, -1), 1, GOLD) for c in range(1, cols_per_row)],
        ]))
        elements.append(cevap_table)

    doc.build(elements, onFirstPage=_draw_page, onLaterPages=_draw_page)
    return buffer.getvalue()


def _convert_ai_to_question(ai_q: dict, grade: int, subject: str, kazanim_text: str, blueprint_key: str) -> Question:
    """AI çıktısını Question dataclass'a çevir.
    Otomatik olarak ay/ünite etiketleri ekler (KURAL).
    """
    tip = ai_q.get("soru_tipi", "mcq")
    tip_info = SORU_TIPI_MAP.get(tip, SORU_TIPI_MAP["mcq"])

    choices = {}
    secenekler = ai_q.get("secenekler", [])
    for i, sec in enumerate(secenekler):
        choices[chr(65 + i)] = str(sec)

    dogru = ai_q.get("dogru", 0)
    if isinstance(dogru, int) and choices:
        correct_choice = chr(65 + dogru) if 0 <= dogru < len(choices) else "A"
    elif isinstance(dogru, str):
        # Boşluk doldurma / kısa cevap
        correct_choice = dogru
        choices = {"A": dogru}
    else:
        correct_choice = "A"

    # ── KURAL: Ay/ünite etiketleme ──
    tags = ["ai_blueprint", subject.lower()]
    month_info = _resolve_kazanim_month(grade, subject, kazanim_text)
    month_period = month_info.get("month_period", [])
    unit_name = month_info.get("unit_name", "")
    ay_tags = month_info.get("ay_tags", [])
    for at in ay_tags:
        if at not in tags:
            tags.append(at)
    if unit_name:
        unite_tag = f"unite_{unit_name[:30].lower().replace(' ', '_')}"
        if unite_tag not in tags:
            tags.append(unite_tag)

    # ── MEB pipeline metadata ──
    if ai_q.get('beceri_etiketi'):
        _be_tag = f"beceri_{ai_q['beceri_etiketi']}"
        if _be_tag not in tags:
            tags.append(_be_tag)
    if ai_q.get('engine_type'):
        _en_tag = ai_q['engine_type'].lower()
        if _en_tag not in tags:
            tags.append(_en_tag)

    # MEB validator → kalite puanı ve durum
    _meb_quality = ai_q.get('validator_score', 0)
    _meb_status = ai_q.get('validator_status', '')
    if _meb_status == 'ONAY':
        _q_status = "approved"
    elif _meb_status == 'REPAIR':
        _q_status = "in_review"
    else:
        _q_status = "draft"

    _q_source = "meb_pipeline" if _meb_quality else "ai_blueprint"

    # Görsel verisi (matplotlib veya DALL-E ile üretilmiş)
    _gorsel_data = ai_q.get('gorsel') or ai_q.get('image_data') or ""

    return Question(
        grade=grade,
        subject=subject,
        outcome_id="",
        question_type=tip_info["question_type"],
        choices_count=tip_info["choices_count"] if tip_info["choices_count"] > 0 else len(choices),
        difficulty=ai_q.get("zorluk", "Orta"),
        stem=ai_q.get("metin", ""),
        choices=choices,
        correct_choice=correct_choice,
        explanation=ai_q.get("aciklama", ""),
        tags=tags,
        status=_q_status,
        source=_q_source,
        blueprint_source=blueprint_key,
        quality_score=_meb_quality,
        month_period=month_period,
        unit_name=unit_name,
        image_data=_gorsel_data,
    )


def _reset_kb_wizard():
    """Kazanım bazlı AI wizard state temizle."""
    for key in ['kb_step', 'kb_grade', 'kb_subject', 'kb_selected_outcomes',
                'kb_test_turu', 'kb_blueprint_key', 'kb_blueprint', 'kb_overrides',
                'kb_generated_questions', 'kb_review_status', 'kb_initialized']:
        if key in st.session_state:
            del st.session_state[key]


def _render_kazanim_bazli_ai_uretim():
    """Kazanım Bazlı AI Soru Üretimi - 5 adımlık wizard."""
    store = get_store()

    # Her açılışta temiz başla (kullanıcı aktif üretim yapmıyorsa sıfırla)
    if 'kb_step' not in st.session_state:
        st.session_state.kb_step = 1
    if 'kb_initialized' not in st.session_state:
        _reset_kb_wizard()
        st.session_state.kb_step = 1
        st.session_state.kb_initialized = True

    # Sıfırla butonu
    if st.session_state.kb_step > 1:
        if st.button("🔄 Sıfırla / Yeni Üretim", key="kb_reset_btn"):
            _reset_kb_wizard()
            st.session_state.kb_step = 1
            st.rerun()

    step = st.session_state.kb_step
    st.progress(step / 5)
    st.caption(f"Adım {step}/5")

    # ==========================================
    # ADIM 1: SINIF + DERS + KAZANIM SEÇİMİ
    # ==========================================
    if step == 1:
        st.markdown("### 1️⃣ Sınıf, Ders ve Kazanım Seçimi")

        col1, col2 = st.columns(2)
        with col1:
            kb_grade = st.selectbox("Sınıf", GRADES, index=4, format_func=_grade_label, key="kb_grade_select")
        with col2:
            # Seçilen sınıfa göre dersleri filtrele
            grade_plans = store.get_annual_plans(grade=kb_grade)
            available_subjects = sorted(set(p.subject for p in grade_plans))
            if not available_subjects:
                st.warning(f"{_grade_label(kb_grade)} için yıllık plan verisi bulunamadı. Önce 'Excel İçe Aktar' sekmesinden plan yükleyin.")
                return
            kb_subject = st.selectbox("Ders", available_subjects, key="kb_subject_select")

        # Bu sınıf/ders için planları getir
        filtered_plans = [p for p in grade_plans if p.subject == kb_subject]
        if not filtered_plans:
            st.warning(f"{_grade_label(kb_grade)} - {kb_subject} için yıllık plan bulunamadı.")
            return

        # Ünite bazlı grupla
        unite_kazanimlar = {}
        for plan in filtered_plans:
            unit = plan.unit or "Genel"
            if unit not in unite_kazanimlar:
                unite_kazanimlar[unit] = []
            for outcome in plan.learning_outcomes:
                if outcome and outcome not in unite_kazanimlar[unit]:
                    unite_kazanimlar[unit].append(outcome)

        total_outcomes = sum(len(v) for v in unite_kazanimlar.values())
        c1, c2, c3 = st.columns(3)
        c1.metric("Kayıt", len(filtered_plans))
        c2.metric("Ünite", len(unite_kazanimlar))
        c3.metric("Kazanım", total_outcomes)

        st.markdown("---")

        secim_modu = st.radio("Seçim Modu", ["Tek Kazanım", "Ünite", "Özel Seçim", "🤖 Otomatik"],
                              horizontal=True, key="kb_secim_modu")

        selected_outcomes = []

        if secim_modu == "Ünite":
            unite_list = list(unite_kazanimlar.keys())
            selected_unite = st.selectbox("Ünite Seçin", unite_list, key="kb_unite_select")
            if selected_unite:
                selected_outcomes = unite_kazanimlar[selected_unite]
                st.info(f"**{selected_unite}** ünitesinden {len(selected_outcomes)} kazanım seçildi")
                with st.expander("Kazanımları Gör"):
                    for i, k in enumerate(selected_outcomes):
                        st.markdown(f"{i+1}. {k}")

        elif secim_modu == "Tek Kazanım":
            all_outcomes_flat = []
            for unit, outcomes in unite_kazanimlar.items():
                for o in outcomes:
                    all_outcomes_flat.append(f"[{unit}] {o}")

            if all_outcomes_flat:
                selected = st.selectbox("Kazanım Seçin", all_outcomes_flat, key="kb_tek_kazanim")
                if selected:
                    # "[Ünite] kazanım" formatından kazanımı ayıkla
                    kazanim = selected.split("] ", 1)[1] if "] " in selected else selected
                    selected_outcomes = [kazanim]

        elif secim_modu == "🤖 Otomatik":
            # Stok eksik olan kazanımları otomatik seç
            from models.olcme_degerlendirme import OutcomeSourceResolver, StockController
            _resolver = OutcomeSourceResolver(store)
            _suggestions = _resolver.suggest_next_outcomes(kb_grade, kb_subject, count=10)
            if _suggestions:
                st.info(f"🤖 Stok eksik **{len(_suggestions)}** kazanım otomatik seçildi (ünite sırasına göre)")
                for sg in _suggestions:
                    st.caption(f"• {sg['text'][:70]}... (stok: {sg['current_stock']}, eksik: {sg['needed']})")
                selected_outcomes = [sg["text"] for sg in _suggestions]
            else:
                # Tüm kazanımların stoğu dolu, ilk üniteyi seç
                first_unit = list(unite_kazanimlar.keys())[0] if unite_kazanimlar else ""
                if first_unit:
                    selected_outcomes = unite_kazanimlar[first_unit][:5]
                    st.info(f"Tüm kazanımlarda stok yeterli. İlk üniteden {len(selected_outcomes)} kazanım seçildi.")

        else:  # Özel Seçim
            for unit, outcomes in unite_kazanimlar.items():
                with st.expander(f"📁 {unit} ({len(outcomes)} kazanım)"):
                    for i, k in enumerate(outcomes):
                        if st.checkbox(k[:80], key=f"kb_oz_{unit}_{i}", value=False):
                            selected_outcomes.append(k)

        if selected_outcomes:
            st.success(f"**{len(selected_outcomes)}** kazanım seçildi")
            if st.button("Devam →", type="primary", key="kb_step1_next"):
                st.session_state.kb_grade = kb_grade
                st.session_state.kb_subject = kb_subject
                st.session_state.kb_selected_outcomes = selected_outcomes
                st.session_state.kb_step = 2
                st.rerun()
        else:
            st.info("En az 1 kazanım seçin")

    # ==========================================
    # ADIM 2: TEST TÜRÜ + BLUEPRINT AYARLARI
    # ==========================================
    elif step == 2:
        st.markdown("### 2️⃣ Test Türü ve Ayarlar")

        grade = st.session_state.kb_grade
        subject = st.session_state.kb_subject
        outcomes = st.session_state.kb_selected_outcomes

        st.info(f"**{_grade_label(grade)} - {subject}** | {len(outcomes)} kazanım seçili")

        # Test türü seçimi
        test_turu_options = list(TEST_TURU_LABELS.keys())
        test_turu_labels = list(TEST_TURU_LABELS.values())
        test_idx = st.radio("Test Türü", test_turu_labels, index=0, key="kb_test_turu_radio")
        test_turu = test_turu_options[test_turu_labels.index(test_idx)]

        # Blueprint eşleştir
        bp_key, bp = _find_ai_blueprint(grade, subject, test_turu)
        st.caption(f"Eşleşen şablon: `{bp_key}`")

        st.markdown("---")
        st.markdown("#### Ayarlar (düzenlenebilir)")

        col1, col2 = st.columns(2)
        with col1:
            soru_sayisi = st.number_input("Soru Sayısı", min_value=3, max_value=40,
                                          value=bp.get("soru_sayisi", 12), key="kb_soru_sayisi")

        with col2:
            st.markdown("**Zorluk Dağılımı (%)**")
            z = bp.get("zorluk_orani", {})
            kolay = st.slider("Kolay", 0, 100, z.get("kolay", 30), key="kb_kolay")
            orta = st.slider("Orta", 0, 100, z.get("orta", 50), key="kb_orta")
            zor = 100 - kolay - orta
            st.caption(f"Zor: **{zor}%** (otomatik)")
            if zor < 0:
                st.error("Kolay + Orta %100'ü aşamaz!")
                return

        st.markdown("**Soru Turu Secimi**")

        # Soru turu secimi - yeni turler
        soru_turu_secenekleri = list(SORU_TIPI_LABELS.keys())
        soru_turu_labels_list = list(SORU_TIPI_LABELS.values())
        secili_tur_label = st.selectbox(
            "Soru Turu",
            soru_turu_labels_list,
            index=0,
            key="kb_soru_turu_sec"
        )
        secili_tur_key = soru_turu_secenekleri[soru_turu_labels_list.index(secili_tur_label)]
        tip_overrides = {secili_tur_key: 100}

        tip_info = SORU_TIPI_MAP[secili_tur_key]
        if tip_info["choices_count"] > 0:
            st.info(f"**{secili_tur_label}** - {tip_info['choices_count']} secenek")
        else:
            st.info(f"**{secili_tur_label}** - Açık cevap")
            return

        if bp.get("notlar"):
            st.caption(f"💡 {bp['notlar']}")

        # --- Görsel Ayarları ---
        st.markdown("---")
        st.markdown("**📸 Görsel Ayarları**")
        gorsel_modu = st.radio("Görsel Modu", [
            "Görsel Yok",
            "Matplotlib Şablonları",
            "DALL-E 3 (AI Görsel)",
            "Karışık (Şablon + DALL-E)"
        ], horizontal=True, key="kb_gorsel_modu")

        gorsel_orani = 0
        if gorsel_modu != "Görsel Yok":
            gorsel_orani = st.slider("Görsel Soru Oranı (%)", 20, 100, 50, 10, key="kb_gorsel_orani")
            gorsel_adet = int(soru_sayisi * gorsel_orani / 100)
            st.caption(f"📸 {gorsel_adet}/{soru_sayisi} soru görselli üretilecek")

        # --- AI Model Seçimi ---
        st.markdown("---")
        st.markdown("**🧠 AI Model Seçimi**")
        from models.meb_sinav_motoru import MebSinavMotoru
        model_options = MebSinavMotoru.MODEL_OPTIONS
        model_keys = list(model_options.keys())
        model_labels = [f"{k} — {v}" for k, v in model_options.items()]
        default_idx = model_keys.index(MebSinavMotoru.DEFAULT_MODEL) if MebSinavMotoru.DEFAULT_MODEL in model_keys else 0
        secili_model_label = st.radio("Model", model_labels, index=default_idx, horizontal=True, key="kb_ai_model")
        secili_model = model_keys[model_labels.index(secili_model_label)]
        if secili_model == "gpt-4o":
            st.caption("💎 **gpt-4o** — ÖSYM kalitesinde soru üretimi. Daha yavaş ama çok daha kaliteli.")
        else:
            st.caption("⚡ **gpt-4o-mini** — Hızlı üretim. Kalite orta seviye.")

        # --- Soru Stoğu Kontrol Paneli ---
        st.markdown("---")
        st.markdown("#### 📦 Mevcut Soru Stoğu")
        from models.olcme_degerlendirme import StockController
        _sc = StockController(store)
        _kaz_list = [{"outcome_id": "", "outcome_text": oc} for oc in outcomes]
        _stok_rapor = _sc.check_stock(grade, subject, _kaz_list)

        stok_cols = st.columns([3, 1, 1, 1])
        stok_cols[0].markdown("**Kazanım**")
        stok_cols[1].markdown("**Onaylı**")
        stok_cols[2].markdown("**Gerekli**")
        stok_cols[3].markdown("**Durum**")

        for det in _stok_rapor.outcome_details:
            sc1, sc2, sc3, sc4 = st.columns([3, 1, 1, 1])
            sc1.caption(det["outcome_text"][:60] + ("..." if len(det["outcome_text"]) > 60 else ""))
            sc2.caption(str(det["available"]))
            sc3.caption(str(det["required"]))
            sc4.caption("✅" if det["gap"] <= 0 else f"⚠️ -{det['gap']}")

        if _stok_rapor.status != "OK":
            st.warning(f"⚠️ {_stok_rapor.insufficient_count} kazanımda stok eksik. "
                       "Soru üretimi sırasında otomatik tamamlanacak.")

        col_back, col_next = st.columns(2)
        with col_back:
            if st.button("← Geri", key="kb_step2_back"):
                st.session_state.kb_step = 1
                st.rerun()
        with col_next:
            if st.button("Soruları Üret →", type="primary", key="kb_step2_next"):
                st.session_state.kb_test_turu = test_turu
                st.session_state.kb_blueprint_key = bp_key
                st.session_state.kb_overrides = {
                    "soru_sayisi": soru_sayisi,
                    "sure_dk": bp.get("sure_dk", 20),
                    "zorluk_orani": {"kolay": kolay, "orta": orta, "zor": zor},
                    "soru_tipi_profili": tip_overrides,
                    "gorsel_modu": gorsel_modu,
                    "gorsel_orani": gorsel_orani,
                    "ai_model": secili_model,
                }
                st.session_state.kb_blueprint = bp
                st.session_state.kb_step = 3
                st.rerun()

    # ==========================================
    # ADIM 3: AI ÜRETİM
    # ==========================================
    elif step == 3:
        st.markdown("### 3️⃣ AI Soru Üretimi")

        grade = st.session_state.kb_grade
        subject = st.session_state.kb_subject
        outcomes = st.session_state.kb_selected_outcomes
        bp = st.session_state.kb_blueprint
        overrides = st.session_state.kb_overrides
        bp_key = st.session_state.kb_blueprint_key
        soru_sayisi = overrides.get("soru_sayisi", bp.get("soru_sayisi", 12))

        gorsel_modu = overrides.get("gorsel_modu", "Görsel Yok")
        gorsel_orani = overrides.get("gorsel_orani", 0)
        gorsel_info = f" | 📸 {gorsel_modu} ({gorsel_orani}%)" if gorsel_modu != "Görsel Yok" else ""
        ai_model = overrides.get("ai_model", "gpt-4o")
        model_badge = "💎 gpt-4o (ÖSYM Kalite)" if ai_model == "gpt-4o" else "⚡ gpt-4o-mini (Hızlı)"
        st.info(f"**{_grade_label(grade)} - {subject}** | {len(outcomes)} kazanım | {soru_sayisi} soru | {model_badge}{gorsel_info}")

        with st.spinner(f"🤖 {soru_sayisi} soru üretiliyor ({ai_model})... (Bu işlem 15-60 saniye sürebilir)"):
            questions = _generate_ai_questions_batch(subject, grade, outcomes, bp, overrides)

        # ── GÖRSEL-ZORUNLU DERSLER: Geometri, Fizik vb. için otomatik matplotlib görsel üret ──
        _GORSEL_ZORUNLU_DERSLER = {"Geometri", "Fizik", "Kimya", "Biyoloji", "Fen Bilimleri", "Cografya", "Matematik"}
        if questions and subject in _GORSEL_ZORUNLU_DERSLER:
            import base64, io
            gorsel_motor = _get_meb_motoru(model=ai_model)
            gorsel_basari = 0
            with st.spinner(f"📐 {len(questions)} soruya {subject} görseli üretiliyor..."):
                for qi, q_data in enumerate(questions):
                    try:
                        soru_dict = {
                            "kok": q_data.get("metin", "") if isinstance(q_data, dict) else getattr(q_data, "question_text", ""),
                            "secenekler": {},
                            "gorsel_aciklama": q_data.get("gorsel_aciklama", "") if isinstance(q_data, dict) else getattr(q_data, "gorsel_aciklama", ""),
                        }
                        # Şıkları dict'e çevir
                        sec = q_data.get("secenekler", []) if isinstance(q_data, dict) else []
                        harfler = ["A", "B", "C", "D", "E"]
                        for hi, s in enumerate(sec):
                            if hi < len(harfler):
                                soru_dict["secenekler"][harfler[hi]] = s

                        kod = gorsel_motor.generate_gorsel_kod(soru_dict, subject, grade)
                        if kod and len(kod) > 30:
                            import matplotlib
                            matplotlib.use('Agg')
                            import matplotlib.pyplot as plt
                            import matplotlib.patches as patches
                            import numpy as np

                            fig, ax = plt.subplots(figsize=(7, 5))
                            local_ns = {"fig": fig, "ax": ax, "plt": plt, "np": np,
                                        "patches": patches, "math": __import__("math")}
                            exec(kod, {"__builtins__": {}}, local_ns)
                            fig = local_ns.get("fig", fig)

                            buf = io.BytesIO()
                            fig.savefig(buf, format='png', dpi=150, bbox_inches='tight',
                                        facecolor='white', edgecolor='none')
                            plt.close(fig)
                            buf.seek(0)
                            img_b64 = base64.b64encode(buf.read()).decode('utf-8')

                            if isinstance(q_data, dict):
                                q_data['gorsel'] = img_b64
                            else:
                                q_data.image_data = img_b64
                            gorsel_basari += 1
                    except Exception:
                        pass  # Görsel üretim başarısız — soru metinle devam eder
            if gorsel_basari > 0:
                st.success(f"📐 {gorsel_basari}/{len(questions)} soruya görsel eklendi")

        # Görsel modu aktifse, belirli oranda soruya görsel ekle
        if questions and gorsel_modu != "Görsel Yok" and gorsel_orani > 0:
            import base64
            gorsel_adet = int(len(questions) * gorsel_orani / 100)
            gorsel_adet = max(1, min(gorsel_adet, len(questions)))

            with st.spinner(f"📸 {gorsel_adet} soruya görsel ekleniyor..."):
                for gi in range(gorsel_adet):
                    q = questions[gi]
                    try:
                        if gorsel_modu in ["Matplotlib Şablonları", "Karışık (Şablon + DALL-E)"]:
                            from views.question_builder._visual_questions import generate_visual_question, get_available_visual_subjects
                            avail = get_available_visual_subjects()
                            match = [a for a in avail if a.lower() in subject.lower() or subject.lower() in a.lower()]
                            sablon_ders = match[0] if match else (avail[0] if avail else None)
                            if sablon_ders:
                                result = generate_visual_question(sablon_ders)
                                if result:
                                    img = result.get('image_data') or result.get('gorsel')
                                    if img:
                                        q.image_data = base64.b64encode(img).decode('utf-8') if isinstance(img, bytes) else img
                                        q.blueprint_source = (q.blueprint_source or "") + "+gorsel_sablon"

                        if gorsel_modu in ["DALL-E 3 (AI Görsel)", "Karışık (Şablon + DALL-E)"] and not getattr(q, 'image_data', None):
                            gorsel_data = _generate_question_image(
                                gorsel_aciklama=q.question_text[:200],
                                ders=subject,
                                konu=getattr(q, 'topic', ''),
                                soru_metni=q.question_text
                            )
                            if gorsel_data:
                                q.image_data = base64.b64encode(gorsel_data).decode('utf-8')
                                q.blueprint_source = (q.blueprint_source or "") + "+gorsel_dalle"
                    except Exception:
                        pass  # Görsel eklenemezse sorular metinsiz devam eder

        if questions:
            st.session_state.kb_generated_questions = questions
            st.session_state.kb_review_status = {i: "bekliyor" for i in range(len(questions))}
            gorsel_sayisi = sum(1 for q in questions if getattr(q, 'image_data', None))
            gorsel_msg = f" ({gorsel_sayisi} görselli)" if gorsel_sayisi > 0 else ""
            st.success(f"✅ {len(questions)} soru başarıyla üretildi!{gorsel_msg}")
            st.session_state.kb_step = 4
            st.rerun()
        else:
            st.error("Soru üretilemedi. API anahtarınızı ve internet bağlantınızı kontrol edin.")
            col1, col2 = st.columns(2)
            with col1:
                if st.button("← Geri", key="kb_step3_back"):
                    st.session_state.kb_step = 2
                    st.rerun()
            with col2:
                if st.button("🔄 Tekrar Dene", key="kb_step3_retry"):
                    st.rerun()

    # ==========================================
    # ADIM 4: İNCELEME
    # ==========================================
    elif step == 4:
        st.markdown("### 4️⃣ Soruları İncele")

        questions = st.session_state.kb_generated_questions
        review = st.session_state.kb_review_status
        bp_key = st.session_state.kb_blueprint_key
        grade = st.session_state.kb_grade
        subject = st.session_state.kb_subject
        outcomes = st.session_state.kb_selected_outcomes

        onay = sum(1 for v in review.values() if v == "onay")
        red = sum(1 for v in review.values() if v == "red")
        bekliyor = sum(1 for v in review.values() if v == "bekliyor")

        c1, c2, c3, c4 = st.columns(4)
        c1.metric("Toplam", len(questions))
        c2.metric("Onaylı", onay)
        c3.metric("Reddedildi", red)
        c4.metric("Bekliyor", bekliyor)

        # MEB Pipeline özet bilgisi
        _meb_onay = sum(1 for _q in questions if _q.get('validator_status') == 'ONAY')
        _meb_repair = sum(1 for _q in questions if _q.get('validator_status') == 'REPAIR')
        if _meb_onay or _meb_repair:
            _meb_badges = []
            if _meb_onay:
                _meb_badges.append(f'<span style="background:#059669;color:white;padding:3px 10px;border-radius:8px;font-size:0.75rem;font-weight:700">{_meb_onay} MEB ONAY</span>')
            if _meb_repair:
                _meb_badges.append(f'<span style="background:#d97706;color:white;padding:3px 10px;border-radius:8px;font-size:0.75rem;font-weight:700">{_meb_repair} ONARIM</span>')
            _avg_score = 0
            _scored = [_q.get('validator_score', 0) for _q in questions if _q.get('validator_score')]
            if _scored:
                _avg_score = sum(_scored) / len(_scored)
            st.markdown(f"""<div style="background:linear-gradient(135deg,#1e1b4b,#4338ca);
                padding:12px 20px;border-radius:12px;color:white;margin:4px 0 12px 0;display:flex;align-items:center;gap:12px;">
                <b>MEB Pipeline</b> {" ".join(_meb_badges)}
                <span style="margin-left:auto;font-size:0.8rem;opacity:0.9">Ort. Puan: <b>{_avg_score:.0f}</b>/100</span>
                </div>""", unsafe_allow_html=True)

        # Toplu islem - belirgin banner
        st.markdown("""<div style="background:linear-gradient(135deg,#059669,#10b981);
            padding:14px 20px;border-radius:12px;color:white;margin:8px 0 16px 0;">
            <b>Toplu Onay Islemleri</b> - Tum soruları tek seferde onaylayabilir veya reddedebilirsiniz
            </div>""", unsafe_allow_html=True)

        col_all1, col_all2, col_all3 = st.columns(3)
        with col_all1:
            if st.button("Tümünu Onayla", key="kb_approve_all", type="primary", use_container_width=True):
                for i in review:
                    review[i] = "onay"
                st.session_state.kb_review_status = review
                st.rerun()
        with col_all2:
            if st.button("Tümünu Reddet", key="kb_reject_all", use_container_width=True):
                for i in review:
                    review[i] = "red"
                st.session_state.kb_review_status = review
                st.rerun()
        with col_all3:
            if st.button("Tümünu Onayla ve Kaydet", key="kb_approve_save_all", type="primary", use_container_width=True):
                for i in review:
                    review[i] = "onay"
                st.session_state.kb_review_status = review
                # Anında kaydet - Step 5'e geçmeden
                saved = 0
                for i_q, aq in enumerate(questions):
                    if review.get(i_q) == "onay":
                        kazanim_idx = aq.get("kazanim_index", 0)
                        kazanim_text = outcomes[kazanim_idx] if 0 <= kazanim_idx < len(outcomes) else (outcomes[0] if outcomes else "")
                        question = _convert_ai_to_question(aq, grade, subject, kazanim_text, bp_key)
                        question.status = "approved"
                        store.save_question(question)
                        saved += 1
                st.success(f"✅ {saved} soru anında soru bankasına kaydedildi! (Durum: Onaylı)")
                st.balloons()

        # PDF Indir butonlari
        st.markdown("""<div style="background:linear-gradient(135deg,#1565c0,#42a5f5);
            padding:14px 20px;border-radius:12px;color:white;margin:8px 0 16px 0;">
            <b>PDF Indir</b> - Uretilen sorulari PDF olarak indirin
            </div>""", unsafe_allow_html=True)

        col_pdf1, col_pdf2 = st.columns(2)
        with col_pdf1:
            pdf_bytes = _generate_ai_sorular_pdf(questions, grade, subject, cevap_goster=False)
            sinif_str = _grade_label(grade).replace(".", "").replace(" ", "_")
            st.download_button(
                "📄 Soru Kagidi (PDF)",
                data=pdf_bytes,
                file_name=f"{subject}_{sinif_str}_sorular.pdf",
                mime="application/pdf",
                key="kb_pdf_soru",
                use_container_width=True
            )
        with col_pdf2:
            pdf_cevap = _generate_ai_sorular_pdf(questions, grade, subject, cevap_goster=True)
            st.download_button(
                "📄 Cevapli Versiyon (PDF)",
                data=pdf_cevap,
                file_name=f"{subject}_{sinif_str}_cevapli.pdf",
                mime="application/pdf",
                key="kb_pdf_cevap",
                use_container_width=True
            )

        st.markdown("---")

        for i, q in enumerate(questions):
            tip_label = SORU_TIPI_LABELS.get(q.get("soru_tipi", "mcq"), q.get("soru_tipi", ""))
            zorluk = q.get("zorluk", "Orta")
            status_icon = {"onay": "✅", "red": "❌", "bekliyor": "⏳"}.get(review.get(i, "bekliyor"), "⏳")

            # MEB Validator rozeti
            _vs = q.get('validator_status', '')
            _vsc = q.get('validator_score', 0)
            if _vs == 'ONAY':
                _badge = f" | MEB ONAY ({_vsc})"
            elif _vs == 'REPAIR':
                _badge = f" | ONARIM ({_vsc})"
            else:
                _badge = ""

            with st.expander(f"{status_icon} Soru {i+1}/{len(questions)} ({tip_label} - {zorluk}{_badge})"):
                # MEB Validator rozet HTML
                if _vs == 'ONAY':
                    st.markdown(f'<span style="background:#059669;color:white;padding:2px 8px;border-radius:8px;font-size:0.68rem;font-weight:700">MEB ONAY {_vsc}</span>', unsafe_allow_html=True)
                elif _vs == 'REPAIR':
                    st.markdown(f'<span style="background:#d97706;color:white;padding:2px 8px;border-radius:8px;font-size:0.68rem;font-weight:700">ONARIM {_vsc}</span>', unsafe_allow_html=True)

                # Beceri etiketi
                if q.get('beceri_etiketi'):
                    st.markdown(f'<span style="background:#6366f1;color:white;padding:2px 8px;border-radius:8px;font-size:0.68rem;font-weight:700">{q["beceri_etiketi"]}</span>', unsafe_allow_html=True)

                # Kazanım
                kazanim_idx = q.get("kazanim_index", 0)
                if 0 <= kazanim_idx < len(outcomes):
                    st.caption(f"📌 Kazanım: {outcomes[kazanim_idx][:100]}")

                # Soru görseli (Geometri, Fizik vb. için otomatik üretilmiş matplotlib)
                _gorsel_b64 = q.get('gorsel') or q.get('image_data')
                if _gorsel_b64:
                    try:
                        import base64 as _b64
                        if isinstance(_gorsel_b64, str) and len(_gorsel_b64) > 100:
                            st.image(_b64.b64decode(_gorsel_b64) if not _gorsel_b64.startswith('data:') else _gorsel_b64, width=500)
                    except Exception:
                        pass

                # Veri tablosu (Coğrafya vb. dersler için)
                if q.get('veri_tablosu'):
                    vt = q['veri_tablosu']
                    try:
                        import pandas as pd
                        df = pd.DataFrame(vt.get('satirlar', []), columns=vt.get('sutunlar', []))
                        st.dataframe(df, use_container_width=True, hide_index=True)
                    except Exception:
                        pass

                # Soru metni
                st.markdown(f"**{q.get('metin', '')}**")

                # Seçenekler
                secenekler = q.get("secenekler", [])
                dogru = q.get("dogru", 0)

                soru_tipi = q.get("soru_tipi", "mcq")
                if secenekler and soru_tipi in ("mcq", "mcq5", "dogru_yanlis"):
                    for j, sec in enumerate(secenekler):
                        prefix = chr(65 + j)
                        if isinstance(dogru, int) and j == dogru:
                            st.markdown(f"**{prefix}) {sec}** ✓")
                        else:
                            st.markdown(f"{prefix}) {sec}")
                elif isinstance(dogru, str):
                    if soru_tipi in ("acik_uclu", "klasik"):
                        st.markdown(f"**Ornek Cevap:**\n\n{dogru}")
                    else:
                        st.markdown(f"**Cevap:** {dogru}")

                # Açıklama
                if q.get("aciklama"):
                    st.caption(f"💡 {q['aciklama']}")

                # Butonlar
                col_a, col_r = st.columns(2)
                with col_a:
                    if st.button("✅ Onayla", key=f"kb_approve_{i}"):
                        st.session_state.kb_review_status[i] = "onay"
                        st.rerun()
                with col_r:
                    if st.button("❌ Reddet", key=f"kb_reject_{i}"):
                        st.session_state.kb_review_status[i] = "red"
                        st.rerun()

        st.markdown("---")
        onay_count = sum(1 for v in st.session_state.kb_review_status.values() if v == "onay")

        col_back, col_save_now, col_next = st.columns(3)
        with col_back:
            if st.button("← Geri (Tekrar Üret)", key="kb_step4_back"):
                st.session_state.kb_step = 3
                st.rerun()
        with col_save_now:
            if onay_count > 0:
                if st.button(f"💾 Anında Kaydet ({onay_count} soru)", type="primary", key="kb_instant_save"):
                    saved = 0
                    for i_q, aq in enumerate(questions):
                        if review.get(i_q) == "onay":
                            kazanim_idx = aq.get("kazanim_index", 0)
                            kazanim_text = outcomes[kazanim_idx] if 0 <= kazanim_idx < len(outcomes) else (outcomes[0] if outcomes else "")
                            question = _convert_ai_to_question(aq, grade, subject, kazanim_text, bp_key)
                            question.status = "approved"
                            store.save_question(question)
                            saved += 1
                    st.success(f"✅ {saved} soru anında soru bankasına kaydedildi!")
                    st.balloons()
        with col_next:
            if onay_count > 0:
                if st.button(f"Durum Seçerek Kaydet ({onay_count}) →", key="kb_step4_next"):
                    st.session_state.kb_step = 5
                    st.rerun()
            else:
                st.warning("Kaydetmek için en az 1 soru onaylamalısınız")

    # ==========================================
    # ADIM 5: KAYDET
    # ==========================================
    elif step == 5:
        st.markdown("### 5️⃣ Soru Bankasına Kaydet")

        questions = st.session_state.kb_generated_questions
        review = st.session_state.kb_review_status
        grade = st.session_state.kb_grade
        subject = st.session_state.kb_subject
        outcomes = st.session_state.kb_selected_outcomes
        bp_key = st.session_state.kb_blueprint_key

        approved_qs = [questions[i] for i in review if review[i] == "onay"]
        st.info(f"**{len(approved_qs)}** soru onaylandı ve kaydedilecek")

        kayit_durumu = st.radio("Kayıt Durumu", ["draft", "in_review", "approved"],
                                format_func=lambda x: {"draft": "Taslak", "in_review": "İncelemeye Gönder", "approved": "Doğrudan Onayla"}.get(x, x),
                                index=0, key="kb_kayit_durumu")

        col_back, col_save = st.columns(2)
        with col_back:
            if st.button("← Geri", key="kb_step5_back"):
                st.session_state.kb_step = 4
                st.rerun()
        with col_save:
            if st.button(f"💾 {len(approved_qs)} Soruyu Kaydet", type="primary", key="kb_save"):
                saved = 0
                for aq in approved_qs:
                    kazanim_idx = aq.get("kazanim_index", 0)
                    kazanim_text = outcomes[kazanim_idx] if 0 <= kazanim_idx < len(outcomes) else (outcomes[0] if outcomes else "")
                    question = _convert_ai_to_question(aq, grade, subject, kazanim_text, bp_key)
                    question.status = kayit_durumu
                    store.save_question(question)
                    saved += 1

                st.success(f"✅ {saved} soru başarıyla soru bankasına kaydedildi!")
                st.balloons()

                col_new, col_bank = st.columns(2)
                with col_new:
                    if st.button("🔄 Yeni Üretim Başlat", key="kb_new"):
                        _reset_kb_wizard()
                        st.rerun()
                with col_bank:
                    st.info("Soru Bankası sekmesinden soruları görüntüleyebilirsiniz")


def _render_kazanimlar_browse():
    """Kazanımları görüntüleme - bağımsız fonksiyon."""
    store = get_store()
    all_plans = store.get_annual_plans()

    if all_plans:
        siniflar = sorted(set(p.grade for p in all_plans), key=_grade_sort_key)
        styled_stat_row([
            ("Toplam Kayıt",   str(len(all_plans)),                                      "#2563eb", "📚"),
            ("Sınıf Sayısı",   str(len(siniflar)),                                       "#8b5cf6", "🎓"),
            ("Ders Sayısı",    str(len(set(p.subject for p in all_plans))),               "#10b981", "📖"),
            ("Toplam Kazanım", str(sum(len(p.learning_outcomes) for p in all_plans)),     "#f59e0b", "🎯"),
        ], compact=True)

    if not all_plans:
        st.info("Henüz yıllık plan yüklenmemiş.")
        return

    # Filtreler
    siniflar_mevcut = sorted(set(p.grade for p in all_plans), key=_grade_sort_key)
    dersler_mevcut = sorted(set(p.subject for p in all_plans))

    col_f1, col_f2, col_f3 = st.columns(3)
    with col_f1:
        filter_grade = st.selectbox("Sınıf", siniflar_mevcut,
                                    format_func=_grade_label,
                                    key="yp_filter_grade")
    with col_f2:
        grade_dersler = sorted(set(p.subject for p in all_plans if p.grade == filter_grade))
        filter_subject = st.selectbox("Ders", grade_dersler if grade_dersler else dersler_mevcut,
                                      key="yp_filter_subject")
    with col_f3:
        filter_query = st.text_input("Arama", key="yp_filter_query", placeholder="Konu veya kazanımda ara...")

    filtered_plans = store.get_annual_plans(grade=filter_grade, subject=filter_subject, query=filter_query if filter_query else None)

    if not filtered_plans:
        st.info("Bu filtrelere uygun plan bulunamadı.")
        return

    st.success(f"**{len(filtered_plans)}** kayıt | {_grade_label(filter_grade)} - {filter_subject}")

    # Ünitelere göre grupla
    uniteler = {}
    for p in filtered_plans:
        unite_key = p.unit if p.unit else "Belirtilmemiş"
        if unite_key not in uniteler:
            uniteler[unite_key] = []
        uniteler[unite_key].append(p)

    for unite_adi, unite_planlari in uniteler.items():
        toplam_kazanim = sum(len(p.learning_outcomes) for p in unite_planlari)
        with st.expander(f"📖 {unite_adi} ({len(unite_planlari)} konu, {toplam_kazanim} kazanım)", expanded=False):
            for p in unite_planlari:
                hafta_str = f"**{p.week}** | " if p.week else ""
                st.markdown(f"{hafta_str}📌 **{p.topic}**" if p.topic else f"{hafta_str}_(Konu belirtilmemiş)_")
                if p.learning_outcomes:
                    for outcome in p.learning_outcomes:
                        st.markdown(f"  - 🎯 {outcome}")
                info_parts = []
                if p.hours:
                    info_parts.append(f"Saat: {p.hours}")
                if p.methods:
                    info_parts.append(f"Yöntem: {p.methods[:80]}...")
                if p.assessment:
                    info_parts.append(f"Ölçme: {p.assessment[:80]}...")
                if info_parts:
                    st.caption(" | ".join(info_parts))
                st.markdown("---")

    with st.expander("📊 Tablo Görünümü", expanded=False):
        tablo_data = []
        for p in filtered_plans:
            tablo_data.append({
                "Hafta": p.week, "Ünite": p.unit, "Konu": p.topic,
                "Kazanım Sayısı": len(p.learning_outcomes),
                "Kazanımlar": "; ".join(p.learning_outcomes[:3]) + ("..." if len(p.learning_outcomes) > 3 else ""),
                "Saat": p.hours,
            })
        st.dataframe(pd.DataFrame(tablo_data), use_container_width=True, hide_index=True)

    with st.expander("🗑️ Plan Yönetimi", expanded=False):
        st.warning(f"⚠️ {_grade_label(filter_grade)} - {filter_subject} için **{len(filtered_plans)}** kayıt mevcut")
        if confirm_action(f"🗑️ {_grade_label(filter_grade)} {filter_subject} Planlarını Sil", f"{_grade_label(filter_grade)} - {filter_subject} için tüm yıllık plan kayıtlarını silmek istediğinize emin misiniz?", key="yp_delete_filtered"):
            deleted = store.delete_annual_plans_bulk(grade=filter_grade, subject=filter_subject)
            st.success(f"✅ {deleted} kayıt silindi.")
            st.rerun()


def _compute_outcome_hash(grade, text):
    """Kazanım metninden soru bankası eşleştirme hash'i üret.
    bulk_generate_questions.py ile aynı hash fonksiyonu."""
    import hashlib
    raw = f"{grade}_{text.strip()}"
    return f"bulk_{hashlib.md5(raw.encode('utf-8')).hexdigest()[:12]}"


def _render_kazanim_yeterlilik_sinavi(store):
    """Kazanım Yeterlilik Sınavı - Ünite/Hafta bazlı sınav oluşturucu."""
    import random

    all_plans = store.get_annual_plans()

    if not all_plans:
        st.warning("Henüz yıllık plan yüklenmemiş. 'Excel İçe Aktar' sekmesinden plan yükleyin.")
        return

    # ============================================
    # ADIM 1: SINIF + DERS SEÇİMİ
    # ============================================
    st.markdown("##### 1. Sınıf ve Ders Seçimi")

    siniflar = sorted(set(p.grade for p in all_plans), key=_grade_sort_key)
    dersler_all = sorted(set(p.subject for p in all_plans))

    col_s1, col_s2 = st.columns(2)
    with col_s1:
        yt_grade = st.selectbox("Sınıf", siniflar,
                                format_func=_grade_label,
                                key="yt_grade")
    with col_s2:
        grade_dersler = sorted(set(p.subject for p in all_plans if p.grade == yt_grade))
        if not grade_dersler:
            grade_dersler = dersler_all
        yt_subject = st.selectbox("Ders", grade_dersler, key="yt_subject")

    # Bu sınıf+ders için planları getir
    filtered_plans = store.get_annual_plans(grade=yt_grade, subject=yt_subject)

    if not filtered_plans:
        st.warning(f"{_grade_label(yt_grade)} {yt_subject} için plan bulunamadı.")
        return

    # Ünitelere göre grupla
    uniteler = {}
    for p in filtered_plans:
        unite_key = p.unit if p.unit else "Belirtilmemiş"
        if unite_key not in uniteler:
            uniteler[unite_key] = []
        uniteler[unite_key].append(p)

    # Haftalara göre grupla
    haftalar = {}
    for p in filtered_plans:
        hafta_key = p.week if p.week else "Belirtilmemiş"
        if hafta_key not in haftalar:
            haftalar[hafta_key] = []
        haftalar[hafta_key].append(p)

    st.markdown("---")

    # ============================================
    # ADIM 2: SEÇİM MODU
    # ============================================
    st.markdown("##### 2. Kapsam Seçimi")

    secim_modu = st.radio(
        "Seçim Modu",
        ["Ünite Bazlı", "Hafta Bazlı", "Tümü"],
        horizontal=True,
        key="yt_secim_modu"
    )

    secilen_kazanimlar = []  # [(text, unit, week)]

    if secim_modu == "Ünite Bazlı":
        unite_listesi = list(uniteler.keys())
        secilen_uniteler = st.multiselect(
            "Ünite(ler) Seçin",
            unite_listesi,
            key="yt_unite_sec"
        )

        if secilen_uniteler:
            for unite in secilen_uniteler:
                for p in uniteler[unite]:
                    for lo in p.learning_outcomes:
                        lo_stripped = lo.strip()
                        if lo_stripped and len(lo_stripped) >= 10:
                            secilen_kazanimlar.append({
                                "text": lo_stripped,
                                "unit": unite,
                                "week": p.week,
                                "topic": p.topic
                            })

    elif secim_modu == "Hafta Bazlı":
        # Hafta numaralarını çıkar ve sırala
        def _extract_week_num(w):
            import re
            nums = re.findall(r'\d+', str(w))
            return int(nums[0]) if nums else 999

        sorted_haftalar = sorted(haftalar.keys(), key=_extract_week_num)

        secilen_haftalar = st.multiselect(
            "Hafta(lar) Seçin",
            sorted_haftalar,
            key="yt_hafta_sec"
        )

        if secilen_haftalar:
            for hafta in secilen_haftalar:
                for p in haftalar[hafta]:
                    for lo in p.learning_outcomes:
                        lo_stripped = lo.strip()
                        if lo_stripped and len(lo_stripped) >= 10:
                            secilen_kazanimlar.append({
                                "text": lo_stripped,
                                "unit": p.unit,
                                "week": hafta,
                                "topic": p.topic
                            })

    else:  # Tümü
        for p in filtered_plans:
            for lo in p.learning_outcomes:
                lo_stripped = lo.strip()
                if lo_stripped and len(lo_stripped) >= 10:
                    secilen_kazanimlar.append({
                        "text": lo_stripped,
                        "unit": p.unit,
                        "week": p.week,
                        "topic": p.topic
                    })

    # Tekrar eden kazanımları kaldır
    seen_texts = set()
    unique_kazanimlar = []
    for k in secilen_kazanimlar:
        if k["text"] not in seen_texts:
            seen_texts.add(k["text"])
            unique_kazanimlar.append(k)
    secilen_kazanimlar = unique_kazanimlar

    if not secilen_kazanimlar:
        if secim_modu != "Tümü":
            st.info("Yukarıdan ünite veya hafta seçin.")
        return

    st.success(f"**{len(secilen_kazanimlar)}** benzersiz kazanım seçildi")

    st.markdown("---")

    # ============================================
    # ADIM 3: KAPSAM ANALİZİ
    # ============================================
    st.markdown("##### 3. Soru Bankası Kapsam Analizi")

    # Her kazanım için soru bankası kontrolü
    kapsam_data = []
    toplam_soru = 0
    eksik_kazanim = 0

    for k in secilen_kazanimlar:
        h = _compute_outcome_hash(yt_grade, k["text"])
        soru_sayisi = store.count_questions_by_outcome(h, status="approved")
        toplam_soru += soru_sayisi

        durum = "Yeterli" if soru_sayisi > 0 else "Eksik"
        if soru_sayisi == 0:
            eksik_kazanim += 1

        kapsam_data.append({
            "Kazanım": k["text"][:80] + ("..." if len(k["text"]) > 80 else ""),
            "Ünite": k["unit"][:30] if k["unit"] else "-",
            "Soru": soru_sayisi,
            "Durum": durum,
            "_hash": h,
            "_full_text": k["text"]
        })

    # Özet metrikler
    col_m1, col_m2, col_m3 = st.columns(3)
    col_m1.metric("Kazanım", len(secilen_kazanimlar))
    col_m2.metric("Soru Bankasında", toplam_soru)
    col_m3.metric("Eksik Kazanım", eksik_kazanim)

    if eksik_kazanim > 0:
        st.warning(f"{eksik_kazanim} kazanım için soru bankasında soru bulunamadı. "
                   "Bu kazanımlar sınava dahil edilemeyecek.")

    # Kapsam tablosu
    with st.expander("Kazanım Detayları", expanded=False):
        display_data = [{k: v for k, v in d.items() if not k.startswith("_")} for d in kapsam_data]
        st.dataframe(pd.DataFrame(display_data), use_container_width=True, hide_index=True)

    # Sorusu olan kazanımlar
    hazir_kazanimlar = [d for d in kapsam_data if d["Soru"] > 0]

    if not hazir_kazanimlar:
        st.error("Seçilen kazanımlar için soru bankasında hiç soru yok! "
                 "Önce 'AI Soru Üret' sekmesinden soru üretin veya toplu üretim çalıştırın.")
        return

    st.markdown("---")

    # ============================================
    # ADIM 4: SINAV AYARLARI
    # ============================================
    st.markdown("##### 4. Sınav Ayarları")

    col_a1, col_a2 = st.columns(2)
    with col_a1:
        soru_per_kazanim = st.number_input(
            "Kazanım Başına Soru",
            min_value=1, max_value=3, value=1,
            key="yt_soru_per_kaz",
            help="Her kazanımdan kaç soru çekilecek"
        )
    with col_a2:
        sinav_suresi = st.number_input(
            "Sınav Süresi (dk)",
            min_value=10, max_value=180, value=40,
            key="yt_sure"
        )

    zorluk_tercihi = st.selectbox(
        "Zorluk Dağılımı",
        ["Karışık", "Kolay Ağırlıklı", "Zor Ağırlıklı"],
        key="yt_zorluk"
    )

    # Sınav adı
    if secim_modu == "Ünite Bazlı":
        secim_ozet = ", ".join(st.session_state.get("yt_unite_sec", [])[:3])
    elif secim_modu == "Hafta Bazlı":
        secim_ozet = ", ".join(st.session_state.get("yt_hafta_sec", [])[:3])
    else:
        secim_ozet = "Tüm Kazanımlar"

    default_name = f"{_grade_label(yt_grade)} {yt_subject} Yeterlilik - {secim_ozet}"
    sinav_adi = st.text_input("Sınav Adı", value=default_name[:80], key="yt_sinav_adi")

    # Tahmini soru sayısı
    max_soru = sum(min(d["Soru"], soru_per_kazanim) for d in hazir_kazanimlar)
    st.info(f"Tahmini soru sayısı: **{max_soru}** ({len(hazir_kazanimlar)} kazanım x {soru_per_kazanim} soru)")

    st.markdown("---")

    # ============================================
    # ADIM 5: SINAV ÜRET
    # ============================================
    st.markdown("##### 5. Sınav Oluştur")

    col_btn1, col_btn2 = st.columns(2)

    with col_btn1:
        uret_btn = st.button("Sınavı Oluştur", type="primary", key="yt_uret_btn")

    with col_btn2:
        aktif_et = st.checkbox("Oluşturulduktan sonra aktif et (online sınav)", key="yt_aktif_et")

    if uret_btn:
        with st.spinner("Sınav oluşturuluyor..."):
            selected_question_ids = []
            kazanim_dagilim = []
            atlanan = 0

            for kd in hazir_kazanimlar:
                h = kd["_hash"]
                # Kazanıma ait onaylı soruları getir
                sorular = store.get_questions(outcome_id=h, status="approved")

                if not sorular:
                    atlanan += 1
                    continue

                # Zorluk filtresi
                if zorluk_tercihi == "Kolay Ağırlıklı":
                    kolay = [q for q in sorular if q.difficulty in ("Kolay", "kolay")]
                    diger = [q for q in sorular if q.difficulty not in ("Kolay", "kolay")]
                    sirali = kolay + diger
                elif zorluk_tercihi == "Zor Ağırlıklı":
                    zor = [q for q in sorular if q.difficulty in ("Zor", "zor")]
                    diger = [q for q in sorular if q.difficulty not in ("Zor", "zor")]
                    sirali = zor + diger
                else:
                    sirali = list(sorular)
                    random.shuffle(sirali)

                # Seçim yap
                secilecek = min(soru_per_kazanim, len(sirali))
                secilen = sirali[:secilecek]
                selected_question_ids.extend([q.id for q in secilen])
                kazanim_dagilim.append({
                    "kazanim": kd["Kazanım"],
                    "soru_sayisi": secilecek
                })

            if not selected_question_ids:
                st.error("Hiç soru seçilemedi!")
                return

            # Soruları karıştır
            random.shuffle(selected_question_ids)

            # Exam objesi oluştur
            exam_status = "active" if aktif_et else "created"
            exam = Exam(
                name=sinav_adi,
                grade=yt_grade,
                subject=yt_subject,
                exam_type="Kazanim Değerlendirme",
                question_ids=selected_question_ids,
                status=exam_status,
                duration_minutes=sinav_suresi
            )
            store.save_exam(exam)

            st.success(f"Sınav oluşturuldu! **{len(selected_question_ids)}** soru, "
                       f"**{len(kazanim_dagilim)}** kazanım kapsandı.")

            if atlanan > 0:
                st.warning(f"{atlanan} kazanım sorusu bulunamadığı için atlandı.")

            # Sınav bilgi kartı
            st.markdown("---")
            st.markdown("#### Sınav Bilgileri")
            col_i1, col_i2, col_i3, col_i4 = st.columns(4)
            col_i1.metric("Sınav ID", exam.id)
            col_i2.metric("Soru Sayısı", len(selected_question_ids))
            col_i3.metric("Süre", f"{sinav_suresi} dk")
            col_i4.metric("Durum", "Aktif" if aktif_et else "Taslak")

            if aktif_et:
                st.info("Sınav **aktif**. Öğrenciler **Online Sınav** sekmesinden bu sınava girebilir.")
            else:
                st.warning("Sınav **taslak** olarak kaydedildi. Öğrencilerin erişebilmesi için "
                          "**Online Sınav → Sınav Yönetimi** sekmesinden aktif edin.")

            # PDF ve Online butonları
            st.markdown("---")
            st.markdown("#### Sınavı Kullan")
            col_act1, col_act2 = st.columns(2)

            with col_act1:
                # PDF İndir
                try:
                    pdf_bytes = _generate_yeterlilik_sinav_pdf(exam, store)
                    st.download_button(
                        label="PDF İndir (Kapak + QR + Sorular)",
                        data=pdf_bytes,
                        file_name=f"{sinav_adi[:50].replace(' ', '_')}.pdf",
                        mime="application/pdf",
                        key="yt_pdf_download"
                    )
                except Exception as e:
                    st.error(f"PDF oluşturma hatası: {e}")

            with col_act2:
                if not aktif_et:
                    if st.button("Online Sınav Olarak Aktif Et", key="yt_aktif_et_btn"):
                        exam.status = "active"
                        store.save_exam(exam)
                        st.success("Sınav aktif edildi! Online Sınav sekmesinden erişilebilir.")
                        st.rerun()
                else:
                    st.success("Online sınav zaten aktif")

            # Dağılım özeti
            with st.expander("Kazanım Dağılımı", expanded=True):
                for kd in kazanim_dagilim:
                    st.write(f"- {kd['kazanim']} ({kd['soru_sayisi']} soru)")


def _generate_yeterlilik_sinav_pdf(exam, store) -> bytes:
    """Yeterlilik sınavı PDF - Kapak sayfası + QR kod + Sorular."""
    from reportlab.lib import colors
    from reportlab.lib.pagesizes import A4
    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
    from reportlab.lib.units import cm
    from reportlab.platypus import SimpleDocTemplate, Paragraph, Spacer, Table, TableStyle, PageBreak, Image
    from reportlab.lib.enums import TA_CENTER
    from reportlab.pdfbase import pdfmetrics
    from reportlab.pdfbase.ttfonts import TTFont

    # Font yükle
    from utils.shared_data import ensure_turkish_pdf_fonts
    font_name, font_bold = ensure_turkish_pdf_fonts()

    buffer = io.BytesIO()
    doc = SimpleDocTemplate(buffer, pagesize=A4, topMargin=1.5*cm, bottomMargin=1.5*cm,
                           leftMargin=2*cm, rightMargin=2*cm)
    styles = getSampleStyleSheet()
    styles.add(ParagraphStyle(name='KurumAdi_YT', fontSize=18, leading=22, alignment=TA_CENTER,
                              spaceAfter=6, fontName=font_bold, textColor=colors.HexColor('#2c3e50')))
    styles.add(ParagraphStyle(name='SınavAdi_YT', fontSize=16, leading=20, alignment=TA_CENTER,
                              spaceAfter=12, fontName=font_bold, textColor=colors.HexColor('#e74c3c')))
    styles.add(ParagraphStyle(name='AltBaşlık_YT', fontSize=10, leading=14, alignment=TA_CENTER,
                              spaceAfter=12, textColor=colors.grey, fontName=font_name))
    styles.add(ParagraphStyle(name='SoruNo_YT', fontSize=11, leading=14, fontName=font_bold,
                              spaceBefore=10, spaceAfter=5))
    styles.add(ParagraphStyle(name='Secenek_YT', fontSize=10, leading=13, leftIndent=20, fontName=font_name))

    elements = []

    # ============================================
    # KAPAK SAYFASI
    # ============================================
    kurum = _load_kurum_ayarlari()

    # Kurum logosu
    if kurum.get('logo_base64'):
        try:
            import base64
            logo_bytes = base64.b64decode(kurum['logo_base64'])
            logo_buf = io.BytesIO(logo_bytes)
            logo_img = Image(logo_buf, width=3*cm, height=3*cm)
            logo_img.hAlign = 'CENTER'
            elements.append(logo_img)
            elements.append(Spacer(1, 0.5*cm))
        except Exception:
            pass

    # Kurum adı
    if kurum.get('kurum_adi'):
        elements.append(Paragraph(kurum['kurum_adi'], styles['KurumAdi_YT']))

    # İletişim
    iletisim = []
    if kurum.get('adres'):
        iletisim.append(kurum['adres'])
    if kurum.get('telefon'):
        iletisim.append(f"Tel: {kurum['telefon']}")
    if kurum.get('web'):
        iletisim.append(kurum['web'])
    if iletisim:
        elements.append(Paragraph(" | ".join(iletisim), styles['AltBaşlık_YT']))

    elements.append(Spacer(1, 1.5*cm))

    # Sınav adı
    elements.append(Paragraph(exam.name, styles['SınavAdi_YT']))
    elements.append(Spacer(1, 0.5*cm))

    # Sınav bilgileri tablosu
    bilgi_data = [
        ['Sınıf:', f"{_grade_label(exam.grade)}"],
        ['Ders:', exam.subject],
        ['Tarih:', exam.created_at[:10]],
        ['Süre:', f"{exam.duration_minutes} dakika"],
        ['Soru Sayısı:', f"{len(exam.question_ids)} soru"],
    ]
    bilgi_table = Table(bilgi_data, colWidths=[4*cm, 9*cm])
    bilgi_table.setStyle(TableStyle([
        ('ALIGN', (0, 0), (0, -1), 'RIGHT'),
        ('ALIGN', (1, 0), (1, -1), 'LEFT'),
        ('FONTNAME', (0, 0), (0, -1), font_bold),
        ('FONTNAME', (1, 0), (1, -1), font_name),
        ('FONTSIZE', (0, 0), (-1, -1), 12),
        ('BOTTOMPADDING', (0, 0), (-1, -1), 8),
        ('TOPPADDING', (0, 0), (-1, -1), 8),
    ]))
    elements.append(bilgi_table)
    elements.append(Spacer(1, 1*cm))

    # Öğrenci bilgi alanı
    ogrenci_data = [
        ['Adı Soyadı:', '___________________________________'],
        ['Numarası:', '___________________________________'],
        ['Şubesi:', '___________________________________'],
    ]
    ogrenci_table = Table(ogrenci_data, colWidths=[3*cm, 10*cm])
    ogrenci_table.setStyle(TableStyle([
        ('FONTNAME', (0, 0), (0, -1), font_bold),
        ('FONTNAME', (1, 0), (1, -1), font_name),
        ('FONTSIZE', (0, 0), (-1, -1), 11),
        ('BOTTOMPADDING', (0, 0), (-1, -1), 12),
        ('TOPPADDING', (0, 0), (-1, -1), 12),
        ('BOX', (0, 0), (-1, -1), 1, colors.black),
        ('INNERGRID', (0, 0), (-1, -1), 0.5, colors.grey),
    ]))
    elements.append(ogrenci_table)
    elements.append(Spacer(1, 0.5*cm))

    # QR Kod
    try:
        import qrcode
        qr_data = {
            "exam_id": exam.id,
            "name": exam.name,
            "grade": exam.grade,
            "subject": exam.subject,
            "questions": len(exam.question_ids),
            "type": "yeterlilik_sinavi"
        }
        qr = qrcode.QRCode(version=1, error_correction=qrcode.constants.ERROR_CORRECT_L, box_size=8, border=2)
        qr.add_data(json.dumps(qr_data, ensure_ascii=False))
        qr.make(fit=True)
        qr_img = qr.make_image(fill_color="black", back_color="white")
        qr_buf = io.BytesIO()
        qr_img.save(qr_buf, format='PNG')
        qr_buf.seek(0)
        qr_image = Image(qr_buf, width=2.5*cm, height=2.5*cm)

        qr_table_data = [[
            qr_image,
            Paragraph(f"<b>Sınav ID:</b> {exam.id}<br/>"
                     f"<font size='8'>Bu QR kodu sınav eşleştirmesi için kullanılır.</font>",
                     styles['AltBaşlık_YT'])
        ]]
        qr_table = Table(qr_table_data, colWidths=[3*cm, 10*cm])
        qr_table.setStyle(TableStyle([
            ('ALIGN', (0, 0), (0, 0), 'CENTER'),
            ('VALIGN', (0, 0), (-1, -1), 'MIDDLE'),
        ]))
        elements.append(qr_table)
    except Exception:
        elements.append(Paragraph(f"<b>Sınav ID:</b> {exam.id}", styles['AltBaşlık_YT']))

    elements.append(Spacer(1, 0.5*cm))

    # Sınav kuralları
    if kurum.get('sinav_kurallari'):
        elements.append(Paragraph("<b>SINAV KURALLARI</b>", styles['SoruNo_YT']))
        for kural in kurum['sinav_kurallari'].split('\n'):
            kural = kural.strip()
            if kural:
                elements.append(Paragraph(kural, styles['Normal']))

    # Sayfa sonu - sorulara geç
    elements.append(PageBreak())

    # ============================================
    # SORULAR
    # ============================================
    for i, qid in enumerate(exam.question_ids, 1):
        question = store.get_question(qid)
        if not question:
            continue

        stem_text = question.stem.replace('<', '&lt;').replace('>', '&gt;')
        elements.append(Paragraph(f"<b>Soru {i}.</b> {stem_text}", styles['SoruNo_YT']))

        for letter, text in question.choices.items():
            text_safe = str(text).replace('<', '&lt;').replace('>', '&gt;')
            elements.append(Paragraph(f"{letter}) {text_safe}", styles['Secenek_YT']))

        elements.append(Spacer(1, 0.3*cm))

    # Cevap anahtarı sayfası
    elements.append(PageBreak())
    elements.append(Paragraph("<b>CEVAP ANAHTARI</b>", styles['SınavAdi_YT']))
    elements.append(Spacer(1, 0.5*cm))

    cevap_data = [['Soru', 'Cevap']]
    for i, qid in enumerate(exam.question_ids, 1):
        question = store.get_question(qid)
        if question:
            cevap_data.append([str(i), question.correct_choice])

    if len(cevap_data) > 1:
        # 3 sütuna böl
        rows_per_col = (len(cevap_data) - 1 + 2) // 3
        cols_data = []
        for c in range(3):
            start = 1 + c * rows_per_col
            end = min(start + rows_per_col, len(cevap_data))
            col_rows = cevap_data[start:end]
            cols_data.append(col_rows)

        max_rows = max(len(c) for c in cols_data) if cols_data else 0
        merged = []
        for r in range(max_rows):
            row = []
            for c in cols_data:
                if r < len(c):
                    row.extend(c[r])
                else:
                    row.extend(['', ''])
            merged.append(row)

        header = ['Soru', 'Cevap', 'Soru', 'Cevap', 'Soru', 'Cevap']
        final_data = [header] + merged

        cevap_table = Table(final_data, colWidths=[2*cm, 2*cm, 2*cm, 2*cm, 2*cm, 2*cm])
        cevap_table.setStyle(TableStyle([
            ('FONTNAME', (0, 0), (-1, 0), font_bold),
            ('FONTNAME', (0, 1), (-1, -1), font_name),
            ('FONTSIZE', (0, 0), (-1, -1), 10),
            ('ALIGN', (0, 0), (-1, -1), 'CENTER'),
            ('GRID', (0, 0), (-1, -1), 0.5, colors.grey),
            ('BACKGROUND', (0, 0), (-1, 0), colors.HexColor('#ecf0f1')),
            ('BOTTOMPADDING', (0, 0), (-1, -1), 5),
            ('TOPPADDING', (0, 0), (-1, -1), 5),
        ]))
        elements.append(cevap_table)

    doc.build(elements)
    buffer.seek(0)
    return buffer.getvalue()


def _render_olcme_takvimi():
    """Olcme Takvimi (Sinav - Deneme - Proje planlama takvimi).
    Veri kaynagi: data/akademik/olcme_takvim.json (AkademikDataStore)
    """
    from models.akademik_takip import (
        AkademikDataStore, OlcmeTakvim, OLCME_TURLERI, DERSLER, SINIFLAR, SUBELER
    )
    from datetime import date

    styled_section("Ölçme Takvimi (Sınav - Deneme - Proje)", "#8b5cf6")

    ak_store = AkademikDataStore()
    akademik_yil_now = datetime.now()
    if akademik_yil_now.month >= 9:
        akademik_yil = f"{akademik_yil_now.year}-{akademik_yil_now.year + 1}"
    else:
        akademik_yil = f"{akademik_yil_now.year - 1}-{akademik_yil_now.year}"

    oc1, oc2, oc3, oc4 = st.columns(4)
    with oc1:
        ot_sinif = st.selectbox("Sınıf", SINIFLAR, index=4, key="od_ot_sinif")
    with oc2:
        ot_sube = st.selectbox("Şube", SUBELER, key="od_ot_sube")
    with oc3:
        ot_ders = st.selectbox("Ders", [None] + DERSLER,
                                format_func=lambda x: "Tüm Dersler" if x is None else x,
                                key="od_ot_ders")
    with oc4:
        ot_donem = st.selectbox("Dönem", ["1. Donem", "2. Donem"], key="od_ot_donem")

    st.caption(f"Sınıf: {ot_sinif} / Şube: {ot_sube} / Yıl: {akademik_yil}")

    takvim = ak_store.get_olcme_takvim(sinif=ot_sinif, ders=ot_ders,
                                        donem=ot_donem, akademik_yil=akademik_yil)

    # -- Ozet metrikler --
    toplam = len(takvim) if takvim else 0
    yazili_c = sum(1 for t in takvim if t.tur == "yazili") if takvim else 0
    deneme_c = sum(1 for t in takvim if t.tur == "deneme") if takvim else 0
    proje_c = sum(1 for t in takvim if t.tur in ("proje", "performans")) if takvim else 0

    styled_stat_row([
        ("Toplam Etkinlik", toplam, "#8b5cf6", "\U0001f4c5"),
        ("Yazılı Sınav", yazili_c, "#2563eb", "\u270d"),
        ("Deneme Sınavı", deneme_c, "#0ea5e9", "\U0001f4dd"),
        ("Proje / Performans", proje_c, "#10b981", "\U0001f4cb"),
    ])

    if takvim:
        takvim_sorted = sorted(takvim, key=lambda x: x.tarih)
        df_data = []
        for t in takvim_sorted:
            tur_label = dict(OLCME_TURLERI).get(t.tur, t.tur)
            df_data.append({
                "Tarih": t.tarih,
                "Ders": t.ders,
                "Tür": tur_label,
                "Açıklama": t.aciklama,
                "ID": t.id,
            })
        df = pd.DataFrame(df_data)
        st.dataframe(df[["Tarih", "Ders", "Tür", "Açıklama"]],
                     use_container_width=True, hide_index=True)

        # Silme
        del_ot_id = st.selectbox("Silinecek Etkinlik",
                                  [f"{d['Tarih']} - {d['Ders']} - {d['Tür']}" for d in df_data],
                                  key="od_del_ot_sel")
        if del_ot_id and confirm_action("Etkinliği Sil", "Seçili ölçme etkinliğini takvimden silmek istediğinize emin misiniz?", key="od_del_ot_btn"):
            idx = [f"{d['Tarih']} - {d['Ders']} - {d['Tür']}" for d in df_data].index(del_ot_id)
            ak_store.delete_olcme_takvim(df_data[idx]["ID"])
            st.success("Etkinlik silindi!")
            st.rerun(scope="fragment")
    else:
        st.info("Ölçme takvimi boş. Aşağıdan yeni etkinlik ekleyebilirsiniz.")

    st.divider()
    with st.form("od_olcme_takvim_form"):
        styled_section("Yeni Ölçme Etkinliği Ekle", "#10b981")
        fc1, fc2 = st.columns(2)
        with fc1:
            ot_n_ders = st.selectbox("Ders", DERSLER, key="od_ot_n_ders")
            ot_n_tarih = st.date_input("Tarih", value=date.today(), key="od_ot_n_tarih")
        with fc2:
            _olcme_tur_labels = [t[1] for t in OLCME_TURLERI]
            ot_n_tur_label = st.selectbox("Tür", _olcme_tur_labels, key="od_ot_n_tur")
            ot_n_tur_idx = _olcme_tur_labels.index(ot_n_tur_label) if ot_n_tur_label in _olcme_tur_labels else 0
            ot_n_tur = OLCME_TURLERI[ot_n_tur_idx][0]
            ot_n_aciklama = st.text_input("Açıklama", key="od_ot_n_acik")

        if st.form_submit_button("Etkinlik Ekle", type="primary"):
            kayit = OlcmeTakvim(
                sinif=ot_sinif, ders=ot_n_ders, tur=ot_n_tur,
                tarih=ot_n_tarih.strftime("%Y-%m-%d"),
                aciklama=ot_n_aciklama,
                donem=ot_donem, akademik_yil=akademik_yil,
            )
            ak_store.save_olcme_takvim(kayit)
            st.success("Ölçme etkinliği eklendi!")
            st.rerun(scope="fragment")


def render_kurum_ayarlari():
    """Kurum ayarları ekranı - Logo, ad ve sınav kapak sayfası ayarları."""
    styled_section("Kurum ve Sistem Ayarlari", "#37474f")
    _render_ayarlar_dashboard()

    # Mevcut ayarları yükle
    ayarlar = _load_kurum_ayarlari()

    st.markdown("### 🏫 Kurum Bilgileri")
    st.info("Bu bilgiler tüm sınav kapak sayfalarında otomatik olarak görünecektir.")

    col1, col2 = st.columns([2, 1])

    with col1:
        # Kurum adı
        kurum_adi = st.text_input(
            "Kurum Adı *",
            value=ayarlar.get("kurum_adi", ""),
            key="ayar_kurum_adi",
            placeholder="Örn: Aykın Koleji"
        )

        # Adres
        adres = st.text_input(
            "Adres (Opsiyonel)",
            value=ayarlar.get("adres", ""),
            key="ayar_adres",
            placeholder="Örn: Cumhuriyet Mah. Eğitim Cad. No:1"
        )

        # Telefon ve Web
        col_t1, col_t2 = st.columns(2)
        with col_t1:
            telefon = st.text_input(
                "Telefon (Opsiyonel)",
                value=ayarlar.get("telefon", ""),
                key="ayar_telefon",
                placeholder="0212 555 00 00"
            )
        with col_t2:
            web = st.text_input(
                "Web Sitesi (Opsiyonel)",
                value=ayarlar.get("web", ""),
                key="ayar_web",
                placeholder="www.okul.edu.tr"
            )

        # Uygulama URL'si - QR kodlar için
        app_base_url = st.text_input(
            "Uygulama URL'si (QR Kod Bağlantısı)",
            value=ayarlar.get("app_base_url", ""),
            key="ayar_app_base_url",
            placeholder="https://okul.smartcampus.app",
            help="Bu URL, sınav kitapçığı ve optik formlardaki QR kodlara eklenir. "
                 "Öğrenciler QR kodu okutarak doğrudan online sınava giriş yapabilir."
        )
        if app_base_url and not app_base_url.startswith(("http://", "https://")):
            st.warning("URL 'http://' veya 'https://' ile başlamalıdır.")

    with col2:
        # Logo yükleme
        st.markdown("**Kurum Logosu**")

        # Mevcut logo varsa göster
        if ayarlar.get("logo_base64"):
            import base64
            try:
                logo_bytes = base64.b64decode(ayarlar["logo_base64"])
                st.image(logo_bytes, caption="Mevcut Logo", width=150)
                if st.button("🗑️ Logoyu Kaldır", key="remove_logo"):
                    ayarlar["logo_base64"] = ""
                    _save_kurum_ayarlari(ayarlar)
                    st.success("Logo kaldırıldı!")
                    st.rerun()
            except Exception:
                st.warning("Logo yüklenemedi")

        # Yeni logo yükle
        uploaded_logo = st.file_uploader(
            "Logo Yükle (PNG/JPG)",
            type=['png', 'jpg', 'jpeg'],
            key="logo_upload"
        )

        if uploaded_logo:
            from utils.security import validate_upload
            _ok, _msg = validate_upload(uploaded_logo, allowed_types=["png", "jpg", "jpeg"], max_mb=50)
            if not _ok:
                st.error(f"⚠️ {_msg}")
                uploaded_logo = None
        if uploaded_logo:
            import base64
            logo_bytes = uploaded_logo.read()
            logo_base64 = base64.b64encode(logo_bytes).decode('utf-8')
            st.image(logo_bytes, caption="Yeni Logo Önizleme", width=150)

    st.markdown("---")

    # Kampus Yonetimi
    st.markdown("### 🏢 Kampus Yönetimi")
    st.caption("Çok subeli/kampuslu okullar için kampus bilgilerini girin. Raporlarda kampus bazli karsilastirma yapilabilir.")

    kampusler = ayarlar.get("kampusler", [])
    kampus_default = "\n".join([f"{k.get('kod', '')}|{k.get('ad', '')}" for k in kampusler]) if kampusler else ""

    kampus_text = st.text_area(
        "Kampusler (her satira bir kampus: KOD|Kampus Adi)",
        value=kampus_default,
        height=100,
        key="ayar_kampusler",
        placeholder="ANA|Ana Kampus\nKAD|Kadikoy Kampusu\nBES|Besiktas Kampusu"
    )

    st.markdown("---")

    # Sinav Kurallari
    st.markdown("### 📋 Varsayilan Sınav Kurallari")
    st.caption("Bu kurallar tum sinav kapak sayfalarinda gorunecektir.")

    sinav_kurallari = st.text_area(
        "Sınav Kurallari",
        value=ayarlar.get("sinav_kurallari", ""),
        height=200,
        key="ayar_sinav_kurallari",
        placeholder="Sınav kurallarini buraya yazin..."
    )

    st.markdown("---")

    # Kaydet butonu
    col_save1, col_save2, col_save3 = st.columns([1, 2, 1])
    with col_save2:
        if st.button("💾 Ayarlari Kaydet", type="primary", use_container_width=True):

            # Logo varsa kaydet
            if uploaded_logo:
                ayarlar["logo_base64"] = logo_base64

            ayarlar["kurum_adi"] = kurum_adi
            ayarlar["adres"] = adres
            ayarlar["telefon"] = telefon
            ayarlar["web"] = web
            ayarlar["app_base_url"] = app_base_url.strip().rstrip("/")
            ayarlar["sinav_kurallari"] = sinav_kurallari

            # Kampusleri parse et
            parsed_kampusler = []
            for line in kampus_text.strip().split("\n"):
                line = line.strip()
                if "|" in line:
                    parts = line.split("|", 1)
                    parsed_kampusler.append({"kod": parts[0].strip(), "ad": parts[1].strip()})
            ayarlar["kampusler"] = parsed_kampusler

            _save_kurum_ayarlari(ayarlar)
            st.success("Kurum ayarlari basariyla kaydedildi!")
            st.balloons()

    # Önizleme
    st.markdown("---")
    st.markdown("### 👁️ Kapak Sayfası Önizleme")

    with st.expander("Kapak Sayfası Önizleme", expanded=False):
        # Önizleme göster
        preview_col1, preview_col2 = st.columns([1, 3])

        with preview_col1:
            if ayarlar.get("logo_base64"):
                import base64
                try:
                    logo_bytes = base64.b64decode(ayarlar["logo_base64"])
                    st.image(logo_bytes, width=100)
                except Exception:
                    st.write("🏫")
            else:
                st.write("🏫 Logo Yok")

        with preview_col2:
            st.markdown(f"### {kurum_adi or '[Kurum Adı]'}")
            if adres:
                st.caption(adres)
            if telefon or web:
                st.caption(f"{telefon or ''} | {web or ''}")

        st.markdown("---")
        st.markdown("#### 📝 [Sınav Adı Buraya Gelecek]")
        st.markdown("**Sınıf:** [X]. Sınıf | **Ders:** [Ders Adı] | **Tarih:** [Tarih]")
        st.markdown("**Uygulayıcı:** [Öğretmen Adı]")
        st.markdown("---")
        st.markdown("**Süre:** [XX] dakika | **Soru Sayısı:** [XX] soru")
        st.markdown("---")
        st.markdown("**📋 Sınav Kuralları:**")
        for rule in (sinav_kurallari or "").split('\n'):
            if rule.strip():
                st.write(rule)


