                    st.write(f"**Sınıf:** {q['grade']}")
                    st.write(f"**Ders:** {q['subject']}")
                    st.write(f"**Zorluk:** {q['difficulty']}")
                    st.write(f"**Doğru Cevap:** {q['correct_answer']}")
