                    current_display.metric("📝 İşlenen", f"{idx + 1} / {total_to_save}")
                    saved_display.metric("✅ Kaydedilen", saved)
                    remaining_display.metric("⏳ Kalan", total_to_save - idx - 1)

                    q_num = q.get('question_number', saved + 1)
