def _render_gorsel_sablon_uretici(store):
    """Alt Sekme 1: Matplotlib şablon tabanlı görsel soru üretici."""
    st.markdown("#### 🎨 Hazır Şablon ile Görsel Soru Üret")
    st.caption("22+ önceden hazırlanmış Matplotlib şablonundan otomatik görsel soru üretin.")

    try:
        from views.question_builder._visual_questions import (
            generate_visual_question, get_available_visual_subjects
        )
        available_subjects = get_available_visual_subjects()
    except ImportError:
        st.error("Görsel soru şablonları yüklenemedi (views/question_builder/_visual_questions.py)")
        return

    if not available_subjects:
        st.warning("Hiç görsel soru şablonu bulunamadı.")
        return

    col1, col2, col3 = st.columns([2, 1, 1])
    with col1:
        selected_subject = st.selectbox(
            "Ders Seçin",
            available_subjects,
            key="gs_sablon_ders"
        )
    with col2:
        toplu_sayi = st.number_input("Adet", min_value=1, max_value=10, value=1, key="gs_sablon_adet")
    with col3:
        zorluk = st.selectbox("Zorluk", ["Kolay", "Orta", "Zor"], index=1, key="gs_sablon_zorluk")

    if st.button("🎨 Şablondan Üret", type="primary", key="gs_sablon_uret"):
        uretilen = []
        progress_bar = st.progress(0)
        for i in range(toplu_sayi):
            result = generate_visual_question(selected_subject)
            if result:
                uretilen.append(result)
            progress_bar.progress((i + 1) / toplu_sayi)

        if uretilen:
            st.session_state['gs_sablon_sonuclar'] = uretilen
            st.success(f"✅ {len(uretilen)} görsel soru üretildi!")
        else:
            st.error("Şablondan soru üretilemedi.")

    # Sonuçları göster
    if 'gs_sablon_sonuclar' in st.session_state and st.session_state['gs_sablon_sonuclar']:
        sonuclar = st.session_state['gs_sablon_sonuclar']
        st.markdown(f"---\n#### Üretilen Sorular ({len(sonuclar)})")

        for idx, soru in enumerate(sonuclar):
            with st.expander(f"Soru {idx+1}: {soru.get('question', soru.get('soru', '')[:60])}...", expanded=(idx == 0)):
                col_img, col_txt = st.columns([1, 1])
                with col_img:
                    img_data = soru.get('image_data') or soru.get('gorsel')
                    if img_data:
                        if isinstance(img_data, str):
                            import base64
                            img_data = base64.b64decode(img_data)
                        st.image(img_data, caption=f"Şablon Görsel {idx+1}", use_container_width=True)

                with col_txt:
                    st.markdown(f"**Soru:** {soru.get('question', soru.get('soru', 'N/A'))}")
                    options = soru.get('options', soru.get('secenekler', []))
                    if options:
                        for opt in options:
                            st.markdown(f"- {opt}")
                    correct = soru.get('correct_answer', soru.get('dogru', 'N/A'))
                    st.markdown(f"**Doğru Cevap:** {correct}")

                # Soru bankasına kaydet butonu
                if st.button(f"💾 Soru Bankasına Kaydet", key=f"gs_sablon_kaydet_{idx}"):
                    _kaydet_gorsel_soru_bankasina(store, soru, selected_subject, zorluk)


