def _kaydet_gorsel_soru_bankasina(store, soru_data: dict, ders: str, zorluk: str):
    """Şablon üretici sonucunu soru bankasına kaydet."""
    import base64

    img_data = soru_data.get('image_data') or soru_data.get('gorsel')
    gorsel_b64 = None
    if img_data:
        if isinstance(img_data, bytes):
            gorsel_b64 = base64.b64encode(img_data).decode('utf-8')
        elif isinstance(img_data, str):
            gorsel_b64 = img_data  # Zaten base64

    soru_metni = soru_data.get('question', soru_data.get('soru', ''))
    secenekler = soru_data.get('options', soru_data.get('secenekler', []))
    dogru = soru_data.get('correct_answer', soru_data.get('dogru', ''))

    # Doğru cevabı seçeneklerden bul
    if isinstance(dogru, int) and secenekler:
        dogru_str = secenekler[dogru] if dogru < len(secenekler) else secenekler[0]
    elif isinstance(dogru, str):
        dogru_str = dogru
    else:
        dogru_str = secenekler[0] if secenekler else ""

    q = Question(
        question_text=soru_metni,
        question_type="mcq",
        options=secenekler,
        correct_answer=dogru_str,
        difficulty=zorluk.lower(),
        subject=ders,
        image_data=gorsel_b64,
        source="template",
        status="approved",
        blueprint_source="gorsel_sablon"
    )
    store.save_question(q)
    st.success(f"✅ Şablon soru kaydedildi! (ID: {q.id})")


# ═══════════════════════════════════════════════════════════════════════════════
# TAB 4: ANALİZ & VİZYON — Soru bankası kalite + sınav trend + AI tavsiye
# ═══════════════════════════════════════════════════════════════════════════════

def _render_tab_analiz_vizyon():
    """Premium analiz & vizyon — soru kalite, sinav trend, AI yorum, yol haritasi."""
    from models.olcme_degerlendirme import get_store as _get_store
    store = _get_store()
    styled_section("Ölçme & Değerlendirme — Analiz & Vizyon", "#8b5cf6")

    questions = _cached_get_questions_light()
    exams = _cached_get_exams()
    results = _cached_get_all_results()
    sessions = _cached_get_sessions()

    total_q = len(questions)
    approved = sum(1 for q in questions if q.status == "approved")
    in_review = sum(1 for q in questions if q.status == "in_review")
    draft = sum(1 for q in questions if q.status == "draft")
    ai_count = sum(1 for q in questions if q.source in ("ai", "ai_bulk_gen"))

    # ── MEGA KPI ──
    styled_stat_row([
        ("Toplam Soru", f"{total_q:,}", "#2563eb", "📝"),
        ("Onaylı", f"{approved:,}", "#10b981", "✅"),
        ("İncelemede", str(in_review), "#f59e0b", "🔍"),
        ("Taslak", str(draft), "#8b5cf6", "📄"),
        ("AI Üretim", f"{ai_count:,}", "#0891b2", "🤖"),
        ("Sınav", str(len(exams)), "#6366f1", "📋"),
        ("Sonuç", str(len(results)), "#ef4444", "🏆"),
    ])

    # ── SORU BANKASI KALİTE ANALİZİ ──
    st.markdown("#### Soru Bankası Kalite Analizi")

    # Onay orani
    onay_oran = round(approved / total_q * 100) if total_q > 0 else 0
    ai_oran = round(ai_count / total_q * 100) if total_q > 0 else 0

    kc1, kc2, kc3 = st.columns(3)
    with kc1:
        o_clr = "#22c55e" if onay_oran >= 80 else ("#f59e0b" if onay_oran >= 50 else "#ef4444")
        st.markdown(f"""<div style="background:#0f172a;border-radius:12px;padding:14px;
        text-align:center;border:1px solid {o_clr}30;">
        <div style="font-size:.7rem;color:#64748b;text-transform:uppercase;">Onay Orani</div>
        <div style="font-size:2rem;font-weight:900;color:{o_clr};">%{onay_oran}</div>
        <div style="font-size:.7rem;color:#475569;">{approved:,}/{total_q:,}</div>
        </div>""", unsafe_allow_html=True)
    with kc2:
        st.markdown(f"""<div style="background:#0f172a;border-radius:12px;padding:14px;
        text-align:center;border:1px solid #0891b230;">
        <div style="font-size:.7rem;color:#64748b;text-transform:uppercase;">AI Üretim Orani</div>
        <div style="font-size:2rem;font-weight:900;color:#0891b2;">%{ai_oran}</div>
        <div style="font-size:.7rem;color:#475569;">{ai_count:,} soru AI ile uretildi</div>
        </div>""", unsafe_allow_html=True)
    with kc3:
        bekleyen = in_review + draft
        b_clr = "#22c55e" if bekleyen == 0 else ("#f59e0b" if bekleyen < 50 else "#ef4444")
        st.markdown(f"""<div style="background:#0f172a;border-radius:12px;padding:14px;
        text-align:center;border:1px solid {b_clr}30;">
        <div style="font-size:.7rem;color:#64748b;text-transform:uppercase;">Bekleyen Islem</div>
        <div style="font-size:2rem;font-weight:900;color:{b_clr};">{bekleyen}</div>
        <div style="font-size:.7rem;color:#475569;">{in_review} inceleme + {draft} taslak</div>
        </div>""", unsafe_allow_html=True)

    # Ders bazli soru dagilimi
    if questions:
        st.markdown("#### Ders Bazlı Soru Dağılımı")
        ders_counts: dict[str, int] = {}
        bloom_counts: dict[str, int] = {}
        tip_counts: dict[str, int] = {}
        for q in questions:
            d = q.subject or "Belirtilmemis"
            ders_counts[d] = ders_counts.get(d, 0) + 1
            b = q.bloom_level or "?"
            bloom_counts[b] = bloom_counts.get(b, 0) + 1
            t = q.question_type or "?"
            tip_counts[t] = tip_counts.get(t, 0) + 1

        import plotly.graph_objects as go
        from utils.chart_utils import SC_COLORS, sc_pie, sc_bar, SC_CHART_CFG

        dc1, dc2 = st.columns(2)
        with dc1:
            if ders_counts:
                sorted_ders = sorted(ders_counts.items(), key=lambda x: -x[1])[:12]
                fig_d = go.Figure(go.Bar(
                    x=[d[0][:15] for d in sorted_ders],
                    y=[d[1] for d in sorted_ders],
                    marker_color=[SC_COLORS[i % len(SC_COLORS)] for i in range(len(sorted_ders))],
                    text=[str(d[1]) for d in sorted_ders], textposition="auto",
                ))
                sc_bar(fig_d, height=280)
                st.plotly_chart(fig_d, use_container_width=True, config=SC_CHART_CFG,
                                key="od_viz_ders_bar")

        with dc2:
            if bloom_counts:
                st.markdown("**Bloom Taksonomisi Dağılımı**")
                fig_b = go.Figure(go.Pie(
                    labels=list(bloom_counts.keys()), values=list(bloom_counts.values()),
                    marker=dict(colors=SC_COLORS[:len(bloom_counts)],
                                line=dict(color="#1e293b", width=2)),
                ))
                sc_pie(fig_b, height=280,
                       center_text=f"<b>{total_q:,}</b><br><span style='font-size:10px;color:#64748b'>Soru</span>")
                st.plotly_chart(fig_b, use_container_width=True, config=SC_CHART_CFG,
                                key="od_viz_bloom_donut")

        # Soru tipi dagilimi
        if tip_counts:
            st.markdown("#### Soru Tipi Dağılımı")
            tip_labels = {"mcq": "Çoktan Seçmeli", "true_false": "Doğru/Yanlış",
                          "fill_blank": "Boşluk Doldurma", "matching": "Eşleştirme",
                          "ordering": "Sıralama", "cloze": "Cloze", "math_expr": "Matematik"}
            sorted_tips = sorted(tip_counts.items(), key=lambda x: -x[1])
            fig_t = go.Figure(go.Pie(
                labels=[tip_labels.get(t[0], t[0]) for t in sorted_tips],
                values=[t[1] for t in sorted_tips],
                marker=dict(colors=SC_COLORS[:len(sorted_tips)],
                            line=dict(color="#1e293b", width=2)),
            ))
            sc_pie(fig_t, height=260)
            st.plotly_chart(fig_t, use_container_width=True, config=SC_CHART_CFG,
                            key="od_viz_tip_donut")

    # ── SINAV SONUC ANALIZI ──
    if results:
        st.markdown("---")
        st.markdown("#### Sınav Sonuç Analizi")

        puanlar = [r.score for r in results if r.score is not None]
        if puanlar:
            avg = round(sum(puanlar) / len(puanlar), 1)
            mx = max(puanlar)
            mn = min(puanlar)

            sc1, sc2, sc3 = st.columns(3)
            with sc1:
                a_clr = "#22c55e" if avg >= 70 else ("#f59e0b" if avg >= 50 else "#ef4444")
                st.markdown(f"""<div style="background:#0f172a;border-radius:12px;padding:14px;
                text-align:center;border:1px solid {a_clr}30;">
                <div style="font-size:.7rem;color:#64748b;">Ortalama Puan</div>
                <div style="font-size:2rem;font-weight:900;color:{a_clr};">{avg}</div>
                </div>""", unsafe_allow_html=True)
            with sc2:
                st.markdown(f"""<div style="background:#0f172a;border-radius:12px;padding:14px;
                text-align:center;border:1px solid #22c55e30;">
                <div style="font-size:.7rem;color:#64748b;">En Yüksek</div>
                <div style="font-size:2rem;font-weight:900;color:#22c55e;">{mx:.0f}</div>
                </div>""", unsafe_allow_html=True)
            with sc3:
                st.markdown(f"""<div style="background:#0f172a;border-radius:12px;padding:14px;
                text-align:center;border:1px solid #ef444430;">
                <div style="font-size:.7rem;color:#64748b;">En Düşük</div>
                <div style="font-size:2rem;font-weight:900;color:#ef4444;">{mn:.0f}</div>
                </div>""", unsafe_allow_html=True)

            # Puan dagilimi histogram
            ranges = {"0-29": 0, "30-44": 0, "45-54": 0, "55-69": 0, "70-84": 0, "85-100": 0}
            for p in puanlar:
                if p < 30: ranges["0-29"] += 1
                elif p < 45: ranges["30-44"] += 1
                elif p < 55: ranges["45-54"] += 1
                elif p < 70: ranges["55-69"] += 1
                elif p < 85: ranges["70-84"] += 1
                else: ranges["85-100"] += 1

            range_colors = ["#ef4444", "#f97316", "#f59e0b", "#eab308", "#22c55e", "#6366f1"]
            fig_h = go.Figure(go.Bar(
                x=list(ranges.keys()), y=list(ranges.values()),
                marker_color=range_colors, text=list(ranges.values()), textposition="auto",
            ))
            sc_bar(fig_h, height=260)
            st.plotly_chart(fig_h, use_container_width=True, config=SC_CHART_CFG,
                            key="od_viz_puan_hist")

    # ── OTOMATIK YORUM & AKSIYON ──
    st.markdown("---")
    st.markdown("#### Akıllı Değerlendirme & Öneriler")

    findings = []
    actions = []

    # Soru bankasi analizi
    if total_q > 0:
        if onay_oran < 50:
            findings.append(("warning", "📝", f"Soru onay oranı düşük: %{onay_oran}",
                             f"{total_q - approved:,} soru onay bekliyor. İnceleme sürecini hızlandırın."))
        if ai_oran > 80:
            findings.append(("info", "🤖", f"AI üretim oranı çok yüksek: %{ai_oran}",
                             "Manuel soru üretimini artırın — AI soruları çeşitlilik için destekleyici olmalı."))

        # Ders dengesi
        if ders_counts:
            max_ders = max(ders_counts.values())
            min_ders = min(ders_counts.values())
            if max_ders > min_ders * 5:
                findings.append(("warning", "⚖️", "Ders bazlı soru dağılımı dengesiz",
                                 "Bazı derslerde çok az soru var. Eksik derslere AI ile soru üretin."))

        # Bloom taksonomisi
        if bloom_counts:
            ust_duzey = sum(v for k, v in bloom_counts.items() if k in ("analiz", "sentez", "degerlendirme", "uygulama"))
            alt_duzey = sum(v for k, v in bloom_counts.items() if k in ("bilgi", "kavrama", "hatirlama"))
            if total_q > 100 and ust_duzey < alt_duzey * 0.3:
                findings.append(("warning", "🧠", "Üst düzey düşünme soruları az",
                                 "Bloom taksonomisinde analiz/sentez/değerlendirme sorularını artırın."))

    # Sinav sonuc analizi
    if results and puanlar:
        if avg < 50:
            findings.append(("critical", "📊", f"Sınav ortalaması çok düşük: {avg}",
                             "Soruların zorluk seviyesini kontrol edin veya ek destek programı başlatın."))
            actions.append(("ACIL", "📊", "Sınav zorluğunu kalibre edin", "Zorluk Kalibrasyonu aracını kullanın"))
        elif avg < 60:
            findings.append(("warning", "📊", f"Sınav ortalaması düşük: {avg}",
                             "Etüt programı + odev desteği ile başarıyı artırın."))

    # Sinav sayisi
    if len(exams) == 0:
        findings.append(("info", "📋", "Henüz sınav oluşturulmamış",
                         "Sınavlar sekmesinden ilk sınavınızı oluşturun."))
        actions.append(("YÜKSEK", "📋", "İlk sınavı oluşturun", "Sınavlar > Sınav Oluştur"))

    if len(results) == 0 and len(exams) > 0:
        findings.append(("warning", "🏆", "Sınav var ama sonuç yok",
                         "Öğrencilerin sınavı çözmesi gerekiyor. Aktif Sınavlar sekmesini kontrol edin."))

    # Aksiyon onerileri
    if total_q < 1000:
        actions.append(("ORTA", "📝", f"Soru bankasını zenginleştirin ({total_q:,} → 5,000+ hedef)",
                        "Soru Havuzu > Soru Üret sekmesinden AI ile toplu üretim"))
    if in_review > 10:
        actions.append(("YÜKSEK", "🔍", f"{in_review} soru inceleme bekliyor",
                        "Soru Havuzu > Soru Bankası > İnceleme kuyruğu"))

    # Render bulgular
    if findings:
        for sev, icon, title, detail in findings:
            bg = {"critical": "linear-gradient(135deg,#1c0505,#3b0f0f)",
                  "warning": "linear-gradient(135deg,#1c1305,#3b2a0f)",
                  "info": "linear-gradient(135deg,#050c1c,#0f1e3b)"}.get(sev, "")
            border = {"critical": "#ef4444", "warning": "#f59e0b", "info": "#3b82f6"}.get(sev, "#64748b")
            title_c = {"critical": "#fca5a5", "warning": "#fcd34d", "info": "#93c5fd"}.get(sev, "#c7d2fe")

            st.markdown(f"""<div style="background:{bg};border-radius:12px;padding:14px 18px;
            margin:6px 0;border-left:4px solid {border};">
            <div style="font-size:.92rem;font-weight:700;color:{title_c};">{icon} {title}</div>
            <div style="font-size:.8rem;color:#cbd5e1;margin-top:4px;">{detail}</div>
            </div>""", unsafe_allow_html=True)

    # Render aksiyonlar
    if actions:
        st.markdown("#### Aksiyon Planı")
        pri_colors = {"ACIL": "#ef4444", "YÜKSEK": "#f97316", "ORTA": "#f59e0b", "DÜŞÜK": "#22c55e"}
        for pri, icon, gorev, modul in actions:
            clr = pri_colors.get(pri, "#64748b")
            st.markdown(f"""<div style="display:flex;gap:10px;align-items:center;padding:8px 0;
            border-bottom:1px solid #1e293b;">
            <span style="font-size:1.1rem;">{icon}</span>
            <div style="flex:1;">
            <div style="color:#e2e8f0;font-weight:600;font-size:.88rem;">{gorev}</div>
            <div style="color:#475569;font-size:.72rem;">{modul}</div>
            </div>
            <span style="font-size:.6rem;color:{clr};font-weight:700;background:{clr}15;
            padding:2px 8px;border-radius:4px;">{pri}</span>
            </div>""", unsafe_allow_html=True)

    # ── AI VIZYON ──
    st.markdown("---")
    # ═══ SORU BANKASI DERIN ANALIZ ═══
    if questions:
        st.markdown("---")
        st.markdown("#### Soru Bankası Derin Kalite Analizi")

        # Zorluk dagilimi
        zorluk_counts: dict[str, int] = {}
        kaynak_counts: dict[str, int] = {}
        sinif_counts: dict[str, int] = {}
        ders_bloom: dict[str, dict[str, int]] = {}

        for q in questions:
            z = q.difficulty or "?"
            zorluk_counts[z] = zorluk_counts.get(z, 0) + 1
            s = q.source or "manuel"
            kaynak_counts[s] = kaynak_counts.get(s, 0) + 1
            g = str(q.grade) if q.grade else "?"
            sinif_counts[g] = sinif_counts.get(g, 0) + 1
            d = q.subject or "?"
            b = q.bloom_level or "?"
            ders_bloom.setdefault(d, {}).setdefault(b, 0)
            ders_bloom[d][b] += 1

        import plotly.graph_objects as go
        from utils.chart_utils import SC_COLORS, sc_pie, sc_bar, SC_CHART_CFG

        zc1, zc2, zc3 = st.columns(3)
        with zc1:
            st.markdown("**Zorluk Dağılımı**")
            zorluk_colors = {"Kolay": "#22c55e", "Orta": "#f59e0b", "Zor": "#ef4444"}
            if zorluk_counts:
                fig_z = go.Figure(go.Pie(
                    labels=list(zorluk_counts.keys()), values=list(zorluk_counts.values()),
                    marker=dict(colors=[zorluk_colors.get(k, "#64748b") for k in zorluk_counts.keys()],
                                line=dict(color="#1e293b", width=2))))
                sc_pie(fig_z, height=240, center_text=f"<b>{total_q:,}</b>")
                st.plotly_chart(fig_z, use_container_width=True, config=SC_CHART_CFG,
                                key="od_derin_zorluk")
                # Ideal dagilim yorumu
                kolay_pct = round(zorluk_counts.get("Kolay", 0) / total_q * 100) if total_q else 0
                orta_pct = round(zorluk_counts.get("Orta", 0) / total_q * 100) if total_q else 0
                zor_pct = round(zorluk_counts.get("Zor", 0) / total_q * 100) if total_q else 0
                st.caption(f"Kolay %{kolay_pct} | Orta %{orta_pct} | Zor %{zor_pct}")
                ideal = "İdeal: %25 Kolay, %50 Orta, %25 Zor"
                if orta_pct < 40:
                    st.warning(f"⚠️ Orta zorluk az (%{orta_pct}). {ideal}")
                elif zor_pct < 15:
                    st.info(f"ℹ️ Zor soru az (%{zor_pct}). {ideal}")
                else:
                    st.success(f"✅ Dengeli dağılım. {ideal}")

        with zc2:
            st.markdown("**Kaynak Dağılımı**")
            kaynak_labels = {"ai": "AI", "ai_bulk_gen": "AI Toplu", "manuel": "Manuel",
                             "imported": "İçe Aktarılan", "template": "Şablon", "pdf_visual_import": "PDF"}
            if kaynak_counts:
                fig_k = go.Figure(go.Pie(
                    labels=[kaynak_labels.get(k, k) for k in kaynak_counts.keys()],
                    values=list(kaynak_counts.values()),
                    marker=dict(colors=SC_COLORS[:len(kaynak_counts)],
                                line=dict(color="#1e293b", width=2))))
                sc_pie(fig_k, height=240)
                st.plotly_chart(fig_k, use_container_width=True, config=SC_CHART_CFG,
                                key="od_derin_kaynak")

        with zc3:
            st.markdown("**Sınıf Dağılımı**")
            if sinif_counts:
                sorted_sinif = sorted(sinif_counts.items(), key=lambda x: int(x[0]) if x[0].isdigit() else 0)
                fig_s = go.Figure(go.Bar(
                    x=[f"{s[0]}. Sınıf" if s[0].isdigit() else s[0] for s in sorted_sinif],
                    y=[s[1] for s in sorted_sinif],
                    marker_color=[SC_COLORS[i % len(SC_COLORS)] for i in range(len(sorted_sinif))],
                    text=[str(s[1]) for s in sorted_sinif], textposition="auto"))
                sc_bar(fig_s, height=240)
                st.plotly_chart(fig_s, use_container_width=True, config=SC_CHART_CFG,
                                key="od_derin_sinif")

        # Ders × Bloom Heatmap
        if ders_bloom and len(ders_bloom) >= 2:
            st.markdown("#### Ders × Bloom Taksonomisi Matrisi")
            st.caption("Her derste hangi düşünme seviyesinde kaç soru var — dengesizlik tespiti")

            all_blooms = sorted(set(b for db in ders_bloom.values() for b in db))
            all_ders = sorted(ders_bloom.keys())[:10]
            z_data = [[ders_bloom.get(d, {}).get(b, 0) for d in all_ders] for b in all_blooms]

            fig_hm = go.Figure(go.Heatmap(
                z=z_data, x=[d[:12] for d in all_ders], y=all_blooms,
                colorscale=[[0, "#0f172a"], [0.5, "#6366f1"], [1, "#c4b5fd"]],
                text=[[str(v) for v in row] for row in z_data],
                texttemplate="%{text}", textfont=dict(size=10, color="#fff"),
                showscale=True,
                colorbar=dict(title=dict(text="Soru", font=dict(color="#94a3b8")),
                              tickfont=dict(color="#94a3b8")),
            ))
            fig_hm.update_layout(
                height=max(200, len(all_blooms) * 35), margin=dict(l=100, r=20, t=10, b=60),
                paper_bgcolor="rgba(0,0,0,0)", plot_bgcolor="rgba(0,0,0,0)",
                xaxis=dict(tickfont=dict(color="#c7d2fe", size=9), tickangle=-30),
                yaxis=dict(tickfont=dict(color="#94a3b8", size=9)))
            st.plotly_chart(fig_hm, use_container_width=True, config=SC_CHART_CFG,
                            key="od_derin_bloom_hm")

    # ═══ SINAV SONUC DERIN ANALIZ ═══
    if results:
        st.markdown("---")
        st.markdown("#### Zorluk Bazlı Başarı Analizi")
        st.caption("Kolay / Orta / Zor sorulardaki doğru oranları — öğrenci ne seviyede takılıyor?")

        diff_totals: dict[str, dict] = {}
        for r in results:
            db = r.difficulty_breakdown if hasattr(r, 'difficulty_breakdown') and r.difficulty_breakdown else {}
            if isinstance(db, dict):
                for level, data in db.items():
                    if level not in diff_totals:
                        diff_totals[level] = {"correct": 0, "total": 0}
                    if isinstance(data, dict):
                        diff_totals[level]["correct"] += data.get("correct", 0)
                        diff_totals[level]["total"] += data.get("total", 0)

        if diff_totals:
            diff_labels = list(diff_totals.keys())
            diff_correct = [diff_totals[l]["correct"] for l in diff_labels]
            diff_total = [diff_totals[l]["total"] for l in diff_labels]
            diff_pct = [round(c / t * 100) if t > 0 else 0 for c, t in zip(diff_correct, diff_total)]

            dc1, dc2 = st.columns(2)
            with dc1:
                diff_colors_map = {"Kolay": "#22c55e", "Orta": "#f59e0b", "Zor": "#ef4444"}
                fig_diff = go.Figure()
                fig_diff.add_trace(go.Bar(
                    x=diff_labels, y=diff_pct,
                    marker_color=[diff_colors_map.get(l, "#6366f1") for l in diff_labels],
                    text=[f"%{p}" for p in diff_pct], textposition="auto"))
                fig_diff.update_layout(
                    height=260, margin=dict(l=40, r=20, t=20, b=40),
                    paper_bgcolor="rgba(0,0,0,0)", plot_bgcolor="rgba(0,0,0,0)",
                    yaxis=dict(range=[0, 100], gridcolor="#1e293b", tickfont=dict(color="#94a3b8"),
                               title="Doğru Oranı (%)"),
                    xaxis=dict(tickfont=dict(color="#c7d2fe", size=12)),
                    font=dict(color="#94a3b8"))
                st.plotly_chart(fig_diff, use_container_width=True, config=SC_CHART_CFG,
                                key="od_derin_diff_bar")

            with dc2:
                # Yorum
                for level in diff_labels:
                    pct = round(diff_totals[level]["correct"] / diff_totals[level]["total"] * 100) if diff_totals[level]["total"] > 0 else 0
                    clr = "#22c55e" if pct >= 70 else ("#f59e0b" if pct >= 50 else "#ef4444")
                    if level == "Kolay" and pct < 80:
                        yorum = "Kolay sorularda bile düşük — temel kavram eksikliği var"
                    elif level == "Orta" and pct < 50:
                        yorum = "Orta sorularda takılıyor — pekiştirme çalışması gerekli"
                    elif level == "Zor" and pct < 30:
                        yorum = "Zor sorularda düşük — beklenen, üst düzey düşünme geliştirilmeli"
                    elif pct >= 80:
                        yorum = "Mükemmel başarı bu seviyede"
                    else:
                        yorum = "Kabul edilebilir"

                    st.markdown(f"""<div style="background:#0f172a;border-radius:8px;padding:10px 14px;
                    margin:4px 0;border-left:3px solid {clr};">
                    <div style="display:flex;justify-content:space-between;">
                    <span style="color:#e2e8f0;font-weight:600;">{level}</span>
                    <span style="color:{clr};font-weight:800;">%{pct} ({diff_totals[level]['correct']}/{diff_totals[level]['total']})</span>
                    </div>
                    <div style="font-size:.75rem;color:#94a3b8;margin-top:2px;">{yorum}</div>
                    </div>""", unsafe_allow_html=True)

        # Kazanim bazli basari
        st.markdown("#### Kazanım Bazlı Başarı Analizi")
        outcome_totals: dict[str, dict] = {}
        for r in results:
            ob = r.outcome_breakdown if hasattr(r, 'outcome_breakdown') and r.outcome_breakdown else {}
            if isinstance(ob, dict):
                for oid, data in ob.items():
                    if oid not in outcome_totals:
                        outcome_totals[oid] = {"correct": 0, "total": 0, "text": ""}
                    if isinstance(data, dict):
                        outcome_totals[oid]["correct"] += data.get("correct", 0)
                        outcome_totals[oid]["total"] += data.get("total", 0)
                        if data.get("text"):
                            outcome_totals[oid]["text"] = data["text"]

        if outcome_totals:
            sorted_outcomes = sorted(outcome_totals.items(),
                                      key=lambda x: x[1]["correct"] / max(x[1]["total"], 1))
            # En zayif 5 kazanim
            zayif = sorted_outcomes[:5]
            if zayif:
                st.markdown("**En Zayıf 5 Kazanım** (öncelikli çalışılması gereken)")
                for oid, data in zayif:
                    pct = round(data["correct"] / data["total"] * 100) if data["total"] > 0 else 0
                    clr = "#ef4444" if pct < 50 else "#f59e0b"
                    text = data.get("text", oid)[:60]
                    st.markdown(f"""<div style="background:#1c0505;border-radius:8px;padding:8px 12px;
                    margin:3px 0;border-left:3px solid {clr};">
                    <div style="display:flex;justify-content:space-between;">
                    <span style="color:#fca5a5;font-size:.82rem;">{text}</span>
                    <span style="color:{clr};font-weight:700;">%{pct}</span>
                    </div></div>""", unsafe_allow_html=True)

            # En guclu 5 kazanim
            guclu = sorted_outcomes[-5:][::-1]
            if guclu:
                st.markdown("**En Güçlü 5 Kazanım** (pekiştirmeye devam)")
                for oid, data in guclu:
                    pct = round(data["correct"] / data["total"] * 100) if data["total"] > 0 else 0
                    st.markdown(f"""<div style="background:#052e16;border-radius:8px;padding:8px 12px;
                    margin:3px 0;border-left:3px solid #22c55e;">
                    <div style="display:flex;justify-content:space-between;">
                    <span style="color:#86efac;font-size:.82rem;">{data.get('text', oid)[:60]}</span>
                    <span style="color:#22c55e;font-weight:700;">%{pct}</span>
                    </div></div>""", unsafe_allow_html=True)

    # ═══ 2. SINAV SONUC YORUMLAMA — Her sinav icin otomatik yorum ═══
    if results:
        st.markdown("---")
        st.markdown("#### Sınav Bazlı Akıllı Yorumlar")
        for exam in exams[-5:]:  # son 5 sinav
            exam_id = exam.id if hasattr(exam, 'id') else exam.get('id', '')
            exam_name = exam.name if hasattr(exam, 'name') else exam.get('name', '?')
            exam_results = [r for r in results if r.exam_id == exam_id]
            if not exam_results:
                continue
            scores = [r.score for r in exam_results if r.score is not None]
            if not scores:
                continue
            avg = round(sum(scores) / len(scores), 1)
            mx, mn = max(scores), min(scores)
            basarili = sum(1 for s in scores if s >= 50)
            basarisiz = len(scores) - basarili

            # Verdict
            if avg >= 80:
                v_emoji, v_clr, v_yorum = "🏆", "#22c55e", "Mükemmel performans — sınıf hedefin üstünde"
            elif avg >= 65:
                v_emoji, v_clr, v_yorum = "✅", "#10b981", "İyi — genel başarı tatmin edici"
            elif avg >= 50:
                v_emoji, v_clr, v_yorum = "⚡", "#f59e0b", "Orta — bazı öğrenciler destek bekliyor"
            else:
                v_emoji, v_clr, v_yorum = "🔴", "#ef4444", "Düşük — acil müdahale gerekli, konu tekrarı yapın"

            # Aksiyon
            if avg < 50:
                aksiyon = "Konu tekrarı + etüt programı + bireysel destek planlayın"
            elif basarisiz > basarili:
                aksiyon = "Sınıfın yarısından fazlası başarısız — soru zorluğunu kontrol edin"
            elif mx - mn > 40:
                aksiyon = "Büyük puan farkı — seviye grupları oluşturup farklılaştırılmış öğretim uygulayın"
            else:
                aksiyon = "Başarıyı koruyun, bir sonraki sınav için hedef yükseltin"

            st.markdown(f"""<div style="background:#0f172a;border-radius:12px;padding:14px 18px;
            margin:6px 0;border-left:4px solid {v_clr};">
            <div style="display:flex;justify-content:space-between;align-items:center;">
            <div>
            <div style="font-size:.9rem;font-weight:700;color:#e2e8f0;">{v_emoji} {exam_name}</div>
            <div style="font-size:.78rem;color:#94a3b8;margin-top:2px;">
            {len(exam_results)} öğrenci | Ort: {avg} | Max: {mx:.0f} | Min: {mn:.0f} |
            Başarılı: {basarili} | Başarısız: {basarisiz}</div>
            </div>
            <div style="font-size:1.8rem;font-weight:900;color:{v_clr};">{avg}</div>
            </div>
            <div style="font-size:.78rem;color:{v_clr};margin-top:4px;">{v_yorum}</div>
            <div style="font-size:.75rem;color:#818cf8;margin-top:4px;padding:4px 8px;
            background:rgba(99,102,241,0.08);border-radius:6px;">💡 {aksiyon}</div>
            </div>""", unsafe_allow_html=True)

    # ═══ 3. OGRENCI KARNESI — Radar + Trend ═══
    if results:
        st.markdown("---")
        st.markdown("#### Öğrenci Bazlı Performans Radar")
        st.caption("Her öğrencinin ders bazlı başarısı — radar chart ile görselleştirme")

        # Ogrenci bazli ders puanlari
        stu_ders: dict[str, dict[str, list]] = {}
        stu_names: dict[str, str] = {}
        _exam_map = {e.id: e for e in exams} if exams else {}
        for r in results:
            sid = r.student_id or ""
            sname = r.student_name or ""
            stu_names[sid] = sname
            ders = r.subject if hasattr(r, 'subject') and r.subject else (
                getattr(_exam_map.get(r.exam_id), 'subject', '?') if r.exam_id else '?')
            if sid and ders:
                stu_ders.setdefault(sid, {}).setdefault(ders, []).append(r.score or 0)

        # Dropdown ile ogrenci sec
        stu_opts = {f"{stu_names.get(sid, sid)}": sid for sid in stu_ders if len(stu_ders[sid]) >= 2}
        if stu_opts:
            sel_stu = st.selectbox("Öğrenci Seçin", [""] + list(stu_opts.keys()), key="od_viz_stu_sel")
            if sel_stu and sel_stu in stu_opts:
                sid = stu_opts[sel_stu]
                ders_map = {d: round(sum(p)/len(p), 1) for d, p in stu_ders[sid].items()}

                if len(ders_map) >= 3:
                    import plotly.graph_objects as go
                    from utils.chart_utils import SC_CHART_CFG
                    cats = list(ders_map.keys())
                    vals = list(ders_map.values())
                    fig_r = go.Figure()
                    fig_r.add_trace(go.Scatterpolar(
                        r=vals + [vals[0]], theta=cats + [cats[0]],
                        fill="toself", fillcolor="rgba(99,102,241,0.15)",
                        line=dict(color="#818cf8", width=2), marker=dict(size=6)))
                    fig_r.update_layout(
                        polar=dict(radialaxis=dict(visible=True, range=[0, 100],
                                                    showticklabels=False, gridcolor="#1e293b"),
                                   angularaxis=dict(tickfont=dict(size=10, color="#94a3b8"),
                                                     gridcolor="#1e293b"),
                                   bgcolor="rgba(0,0,0,0)"),
                        showlegend=False, height=300,
                        margin=dict(l=60, r=60, t=20, b=20),
                        paper_bgcolor="rgba(0,0,0,0)", plot_bgcolor="rgba(0,0,0,0)")
                    st.plotly_chart(fig_r, use_container_width=True, config=SC_CHART_CFG,
                                    key="od_viz_stu_radar")

                # Yorum
                en_iyi = max(ders_map.items(), key=lambda x: x[1]) if ders_map else None
                en_kotu = min(ders_map.items(), key=lambda x: x[1]) if ders_map else None
                if en_iyi and en_kotu and en_iyi[0] != en_kotu[0]:
                    fark = en_iyi[1] - en_kotu[1]
                    st.markdown(f"""<div style="background:#0f172a;border-radius:10px;padding:10px 14px;
                    margin:4px 0;border-left:3px solid #6366f1;">
                    <span style="color:#a5b4fc;font-size:.85rem;">
                    📊 En güçlü: <b>{en_iyi[0]}</b> ({en_iyi[1]}) | En zayıf: <b>{en_kotu[0]}</b> ({en_kotu[1]})
                    | Fark: {fark:.0f} puan
                    {' — Bu öğrenci ' + en_kotu[0] + ' dersinde desteğe ihtiyaç duyuyor' if fark > 20 else ''}
                    </span></div>""", unsafe_allow_html=True)
        else:
            st.info("Radar analiz için en az 2 farklı derste sonucu olan öğrenci gerekli.")

    # ═══ 4. CANLI IZLEME UYARI SİSTEMİ ═══
    if sessions:
        st.markdown("---")
        st.markdown("#### Canlı Sınav İzleme — Akıllı Uyarılar")

        aktif_sessions = [s for s in sessions if s.status == "in_progress"]
        tamamlanan = sum(1 for s in sessions if s.status == "submitted")

        if aktif_sessions:
            st.markdown(f"""<div style="background:linear-gradient(135deg,#422006,#78350f);
            border-radius:12px;padding:14px 18px;margin:6px 0;border:1px solid rgba(245,158,11,0.3);">
            <div style="font-size:1rem;font-weight:700;color:#fcd34d;">
            🔴 {len(aktif_sessions)} öğrenci şu anda sınav çözüyor</div>
            <div style="font-size:.82rem;color:#fef3c7;margin-top:4px;">
            Tamamlanan: {tamamlanan} | Devam Eden: {len(aktif_sessions)}</div>
            </div>""", unsafe_allow_html=True)

            for s in aktif_sessions[:10]:
                name = s.student_name if hasattr(s, 'student_name') else "?"
                started = s.started_at if hasattr(s, 'started_at') else ""
                # Sure hesapla
                if started:
                    try:
                        from datetime import datetime as _dt
                        start_dt = _dt.fromisoformat(started.replace("Z", ""))
                        elapsed = (_dt.now() - start_dt).total_seconds() / 60
                        elapsed_str = f"{elapsed:.0f} dk"
                        uyari = ""
                        if elapsed > 60:
                            uyari = "⚠️ 60+ dk geçti — süre kontrolü yapın"
                        elif elapsed > 45:
                            uyari = "🟡 45+ dk — süre daralıyor"
                    except Exception:
                        elapsed_str = "-"
                        uyari = ""
                else:
                    elapsed_str = "-"
                    uyari = ""

                st.markdown(f"""<div style="display:flex;align-items:center;gap:10px;padding:4px 0;
                border-bottom:1px solid #1e293b;">
                <span style="color:#22c55e;">🟢</span>
                <span style="color:#e2e8f0;font-weight:600;flex:1;">{name}</span>
                <span style="color:#94a3b8;font-size:.8rem;">{elapsed_str}</span>
                <span style="color:#f59e0b;font-size:.75rem;">{uyari}</span>
                </div>""", unsafe_allow_html=True)
        else:
            st.info(f"Şu anda aktif sınav oturumu yok. Toplam tamamlanan: {tamamlanan}")

    # ═══ 5. VELİ/ÖĞRENCİ EKRANI İÇİN SONUÇ YORUM MOTORU ═══
    if results:
        st.markdown("---")
        st.markdown("#### Veli & Öğrenci İçin Otomatik Yorum Üretici")
        st.caption("Bu yorumlar veli/öğrenci panelinde ve AI Destek'te otomatik gösterilir")

        # Son 5 sonuc icin yorum
        for r in sorted(results, key=lambda x: getattr(x, 'graded_at', ''), reverse=True)[:5]:
            score = r.score or 0
            name = r.student_name or "?"
            exam_obj = store.get_exam(r.exam_id)
            exam_name = exam_obj.name if exam_obj else "?"
            ders = exam_obj.subject if exam_obj else "?"

            if score >= 85:
                veli_msg = f"Tebrikler! {name}, {ders} sınavında {score:.0f} puan alarak mükemmel bir başarı gösterdi."
                ogr_msg = f"Harika gidiyorsun! {ders}'te {score:.0f} puan — devam et! 🌟"
                clr = "#22c55e"
            elif score >= 70:
                veli_msg = f"{name}, {ders} sınavında {score:.0f} puan aldı. İyi bir performans, küçük iyileştirmelerle daha da yükselir."
                ogr_msg = f"İyi iş! {ders}'te {score:.0f} — biraz daha çalışırsan 85+ yaparsın! ✅"
                clr = "#10b981"
            elif score >= 50:
                veli_msg = f"{name}, {ders} sınavında {score:.0f} puan aldı. Geçer düzeyde ama ek çalışma önerilir."
                ogr_msg = f"{ders}'te {score:.0f} — eksik konuları tekrar et, etüde katıl! ⚡"
                clr = "#f59e0b"
            else:
                veli_msg = f"{name}, {ders} sınavında {score:.0f} puan aldı. Öğretmenle görüşmenizi ve ek destek planlamanızı öneririz."
                ogr_msg = f"{ders}'te {score:.0f} — endişelenme, birlikte çalışacağız! Öğretmeninden yardım iste 💪"
                clr = "#ef4444"

            st.markdown(f"""<div style="background:#0f172a;border-radius:10px;padding:12px 16px;
            margin:4px 0;border-left:3px solid {clr};">
            <div style="font-size:.82rem;font-weight:700;color:#e2e8f0;">{exam_name} — {name} ({score:.0f})</div>
            <div style="font-size:.78rem;color:#94a3b8;margin-top:4px;">
            <b>Veli mesajı:</b> {veli_msg}</div>
            <div style="font-size:.78rem;color:#818cf8;margin-top:2px;">
            <b>Öğrenci mesajı:</b> {ogr_msg}</div>
            </div>""", unsafe_allow_html=True)

    # ── AI VIZYON ──
    st.markdown("---")
    _vizyon_key = "_od_vizyon_text"
    if st.session_state.get(_vizyon_key):
        st.markdown(f"""
        <div style="background:linear-gradient(135deg,#0f172a,#1e1b4b,#4c1d95);
        border-radius:16px;padding:24px;margin:8px 0;border:1.5px solid rgba(139,92,246,0.3);">
        <div style="font-size:.9rem;font-weight:800;color:#c4b5fd;margin-bottom:10px;">
        🔮 Ölçme & Değerlendirme Vizyonu</div>
        <div style="color:#e2e8f0;font-size:.88rem;line-height:1.7;">
        {st.session_state[_vizyon_key]}</div>
        </div>""", unsafe_allow_html=True)
    else:
        if st.button("🔮 AI Vizyon Oluştur — Ölçme & Değerlendirme Yol Haritası",
                       key="od_vizyon_btn", type="primary", use_container_width=True):
            try:
                from utils.smarti_helper import _get_client, _get_ai_response
                client = _get_client()
                if client:
                    with st.spinner("AI vizyon oluşturuyor..."):
                        context = (
                            f"Ölçme & Değerlendirme modülü: {total_q:,} soru ({approved:,} onaylı, "
                            f"{ai_count:,} AI üretim), {len(exams)} sınav, {len(results)} sonuç. "
                            f"Onay oranı %{onay_oran}, AI oranı %{ai_oran}. "
                            f"Sınav ortalaması: {avg if results and puanlar else 'veri yok'}. "
                            f"Bloom dağılımı: {dict(bloom_counts) if bloom_counts else 'yok'}. "
                            f"3 yıllık vizyon yaz: soru bankası kalite hedefi, sınav çeşitliliği, "
                            f"adaptif test, psikometrik olgunluk, AI entegrasyon derinliği. "
                            f"Somut, cesur, ölçülebilir. 300 kelime. Türkçe."
                        )
                        result = _get_ai_response(client, [
                            {"role": "system", "content": "Eğitim ölçme & değerlendirme uzmanı. Cesur, somut, vizyoner."},
                            {"role": "user", "content": context},
                        ])
                        if result:
                            st.session_state[_vizyon_key] = result
                            st.rerun()
            except Exception:
                pass

    # ── KURUM AYARLARI ──
    st.markdown("---")
    with st.expander("⚙️ Kurum Ayarlari (Logo, Sinav Kapak Sayfasi)", expanded=False):
        render_kurum_ayarlari()


# Public API — called by other modules for embedded rendering
_PUBLIC_API = [render_olcme_degerlendirme_embedded]


# Ana cagri
if __name__ == "__main__":
    render_olcme_degerlendirme_v2()
